// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'genesis',
  name: 'Gênesis',
  englishName: 'Genesis',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'In the beginning, God created the heavens and the earth.', pt: 'No princípio criou Deus os céus e a terra.' },
      { v: 2, en: 'The earth was formless and empty. Darkness was on the surface of the deep and God’s Spirit was hovering over the surface of the waters.', pt: 'A terra era sem forma e vazia; e havia trevas sobre a face do abismo, mas o Espírito de Deus pairava sobre a face das águas.' },
      { v: 3, en: 'God said, “Let there be light,” and there was light.', pt: 'Disse Deus: haja luz. E houve luz.' },
      { v: 4, en: 'God saw the light, and saw that it was good. God divided the light from the darkness.', pt: 'Viu Deus que a luz era boa; e fez separação entre a luz e as trevas.' },
      { v: 5, en: 'God called the light “day”, and the darkness he called “night”. There was evening and there was morning, the first day.', pt: 'E Deus chamou à luz dia, e às trevas noite. E foi a tarde e a manhã, o dia primeiro.' },
      { v: 6, en: 'God said, “Let there be an expanse in the middle of the waters, and let it divide the waters from the waters.”', pt: 'E disse Deus: haja um firmamento no meio das águas, e haja separação entre águas e águas.' },
      { v: 7, en: 'God made the expanse, and divided the waters which were under the expanse from the waters which were above the expanse; and it was so.', pt: 'Fez, pois, Deus o firmamento, e separou as águas que estavam debaixo do firmamento das que estavam por cima do firmamento. E assim foi.' },
      { v: 8, en: 'God called the expanse “sky”. There was evening and there was morning, a second day.', pt: 'Chamou Deus ao firmamento céu. E foi a tarde e a manhã, o dia segundo.' },
      { v: 9, en: 'God said, “Let the waters under the sky be gathered together to one place, and let the dry land appear”; and it was so.', pt: 'E disse Deus: Ajuntem-se num só lugar as águas que estão debaixo do céu, e apareça o elemento seco. E assim foi.' },
      { v: 10, en: 'God called the dry land “earth”, and the gathering together of the waters he called “seas”. God saw that it was good.', pt: 'Chamou Deus ao elemento seco terra, e ao ajuntamento das águas mares. E viu Deus que isso era bom.' },
      { v: 11, en: 'God said, “Let the earth yield grass, herbs yielding seeds, and fruit trees bearing fruit after their kind, with their seeds in it, on the earth”; and it was so.', pt: 'E disse Deus: Produza a terra relva, ervas que dêem semente, e árvores frutíferas que, segundo as suas espécies, dêem fruto que tenha em si a sua semente, sobre a terra. E assim foi.' },
      { v: 12, en: 'The earth yielded grass, herbs yielding seed after their kind, and trees bearing fruit, with their seeds in it, after their kind; and God saw that it was good.', pt: 'A terra, pois, produziu relva, ervas que davam semente segundo as suas espécies, e árvores que davam fruto que tinha em si a sua semente, segundo as suas espécies. E viu Deus que isso era bom.' },
      { v: 13, en: 'There was evening and there was morning, a third day.', pt: 'E foi a tarde e a manhã, o dia terceiro.' },
      { v: 14, en: 'God said, “Let there be lights in the expanse of the sky to divide the day from the night; and let them be for signs to mark seasons, days, and years;', pt: 'E disse Deus: haja luminares no firmamento do céu, para fazerem separação entre o dia e a noite; sejam eles para sinais e para estações, e para dias e anos;' },
      { v: 15, en: 'and let them be for lights in the expanse of the sky to give light on the earth”; and it was so.', pt: 'e sirvam de luminares no firmamento do céu, para alumiar a terra. E assim foi.' },
      { v: 16, en: 'God made the two great lights: the greater light to rule the day, and the lesser light to rule the night. He also made the stars.', pt: 'Deus, pois, fez os dois grandes luminares: o luminar maior para governar o dia, e o luminar menor para governar a noite; fez também as estrelas.' },
      { v: 17, en: 'God set them in the expanse of the sky to give light to the earth,', pt: 'E Deus os pôs no firmamento do céu para alumiar a terra,' },
      { v: 18, en: 'and to rule over the day and over the night, and to divide the light from the darkness. God saw that it was good.', pt: 'para governar o dia e a noite, e para fazer separação entre a luz e as trevas. E viu Deus que isso era bom.' },
      { v: 19, en: 'There was evening and there was morning, a fourth day.', pt: 'E foi a tarde e a manhã, o dia quarto.' },
      { v: 20, en: 'God said, “Let the waters abound with living creatures, and let birds fly above the earth in the open expanse of the sky.”', pt: 'E disse Deus: Produzam as águas cardumes de seres viventes; e voem as aves acima da terra no firmamento do céu.' },
      { v: 21, en: 'God created the large sea creatures and every living creature that moves, with which the waters swarmed, after their kind, and every winged bird after its kind. God saw that it was good.', pt: 'Criou, pois, Deus os monstros marinhos, e todos os seres viventes que se arrastavam, os quais as águas produziram abundantemente segundo as suas espécies; e toda ave que voa, segundo a sua espécie. E viu Deus que isso era bom.' },
      { v: 22, en: 'God blessed them, saying, “Be fruitful, and multiply, and fill the waters in the seas, and let birds multiply on the earth.”', pt: 'Então Deus os abençoou, dizendo: Frutificai e multiplicai-vos, e enchei as águas dos mares; e multipliquem-se as aves sobre a terra.' },
      { v: 23, en: 'There was evening and there was morning, a fifth day.', pt: 'E foi a tarde e a manhã, o dia quinto.' },
      { v: 24, en: 'God said, “Let the earth produce living creatures after their kind, livestock, creeping things, and animals of the earth after their kind”; and it was so.', pt: 'E disse Deus: Produza a terra seres viventes segundo as suas espécies: animais domésticos, répteis, e animais selvagens segundo as suas espécies. E assim foi.' },
      { v: 25, en: 'God made the animals of the earth after their kind, and the livestock after their kind, and everything that creeps on the ground after its kind. God saw that it was good.', pt: 'Deus, pois, fez os animais selvagens segundo as suas espécies, e os animais domésticos segundo as suas espécies, e todos os répteis da terra segundo as suas espécies. E viu Deus que isso era bom.' },
      { v: 26, en: 'God said, “Let us make man in our image, after our likeness: and let them have dominion over the fish of the sea, and over the birds of the sky, and over the livestock, and over all the earth, and over every creeping thing that creeps on the earth.”', pt: 'E disse Deus: Façamos o homem à nossa imagem, conforme a nossa semelhança; domine ele sobre os peixes do mar, sobre as aves do céu, sobre os animais domésticos, e sobre toda a terra, e sobre todo réptil que se arrasta sobre a terra.' },
      { v: 27, en: 'God created man in his own image. In God’s image he created him; male and female he created them.', pt: 'Criou, pois, Deus o homem à sua imagem; à imagem de Deus o criou; homem e mulher os criou.' },
      { v: 28, en: 'God blessed them. God said to them, “Be fruitful, multiply, fill the earth, and subdue it. Have dominion over the fish of the sea, over the birds of the sky, and over every living thing that moves on the earth.”', pt: 'Então Deus os abençoou e lhes disse: Frutificai e multiplicai-vos; enchei a terra e sujeitai-a; dominai sobre os peixes do mar, sobre as aves do céu e sobre todos os animais que se arrastam sobre a terra.' },
      { v: 29, en: 'God said, “Behold, I have given you every herb yielding seed, which is on the surface of all the earth, and every tree, which bears fruit yielding seed. It will be your food.', pt: 'Disse-lhes mais: Eis que vos tenho dado todas as ervas que produzem semente, as quais se acham sobre a face de toda a terra, bem como todas as árvores em que há fruto que dê semente; ser-vos-ão para mantimento.' },
      { v: 30, en: 'To every animal of the earth, and to every bird of the sky, and to everything that creeps on the earth, in which there is life, I have given every green herb for food;” and it was so.', pt: 'E a todos os animais da terra, a todas as aves do céu e a todo ser vivente que se arrasta sobre a terra, tenho dado todas as ervas verdes como mantimento. E assim foi.' },
      { v: 31, en: 'God saw everything that he had made, and, behold, it was very good. There was evening and there was morning, a sixth day.', pt: 'E viu Deus tudo quanto fizera, e eis que era muito bom. E foi a tarde e a manhã, o dia sexto.' },
    ],
    2: [
      { v: 1, en: 'The heavens, the earth, and all their vast array were finished.', pt: 'Assim foram acabados os céus e a terra, com todo o seu exército.' },
      { v: 2, en: 'On the seventh day God finished his work which he had done; and he rested on the seventh day from all his work which he had done.', pt: 'Ora, havendo Deus completado no dia sétimo a obra que tinha feito, descansou nesse dia de toda a obra que fizera.' },
      { v: 3, en: 'God blessed the seventh day, and made it holy, because he rested in it from all his work of creation which he had done.', pt: 'Abençoou Deus o sétimo dia, e o santificou; porque nele descansou de toda a sua obra que criara e fizera.' },
      { v: 4, en: 'This is the history of the generations of the heavens and of the earth when they were created, in the day that Yahweh God made the earth and the heavens.', pt: 'Eis as origens dos céus e da terra, quando foram criados. No dia em que o Senhor Deus fez a terra e os céus' },
      { v: 5, en: 'No plant of the field was yet in the earth, and no herb of the field had yet sprung up; for Yahweh God had not caused it to rain on the earth. There was not a man to till the ground,', pt: 'não havia ainda nenhuma planta do campo na terra, pois nenhuma erva do campo tinha ainda brotado; porque o Senhor Deus não tinha feito chover sobre a terra, nem havia homem para lavrar a terra.' },
      { v: 6, en: 'but a mist went up from the earth, and watered the whole surface of the ground.', pt: 'Um vapor, porém, subia da terra, e regava toda a face da terra.' },
      { v: 7, en: 'Yahweh God formed man from the dust of the ground, and breathed into his nostrils the breath of life; and man became a living soul.', pt: 'E formou o Senhor Deus o homem do pó da terra, e soprou-lhe nas narinas o fôlego da vida; e o homem tornou-se alma vivente.' },
      { v: 8, en: 'Yahweh God planted a garden eastward, in Eden, and there he put the man whom he had formed.', pt: 'Então plantou o Senhor Deus um jardim, da banda do oriente, no Éden; e pôs ali o homem que tinha formado.' },
      { v: 9, en: 'Out of the ground Yahweh God made every tree to grow that is pleasant to the sight, and good for food, including the tree of life in the middle of the garden and the tree of the knowledge of good and evil.', pt: 'E o Senhor Deus fez brotar da terra toda qualidade de árvores agradáveis à vista e boas para comida, bem como a árvore da vida no meio do jardim, e a árvore do conhecimento do bem e do mal.' },
      { v: 10, en: 'A river went out of Eden to water the garden; and from there it was parted, and became the source of four rivers.', pt: 'E saía um rio do Éden para regar o jardim; e dali se dividia e se tornava em quatro braços.' },
      { v: 11, en: 'The name of the first is Pishon: it flows through the whole land of Havilah, where there is gold;', pt: 'O nome do primeiro é Pisom: este é o que rodeia toda a terra de Havilá, onde há ouro;' },
      { v: 12, en: 'and the gold of that land is good. Bdellium and onyx stone are also there.', pt: 'e o ouro dessa terra é bom: ali há o bdélio, e a pedra de berilo.' },
      { v: 13, en: 'The name of the second river is Gihon. It is the same river that flows through the whole land of Cush.', pt: 'O nome do segundo rio é Giom: este é o que rodeia toda a terra de Cuche.' },
      { v: 14, en: 'The name of the third river is Hiddekel. This is the one which flows in front of Assyria. The fourth river is the Euphrates.', pt: 'O nome do terceiro rio é Tigre: este é o que corre pelo oriente da Assíria. E o quarto rio é o Eufrates.' },
      { v: 15, en: 'Yahweh God took the man, and put him into the garden of Eden to cultivate and keep it.', pt: 'Tomou, pois, o Senhor Deus o homem, e o pôs no jardim do Édem para o lavrar e guardar.' },
      { v: 16, en: 'Yahweh God commanded the man, saying, “You may freely eat of every tree of the garden;', pt: 'Ordenou o Senhor Deus ao homem, dizendo: De toda árvore do jardim podes comer livremente;' },
      { v: 17, en: 'but you shall not eat of the tree of the knowledge of good and evil; for in the day that you eat of it, you will surely die.”', pt: 'mas da árvore do conhecimento do bem e do mal, dessa não comerás; porque no dia em que dela comeres, certamente morrerás.' },
      { v: 18, en: 'Yahweh God said, “It is not good for the man to be alone. I will make him a helper comparable to him.”', pt: 'Disse mais o Senhor Deus: Não é bom que o homem esteja só; far-lhe-ei uma ajudadora que lhe seja idônea.' },
      { v: 19, en: 'Out of the ground Yahweh God formed every animal of the field, and every bird of the sky, and brought them to the man to see what he would call them. Whatever the man called every living creature became its name.', pt: 'Da terra formou, pois, o Senhor Deus todos os animais o campo e todas as aves do céu, e os trouxe ao homem, para ver como lhes chamaria; e tudo o que o homem chamou a todo ser vivente, isso foi o seu nome.' },
      { v: 20, en: 'The man gave names to all livestock, and to the birds of the sky, and to every animal of the field; but for man there was not found a helper comparable to him.', pt: 'Assim o homem deu nomes a todos os animais domésticos, às aves do céu e a todos os animais do campo; mas para o homem não se achava ajudadora idônea.' },
      { v: 21, en: 'Yahweh God caused the man to fall into a deep sleep. As the man slept, he took one of his ribs, and closed up the flesh in its place.', pt: 'Então o Senhor Deus fez cair um sono pesado sobre o homem, e este adormeceu; tomou-lhe, então, uma das costelas, e fechou a carne em seu lugar;' },
      { v: 22, en: 'Yahweh God made a woman from the rib which he had taken from the man, and brought her to the man.', pt: 'e da costela que o senhor Deus lhe tomara, formou a mulher e a trouxe ao homem.' },
      { v: 23, en: 'The man said, “This is now bone of my bones, and flesh of my flesh. She will be called ‘woman,’ because she was taken out of Man.”', pt: 'Então disse o homem: Esta é agora osso dos meus ossos, e carne da minha carne; ela será chamada varoa, porquanto do varão foi tomada.' },
      { v: 24, en: 'Therefore a man will leave his father and his mother, and will join with his wife, and they will be one flesh.', pt: 'Portanto deixará o homem a seu pai e a sua mãe, e unir-se-á à sua mulher, e serão uma só carne.' },
      { v: 25, en: 'The man and his wife were both naked, and they were not ashamed.', pt: 'E ambos estavam nus, o homem e sua mulher; e não se envergonhavam.' },
    ],
    3: [
      { v: 1, en: 'Now the serpent was more subtle than any animal of the field which Yahweh God had made. He said to the woman, “Has God really said, ‘You shall not eat of any tree of the garden?’”', pt: 'Ora, a serpente era o mais astuto de todos os animais do campo, que o Senhor Deus tinha feito. E esta disse à mulher: É assim que Deus disse: Não comereis de toda árvore do jardim?' },
      { v: 2, en: 'The woman said to the serpent, “We may eat fruit from the trees of the garden,', pt: 'Respondeu a mulher à serpente: Do fruto das árvores do jardim podemos comer,' },
      { v: 3, en: 'but not the fruit of the tree which is in the middle of the garden. God has said, ‘You shall not eat of it. You shall not touch it, lest you die.’”', pt: 'mas do fruto da árvore que está no meio do jardim, disse Deus: Não comereis dele, nem nele tocareis, para que não morrais.' },
      { v: 4, en: 'The serpent said to the woman, “You won’t really die,', pt: 'Disse a serpente à mulher: Certamente não morrereis.' },
      { v: 5, en: 'for God knows that in the day you eat it, your eyes will be opened, and you will be like God, knowing good and evil.”', pt: 'Porque Deus sabe que no dia em que comerdes desse fruto, vossos olhos se abrirão, e sereis como Deus, conhecendo o bem e o mal.' },
      { v: 6, en: 'When the woman saw that the tree was good for food, and that it was a delight to the eyes, and that the tree was to be desired to make one wise, she took some of its fruit, and ate; and she gave some to her husband with her, and he ate it, too.', pt: 'Então, vendo a mulher que aquela árvore era boa para se comer, e agradável aos olhos, e árvore desejável para dar entendimento, tomou do seu fruto, comeu, e deu a seu marido, e ele também comeu.' },
      { v: 7, en: 'Their eyes were opened, and they both knew that they were naked. They sewed fig leaves together, and made coverings for themselves.', pt: 'Então foram abertos os olhos de ambos, e conheceram que estavam nus; pelo que coseram folhas de figueira, e fizeram para si aventais.' },
      { v: 8, en: 'They heard Yahweh God’s voice walking in the garden in the cool of the day, and the man and his wife hid themselves from the presence of Yahweh God among the trees of the garden.', pt: 'E, ouvindo a voz do Senhor Deus, que passeava no jardim à tardinha, esconderam-se o homem e sua mulher da presença do Senhor Deus, entre as árvores do jardim.' },
      { v: 9, en: 'Yahweh God called to the man, and said to him, “Where are you?”', pt: 'Mas chamou o Senhor Deus ao homem, e perguntou-lhe: Onde estás?' },
      { v: 10, en: 'The man said, “I heard your voice in the garden, and I was afraid, because I was naked; and I hid myself.”', pt: 'Respondeu-lhe o homem: Ouvi a tua voz no jardim e tive medo, porque estava nu; e escondi-me.' },
      { v: 11, en: 'God said, “Who told you that you were naked? Have you eaten from the tree that I commanded you not to eat from?”', pt: 'Deus perguntou-lhe mais: Quem te mostrou que estavas nu? Comeste da árvore de que te ordenei que não comesses?' },
      { v: 12, en: 'The man said, “The woman whom you gave to be with me, she gave me fruit from the tree, and I ate it.”', pt: 'Ao que respondeu o homem: A mulher que me deste por companheira deu-me a árvore, e eu comi.' },
      { v: 13, en: 'Yahweh God said to the woman, “What have you done?” The woman said, “The serpent deceived me, and I ate.”', pt: 'Perguntou o Senhor Deus à mulher: Que é isto que fizeste? Respondeu a mulher: A serpente enganou-me, e eu comi.' },
      { v: 14, en: 'Yahweh God said to the serpent, “Because you have done this, you are cursed above all livestock, and above every animal of the field. You shall go on your belly and you shall eat dust all the days of your life.', pt: 'Então o Senhor Deus disse à serpente: Porquanto fizeste isso, maldita serás tu dentre todos os animais domésticos, e dentre todos os animais do campo; sobre o teu ventre andarás, e pó comerás todos os dias da tua vida.' },
      { v: 15, en: 'I will put hostility between you and the woman, and between your offspring and her offspring. He will bruise your head, and you will bruise his heel.”', pt: 'Porei inimizade entre ti e a mulher, e entre a tua descendência e a sua descendência; esta te ferirá a cabeça, e tu lhe ferirás o calcanhar.' },
      { v: 16, en: 'To the woman he said, “I will greatly multiply your pain in childbirth. In pain you will bear children. Your desire will be for your husband, and he will rule over you.”', pt: 'E à mulher disse: Multiplicarei grandemente a dor da tua conceição; em dor darás à luz filhos; e o teu desejo será para o teu marido, e ele te dominará.' },
      { v: 17, en: 'To Adam he said, “Because you have listened to your wife’s voice, and ate from the tree, about which I commanded you, saying, ‘You shall not eat of it,’ the ground is cursed for your sake. You will eat from it with much labor all the days of your life.', pt: 'E ao homem disse: Porquanto deste ouvidos à voz de tua mulher, e comeste da árvore de que te ordenei dizendo: Não comerás dela; maldita é a terra por tua causa; em fadiga comerás dela todos os dias da tua vida.' },
      { v: 18, en: 'It will yield thorns and thistles to you; and you will eat the herb of the field.', pt: 'Ela te produzirá espinhos e abrolhos; e comerás das ervas do campo.' },
      { v: 19, en: 'By the sweat of your face will you eat bread until you return to the ground, for out of it you were taken. For you are dust, and to dust you shall return.”', pt: 'Do suor do teu rosto comerás o teu pão, até que tornes à terra, porque dela foste tomado; porquanto és pó, e ao pó tornarás.' },
      { v: 20, en: 'The man called his wife Eve because she would be the mother of all the living.', pt: 'Chamou Adão à sua mulher Eva, porque era a mãe de todos os viventes.' },
      { v: 21, en: 'Yahweh God made coats of animal skins for Adam and for his wife, and clothed them.', pt: 'E o Senhor Deus fez túnicas de peles para Adão e sua mulher, e os vestiu.' },
      { v: 22, en: 'Yahweh God said, “Behold, the man has become like one of us, knowing good and evil. Now, lest he reach out his hand, and also take of the tree of life, and eat, and live forever—”', pt: 'Então disse o Senhor Deus: Eis que o homem se tem tornado como um de nós, conhecendo o bem e o mal. Ora, não suceda que estenda a sua mão, e tome também da árvore da vida, e coma e viva eternamente.' },
      { v: 23, en: 'Therefore Yahweh God sent him out from the garden of Eden, to till the ground from which he was taken.', pt: 'O Senhor Deus, pois, o lançou fora do jardim do Éden para lavrar a terra, de que fora tomado.' },
      { v: 24, en: 'So he drove out the man; and he placed cherubim at the east of the garden of Eden, and a flaming sword which turned every way, to guard the way to the tree of life.', pt: 'E havendo lançado fora o homem, pôs ao oriente do jardim do Éden os querubins, e uma espada flamejante que se volvia por todos os lados, para guardar o caminho da árvore da vida.' },
    ],
    4: [
      { v: 1, en: 'The man knew Eve his wife. She conceived, and gave birth to Cain, and said, “I have gotten a man with Yahweh’s help.”', pt: 'Conheceu Adão a Eva, sua mulher; ela concebeu e, tendo dado à luz a Caim, disse: Alcancei do Senhor um varão.' },
      { v: 2, en: 'Again she gave birth, to Cain’s brother Abel. Abel was a keeper of sheep, but Cain was a tiller of the ground.', pt: 'Tornou a dar à luz a um filho - a seu irmão Abel. Abel foi pastor de ovelhas, e Caim foi lavrador da terra.' },
      { v: 3, en: 'As time passed, Cain brought an offering to Yahweh from the fruit of the ground.', pt: 'Ao cabo de dias trouxe Caim do fruto da terra uma oferta ao Senhor.' },
      { v: 4, en: 'Abel also brought some of the firstborn of his flock and of its fat. Yahweh respected Abel and his offering,', pt: 'Abel também trouxe dos primogênitos das suas ovelhas, e da sua gordura. Ora, atentou o Senhor para Abel e para a sua oferta,' },
      { v: 5, en: 'but he didn’t respect Cain and his offering. Cain was very angry, and the expression on his face fell.', pt: 'mas para Caim e para a sua oferta não atentou. Pelo que irou-se Caim fortemente, e descaiu-lhe o semblante.' },
      { v: 6, en: 'Yahweh said to Cain, “Why are you angry? Why has the expression of your face fallen?', pt: 'Então o Senhor perguntou a Caim: Por que te iraste? e por que está descaído o teu semblante?' },
      { v: 7, en: 'If you do well, won’t it be lifted up? If you don’t do well, sin crouches at the door. Its desire is for you, but you are to rule over it.”', pt: 'Porventura se procederes bem, não se há de levantar o teu semblante? e se não procederes bem, o pecado jaz à porta, e sobre ti será o seu desejo; mas sobre ele tu deves dominar.' },
      { v: 8, en: 'Cain said to Abel, his brother, “Let’s go into the field.” While they were in the field, Cain rose up against Abel, his brother, and killed him.', pt: 'Falou Caim com o seu irmão Abel. E, estando eles no campo, Caim se levantou contra o seu irmão Abel, e o matou.' },
      { v: 9, en: 'Yahweh said to Cain, “Where is Abel, your brother?” He said, “I don’t know. Am I my brother’s keeper?”', pt: 'Perguntou, pois, o Senhor a Caim: Onde está Abel, teu irmão? Respondeu ele: Não sei; sou eu o guarda do meu irmão?' },
      { v: 10, en: 'Yahweh said, “What have you done? The voice of your brother’s blood cries to me from the ground.', pt: 'E disse Deus: Que fizeste? A voz do sangue de teu irmão está clamando a mim desde a terra.' },
      { v: 11, en: 'Now you are cursed because of the ground, which has opened its mouth to receive your brother’s blood from your hand.', pt: 'Agora maldito és tu desde a terra, que abriu a sua boca para da tua mão receber o sangue de teu irmão.' },
      { v: 12, en: 'From now on, when you till the ground, it won’t yield its strength to you. You will be a fugitive and a wanderer in the earth.”', pt: 'Quando lavrares a terra, não te dará mais a sua força; fugitivo e vagabundo serás na terra.' },
      { v: 13, en: 'Cain said to Yahweh, “My punishment is greater than I can bear.', pt: 'Então disse Caim ao Senhor: É maior a minha punição do que a que eu possa suportar.' },
      { v: 14, en: 'Behold, you have driven me out today from the surface of the ground. I will be hidden from your face, and I will be a fugitive and a wanderer in the earth. Whoever finds me will kill me.”', pt: 'Eis que hoje me lanças da face da terra; também da tua presença ficarei escondido; serei fugitivo e vagabundo na terra; e qualquer que me encontrar matar-me-á.' },
      { v: 15, en: 'Yahweh said to him, “Therefore whoever slays Cain, vengeance will be taken on him sevenfold.” Yahweh appointed a sign for Cain, so that anyone finding him would not strike him.', pt: 'O Senhor, porém, lhe disse: Portanto quem matar a Caim, sete vezes sobre ele cairá a vingança. E pôs o Senhor um sinal em Caim, para que não o ferisse quem quer que o encontrasse.' },
      { v: 16, en: 'Cain left Yahweh’s presence, and lived in the land of Nod, east of Eden.', pt: 'Então saiu Caim da presença do Senhor, e habitou na terra de Node, ao oriente do Éden.' },
      { v: 17, en: 'Cain knew his wife. She conceived, and gave birth to Enoch. He built a city, and called the name of the city, after the name of his son, Enoch.', pt: 'Conheceu Caim a sua mulher, a qual concebeu, e deu à luz a Enoque. Caim edificou uma cidade, e lhe deu o nome do filho, Enoque.' },
      { v: 18, en: 'To Enoch was born Irad. Irad became the father of Mehujael. Mehujael became the father of Methushael. Methushael became the father of Lamech.', pt: 'A Enoque nasceu Irade, e Irade gerou a Meüjael, e Meüjael gerou a Metusael, e Metusael gerou a Lameque.' },
      { v: 19, en: 'Lamech took two wives: the name of the first one was Adah, and the name of the second one was Zillah.', pt: 'Lameque tomou para si duas mulheres: o nome duma era Ada, e o nome da outra Zila.' },
      { v: 20, en: 'Adah gave birth to Jabal, who was the father of those who dwell in tents and have livestock.', pt: 'E Ada deu à luz a Jabal; este foi o pai dos que habitam em tendas e possuem gado.' },
      { v: 21, en: 'His brother’s name was Jubal, who was the father of all who handle the harp and pipe.', pt: 'O nome do seu irmão era Jubal; este foi o pai de todos os que tocam harpa e flauta.' },
      { v: 22, en: 'Zillah also gave birth to Tubal Cain, the forger of every cutting instrument of brass and iron. Tubal Cain’s sister was Naamah.', pt: 'A Zila também nasceu um filho, Tubal-Caim, fabricante de todo instrumento cortante de cobre e de ferro; e a irmã de Tubal-Caim foi Naama.' },
      { v: 23, en: 'Lamech said to his wives, “Adah and Zillah, hear my voice. You wives of Lamech, listen to my speech, for I have slain a man for wounding me, a young man for bruising me.', pt: 'Disse Lameque a suas mulheres: Ada e Zila, ouvi a minha voz; escutai, mulheres de Lameque, as minhas palavras; pois matei um homem por me ferir, e um mancebo por me pisar.' },
      { v: 24, en: 'If Cain will be avenged seven times, truly Lamech seventy-seven times.”', pt: 'Se Caim há de ser vingado sete vezes, com certeza Lameque o será setenta e sete vezes.' },
      { v: 25, en: 'Adam knew his wife again. She gave birth to a son, and named him Seth, saying, “for God has given me another child instead of Abel, for Cain killed him.”', pt: 'Tornou Adão a conhecer sua mulher, e ela deu à luz um filho, a quem pôs o nome de Sete; porque, disse ela, Deus me deu outro filho em lugar de Abel; porquanto Caim o matou.' },
      { v: 26, en: 'A son was also born to Seth, and he named him Enosh. At that time men began to call on Yahweh’s name.', pt: 'A Sete também nasceu um filho, a quem pôs o nome de Enos. Foi nesse tempo, que os homens começaram a invocar o nome do Senhor.' },
    ],
    5: [
      { v: 1, en: 'This is the book of the generations of Adam. In the day that God created man, he made him in God’s likeness.', pt: 'Este é o livro das gerações de Adão. No dia em que Deus criou o homem, à semelhança de Deus o fez.' },
      { v: 2, en: 'He created them male and female, and blessed them. On the day they were created, he named them “Adam”.', pt: 'Homem e mulher os criou; e os abençoou, e os chamou pelo nome de homem, no dia em que foram criados.' },
      { v: 3, en: 'Adam lived one hundred thirty years, and became the father of a son in his own likeness, after his image, and named him Seth.', pt: 'Adão viveu cento e trinta anos, e gerou um filho à sua semelhança, conforme a sua imagem, e pôs-lhe o nome de Sete.' },
      { v: 4, en: 'The days of Adam after he became the father of Seth were eight hundred years, and he became the father of other sons and daughters.', pt: 'E foram os dias de Adão, depois que gerou a Sete, oitocentos anos; e gerou filhos e filhas.' },
      { v: 5, en: 'All the days that Adam lived were nine hundred thirty years, then he died.', pt: 'Todos os dias que Adão viveu foram novecentos e trinta anos; e morreu.' },
      { v: 6, en: 'Seth lived one hundred five years, then became the father of Enosh.', pt: 'Sete viveu cento e cinco anos, e gerou a Enos.' },
      { v: 7, en: 'Seth lived after he became the father of Enosh eight hundred seven years, and became the father of other sons and daughters.', pt: 'Viveu Sete, depois que gerou a Enos, oitocentos e sete anos; e gerou filhos e filhas.' },
      { v: 8, en: 'All of the days of Seth were nine hundred twelve years, then he died.', pt: 'Todos os dias de Sete foram novecentos e doze anos; e morreu.' },
      { v: 9, en: 'Enosh lived ninety years, and became the father of Kenan.', pt: 'Enos viveu noventa anos, e gerou a Quenã.' },
      { v: 10, en: 'Enosh lived after he became the father of Kenan, eight hundred fifteen years, and became the father of other sons and daughters.', pt: 'viveu Enos, depois que gerou a Quenã, oitocentos e quinze anos; e gerou filhos e filhas.' },
      { v: 11, en: 'All of the days of Enosh were nine hundred five years, then he died.', pt: 'Todos os dias de Enos foram novecentos e cinco anos; e morreu.' },
      { v: 12, en: 'Kenan lived seventy years, then became the father of Mahalalel.', pt: 'Quenã viveu setenta anos, e gerou a Maalalel.' },
      { v: 13, en: 'Kenan lived after he became the father of Mahalalel eight hundred forty years, and became the father of other sons and daughters', pt: 'Viveu Quenã, depois que gerou a Maalalel, oitocentos e quarenta anos, e gerou filhos e filhas.' },
      { v: 14, en: 'and all of the days of Kenan were nine hundred ten years, then he died.', pt: 'Todos os dias de Quenã foram novecentos e dez anos; e morreu.' },
      { v: 15, en: 'Mahalalel lived sixty-five years, then became the father of Jared.', pt: 'Maalalel viveu sessenta e cinco anos, e gerou a Jarede.' },
      { v: 16, en: 'Mahalalel lived after he became the father of Jared eight hundred thirty years, and became the father of other sons and daughters.', pt: 'Viveu Maalalel, depois que gerou a Jarede, oitocentos e trinta anos; e gerou filhos e filhas.' },
      { v: 17, en: 'All of the days of Mahalalel were eight hundred ninety-five years, then he died.', pt: 'Todos os dias de Maalalel foram oitocentos e noventa e cinco anos; e morreu.' },
      { v: 18, en: 'Jared lived one hundred sixty-two years, then became the father of Enoch.', pt: 'Jarede viveu cento e sessenta e dois anos, e gerou a Enoque.' },
      { v: 19, en: 'Jared lived after he became the father of Enoch eight hundred years, and became the father of other sons and daughters.', pt: 'Viveu Jarede, depois que gerou a Enoque, oitocentos anos; e gerou filhos e filhas.' },
      { v: 20, en: 'All of the days of Jared were nine hundred sixty-two years, then he died.', pt: 'Todos os dias de Jarede foram novecentos e sessenta e dois anos; e morreu.' },
      { v: 21, en: 'Enoch lived sixty-five years, then became the father of Methuselah.', pt: 'Enoque viveu sessenta e cinco anos, e gerou a Matusalém.' },
      { v: 22, en: 'After Methuselah’s birth, Enoch walked with God for three hundred years, and became the father of more sons and daughters.', pt: 'Andou Enoque com Deus, depois que gerou a Matusalém, trezentos anos; e gerou filhos e filhas.' },
      { v: 23, en: 'All the days of Enoch were three hundred sixty-five years.', pt: 'Todos os dias de Enoque foram trezentos e sessenta e cinco anos;' },
      { v: 24, en: 'Enoch walked with God, and he was not found, for God took him.', pt: 'Enoque andou com Deus; e não apareceu mais, porquanto Deus o tomou.' },
      { v: 25, en: 'Methuselah lived one hundred eighty-seven years, then became the father of Lamech.', pt: 'Matusalém viveu cento e oitenta e sete anos, e gerou a Lameque.' },
      { v: 26, en: 'Methuselah lived after he became the father of Lamech seven hundred eighty-two years, and became the father of other sons and daughters.', pt: 'Viveu Matusalém, depois que gerou a Lameque, setecentos e oitenta e dois anos; e gerou filhos e filhas.' },
      { v: 27, en: 'All the days of Methuselah were nine hundred sixty-nine years, then he died.', pt: 'Todos os dias de Matusalém foram novecentos e sessenta e nove anos; e morreu.' },
      { v: 28, en: 'Lamech lived one hundred eighty-two years, then became the father of a son.', pt: 'Lameque viveu cento e oitenta e dois anos, e gerou um filho,' },
      { v: 29, en: 'He named him Noah, saying, “This one will comfort us in our work and in the toil of our hands, caused by the ground which Yahweh has cursed.”', pt: 'a quem chamou Noé, dizendo: Este nos consolará acerca de nossas obras e do trabalho de nossas mãos, os quais provêm da terra que o Senhor amaldiçoou.' },
      { v: 30, en: 'Lamech lived after he became the father of Noah five hundred ninety-five years, and became the father of other sons and daughters.', pt: 'Viveu Lameque, depois que gerou a Noé, quinhentos e noventa e cinco anos; e gerou filhos e filhas.' },
      { v: 31, en: 'All the days of Lamech were seven hundred seventy-seven years, then he died.', pt: 'Todos os dias de Lameque foram setecentos e setenta e sete anos; e morreu.' },
      { v: 32, en: 'Noah was five hundred years old, then Noah became the father of Shem, Ham, and Japheth.', pt: 'E era Noé da idade de quinhentos anos; e gerou Noé a Sem, Cão e Jafé.' },
    ],
    6: [
      { v: 1, en: 'When men began to multiply on the surface of the ground, and daughters were born to them,', pt: 'Sucedeu que, quando os homens começaram a multiplicar-se sobre a terra, e lhes nasceram filhas,' },
      { v: 2, en: 'God’s sons saw that men’s daughters were beautiful, and they took any that they wanted for themselves as wives.', pt: 'viram os filhos de Deus que as filhas dos homens eram formosas; e tomaram para si mulheres de todas as que escolheram.' },
      { v: 3, en: 'Yahweh said, “My Spirit will not strive with man forever, because he also is flesh; so his days will be one hundred twenty years.”', pt: 'Então disse o Senhor: O meu Espírito não permanecerá para sempre no homem, porquanto ele é carne, mas os seus dias serão cento e vinte anos.' },
      { v: 4, en: 'The Nephilim were in the earth in those days, and also after that, when God’s sons came in to men’s daughters and had children with them. Those were the mighty men who were of old, men of renown.', pt: 'Naqueles dias estavam os nefilins na terra, e também depois, quando os filhos de Deus conheceram as filhas dos homens, as quais lhes deram filhos. Esses nefilins eram os valentes, os homens de renome, que houve na antigüidade.' },
      { v: 5, en: 'Yahweh saw that the wickedness of man was great in the earth, and that every imagination of the thoughts of man’s heart was continually only evil.', pt: 'Viu o Senhor que era grande a maldade do homem na terra, e que toda a imaginação dos pensamentos de seu coração era má continuamente.' },
      { v: 6, en: 'Yahweh was sorry that he had made man on the earth, and it grieved him in his heart.', pt: 'Então arrependeu-se o Senhor de haver feito o homem na terra, e isso lhe pesou no coração' },
      { v: 7, en: 'Yahweh said, “I will destroy man whom I have created from the surface of the ground—man, along with animals, creeping things, and birds of the sky—for I am sorry that I have made them.”', pt: 'E disse o Senhor: Destruirei da face da terra o homem que criei, tanto o homem como o animal, os répteis e as aves do céu; porque me arrependo de os haver feito.' },
      { v: 8, en: 'But Noah found favor in Yahweh’s eyes.', pt: 'Noé, porém, achou graça aos olhos do Senhor.' },
      { v: 9, en: 'This is the history of the generations of Noah: Noah was a righteous man, blameless among the people of his time. Noah walked with God.', pt: 'Estas são as gerações de Noé. Era homem justo e perfeito em suas gerações, e andava com Deus.' },
      { v: 10, en: 'Noah became the father of three sons: Shem, Ham, and Japheth.', pt: 'Gerou Noé três filhos: Sem, Cão e Jafé.' },
      { v: 11, en: 'The earth was corrupt before God, and the earth was filled with violence.', pt: 'A terra, porém, estava corrompida diante de Deus, e cheia de violência.' },
      { v: 12, en: 'God saw the earth, and saw that it was corrupt, for all flesh had corrupted their way on the earth.', pt: 'Viu Deus a terra, e eis que estava corrompida; porque toda a carne havia corrompido o seu caminho sobre a terra.' },
      { v: 13, en: 'God said to Noah, “I will bring an end to all flesh, for the earth is filled with violence through them. Behold, I will destroy them and the earth.', pt: 'Então disse Deus a Noé: O fim de toda carne é chegado perante mim; porque a terra está cheia da violência dos homens; eis que os destruirei juntamente com a terra.' },
      { v: 14, en: 'Make a ship of gopher wood. You shall make rooms in the ship, and shall seal it inside and outside with pitch.', pt: 'Faze para ti uma arca de madeira de gôfer: farás compartimentos na arca, e a revestirás de betume por dentro e por fora.' },
      { v: 15, en: 'This is how you shall make it. The length of the ship shall be three hundred cubits, its width fifty cubits, and its height thirty cubits.', pt: 'Desta maneira a farás: o comprimento da arca será de trezentos côvados, a sua largura de cinqüenta e a sua altura de trinta.' },
      { v: 16, en: 'You shall make a roof in the ship, and you shall finish it to a cubit upward. You shall set the door of the ship in its side. You shall make it with lower, second, and third levels.', pt: 'Farás na arca uma janela e lhe darás um côvado de altura; e a porta da arca porás no seu lado; fá-la-ás com andares, baixo, segundo e terceiro.' },
      { v: 17, en: 'I, even I, do bring the flood of waters on this earth, to destroy all flesh having the breath of life from under the sky. Everything that is in the earth will die.', pt: 'Porque eis que eu trago o dilúvio sobre a terra, para destruir, de debaixo do céu, toda a carne em que há espírito de vida; tudo o que há na terra expirará.' },
      { v: 18, en: 'But I will establish my covenant with you. You shall come into the ship, you, your sons, your wife, and your sons’ wives with you.', pt: 'Mas contigo estabelecerei o meu pacto; entrarás na arca, tu e contigo teus filhos, tua mulher e as mulheres de teus filhos.' },
      { v: 19, en: 'Of every living thing of all flesh, you shall bring two of every sort into the ship, to keep them alive with you. They shall be male and female.', pt: 'De tudo o que vive, de toda a carne, dois de cada espécie, farás entrar na arca, para os conservares vivos contigo; macho e fêmea serão.' },
      { v: 20, en: 'Of the birds after their kind, of the livestock after their kind, of every creeping thing of the ground after its kind, two of every sort will come to you, to keep them alive.', pt: 'Das aves segundo as suas espécies, do gado segundo as suas espécies, de todo réptil da terra segundo as suas espécies, dois de cada espécie virão a ti, para os conservares em vida.' },
      { v: 21, en: 'Take with you some of all food that is eaten, and gather it to yourself; and it will be for food for you, and for them.”', pt: 'Leva contigo de tudo o que se come, e ajunta-o para ti; e te será para alimento, a ti e a eles.' },
      { v: 22, en: 'Thus Noah did. He did all that God commanded him.', pt: 'Assim fez Noé; segundo tudo o que Deus lhe mandou, assim o fez.' },
    ],
    7: [
      { v: 1, en: 'Yahweh said to Noah, “Come with all of your household into the ship, for I have seen your righteousness before me in this generation.', pt: 'Depois disse o Senhor a Noé: Entra na arca, tu e toda a tua casa, porque tenho visto que és justo diante de mim nesta geração.' },
      { v: 2, en: 'You shall take seven pairs of every clean animal with you, the male and his female. Of the animals that are not clean, take two, the male and his female.', pt: 'De todos os animais limpos levarás contigo sete e sete, o macho e sua fêmea; mas dos animais que não são limpos, dois, o macho e sua fêmea;' },
      { v: 3, en: 'Also of the birds of the sky, seven and seven, male and female, to keep seed alive on the surface of all the earth.', pt: 'também das aves do céu sete e sete, macho e fêmea, para se conservar em vida sua espécie sobre a face de toda a terra.' },
      { v: 4, en: 'In seven days, I will cause it to rain on the earth for forty days and forty nights. I will destroy every living thing that I have made from the surface of the ground.”', pt: 'Porque, passados ainda sete dias, farei chover sobre a terra quarenta dias e quarenta noites, e exterminarei da face da terra todas as criaturas que fiz.' },
      { v: 5, en: 'Noah did everything that Yahweh commanded him.', pt: 'E Noé fez segundo tudo o que o Senhor lhe ordenara.' },
      { v: 6, en: 'Noah was six hundred years old when the flood of waters came on the earth.', pt: 'Tinha Noé seiscentos anos de idade, quando o dilúvio veio sobre a terra.' },
      { v: 7, en: 'Noah went into the ship with his sons, his wife, and his sons’ wives, because of the floodwaters.', pt: 'Noé entrou na arca com seus filhos, sua mulher e as mulheres de seus filhos, por causa das águas do dilúvio.' },
      { v: 8, en: 'Clean animals, unclean animals, birds, and everything that creeps on the ground', pt: 'Dos animais limpos e dos que não são limpos, das aves, e de todo réptil sobre a terra,' },
      { v: 9, en: 'went by pairs to Noah into the ship, male and female, as God commanded Noah.', pt: 'entraram dois a dois para junto de Noé na arca, macho e fêmea, como Deus ordenara a Noé.' },
      { v: 10, en: 'After the seven days, the floodwaters came on the earth.', pt: 'Passados os sete dias, vieram sobre a terra as águas do dilúvio.' },
      { v: 11, en: 'In the six hundredth year of Noah’s life, in the second month, on the seventeenth day of the month, on the same day all the fountains of the great deep burst open, and the sky’s windows opened.', pt: 'No ano seiscentos da vida de Noé, no mês segundo, aos dezessete dias do mês, romperam-se todas as fontes do grande abismo, e as janelas do céu se abriram,' },
      { v: 12, en: 'It rained on the earth forty days and forty nights.', pt: 'e caiu chuva sobre a terra quarenta dias e quarenta noites.' },
      { v: 13, en: 'In the same day Noah, and Shem, Ham, and Japheth—the sons of Noah—and Noah’s wife and the three wives of his sons with them, entered into the ship—', pt: 'Nesse mesmo dia entrou Noé na arca, e juntamente com ele seus filhos Sem, Cão e Jafé, como também sua mulher e as três mulheres de seus filhos,' },
      { v: 14, en: 'they, and every animal after its kind, all the livestock after their kind, every creeping thing that creeps on the earth after its kind, and every bird after its kind, every bird of every sort.', pt: 'e com eles todo animal segundo a sua espécie, todo o gado segundo a sua espécie, todo réptil que se arrasta sobre a terra segundo a sua espécie e toda ave segundo a sua espécie, pássaros de toda qualidade.' },
      { v: 15, en: 'Pairs from all flesh with the breath of life in them went into the ship to Noah.', pt: 'Entraram para junto de Noé na arca, dois a dois de toda a carne em que havia espírito de vida.' },
      { v: 16, en: 'Those who went in, went in male and female of all flesh, as God commanded him; then Yahweh shut him in.', pt: 'E os que entraram eram macho e fêmea de toda a carne, como Deus lhe tinha ordenado; e o Senhor o fechou dentro.' },
      { v: 17, en: 'The flood was forty days on the earth. The waters increased, and lifted up the ship, and it was lifted up above the earth.', pt: 'Veio o dilúvio sobre a terra durante quarenta dias; e as águas cresceram e levantaram a arca, e ela se elevou por cima da terra.' },
      { v: 18, en: 'The waters rose, and increased greatly on the earth; and the ship floated on the surface of the waters.', pt: 'Prevaleceram as águas e cresceram grandemente sobre a terra; e a arca vagava sobre as águas.' },
      { v: 19, en: 'The waters rose very high on the earth. All the high mountains that were under the whole sky were covered.', pt: 'As águas prevaleceram excessivamente sobre a terra; e todos os altos montes que havia debaixo do céu foram cobertos.' },
      { v: 20, en: 'The waters rose fifteen cubits higher, and the mountains were covered.', pt: 'Quinze côvados acima deles prevaleceram as águas; e assim foram cobertos.' },
      { v: 21, en: 'All flesh died that moved on the earth, including birds, livestock, animals, every creeping thing that creeps on the earth, and every man.', pt: 'Pereceu toda a carne que se movia sobre a terra, tanto ave como gado, animais selvagens, todo réptil que se arrasta sobre a terra, e todo homem.' },
      { v: 22, en: 'All on the dry land, in whose nostrils was the breath of the spirit of life, died.', pt: 'Tudo o que tinha fôlego do espírito de vida em suas narinas, tudo o que havia na terra seca, morreu.' },
      { v: 23, en: 'Every living thing was destroyed that was on the surface of the ground, including man, livestock, creeping things, and birds of the sky. They were destroyed from the earth. Only Noah was left, and those who were with him in the ship.', pt: 'Assim foram exterminadas todas as criaturas que havia sobre a face da terra, tanto o homem como o gado, o réptil, e as aves do céu; todos foram exterminados da terra; ficou somente Noé, e os que com ele estavam na arca.' },
      { v: 24, en: 'The waters flooded the earth one hundred fifty days.', pt: 'E prevaleceram as águas sobre a terra cento e cinqüenta dias.' },
    ],
    8: [
      { v: 1, en: 'God remembered Noah, all the animals, and all the livestock that were with him in the ship; and God made a wind to pass over the earth. The waters subsided.', pt: 'Deus lembrou-se de Noé, de todos os animais e de todo o gado, que estavam com ele na arca; e Deus fez passar um vento sobre a terra, e as águas começaram a diminuir.' },
      { v: 2, en: 'The deep’s fountains and the sky’s windows were also stopped, and the rain from the sky was restrained.', pt: 'Cerraram-se as fontes do abismo e as janelas do céu, e a chuva do céu se deteve;' },
      { v: 3, en: 'The waters continually receded from the earth. After the end of one hundred fifty days the waters decreased.', pt: 'as águas se foram retirando de sobre a terra; no fim de cento e cinqüenta dias começaram a minguar.' },
      { v: 4, en: 'The ship rested in the seventh month, on the seventeenth day of the month, on Ararat’s mountains.', pt: 'No sétimo mês, no dia dezessete do mês, repousou a arca sobre os montes de Arará.' },
      { v: 5, en: 'The waters receded continually until the tenth month. In the tenth month, on the first day of the month, the tops of the mountains were visible.', pt: 'E as águas foram minguando até o décimo mês; no décimo mês, no primeiro dia do mês, apareceram os cumes dos montes.' },
      { v: 6, en: 'At the end of forty days, Noah opened the window of the ship which he had made,', pt: 'Ao cabo de quarenta dias, abriu Noé a janela que havia feito na arca;' },
      { v: 7, en: 'and he sent out a raven. It went back and forth, until the waters were dried up from the earth.', pt: 'soltou um corvo que, saindo, ia e voltava até que as águas se secaram de sobre a terra.' },
      { v: 8, en: 'He himself sent out a dove to see if the waters were abated from the surface of the ground,', pt: 'Depois soltou uma pomba, para ver se as águas tinham minguado de sobre a face da terra;' },
      { v: 9, en: 'but the dove found no place to rest her foot, and she returned into the ship to him, for the waters were on the surface of the whole earth. He put out his hand, and took her, and brought her to him into the ship.', pt: 'mas a pomba não achou onde pousar a planta do pé, e voltou a ele para a arca; porque as águas ainda estavam sobre a face de toda a terra; e Noé, estendendo a mão, tomou-a e a recolheu consigo na arca.' },
      { v: 10, en: 'He waited yet another seven days; and again he sent the dove out of the ship.', pt: 'Esperou ainda outros sete dias, e tornou a soltar a pomba fora da arca.' },
      { v: 11, en: 'The dove came back to him at evening and, behold, in her mouth was a freshly plucked olive leaf. So Noah knew that the waters were abated from the earth.', pt: 'Â tardinha a pomba voltou para ele, e eis no seu bico uma folha verde de oliveira; assim soube Noé que as águas tinham minguado de sobre a terra.' },
      { v: 12, en: 'He waited yet another seven days, and sent out the dove; and she didn’t return to him anymore.', pt: 'Então esperou ainda outros sete dias, e soltou a pomba; e esta não tornou mais a ele.' },
      { v: 13, en: 'In the six hundred first year, in the first month, the first day of the month, the waters were dried up from the earth. Noah removed the covering of the ship, and looked. He saw that the surface of the ground was dried.', pt: 'No ano seiscentos e um, no mês primeiro, no primeiro dia do mês, secaram-se as águas de sobre a terra. Então Noé tirou a cobertura da arca: e olhou, e eis que a face a terra estava enxuta.' },
      { v: 14, en: 'In the second month, on the twenty-seventh day of the month, the earth was dry.', pt: 'No segundo mês, aos vinte e sete dias do mês, a terra estava seca.' },
      { v: 15, en: 'God spoke to Noah, saying,', pt: 'Então falou Deus a Noé, dizendo:' },
      { v: 16, en: '“Go out of the ship, you, your wife, your sons, and your sons’ wives with you.', pt: 'Sai da arca, tu, e juntamente contigo tua mulher, teus filhos e as mulheres de teus filhos.' },
      { v: 17, en: 'Bring out with you every living thing that is with you of all flesh, including birds, livestock, and every creeping thing that creeps on the earth, that they may breed abundantly in the earth, and be fruitful, and multiply on the earth.”', pt: 'Todos os animais que estão contigo, de toda a carne, tanto aves como gado e todo réptil que se arrasta sobre a terra, traze-os para fora contigo; para que se reproduzam abundantemente na terra, frutifiquem e se multipliquem sobre a terra.' },
      { v: 18, en: 'Noah went out, with his sons, his wife, and his sons’ wives with him.', pt: 'Então saiu Noé, e com ele seus filhos, sua mulher e as mulheres de seus filhos;' },
      { v: 19, en: 'Every animal, every creeping thing, and every bird, whatever moves on the earth, after their families, went out of the ship.', pt: 'todo animal, todo réptil e toda ave, tudo o que se move sobre a terra, segundo as suas famílias, saiu da arca.' },
      { v: 20, en: 'Noah built an altar to Yahweh, and took of every clean animal, and of every clean bird, and offered burnt offerings on the altar.', pt: 'Edificou Noé um altar ao Senhor; e tomou de todo animal limpo e de toda ave limpa, e ofereceu holocaustos sobre o altar.' },
      { v: 21, en: 'Yahweh smelled the pleasant aroma. Yahweh said in his heart, “I will not again curse the ground any more for man’s sake because the imagination of man’s heart is evil from his youth. I will never again strike every living thing, as I have done.', pt: 'Sentiu o Senhor o suave cheiro e disse em seu coração: Não tornarei mais a amaldiçoar a terra por causa do homem; porque a imaginação do coração do homem é má desde a sua meninice; nem tornarei mais a ferir todo vivente, como acabo de fazer.' },
      { v: 22, en: 'While the earth remains, seed time and harvest, and cold and heat, and summer and winter, and day and night will not cease.”', pt: 'Enquanto a terra durar, não deixará de haver sementeira e ceifa, frio e calor, verão e inverno, dia e noite.' },
    ],
    9: [
      { v: 1, en: 'God blessed Noah and his sons, and said to them, “Be fruitful, multiply, and replenish the earth.', pt: 'Abençoou Deus a Noé e a seus filhos, e disse-lhes: Frutificai e multiplicai-vos, e enchei a terra.' },
      { v: 2, en: 'The fear of you and the dread of you will be on every animal of the earth, and on every bird of the sky. Everything that moves along the ground, and all the fish of the sea, are delivered into your hand.', pt: 'Terão medo e pavor de vós todo animal da terra, toda ave do céu, tudo o que se move sobre a terra e todos os peixes do mar; nas vossas mãos são entregues.' },
      { v: 3, en: 'Every moving thing that lives will be food for you. As I gave you the green herb, I have given everything to you.', pt: 'Tudo quanto se move e vive vos servirá de mantimento, bem como a erva verde; tudo vos tenho dado.' },
      { v: 4, en: 'But flesh with its life, that is, its blood, you shall not eat.', pt: 'A carne, porém, com sua vida, isto é, com seu sangue, não comereis.' },
      { v: 5, en: 'I will surely require your life’s blood. At the hand of every animal I will require it. At the hand of man, even at the hand of every man’s brother, I will require the life of man.', pt: 'Certamente requererei o vosso sangue, o sangue das vossas vidas; de todo animal o requererei; como também do homem, sim, da mão do irmão de cada um requererei a vida do homem.' },
      { v: 6, en: 'Whoever sheds man’s blood, his blood will be shed by man, for God made man in his own image.', pt: 'Quem derramar sangue de homem, pelo homem terá o seu sangue derramado; porque Deus fez o homem à sua imagem.' },
      { v: 7, en: 'Be fruitful and multiply. Increase abundantly in the earth, and multiply in it.”', pt: 'Mas vós frutificai, e multiplicai-vos; povoai abundantemente a terra, e multiplicai-vos nela.' },
      { v: 8, en: 'God spoke to Noah and to his sons with him, saying,', pt: 'Disse também Deus a Noé, e a seus filhos com ele:' },
      { v: 9, en: '“As for me, behold, I establish my covenant with you, and with your offspring after you,', pt: 'Eis que eu estabeleço o meu pacto convosco e com a vossa descendência depois de vós,' },
      { v: 10, en: 'and with every living creature that is with you: the birds, the livestock, and every animal of the earth with you, of all that go out of the ship, even every animal of the earth.', pt: 'e com todo ser vivente que convosco está: com as aves, com o gado e com todo animal da terra; com todos os que saíram da arca, sim, com todo animal da terra.' },
      { v: 11, en: 'I will establish my covenant with you: All flesh will not be cut off any more by the waters of the flood. There will never again be a flood to destroy the earth.”', pt: 'Sim, estabeleço o meu pacto convosco; não será mais destruída toda a carne pelas águas do dilúvio; e não haverá mais dilúvio, para destruir a terra.' },
      { v: 12, en: 'God said, “This is the token of the covenant which I make between me and you and every living creature that is with you, for perpetual generations:', pt: 'E disse Deus: Este é o sinal do pacto que firmo entre mim e vós e todo ser vivente que está convosco, por gerações perpétuas:' },
      { v: 13, en: 'I set my rainbow in the cloud, and it will be a sign of a covenant between me and the earth.', pt: 'O meu arco tenho posto nas nuvens, e ele será por sinal de haver um pacto entre mim e a terra.' },
      { v: 14, en: 'When I bring a cloud over the earth, that the rainbow will be seen in the cloud,', pt: 'E acontecerá que, quando eu trouxer nuvens sobre a terra, e aparecer o arco nas nuvens,' },
      { v: 15, en: 'I will remember my covenant, which is between me and you and every living creature of all flesh, and the waters will no more become a flood to destroy all flesh.', pt: 'então me lembrarei do meu pacto, que está entre mim e vós e todo ser vivente de toda a carne; e as águas não se tornarão mais em dilúvio para destruir toda a carne.' },
      { v: 16, en: 'The rainbow will be in the cloud. I will look at it, that I may remember the everlasting covenant between God and every living creature of all flesh that is on the earth.”', pt: 'O arco estará nas nuvens, e olharei para ele a fim de me lembrar do pacto perpétuo entre Deus e todo ser vivente de toda a carne que está sobre a terra.' },
      { v: 17, en: 'God said to Noah, “This is the token of the covenant which I have established between me and all flesh that is on the earth.”', pt: 'Disse Deus a Noé ainda: Esse é o sinal do pacto que tenho estabelecido entre mim e toda a carne que está sobre a terra.' },
      { v: 18, en: 'The sons of Noah who went out from the ship were Shem, Ham, and Japheth. Ham is the father of Canaan.', pt: 'Ora, os filhos de Noé, que saíram da arca, foram Sem, Cão e Jafé; e Cão é o pai de Canaã.' },
      { v: 19, en: 'These three were the sons of Noah, and from these, the whole earth was populated.', pt: 'Estes três foram os filhos de Noé; e destes foi povoada toda a terra.' },
      { v: 20, en: 'Noah began to be a farmer, and planted a vineyard.', pt: 'E começou Noé a cultivar a terra e plantou uma vinha.' },
      { v: 21, en: 'He drank of the wine and got drunk. He was uncovered within his tent.', pt: 'Bebeu do vinho, e embriagou-se; e achava-se nu dentro da sua tenda.' },
      { v: 22, en: 'Ham, the father of Canaan, saw the nakedness of his father, and told his two brothers outside.', pt: 'E Cão, pai de Canaã, viu a nudez de seu pai, e o contou a seus dois irmãos que estavam fora.' },
      { v: 23, en: 'Shem and Japheth took a garment, and laid it on both their shoulders, went in backwards, and covered the nakedness of their father. Their faces were backwards, and they didn’t see their father’s nakedness.', pt: 'Então tomaram Sem e Jafé uma capa, e puseram-na sobre os seus ombros, e andando virados para trás, cobriram a nudez de seu pai, tendo os rostos virados, de maneira que não viram a nudez de seu pai.' },
      { v: 24, en: 'Noah awoke from his wine, and knew what his youngest son had done to him.', pt: 'Despertado que foi Noé do seu vinho, soube o que seu filho mais moço lhe fizera;' },
      { v: 25, en: 'He said, “Canaan is cursed. He will be a servant of servants to his brothers.”', pt: 'e disse: Maldito seja Canaã; servo dos servos será de seus irmãos.' },
      { v: 26, en: 'He said, “Blessed be Yahweh, the God of Shem. Let Canaan be his servant.', pt: 'Disse mais: Bendito seja o Senhor, o Deus de Sem; e seja-lhe Canaã por servo.' },
      { v: 27, en: 'May God enlarge Japheth. Let him dwell in the tents of Shem. Let Canaan be his servant.”', pt: 'Alargue Deus a Jafé, e habite Jafé nas tendas de Sem; e seja-lhe Canaã por servo.' },
      { v: 28, en: 'Noah lived three hundred fifty years after the flood.', pt: 'Viveu Noé, depois do dilúvio, trezentos e cinqüenta anos.' },
      { v: 29, en: 'All the days of Noah were nine hundred fifty years, and then he died.', pt: 'E foram todos os dias de Noé novecentos e cinqüenta anos; e morreu.' },
    ],
    10: [
      { v: 1, en: 'Now this is the history of the generations of the sons of Noah and of Shem, Ham, and Japheth. Sons were born to them after the flood.', pt: 'Estas, pois, são as gerações dos filhos de Noé: Sem, Cão e Jafé, aos quais nasceram filhos depois do dilúvio.' },
      { v: 2, en: 'The sons of Japheth were: Gomer, Magog, Madai, Javan, Tubal, Meshech, and Tiras.', pt: 'Os filhos de Jafé: Gomer, Magogue, Madai, Javã, Tubal, Meseque e Tiras.' },
      { v: 3, en: 'The sons of Gomer were: Ashkenaz, Riphath, and Togarmah.', pt: 'Os filhos de Gomer: Asquenaz, Rifate e Togarma.' },
      { v: 4, en: 'The sons of Javan were: Elishah, Tarshish, Kittim, and Dodanim.', pt: 'Os filhos de Javã: Elisá, Társis, Quitim e Dodanim.' },
      { v: 5, en: 'Of these were the islands of the nations divided in their lands, everyone after his language, after their families, in their nations.', pt: 'Por estes foram repartidas as ilhas das nações nas suas terras, cada qual segundo a sua língua, segundo as suas famílias, entre as suas nações.' },
      { v: 6, en: 'The sons of Ham were: Cush, Mizraim, Put, and Canaan.', pt: 'Os filhos de Cão: Cuche, Mizraim, Pute e Canaã.' },
      { v: 7, en: 'The sons of Cush were: Seba, Havilah, Sabtah, Raamah, and Sabteca. The sons of Raamah were: Sheba and Dedan.', pt: 'Os filhos de Cuche: Seba, Havilá, Sabtá, Raamá e Sabtecá; e os filhos de Raamá são Sebá e Dedã.' },
      { v: 8, en: 'Cush became the father of Nimrod. He began to be a mighty one in the earth.', pt: 'Cuche também gerou a Ninrode, o qual foi o primeiro a ser poderoso na terra.' },
      { v: 9, en: 'He was a mighty hunter before Yahweh. Therefore it is said, “like Nimrod, a mighty hunter before Yahweh”.', pt: 'Ele era poderoso caçador diante do Senhor; pelo que se diz: Como Ninrode, poderoso caçador diante do Senhor.' },
      { v: 10, en: 'The beginning of his kingdom was Babel, Erech, Accad, and Calneh, in the land of Shinar.', pt: 'O princípio do seu reino foi Babel, Ereque, Acade e Calné, na terra de Sinar.' },
      { v: 11, en: 'Out of that land he went into Assyria, and built Nineveh, Rehoboth Ir, Calah,', pt: 'Desta mesma terra saiu ele para a Assíria e edificou Nínive, Reobote-Ir, Calá,' },
      { v: 12, en: 'and Resen between Nineveh and the great city Calah.', pt: 'e Résem entre Nínive e Calá (esta é a grande cidade).' },
      { v: 13, en: 'Mizraim became the father of Ludim, Anamim, Lehabim, Naphtuhim,', pt: 'Mizraim gerou a Ludim, Anamim, Leabim, Naftuim,' },
      { v: 14, en: 'Pathrusim, Casluhim (which the Philistines descended from), and Caphtorim.', pt: 'Patrusim, Casluim (donde saíram os filisteus) e Caftorim.' },
      { v: 15, en: 'Canaan became the father of Sidon (his firstborn), Heth,', pt: 'Canaã gerou a Sidom, seu primogênito, e Hete,' },
      { v: 16, en: 'the Jebusites, the Amorites, the Girgashites,', pt: 'e ao jebuseu, o amorreu, o girgaseu,' },
      { v: 17, en: 'the Hivites, the Arkites, the Sinites,', pt: 'o heveu, o arqueu, o sineu,' },
      { v: 18, en: 'the Arvadites, the Zemarites, and the Hamathites. Afterward the families of the Canaanites were spread abroad.', pt: 'o arvadeu, o zemareu e o hamateu. Depois se espalharam as famílias dos cananeus.' },
      { v: 19, en: 'The border of the Canaanites was from Sidon—as you go toward Gerar—to Gaza—as you go toward Sodom, Gomorrah, Admah, and Zeboiim—to Lasha.', pt: 'Foi o termo dos cananeus desde Sidom, em direção a Gerar, até Gaza; e daí em direção a Sodoma, Gomorra, Admá e Zeboim, até Lasa.' },
      { v: 20, en: 'These are the sons of Ham, after their families, according to their languages, in their lands and their nations.', pt: 'São esses os filhos de Cão segundo as suas famílias, segundo as suas línguas, em suas terras, em suas nações.' },
      { v: 21, en: 'Children were also born to Shem, the father of all the children of Eber, the elder brother of Japheth.', pt: 'A Sem, que foi o pai de todos os filhos de Eber e irmão mais velho de Jafé, a ele também nasceram filhos.' },
      { v: 22, en: 'The sons of Shem were: Elam, Asshur, Arpachshad, Lud, and Aram.', pt: 'Os filhos de Sem foram: Elão, Assur, Arfaxade, Lude e Arão.' },
      { v: 23, en: 'The sons of Aram were: Uz, Hul, Gether, and Mash.', pt: 'Os filhos de Arão: Uz, Hul, Geter e Más.' },
      { v: 24, en: 'Arpachshad became the father of Shelah. Shelah became the father of Eber.', pt: 'Arfaxade gerou a Selá; e Selá gerou a Eber.' },
      { v: 25, en: 'To Eber were born two sons. The name of the one was Peleg, for in his days the earth was divided. His brother’s name was Joktan.', pt: 'A Eber nasceram dois filhos: o nome de um foi Pelegue, porque nos seus dias foi dividida a terra; e o nome de seu irmão foi Joctã.' },
      { v: 26, en: 'Joktan became the father of Almodad, Sheleph, Hazarmaveth, Jerah,', pt: 'Joctã gerou a Almodá, Selefe, Hazarmavé, Jerá,' },
      { v: 27, en: 'Hadoram, Uzal, Diklah,', pt: 'Hadorão, Usal, Dicla,' },
      { v: 28, en: 'Obal, Abimael, Sheba,', pt: 'Obal, Abimael, Sebá,' },
      { v: 29, en: 'Ophir, Havilah, and Jobab. All these were the sons of Joktan.', pt: 'Ofir, Havilá e Jobabe: todos esses foram filhos de Joctã.' },
      { v: 30, en: 'Their dwelling extended from Mesha, as you go toward Sephar, the mountain of the east.', pt: 'E foi a sua habitação desde Messa até Sefar, montanha do oriente.' },
      { v: 31, en: 'These are the sons of Shem, by their families, according to their languages, lands, and nations.', pt: 'Esses são os filhos de Sem segundo as suas famílias, segundo as suas línguas, em suas terras, segundo as suas nações.' },
      { v: 32, en: 'These are the families of the sons of Noah, by their generations, according to their nations. The nations divided from these in the earth after the flood.', pt: 'Essas são as famílias dos filhos de Noé segundo as suas gerações, em suas nações; e delas foram disseminadas as nações na terra depois do dilúvio.' },
    ],
    11: [
      { v: 1, en: 'The whole earth was of one language and of one speech.', pt: 'Ora, toda a terra tinha uma só língua e um só idioma.' },
      { v: 2, en: 'As they traveled from the east, they found a plain in the land of Shinar, and they lived there.', pt: 'E deslocando-se os homens para o oriente, acharam um vale na terra de Sinar; e ali habitaram.' },
      { v: 3, en: 'They said to one another, “Come, let’s make bricks, and burn them thoroughly.” They had brick for stone, and they used tar for mortar.', pt: 'Disseram uns aos outros: Eia pois, façamos tijolos, e queimemo-los bem. Os tijolos lhes serviram de pedras e o betume de argamassa.' },
      { v: 4, en: 'They said, “Come, let’s build ourselves a city, and a tower whose top reaches to the sky, and let’s make a name for ourselves, lest we be scattered abroad on the surface of the whole earth.”', pt: 'Disseram mais: Eia, edifiquemos para nós uma cidade e uma torre cujo cume toque no céu, e façamo-nos um nome, para que não sejamos espalhados sobre a face de toda a terra.' },
      { v: 5, en: 'Yahweh came down to see the city and the tower, which the children of men built.', pt: 'Então desceu o Senhor para ver a cidade e a torre que os filhos dos homens edificavam;' },
      { v: 6, en: 'Yahweh said, “Behold, they are one people, and they have all one language, and this is what they begin to do. Now nothing will be withheld from them, which they intend to do.', pt: 'e disse: Eis que o povo é um e todos têm uma só língua; e isto é o que começam a fazer; agora não haverá restrição para tudo o que eles intentarem fazer.' },
      { v: 7, en: 'Come, let’s go down, and there confuse their language, that they may not understand one another’s speech.”', pt: 'Eia, desçamos, e confundamos ali a sua linguagem, para que não entenda um a língua do outro.' },
      { v: 8, en: 'So Yahweh scattered them abroad from there on the surface of all the earth. They stopped building the city.', pt: 'Assim o Senhor os espalhou dali sobre a face de toda a terra; e cessaram de edificar a cidade.' },
      { v: 9, en: 'Therefore its name was called Babel, because there Yahweh confused the language of all the earth. From there, Yahweh scattered them abroad on the surface of all the earth.', pt: 'Por isso se chamou o seu nome Babel, porquanto ali confundiu o Senhor a linguagem de toda a terra, e dali o Senhor os espalhou sobre a face de toda a terra.' },
      { v: 10, en: 'This is the history of the generations of Shem: Shem was one hundred years old when he became the father of Arpachshad two years after the flood.', pt: 'Estas são as gerações de Sem. Tinha ele cem anos, quando gerou a Arfaxade, dois anos depois do dilúvio.' },
      { v: 11, en: 'Shem lived five hundred years after he became the father of Arpachshad, and became the father of more sons and daughters.', pt: 'E viveu Sem, depois que gerou a Arfaxade, quinhentos anos; e gerou filhos e filhas.' },
      { v: 12, en: 'Arpachshad lived thirty-five years and became the father of Shelah.', pt: 'Arfaxade viveu trinta e cinco anos, e gerou a Selá.' },
      { v: 13, en: 'Arpachshad lived four hundred three years after he became the father of Shelah, and became the father of more sons and daughters.', pt: 'Viveu Arfaxade, depois que gerou a Selá, quatrocentos e três anos; e gerou filhos e filhas.' },
      { v: 14, en: 'Shelah lived thirty years, and became the father of Eber.', pt: 'Selá viveu trinta anos, e gerou a Eber.' },
      { v: 15, en: 'Shelah lived four hundred three years after he became the father of Eber, and became the father of more sons and daughters.', pt: 'Viveu Selá, depois que gerou a Eber, quatrocentos e três anos; e gerou filhos e filhas.' },
      { v: 16, en: 'Eber lived thirty-four years, and became the father of Peleg.', pt: 'Eber viveu trinta e quatro anos, e gerou a Pelegue.' },
      { v: 17, en: 'Eber lived four hundred thirty years after he became the father of Peleg, and became the father of more sons and daughters.', pt: 'Viveu Eber, depois que gerou a Pelegue, quatrocentos e trinta anos; e gerou filhos e filhas.' },
      { v: 18, en: 'Peleg lived thirty years, and became the father of Reu.', pt: 'Pelegue viveu trinta anos, e gerou a Reú.' },
      { v: 19, en: 'Peleg lived two hundred nine years after he became the father of Reu, and became the father of more sons and daughters.', pt: 'Viveu Pelegue, depois que gerou a Reú, duzentos e nove anos; e gerou filhos e filhas.' },
      { v: 20, en: 'Reu lived thirty-two years, and became the father of Serug.', pt: 'Reú viveu trinta e dois anos, e gerou a Serugue.' },
      { v: 21, en: 'Reu lived two hundred seven years after he became the father of Serug, and became the father of more sons and daughters.', pt: 'Viveu Reú, depois que gerou a Serugue, duzentos e sete anos; e gerou filhos e filhas.' },
      { v: 22, en: 'Serug lived thirty years, and became the father of Nahor.', pt: 'Serugue viveu trinta anos, e gerou a Naor.' },
      { v: 23, en: 'Serug lived two hundred years after he became the father of Nahor, and became the father of more sons and daughters.', pt: 'Viveu Serugue, depois que gerou a Naor, duzentos anos; e gerou filhos e filhas.' },
      { v: 24, en: 'Nahor lived twenty-nine years, and became the father of Terah.', pt: 'Naor viveu vinte e nove anos, e gerou a Tera.' },
      { v: 25, en: 'Nahor lived one hundred nineteen years after he became the father of Terah, and became the father of more sons and daughters.', pt: 'Viveu Naor, depois que gerou a Tera, cento e dezenove anos; e gerou filhos e filhas.' },
      { v: 26, en: 'Terah lived seventy years, and became the father of Abram, Nahor, and Haran.', pt: 'Tera viveu setenta anos, e gerou a Abrão, a Naor e a Harã.' },
      { v: 27, en: 'Now this is the history of the generations of Terah. Terah became the father of Abram, Nahor, and Haran. Haran became the father of Lot.', pt: 'Estas são as gerações de Tera: Tera gerou a Abrão, a Naor e a Harã; e Harã gerou a Ló.' },
      { v: 28, en: 'Haran died before his father Terah in the land of his birth, in Ur of the Chaldees.', pt: 'Harã morreu antes de seu pai Tera, na terra do seu nascimento, em Ur dos Caldeus.' },
      { v: 29, en: 'Abram and Nahor married wives. The name of Abram’s wife was Sarai, and the name of Nahor’s wife was Milcah, the daughter of Haran who was also the father of Iscah.', pt: 'Abrão e Naor tomaram mulheres para si: o nome da mulher de Abrão era Sarai, e o nome da mulher do Naor era Milca, filha de Harã, que foi pai de Milca e de Iscá.' },
      { v: 30, en: 'Sarai was barren. She had no child.', pt: 'Sarai era estéril; não tinha filhos.' },
      { v: 31, en: 'Terah took Abram his son, Lot the son of Haran, his son’s son, and Sarai his daughter-in-law, his son Abram’s wife. They went from Ur of the Chaldees, to go into the land of Canaan. They came to Haran and lived there.', pt: 'Tomou Tera a Abrão seu filho, e a Ló filho de Harã, filho de seu filho, e a Sarai sua nora, mulher de seu filho Abrão, e saiu com eles de Ur dos Caldeus, a fim de ir para a terra de Canaã; e vieram até Harã, e ali habitaram.' },
      { v: 32, en: 'The days of Terah were two hundred five years. Terah died in Haran.', pt: 'Foram os dias de Tera duzentos e cinco anos; e morreu Tera em Harã.' },
    ],
    12: [
      { v: 1, en: 'Now Yahweh said to Abram, “Leave your country, and your relatives, and your father’s house, and go to the land that I will show you.', pt: 'Ora, o Senhor disse a Abrão: Sai-te da tua terra, da tua parentela, e da casa de teu pai, para a terra que eu te mostrarei.' },
      { v: 2, en: 'I will make of you a great nation. I will bless you and make your name great. You will be a blessing.', pt: 'Eu farei de ti uma grande nação; abençoar-te-ei, e engrandecerei o teu nome; e tu, sê uma bênção.' },
      { v: 3, en: 'I will bless those who bless you, and I will curse him who treates you with contempt. All the families of the earth will be blessed through you.”', pt: 'Abençoarei aos que te abençoarem, e amaldiçoarei àquele que te amaldiçoar; e em ti serão benditas todas as famílias da terra.' },
      { v: 4, en: 'So Abram went, as Yahweh had told him. Lot went with him. Abram was seventy-five years old when he departed from Haran.', pt: 'Partiu, pois Abrão, como o Senhor lhe ordenara, e Ló foi com ele. Tinha Abrão setenta e cinco anos quando saiu de Harã.' },
      { v: 5, en: 'Abram took Sarai his wife, Lot his brother’s son, all their possessions that they had gathered, and the people whom they had acquired in Haran, and they went to go into the land of Canaan. They entered into the land of Canaan.', pt: 'Abrão levou consigo a Sarai, sua mulher, e a Ló, filho de seu irmão, e todos os bens que haviam adquirido, e as almas que lhes acresceram em Harã; e saíram a fim de irem à terra de Canaã; e à terra de Canaã chegaram.' },
      { v: 6, en: 'Abram passed through the land to the place of Shechem, to the oak of Moreh. At that time, Canaanites were in the land.', pt: 'Passou Abrão pela terra até o lugar de Siquém, até o carvalho de Moré. Nesse tempo estavam os cananeus na terra.' },
      { v: 7, en: 'Yahweh appeared to Abram and said, “I will give this land to your offspring.” He built an altar there to Yahweh, who had appeared to him.', pt: 'Apareceu, porém, o Senhor a Abrão, e disse: ë tua semente darei esta terra. Abrão, pois, edificou ali um altar ao Senhor, que lhe aparecera.' },
      { v: 8, en: 'He left from there to go to the mountain on the east of Bethel and pitched his tent, having Bethel on the west, and Ai on the east. There he built an altar to Yahweh and called on Yahweh’s name.', pt: 'Então passou dali para o monte ao oriente de Betel, e armou a sua tenda, ficando-lhe Betel ao ocidente, e Ai ao oriente; também ali edificou um altar ao Senhor, e invocou o nome do Senhor.' },
      { v: 9, en: 'Abram traveled, still going on toward the South.', pt: 'Depois continuou Abrão o seu caminho, seguindo ainda para o sul.' },
      { v: 10, en: 'There was a famine in the land. Abram went down into Egypt to live as a foreigner there, for the famine was severe in the land.', pt: 'Ora, havia fome naquela terra; Abrão, pois, desceu ao Egito, para peregrinar ali, porquanto era grande a fome na terra.' },
      { v: 11, en: 'When he had come near to enter Egypt, he said to Sarai his wife, “See now, I know that you are a beautiful woman to look at.', pt: 'Quando ele estava prestes a entrar no Egito, disse a Sarai, sua mulher: Ora, bem sei que és mulher formosa à vista;' },
      { v: 12, en: 'It will happen, when the Egyptians see you, that they will say, ‘This is his wife.’ They will kill me, but they will save you alive.', pt: 'e acontecerá que, quando os egípcios te virem, dirão: Esta é mulher dele. E me matarão a mim, mas a ti te guardarão em vida.' },
      { v: 13, en: 'Please say that you are my sister, that it may be well with me for your sake, and that my soul may live because of you.”', pt: 'Dize, peço-te, que és minha irmã, para que me vá bem por tua causa, e que viva a minha alma em atenção a ti.' },
      { v: 14, en: 'When Abram had come into Egypt, Egyptians saw that the woman was very beautiful.', pt: 'E aconteceu que, entrando Abrão no Egito, viram os egípcios que a mulher era mui formosa.' },
      { v: 15, en: 'The princes of Pharaoh saw her, and praised her to Pharaoh; and the woman was taken into Pharaoh’s house.', pt: 'Até os príncipes de Faraó a viram e gabaram-na diante dele; e foi levada a mulher para a casa de Faraó.' },
      { v: 16, en: 'He dealt well with Abram for her sake. He had sheep, cattle, male donkeys, male servants, female servants, female donkeys, and camels.', pt: 'E ele tratou bem a Abrão por causa dela; e este veio a ter ovelhas, bois e jumentos, servos e servas, jumentas e camelos.' },
      { v: 17, en: 'Yahweh afflicted Pharaoh and his house with great plagues because of Sarai, Abram’s wife.', pt: 'Feriu, porém, o Senhor a Faraó e a sua casa com grandes pragas, por causa de Sarai, mulher de Abrão.' },
      { v: 18, en: 'Pharaoh called Abram and said, “What is this that you have done to me? Why didn’t you tell me that she was your wife?', pt: 'Então chamou Faraó a Abrão, e disse: Que é isto que me fizeste? por que não me disseste que ela era tua mulher?' },
      { v: 19, en: 'Why did you say, ‘She is my sister,’ so that I took her to be my wife? Now therefore, see your wife, take her, and go your way.”', pt: 'Por que disseste: E minha irmã? de maneira que a tomei para ser minha mulher. Agora, pois, eis aqui tua mulher; toma-a e vai-te.' },
      { v: 20, en: 'Pharaoh commanded men concerning him, and they escorted him away with his wife and all that he had.', pt: 'E Faraó deu ordens aos seus guardas a respeito dele, os quais o despediram a ele, e a sua mulher, e a tudo o que tinha.' },
    ],
    13: [
      { v: 1, en: 'Abram went up out of Egypt—he, his wife, all that he had, and Lot with him—into the South.', pt: 'Subiu, pois, Abrão do Egito para o Negebe, levando sua mulher e tudo o que tinha, e Ló o acompanhava.' },
      { v: 2, en: 'Abram was very rich in livestock, in silver, and in gold.', pt: 'Abrão era muito rico em gado, em prata e em ouro.' },
      { v: 3, en: 'He went on his journeys from the South even to Bethel, to the place where his tent had been at the beginning, between Bethel and Ai,', pt: 'Nas suas jornadas subiu do Negebe para Betel, até o lugar onde outrora estivera a sua tenda, entre Betel e Ai,' },
      { v: 4, en: 'to the place of the altar, which he had made there at the first. There Abram called on Yahweh’s name.', pt: 'até o lugar do altar, que dantes ali fizera; e ali invocou Abrão o nome do Senhor.' },
      { v: 5, en: 'Lot also, who went with Abram, had flocks, herds, and tents.', pt: 'E também Ló, que ia com Abrão, tinha rebanhos, gado e tendas.' },
      { v: 6, en: 'The land was not able to bear them, that they might live together; for their substance was great, so that they could not live together.', pt: 'Ora, a terra não podia sustentá-los, para eles habitarem juntos; porque os seus bens eram muitos; de modo que não podiam habitar juntos.' },
      { v: 7, en: 'There was strife between the herdsmen of Abram’s livestock and the herdsmen of Lot’s livestock. The Canaanites and the Perizzites lived in the land at that time.', pt: 'Pelo que houve contenda entre os pastores do gado de Abrão, e os pastores do gado de Ló. E nesse tempo os cananeus e os perizeus habitavam na terra.' },
      { v: 8, en: 'Abram said to Lot, “Please, let there be no strife between you and me, and between your herdsmen and my herdsmen; for we are relatives.', pt: 'Disse, pois, Abrão a Ló: Ora, não haja contenda entre mim e ti, e entre os meus pastores e os teus pastores, porque somos irmãos.' },
      { v: 9, en: 'Isn’t the whole land before you? Please separate yourself from me. If you go to the left hand, then I will go to the right. Or if you go to the right hand, then I will go to the left.”', pt: 'Porventura não está toda a terra diante de ti? Rogo-te que te apartes de mim. Se tu escolheres a esquerda, irei para a direita; e se a direita escolheres, irei eu para a esquerda.' },
      { v: 10, en: 'Lot lifted up his eyes, and saw all the plain of the Jordan, that it was well-watered everywhere, before Yahweh destroyed Sodom and Gomorrah, like the garden of Yahweh, like the land of Egypt, as you go to Zoar.', pt: 'Então Ló levantou os olhos, e viu toda a planície do Jordão, que era toda bem regada (antes de haver o Senhor destruído Sodoma e Gomorra), e era como o jardim do Senhor, como a terra do Egito, até chegar a Zoar.' },
      { v: 11, en: 'So Lot chose the Plain of the Jordan for himself. Lot traveled east, and they separated themselves the one from the other.', pt: 'E Ló escolheu para si toda a planície do Jordão, e partiu para o oriente; assim se apartaram um do outro.' },
      { v: 12, en: 'Abram lived in the land of Canaan, and Lot lived in the cities of the plain, and moved his tent as far as Sodom.', pt: 'Habitou Abrão na terra de Canaã, e Ló habitou nas cidades da planície, e foi armando as suas tendas até chegar a Sodoma.' },
      { v: 13, en: 'Now the men of Sodom were exceedingly wicked and sinners against Yahweh.', pt: 'Ora, os homens de Sodoma eram maus e grandes pecadores contra o Senhor.' },
      { v: 14, en: 'Yahweh said to Abram, after Lot was separated from him, “Now, lift up your eyes, and look from the place where you are, northward and southward and eastward and westward,', pt: 'E disse o Senhor a Abrão, depois que Ló se apartou dele: Levanta agora os olhos, e olha desde o lugar onde estás, para o norte, para o sul, para o oriente e para o ocidente;' },
      { v: 15, en: 'for all the land which you see, I will give to you, and to your offspring forever.', pt: 'porque toda esta terra que vês, te hei de dar a ti, e à tua descendência, para sempre.' },
      { v: 16, en: 'I will make your offspring as the dust of the earth, so that if a man can count the dust of the earth, then your offspring may also be counted.', pt: 'E farei a tua descendência como o pó da terra; de maneira que se puder ser contado o pó da terra, então também poderá ser contada a tua descendência.' },
      { v: 17, en: 'Arise, walk through the land in its length and in its width; for I will give it to you.”', pt: 'Levanta-te, percorre esta terra, no seu comprimento e na sua largura; porque a darei a ti.' },
      { v: 18, en: 'Abram moved his tent, and came and lived by the oaks of Mamre, which are in Hebron, and built an altar there to Yahweh.', pt: 'Então mudou Abrão as suas tendas, e foi habitar junto dos carvalhos de Manre, em Hebrom; e ali edificou um altar ao Senhor.' },
    ],
    14: [
      { v: 1, en: 'In the days of Amraphel, king of Shinar, Arioch, king of Ellasar, Chedorlaomer, king of Elam, and Tidal, king of Goiim,', pt: 'Aconteceu nos dias de Anrafel, rei de Sinar, Arioque, rei de Elasar, Quedorlaomer, rei de Elão, e Tidal, rei de Goiim,' },
      { v: 2, en: 'they made war with Bera, king of Sodom, and with Birsha, king of Gomorrah, Shinab, king of Admah, and Shemeber, king of Zeboiim, and the king of Bela (also called Zoar).', pt: 'que estes fizeram guerra a Bera, rei de Sodoma, a Birsa, rei de Gomorra, a Sinabe, rei de Admá, a Semeber, rei de Zeboim, e ao rei de Belá (esta é Zoar).' },
      { v: 3, en: 'All these joined together in the valley of Siddim (also called the Salt Sea).', pt: 'Todos estes se ajuntaram no vale de Sidim (que é o Mar Salgado).' },
      { v: 4, en: 'They served Chedorlaomer for twelve years, and in the thirteenth year, they rebelled.', pt: 'Doze anos haviam servido a Quedorlaomer, mas ao décimo terceiro ano rebelaram-se.' },
      { v: 5, en: 'In the fourteenth year Chedorlaomer came, and the kings who were with him, and struck the Rephaim in Ashteroth Karnaim, and the Zuzim in Ham, and the Emim in Shaveh Kiriathaim,', pt: 'Por isso, ao décimo quarto ano veio Quedorlaomer, e os reis que estavam com ele, e feriram aos refains em Asterote-Carnaim, aos zuzins em Hão, aos emins em Savé-Quiriataim,' },
      { v: 6, en: 'and the Horites in their Mount Seir, to El Paran, which is by the wilderness.', pt: 'e aos horeus no seu monte Seir, até El-Parã, que está junto ao deserto.' },
      { v: 7, en: 'They returned, and came to En Mishpat (also called Kadesh), and struck all the country of the Amalekites, and also the Amorites, that lived in Hazazon Tamar.', pt: 'Depois voltaram e vieram a En-Mispate (que é Cades), e feriram toda a terra dos amalequitas, e também dos amorreus, que habitavam em Hazazom-Tamar.' },
      { v: 8, en: 'The king of Sodom, and the king of Gomorrah, and the king of Admah, and the king of Zeboiim, and the king of Bela (also called Zoar) went out; and they set the battle in array against them in the valley of Siddim;', pt: 'Então saíram os reis de Sodoma, de Gomorra, de Admá, de Zeboim e de Belá (esta é Zoar), e ordenaram batalha contra eles no vale de Sidim,' },
      { v: 9, en: 'against Chedorlaomer king of Elam, and Tidal king of Goiim, and Amraphel king of Shinar, and Arioch king of Ellasar; four kings against the five.', pt: 'contra Quedorlaomer, rei de Elão, Tidal, rei de Goiim, Anrafel, rei de Sinar, e Arioque, rei de Elasar; quatro reis contra cinco.' },
      { v: 10, en: 'Now the valley of Siddim was full of tar pits; and the kings of Sodom and Gomorrah fled, and some fell there, and those who remained fled to the hills.', pt: 'Ora, o vale de Sidim estava cheio de poços de betume; e fugiram os reis de Sodoma e de Gomorra, e caíram ali; e os restantes fugiram para o monte.' },
      { v: 11, en: 'They took all the goods of Sodom and Gomorrah, and all their food, and went their way.', pt: 'Tomaram, então, todos os bens de Sodoma e de Gomorra com todo o seu mantimento, e se foram.' },
      { v: 12, en: 'They took Lot, Abram’s brother’s son, who lived in Sodom, and his goods, and departed.', pt: 'Tomaram também a Ló, filho do irmão de Abrão, que habitava em Sodoma, e os bens dele, e partiram.' },
      { v: 13, en: 'One who had escaped came and told Abram, the Hebrew. At that time, he lived by the oaks of Mamre, the Amorite, brother of Eshcol, and brother of Aner; and they were allies of Abram.', pt: 'Então veio um que escapara, e o contou a Abrão, o hebreu. Ora, este habitava junto dos carvalhos de Manre, o amorreu, irmão de Escol e de Aner; estes eram aliados de Abrão.' },
      { v: 14, en: 'When Abram heard that his relative was taken captive, he led out his trained men, born in his house, three hundred and eighteen, and pursued as far as Dan.', pt: 'Ouvindo, pois, Abrão que seu irmão estava preso, levou os seus homens treinados, nascidos em sua casa, em número de trezentos e dezoito, e perseguiu os reis até Dã.' },
      { v: 15, en: 'He divided himself against them by night, he and his servants, and struck them, and pursued them to Hobah, which is on the left hand of Damascus.', pt: 'Dividiu-se contra eles de noite, ele e os seus servos, e os feriu, perseguindo-os até Hobá, que fica à esquerda de Damasco.' },
      { v: 16, en: 'He brought back all the goods, and also brought back his relative, Lot, and his goods, and the women also, and the other people.', pt: 'Assim tornou a trazer todos os bens, e tornou a trazer também a Ló, seu irmão, e os bens dele, e também as mulheres e o povo.' },
      { v: 17, en: 'The king of Sodom went out to meet him after his return from the slaughter of Chedorlaomer and the kings who were with him, at the valley of Shaveh (that is, the King’s Valley).', pt: 'Depois que Abrão voltou de ferir a Quedorlaomer e aos reis que estavam com ele, saiu-lhe ao encontro o rei de Sodoma, no vale de Savé (que é o vale do rei).' },
      { v: 18, en: 'Melchizedek king of Salem brought out bread and wine: and he was priest of God Most High.', pt: 'Ora, Melquisedeque, rei de Salém, trouxe pão e vinho; pois era sacerdote do Deus Altíssimo;' },
      { v: 19, en: 'He blessed him, and said, “Blessed be Abram of God Most High, possessor of heaven and earth:', pt: 'e abençoou a Abrão, dizendo: bendito seja Abrão pelo Deus Altíssimo, o Criador dos céus e da terra!' },
      { v: 20, en: 'and blessed be God Most High, who has delivered your enemies into your hand.” Abram gave him a tenth of all.', pt: 'E bendito seja o Deus Altíssimo, que entregou os teus inimigos nas tuas mãos! E Abrão deu-lhe o dízimo de tudo.' },
      { v: 21, en: 'The king of Sodom said to Abram, “Give me the people, and take the goods for yourself.”', pt: 'Então o rei de Sodoma disse a Abrão: Dá-me a mim as pessoas; e os bens toma-os para ti.' },
      { v: 22, en: 'Abram said to the king of Sodom, “I have lifted up my hand to Yahweh, God Most High, possessor of heaven and earth,', pt: 'Abrão, porém, respondeu ao rei de Sodoma: Levanto minha mão ao Senhor, o Deus Altíssimo, o Criador dos céus e da terra,' },
      { v: 23, en: 'that I will not take a thread nor a sandal strap nor anything that is yours, lest you should say, ‘I have made Abram rich.’', pt: 'jurando que não tomarei coisa alguma de tudo o que é teu, nem um fio, nem uma correia de sapato, para que não digas: Eu enriqueci a Abrão;' },
      { v: 24, en: 'I will accept nothing from you except that which the young men have eaten, and the portion of the men who went with me: Aner, Eshcol, and Mamre. Let them take their portion.”', pt: 'salvo tão somente o que os mancebos comeram, e a parte que toca aos homens Aner, Escol e Manre, que foram comigo; que estes tomem a sua parte.' },
    ],
    15: [
      { v: 1, en: 'After these things Yahweh’s word came to Abram in a vision, saying, “Don’t be afraid, Abram. I am your shield, your exceedingly great reward.”', pt: 'Depois destas coisas veio a palavra do Senhor a Abrão numa visão, dizendo: Não temas, Abrão; eu sou o teu escudo, o teu galardão será grandíssimo.' },
      { v: 2, en: 'Abram said, “Lord Yahweh, what will you give me, since I go childless, and he who will inherit my estate is Eliezer of Damascus?”', pt: 'Então disse Abrão: Ó Senhor Deus, que me darás, visto que morro sem filhos, e o herdeiro de minha casa é o damasceno Eliézer?' },
      { v: 3, en: 'Abram said, “Behold, to me you have given no children : and, behold, one born in my house is my heir.”', pt: 'Disse mais Abrão: A mim não me tens dado filhos; eis que um nascido na minha casa será o meu herdeiro.' },
      { v: 4, en: 'Behold, Yahweh’s word came to him, saying, “This man will not be your heir, but he who will come out of your own body will be your heir.”', pt: 'Ao que lhe veio a palavra do Senhor, dizendo: Este não será o teu herdeiro; mas aquele que sair das tuas entranhas, esse será o teu herdeiro.' },
      { v: 5, en: 'Yahweh brought him outside, and said, “Look now toward the sky, and count the stars, if you are able to count them.” He said to Abram, “So will your offspring be.”', pt: 'Então o levou para fora, e disse: Olha agora para o céu, e conta as estrelas, se as podes contar; e acrescentou-lhe: Assim será a tua descendência.' },
      { v: 6, en: 'He believed in Yahweh, who credited it to him for righteousness.', pt: 'E creu Abrão no Senhor, e o Senhor imputou-lhe isto como justiça.' },
      { v: 7, en: 'He said to Abram, “I am Yahweh who brought you out of Ur of the Chaldees, to give you this land to inherit it.”', pt: 'Disse-lhe mais: Eu sou o Senhor, que te tirei de Ur dos caldeus, para te dar esta terra em herança.' },
      { v: 8, en: 'He said, “Lord Yahweh, how will I know that I will inherit it?”', pt: 'Ao que lhe perguntou Abrão: Ó Senhor Deus, como saberei que hei de herdá-la?' },
      { v: 9, en: 'He said to him, “Bring me a heifer three years old, a female goat three years old, a ram three years old, a turtledove, and a young pigeon.”', pt: 'Respondeu-lhe: Toma-me uma novilha de três anos, uma cabra de três anos, um carneiro de três anos, uma rola e um pombinho.' },
      { v: 10, en: 'He brought him all these, and divided them in the middle, and laid each half opposite the other; but he didn’t divide the birds.', pt: 'Ele, pois, lhe trouxe todos estes animais, partiu-os pelo meio, e pôs cada parte deles em frente da outra; mas as aves não partiu.' },
      { v: 11, en: 'The birds of prey came down on the carcasses, and Abram drove them away.', pt: 'E as aves de rapina desciam sobre os cadáveres; Abrão, porém, as enxotava.' },
      { v: 12, en: 'When the sun was going down, a deep sleep fell on Abram. Now terror and great darkness fell on him.', pt: 'Ora, ao pôr do sol, caiu um profundo sono sobre Abrão; e eis que lhe sobrevieram grande pavor e densas trevas.' },
      { v: 13, en: 'He said to Abram, “Know for sure that your offspring will live as foreigners in a land that is not theirs, and will serve them. They will afflict them four hundred years.', pt: 'Então disse o Senhor a Abrão: Sabe com certeza que a tua descendência será peregrina em terra alheia, e será reduzida à escravidão, e será afligida por quatrocentos anos;' },
      { v: 14, en: 'I will also judge that nation, whom they will serve. Afterward they will come out with great wealth,', pt: 'sabe também que eu julgarei a nação a qual ela tem de servir; e depois sairá com muitos bens.' },
      { v: 15, en: 'but you will go to your fathers in peace. You will be buried at a good old age.', pt: 'Tu, porém, irás em paz para teus pais; em boa velhice serás sepultado.' },
      { v: 16, en: 'In the fourth generation they will come here again, for the iniquity of the Amorite is not yet full.”', pt: 'Na quarta geração, porém, voltarão para cá; porque a medida da iniqüidade dos amorreus não está ainda cheia.' },
      { v: 17, en: 'It came to pass that, when the sun went down, and it was dark, behold, a smoking furnace, and a flaming torch passed between these pieces.', pt: 'Quando o sol já estava posto, e era escuro, eis um fogo fumegante e uma tocha de fogo, que passaram por entre aquelas metades.' },
      { v: 18, en: 'In that day Yahweh made a covenant with Abram, saying, “I have given this land to your offspring, from the river of Egypt to the great river, the river Euphrates:', pt: 'Naquele mesmo dia fez o Senhor um pacto com Abrão, dizendo: Â tua descendência tenho dado esta terra, desde o rio do Egito até o grande rio Eufrates;' },
      { v: 19, en: 'the Kenites, the Kenizzites, the Kadmonites,', pt: 'e o queneu, o quenizeu, o cadmoneu,' },
      { v: 20, en: 'the Hittites, the Perizzites, the Rephaim,', pt: 'o heteu, o perizeu, os refains,' },
      { v: 21, en: 'the Amorites, the Canaanites, the Girgashites, and the Jebusites.”', pt: 'o amorreu, o cananeu, o girgaseu e o jebuseu.' },
    ],
    16: [
      { v: 1, en: 'Now Sarai, Abram’s wife, bore him no children. She had a servant, an Egyptian, whose name was Hagar.', pt: 'Ora, Sarai, mulher de Abrão, não lhe dava filhos. Tinha ela uma serva egípcia, que se chamava Agar.' },
      { v: 2, en: 'Sarai said to Abram, “See now, Yahweh has restrained me from bearing. Please go in to my servant. It may be that I will obtain children by her.” Abram listened to the voice of Sarai.', pt: 'Disse Sarai a Abrão: Eis que o Senhor me tem impedido de ter filhos; toma, pois, a minha serva; porventura terei filhos por meio dela. E ouviu Abrão a voz de Sarai.' },
      { v: 3, en: 'Sarai, Abram’s wife, took Hagar the Egyptian, her servant, after Abram had lived ten years in the land of Canaan, and gave her to Abram her husband to be his wife.', pt: 'Assim Sarai, mulher de Abrão, tomou a Agar a egípcia, sua serva, e a deu por mulher a Abrão seu marido, depois de Abrão ter habitado dez anos na terra de Canaã.' },
      { v: 4, en: 'He went in to Hagar, and she conceived. When she saw that she had conceived, her mistress was despised in her eyes.', pt: 'E ele conheceu a Agar, e ela concebeu; e vendo ela que concebera, foi sua senhora desprezada aos seus olhos.' },
      { v: 5, en: 'Sarai said to Abram, “This wrong is your fault. I gave my servant into your bosom, and when she saw that she had conceived, I was despised in her eyes. Yahweh judge between me and you.”', pt: 'Então disse Sarai a Abrão: Sobre ti seja a afronta que me é dirigida a mim; pus a minha serva em teu regaço; vendo ela agora que concebeu, sou desprezada aos seus olhos; o Senhor julgue entre mim e ti.' },
      { v: 6, en: 'But Abram said to Sarai, “Behold, your maid is in your hand. Do to her whatever is good in your eyes.” Sarai dealt harshly with her, and she fled from her face.', pt: 'Ao que disse Abrão a Sarai: Eis que tua serva está nas tuas mãos; faze-lhe como bem te parecer. E Sarai maltratou-a, e ela fugiu de sua face.' },
      { v: 7, en: 'Yahweh’s angel found her by a fountain of water in the wilderness, by the fountain on the way to Shur.', pt: 'Então o anjo do Senhor, achando-a junto a uma fonte no deserto, a fonte que está no caminho de Sur,' },
      { v: 8, en: 'He said, “Hagar, Sarai’s servant, where did you come from? Where are you going?” She said, “I am fleeing from the face of my mistress Sarai.”', pt: 'perguntou-lhe: Agar, serva de Sarai, donde vieste, e para onde vais? Respondeu ela: Da presença de Sarai, minha senhora, vou fugindo.' },
      { v: 9, en: 'Yahweh’s angel said to her, “Return to your mistress, and submit yourself under her hands.”', pt: 'Disse-lhe o anjo do Senhor: Torna-te para tua senhora, e humilha-te debaixo das suas mãos.' },
      { v: 10, en: 'Yahweh’s angel said to her, “I will greatly multiply your offspring, that they will not be counted for multitude.”', pt: 'Disse-lhe mais o anjo do Senhor: Multiplicarei sobremaneira a tua descendência, de modo que não será contada, por numerosa que será.' },
      { v: 11, en: 'Yahweh’s angel said to her, “Behold, you are with child, and will bear a son. You shall call his name Ishmael, because Yahweh has heard your affliction.', pt: 'Disse-lhe ainda o anjo do Senhor: Eis que concebeste, e terás um filho, a quem chamarás Ismael; porquanto o Senhor ouviu a tua aflição.' },
      { v: 12, en: 'He will be like a wild donkey among men. His hand will be against every man, and every man’s hand against him. He will live opposite all of his brothers.”', pt: 'Ele será como um jumento selvagem entre os homens; a sua mão será contra todos, e a mão de todos contra ele; e habitará diante da face de todos os seus irmãos.' },
      { v: 13, en: 'She called the name of Yahweh who spoke to her, “You are a God who sees,” for she said, “Have I even stayed alive after seeing him?”', pt: 'E ela chamou, o nome do Senhor, que com ela falava, El-Rói; pois disse: Não tenho eu também olhado neste lugar para aquele que me vê?' },
      { v: 14, en: 'Therefore the well was called Beer Lahai Roi. Behold, it is between Kadesh and Bered.', pt: 'Pelo que se chamou aquele poço Beer-Laai-Rói; ele está entre Cades e Berede.' },
      { v: 15, en: 'Hagar bore a son for Abram. Abram called the name of his son, whom Hagar bore, Ishmael.', pt: 'E Agar deu um filho a Abrão; e Abrão pôs o nome de Ismael no seu filho que tivera de Agar.' },
      { v: 16, en: 'Abram was eighty-six years old when Hagar bore Ishmael to Abram.', pt: 'Ora, tinha Abrão oitenta e seis anos, quando Agar lhe deu Ismael.' },
    ],
    17: [
      { v: 1, en: 'When Abram was ninety-nine years old, Yahweh appeared to Abram and said to him, “I am God Almighty. Walk before me, and be blameless.', pt: 'Quando Abrão tinha noventa e nove anos, apareceu-lhe o Senhor e lhe disse: Eu sou o Deus Todo-Poderoso; anda em minha presença, e sê perfeito;' },
      { v: 2, en: 'I will make my covenant between me and you, and will multiply you exceedingly.”', pt: 'e firmarei o meu pacto contigo, e sobremaneira te multiplicarei.' },
      { v: 3, en: 'Abram fell on his face. God talked with him, saying,', pt: 'Ao que Abrão se prostrou com o rosto em terra, e Deus falou-lhe, dizendo:' },
      { v: 4, en: '“As for me, behold, my covenant is with you. You will be the father of a multitude of nations.', pt: 'Quanto a mim, eis que o meu pacto é contigo, e serás pai de muitas nações;' },
      { v: 5, en: 'Your name will no more be called Abram, but your name will be Abraham; for I have made you the father of a multitude of nations.', pt: 'não mais serás chamado Abrão, mas Abraão será o teu nome; pois por pai de muitas nações te hei posto;' },
      { v: 6, en: 'I will make you exceedingly fruitful, and I will make nations of you. Kings will come out of you.', pt: 'far-te-ei frutificar sobremaneira, e de ti farei nações, e reis sairão de ti;' },
      { v: 7, en: 'I will establish my covenant between me and you and your offspring after you throughout their generations for an everlasting covenant, to be a God to you and to your offspring after you.', pt: 'estabelecerei o meu pacto contigo e com a tua descendência depois de ti em suas gerações, como pacto perpétuo, para te ser por Deus a ti e à tua descendência depois de ti.' },
      { v: 8, en: 'I will give to you, and to your offspring after you, the land where you are traveling, all the land of Canaan, for an everlasting possession. I will be their God.”', pt: 'Dar-te-ei a ti e à tua descendência depois de ti a terra de tuas peregrinações, toda a terra de Canaã, em perpétua possessão; e serei o seu Deus.' },
      { v: 9, en: 'God said to Abraham, “As for you, you will keep my covenant, you and your offspring after you throughout their generations.', pt: 'Disse mais Deus a Abraão: Ora, quanto a ti, guardarás o meu pacto, tu e a tua descendência depois de ti, nas suas gerações.' },
      { v: 10, en: 'This is my covenant, which you shall keep, between me and you and your offspring after you. Every male among you shall be circumcised.', pt: 'Este é o meu pacto, que guardareis entre mim e vós, e a tua descendência depois de ti: todo varão dentre vugar para aquele que me' },
      { v: 11, en: 'You shall be circumcised in the flesh of your foreskin. It will be a token of the covenant between me and you.', pt: 'Circuncidar-vos-eis na carne do prepúcio; e isto será por sinal de pacto entre mim e vós.' },
      { v: 12, en: 'He who is eight days old will be circumcised among you, every male throughout your generations, he who is born in the house, or bought with money from any foreigner who is not of your offspring.', pt: 'Â idade de oito dias, todo varão dentre vós será circuncidado, por todas as vossas gerações, tanto o nascido em casa como o comprado por dinheiro a qualquer estrangeiro, que não for da tua linhagem.' },
      { v: 13, en: 'He who is born in your house, and he who is bought with your money, must be circumcised. My covenant will be in your flesh for an everlasting covenant.', pt: 'Com efeito será circuncidado o nascido em tua casa, e o comprado por teu dinheiro; assim estará o meu pacto na vossa carne como pacto perpétuo.' },
      { v: 14, en: 'The uncircumcised male who is not circumcised in the flesh of his foreskin, that soul shall be cut off from his people. He has broken my covenant.”', pt: 'Mas o incircunciso, que não se circuncidar na carne do prepúcio, essa alma será extirpada do seu povo; violou o meu pacto.' },
      { v: 15, en: 'God said to Abraham, “As for Sarai your wife, you shall not call her name Sarai, but her name will be Sarah.', pt: 'Disse Deus a Abraão: Quanto a Sarai, tua, mulher, não lhe chamarás mais Sarai, porem Sara será o seu nome.' },
      { v: 16, en: 'I will bless her, and moreover I will give you a son by her. Yes, I will bless her, and she will be a mother of nations. Kings of peoples will come from her.”', pt: 'Abençoá-la-ei, e também dela te darei um filho; sim, abençoá-la-ei, e ela será mãe de nações; reis de povos sairão dela.' },
      { v: 17, en: 'Then Abraham fell on his face, and laughed, and said in his heart, “Will a child be born to him who is one hundred years old? Will Sarah, who is ninety years old, give birth?”', pt: 'Ao que se prostrou Abraão com o rosto em terra, e riu-se, e disse no seu coração: A um homem de cem anos há de nascer um filho? Dará à luz Sara, que tem noventa anos?' },
      { v: 18, en: 'Abraham said to God, “Oh that Ishmael might live before you!”', pt: 'Depois disse Abraão a Deus: Oxalá que viva Ismael diante de ti!' },
      { v: 19, en: 'God said, “No, but Sarah, your wife, will bear you a son. You shall call his name Isaac. I will establish my covenant with him for an everlasting covenant for his offspring after him.', pt: 'E Deus lhe respondeu: Na verdade, Sara, tua mulher, te dará à luz um filho, e lhe chamarás Isaque; com ele estabelecerei o meu pacto como pacto perpétuo para a sua descendência depois dele.' },
      { v: 20, en: 'As for Ishmael, I have heard you. Behold, I have blessed him, and will make him fruitful, and will multiply him exceedingly. He will become the father of twelve princes, and I will make him a great nation.', pt: 'E quanto a Ismael, também te tenho ouvido; eis que o tenho abençoado, e fá-lo-ei frutificar, e multiplicá-lo-ei grandissimamente; doze príncipes gerará, e dele farei uma grande nação.' },
      { v: 21, en: 'But my covenant I establish with Isaac, whom Sarah will bear to you at this set time next year.”', pt: 'O meu pacto, porém, estabelecerei com Isaque, que Sara te dará à luz neste tempo determinado, no ano vindouro.' },
      { v: 22, en: 'When he finished talking with him, God went up from Abraham.', pt: 'Ao acabar de falar com Abraão, subiu Deus diante dele.' },
      { v: 23, en: 'Abraham took Ishmael his son, all who were born in his house, and all who were bought with his money; every male among the men of Abraham’s house, and circumcised the flesh of their foreskin in the same day, as God had said to him.', pt: 'Logo tomou Abraão a seu filho Ismael, e a todos os nascidos na sua casa e a todos os comprados por seu dinheiro, todo varão entre os da casa de Abraão, e lhes circuncidou a carne do prepúcio, naquele mesmo dia, como Deus lhe ordenara.' },
      { v: 24, en: 'Abraham was ninety-nine years old, when he was circumcised in the flesh of his foreskin.', pt: 'Abraão tinha noventa e nove anos, quando lhe foi circuncidada a carne do prepúcio;' },
      { v: 25, en: 'Ishmael, his son, was thirteen years old when he was circumcised in the flesh of his foreskin.', pt: 'E Ismael, seu filho, tinha treze anos, quando lhe foi circuncidada a carne do prepúcio.' },
      { v: 26, en: 'In the same day both Abraham and Ishmael, his son, were circumcised.', pt: 'No mesmo dia foram circuncidados Abraão e seu filho Ismael.' },
      { v: 27, en: 'All the men of his house, those born in the house, and those bought with money from a foreigner, were circumcised with him.', pt: 'E todos os homens da sua casa, assim os nascidos em casa, como os comprados por dinheiro ao estrangeiro, foram circuncidados com ele.' },
    ],
    18: [
      { v: 1, en: 'Yahweh appeared to him by the oaks of Mamre, as he sat in the tent door in the heat of the day.', pt: 'Depois apareceu o Senhor a Abraão junto aos carvalhos de Manre, estando ele sentado à porta da tenda, no maior calor do dia.' },
      { v: 2, en: 'He lifted up his eyes and looked, and saw that three men stood opposite him. When he saw them, he ran to meet them from the tent door, and bowed himself to the earth,', pt: 'Levantando Abraão os olhos, olhou e eis três homens de pé em frente dele. Quando os viu, correu da porta da tenda ao seu encontro, e prostrou-se em terra,' },
      { v: 3, en: 'and said, “My lord, if now I have found favor in your sight, please don’t go away from your servant.', pt: 'e disse: Meu Senhor, se agora tenho achado graça aos teus olhos, rogo-te que não passes de teu servo.' },
      { v: 4, en: 'Now let a little water be fetched, wash your feet, and rest yourselves under the tree.', pt: 'Eia, traga-se um pouco d\'água, e lavai os pés e recostai-vos debaixo da árvore;' },
      { v: 5, en: 'I will get a morsel of bread so you can refresh your heart. After that you may go your way, now that you have come to your servant.” They said, “Very well, do as you have said.”', pt: 'e trarei um bocado de pão; refazei as vossas forças, e depois passareis adiante; porquanto por isso chegastes ate o vosso servo. Responderam-lhe: Faze assim como disseste.' },
      { v: 6, en: 'Abraham hurried into the tent to Sarah, and said, “Quickly prepare three seahs of fine meal, knead it, and make cakes.”', pt: 'Abraão, pois, apressou-se em ir ter com Sara na tenda, e disse-lhe: Amassa depressa três medidas de flor de farinha e faze bolos.' },
      { v: 7, en: 'Abraham ran to the herd, and fetched a tender and good calf, and gave it to the servant. He hurried to dress it.', pt: 'Em seguida correu ao gado, apanhou um bezerro tenro e bom e deu-o ao criado, que se apressou em prepará-lo.' },
      { v: 8, en: 'He took butter, milk, and the calf which he had dressed, and set it before them. He stood by them under the tree, and they ate.', pt: 'Então tomou queijo fresco, e leite, e o bezerro que mandara preparar, e pôs tudo diante deles, ficando em pé ao lado deles debaixo da árvore, enquanto comiam.' },
      { v: 9, en: 'They asked him, “Where is Sarah, your wife?” He said, “See, in the tent.”', pt: 'Perguntaram-lhe eles: Onde está Sara, tua mulher? Ele respondeu: Está ali na tenda.' },
      { v: 10, en: 'He said, “I will certainly return to you at about this time next year; and behold, Sarah your wife will have a son.” Sarah heard in the tent door, which was behind him.', pt: 'E um deles lhe disse: certamente tornarei a ti no ano vindouro; e eis que Sara tua mulher terá um filho. E Sara estava escutando à porta da tenda, que estava atrás dele.' },
      { v: 11, en: 'Now Abraham and Sarah were old, well advanced in age. Sarah had passed the age of childbearing.', pt: 'Ora, Abraão e Sara eram já velhos, e avançados em idade; e a Sara havia cessado o incômodo das mulheres.' },
      { v: 12, en: 'Sarah laughed within herself, saying, “After I have grown old will I have pleasure, my lord being old also?”', pt: 'Sara então riu-se consigo, dizendo: Terei ainda deleite depois de haver envelhecido, sendo também o meu senhor ja velho?' },
      { v: 13, en: 'Yahweh said to Abraham, “Why did Sarah laugh, saying, ‘Will I really bear a child, yet I am old?’', pt: 'Perguntou o Senhor a Abraão: Por que se riu Sara, dizendo: É verdade que eu, que sou velha, darei à luz um filho?' },
      { v: 14, en: 'Is anything too hard for Yahweh? At the set time I will return to you, when the season comes round, and Sarah will have a son.”', pt: 'Há, porventura, alguma coisa difícil ao Senhor? Ao tempo determinado, no ano vindouro, tornarei a ti, e Sara terá um filho.' },
      { v: 15, en: 'Then Sarah denied it, saying, “I didn’t laugh,” for she was afraid. He said, “No, but you did laugh.”', pt: 'Então Sara negou, dizendo: Não me ri; porquanto ela teve medo. Ao que ele respondeu: Não é assim; porque te riste.' },
      { v: 16, en: 'The men rose up from there, and looked toward Sodom. Abraham went with them to see them on their way.', pt: 'E levantaram-se aqueles homens dali e olharam para a banda de Sodoma; e Abraão ia com eles, para os encaminhar.' },
      { v: 17, en: 'Yahweh said, “Will I hide from Abraham what I do,', pt: 'E disse o Senhor: Ocultarei eu a Abraão o que faço,' },
      { v: 18, en: 'since Abraham will surely become a great and mighty nation, and all the nations of the earth will be blessed in him?', pt: 'visto que Abraão certamente virá a ser uma grande e poderosa nação, e por meio dele serão benditas todas as nações da terra?' },
      { v: 19, en: 'For I have known him, to the end that he may command his children and his household after him, that they may keep the way of Yahweh, to do righteousness and justice; to the end that Yahweh may bring on Abraham that which he has spoken of him.”', pt: 'Porque eu o tenho escolhido, a fim de que ele ordene a seus filhos e a sua casa depois dele, para que guardem o caminho do Senhor, para praticarem retidão e justiça; a fim de que o Senhor faça vir sobre Abraão o que a respeito dele tem falado.' },
      { v: 20, en: 'Yahweh said, “Because the cry of Sodom and Gomorrah is great, and because their sin is very grievous,', pt: 'Disse mais o Senhor: Porquanto o clamor de Sodoma e Gomorra se tem multiplicado, e porquanto o seu pecado se tem agravado muito,' },
      { v: 21, en: 'I will go down now, and see whether their deeds are as bad as the reports which have come to me. If not, I will know.”', pt: 'descerei agora, e verei se em tudo têm praticado segundo o seu clamor, que a mim tem chegado; e se não, sabê-lo-ei.' },
      { v: 22, en: 'The men turned from there, and went toward Sodom, but Abraham stood yet before Yahweh.', pt: 'Então os homens, virando os seus rostos dali, foram-se em direção a Sodoma; mas Abraão ficou ainda em pé diante do Senhor.' },
      { v: 23, en: 'Abraham came near, and said, “Will you consume the righteous with the wicked?', pt: 'E chegando-se Abraão, disse: Destruirás também o justo com o ímpio?' },
      { v: 24, en: 'What if there are fifty righteous within the city? Will you consume and not spare the place for the fifty righteous who are in it?', pt: 'Se porventura houver cinqüenta justos na cidade, destruirás e não pouparás o lugar por causa dos cinqüenta justos que ali estão?' },
      { v: 25, en: 'Be it far from you to do things like that, to kill the righteous with the wicked, so that the righteous should be like the wicked. May that be far from you. Shouldn’t the Judge of all the earth do right?”', pt: 'Longe de ti que faças tal coisa, que mates o justo com o ímpio, de modo que o justo seja como o ímpio; esteja isto longe de ti. Não fará justiça o juiz de toda a terra?' },
      { v: 26, en: 'Yahweh said, “If I find in Sodom fifty righteous within the city, then I will spare the whole place for their sake.”', pt: 'Então disse o Senhor: Se eu achar em Sodoma cinqüenta justos dentro da cidade, pouparei o lugar todo por causa deles.' },
      { v: 27, en: 'Abraham answered, “See now, I have taken it on myself to speak to the Lord, although I am dust and ashes.', pt: 'Tornou-lhe Abraão, dizendo: Eis que agora me atrevi a falar ao Senhor, ainda que sou pó e cinza.' },
      { v: 28, en: 'What if there will lack five of the fifty righteous? Will you destroy all the city for lack of five?” He said, “I will not destroy it if I find forty-five there.”', pt: 'Se porventura de cinqüenta justos faltarem cinco, destruirás toda a cidade por causa dos cinco? Respondeu ele: Não a destruirei, se eu achar ali quarenta e cinco.' },
      { v: 29, en: 'He spoke to him yet again, and said, “What if there are forty found there?” He said, “I will not do it for the forty’s sake.”', pt: 'Continuou Abraão ainda a falar-lhe, e disse: Se porventura se acharem ali quarenta? Mais uma vez assentiu: Por causa dos quarenta não o farei.' },
      { v: 30, en: 'He said, “Oh don’t let the Lord be angry, and I will speak. What if there are thirty found there?” He said, “I will not do it if I find thirty there.”', pt: 'Disse Abraão: Ora, não se ire o Senhor, se eu ainda falar. Se porventura se acharem ali trinta? De novo assentiu: Não o farei, se achar ali trinta.' },
      { v: 31, en: 'He said, “See now, I have taken it on myself to speak to the Lord. What if there are twenty found there?” He said, “I will not destroy it for the twenty’s sake.”', pt: 'Tornou Abraão: Eis que outra vez me a atrevi a falar ao Senhor. Se porventura se acharem ali vinte? Respondeu-lhe: Por causa dos vinte não a destruirei.' },
      { v: 32, en: 'He said, “Oh don’t let the Lord be angry, and I will speak just once more. What if ten are found there?” He said, “I will not destroy it for the ten’s sake.”', pt: 'Disse ainda Abraão: Ora, não se ire o Senhor, pois só mais esta vez falarei. Se porventura se acharem ali dez? Ainda assentiu o Senhor: Por causa dos dez não a destruirei.' },
      { v: 33, en: 'Yahweh went his way, as soon as he had finished communing with Abraham, and Abraham returned to his place.', pt: 'E foi-se o Senhor, logo que acabou de falar com Abraão; e Abraão voltou para o seu lugar.' },
    ],
    19: [
      { v: 1, en: 'The two angels came to Sodom at evening. Lot sat in the gate of Sodom. Lot saw them, and rose up to meet them. He bowed himself with his face to the earth,', pt: 'Â tarde chegaram os dois anjos a Sodoma. Ló estava sentado à porta de Sodoma e, vendo-os, levantou-se para os receber; prostrou-se com o rosto em terra,' },
      { v: 2, en: 'and he said, “See now, my lords, please come into your servant’s house, stay all night, wash your feet, and you can rise up early, and go on your way.” They said, “No, but we will stay in the street all night.”', pt: 'e disse: Eis agora, meus senhores, entrai, peço-vos em casa de vosso servo, e passai nela a noite, e lavai os pés; de madrugada vos levantareis e ireis vosso caminho. Responderam eles: Não; antes na praça passaremos a noite.' },
      { v: 3, en: 'He urged them greatly, and they came in with him, and entered into his house. He made them a feast, and baked unleavened bread, and they ate.', pt: 'Entretanto, Ló insistiu muito com eles, pelo que foram com ele e entraram em sua casa; e ele lhes deu um banquete, assando-lhes pães ázimos, e eles comeram.' },
      { v: 4, en: 'But before they lay down, the men of the city, the men of Sodom, surrounded the house, both young and old, all the people from every quarter.', pt: 'Mas antes que se deitassem, cercaram a casa os homens da cidade, isto é, os homens de Sodoma, tanto os moços como os velhos, sim, todo o povo de todos os lados;' },
      { v: 5, en: 'They called to Lot, and said to him, “Where are the men who came in to you this night? Bring them out to us, that we may have sex with them.”', pt: 'e, chamando a Ló, perguntaram-lhe: Onde estão os homens que entraram esta noite em tua casa? Traze-os cá fora a nós, para que os conheçamos.' },
      { v: 6, en: 'Lot went out to them to the door, and shut the door after him.', pt: 'Então Ló saiu-lhes à porta, fechando-a atrás de si,' },
      { v: 7, en: 'He said, “Please, my brothers, don’t act so wickedly.', pt: 'e disse: Meus irmãos, rogo-vos que não procedais tão perversamente;' },
      { v: 8, en: 'See now, I have two virgin daughters. Please let me bring them out to you, and you may do to them what seems good to you. Only don’t do anything to these men, because they have come under the shadow of my roof.”', pt: 'eis aqui, tenho duas filhas que ainda não conheceram varão; eu vo-las trarei para fora, e lhes fareis como bem vos parecer: somente nada façais a estes homens, porquanto entraram debaixo da sombra do meu telhado.' },
      { v: 9, en: 'They said, “Stand back!” Then they said, “This one fellow came in to live as a foreigner, and he appoints himself a judge. Now will we deal worse with you, than with them!” They pressed hard on the man Lot, and came near to break the door.', pt: 'Eles, porém, disseram: Sai daí. Disseram mais: Esse indivíduo, como estrangeiro veio aqui habitar, e quer se arvorar em juiz! Agora te faremos mais mal a ti do que a eles. E arremessaram-se sobre o homem, isto é, sobre Ló, e aproximavam-se para arrombar a porta.' },
      { v: 10, en: 'But the men reached out their hand, and brought Lot into the house to them, and shut the door.', pt: 'Aqueles homens, porém, estendendo as mãos, fizeram Ló entrar para dentro da casa, e fecharam a porta;' },
      { v: 11, en: 'They struck the men who were at the door of the house with blindness, both small and great, so that they wearied themselves to find the door.', pt: 'e feriram de cegueira os que estavam do lado de fora, tanto pequenos como grandes, de maneira que cansaram de procurar a porta.' },
      { v: 12, en: 'The men said to Lot, “Do you have anybody else here? Sons-in-law, your sons, your daughters, and whoever you have in the city, bring them out of the place:', pt: 'Então disseram os homens a Ló: Tens mais alguém aqui? Teu genro, e teus filhos, e tuas filhas, e todos quantos tens na cidade, tira-os para fora deste lugar;' },
      { v: 13, en: 'for we will destroy this place, because the outcry against them has grown so great before Yahweh that Yahweh has sent us to destroy it.”', pt: 'porque nós vamos destruir este lugar, porquanto o seu clamor se tem avolumado diante do Senhor, e o Senhor nos enviou a destruí-lo.' },
      { v: 14, en: 'Lot went out, and spoke to his sons-in-law, who were pledged to marry his daughters, and said, “Get up! Get out of this place, for Yahweh will destroy the city.” But he seemed to his sons-in-law to be joking.', pt: 'Tendo saído Ló, falou com seus genros, que haviam de casar com suas filhas, e disse-lhes: Levantai-vos, saí deste lugar, porque o Senhor há de destruir a cidade. Mas ele pareceu aos seus genros como quem estava zombando.' },
      { v: 15, en: 'When the morning came, then the angels hurried Lot, saying, “Get up! Take your wife, and your two daughters who are here, lest you be consumed in the iniquity of the city.”', pt: 'E ao amanhecer os anjos apertavam com Ló, dizendo: levanta-te, toma tua mulher e tuas duas filhas que aqui estão, para que não pereças no castigo da cidade.' },
      { v: 16, en: 'But he lingered; and the men grabbed his hand, his wife’s hand, and his two daughters’ hands, Yahweh being merciful to him; and they took him out, and set him outside of the city.', pt: 'Ele, porém, se demorava; pelo que os homens pegaram-lhe pela mão a ele, à sua mulher, e às suas filhas, sendo-lhe misericordioso o Senhor. Assim o tiraram e o puseram fora da cidade.' },
      { v: 17, en: 'It came to pass, when they had taken them out, that he said, “Escape for your life! Don’t look behind you, and don’t stay anywhere in the plain. Escape to the mountains, lest you be consumed!”', pt: 'Quando os tinham tirado para fora, disse um deles: Escapa-te, salva tua vida; não olhes para trás de ti, nem te detenhas em toda esta planície; escapa-te lá para o monte, para que não pereças.' },
      { v: 18, en: 'Lot said to them, “Oh, not so, my lord.', pt: 'Respondeu-lhe Ló: Ah, assim não, meu Senhor!' },
      { v: 19, en: 'See now, your servant has found favor in your sight, and you have magnified your loving kindness, which you have shown to me in saving my life. I can’t escape to the mountain, lest evil overtake me, and I die.', pt: 'Eis que agora o teu servo tem achado graça aos teus olhos, e tens engrandecido a tua misericórdia que a mim me fizeste, salvando-me a vida; mas eu não posso escapar-me para o monte; não seja caso me apanhe antes este mal, e eu morra.' },
      { v: 20, en: 'See now, this city is near to flee to, and it is a little one. Oh let me escape there (isn’t it a little one?), and my soul will live.”', pt: 'Eis ali perto aquela cidade, para a qual eu posso fugir, e é pequena. Permite que eu me escape para lá (porventura não é pequena?), e viverá a minha alma.' },
      { v: 21, en: 'He said to him, “Behold, I have granted your request concerning this thing also, that I will not overthrow the city of which you have spoken.', pt: 'Disse-lhe: Quanto a isso também te hei atendido, para não subverter a cidade de que acabas de falar.' },
      { v: 22, en: 'Hurry, escape there, for I can’t do anything until you get there.” Therefore the name of the city was called Zoar.', pt: 'Apressa-te, escapa-te para lá; porque nada poderei fazer enquanto não tiveres ali chegado. Por isso se chamou o nome da cidade Zoar.' },
      { v: 23, en: 'The sun had risen on the earth when Lot came to Zoar.', pt: 'Tinha saído o sol sobre a terra, quando Ló entrou em Zoar.' },
      { v: 24, en: 'Then Yahweh rained on Sodom and on Gomorrah sulfur and fire from Yahweh out of the sky.', pt: 'Então o Senhor, da sua parte, fez chover do céu enxofre e fogo sobre Sodoma e Gomorra.' },
      { v: 25, en: 'He overthrew those cities, all the plain, all the inhabitants of the cities, and that which grew on the ground.', pt: 'E subverteu aquelas cidades e toda a planície, e todos os moradores das cidades, e o que nascia da terra.' },
      { v: 26, en: 'But his wife looked back from behind him, and she became a pillar of salt.', pt: 'Mas a mulher de Ló olhou para trás e ficou convertida em uma estátua de sal.' },
      { v: 27, en: 'Abraham got up early in the morning to the place where he had stood before Yahweh.', pt: 'E Abraão levantou-se de madrugada, e foi ao lugar onde estivera em pé diante do Senhor;' },
      { v: 28, en: 'He looked toward Sodom and Gomorrah, and toward all the land of the plain, and looked, and saw that the smoke of the land went up as the smoke of a furnace.', pt: 'e, contemplando Sodoma e Gomorra e toda a terra da planície, viu que subia da terra fumaça como a de uma fornalha.' },
      { v: 29, en: 'When God destroyed the cities of the plain, God remembered Abraham, and sent Lot out of the middle of the overthrow, when he overthrew the cities in which Lot lived.', pt: 'Ora, aconteceu que, destruindo Deus as cidades da planície, lembrou-se de Abraão, e tirou Ló do meio da destruição, ao subverter aquelas cidades em que Ló habitara.' },
      { v: 30, en: 'Lot went up out of Zoar, and lived in the mountain, and his two daughters with him; for he was afraid to live in Zoar. He lived in a cave with his two daughters.', pt: 'E subiu Ló de Zoar, e habitou no monte, e as suas duas filhas com ele; porque temia habitar em Zoar; e habitou numa caverna, ele e as suas duas filhas.' },
      { v: 31, en: 'The firstborn said to the younger, “Our father is old, and there is not a man in the earth to come in to us in the way of all the earth.', pt: 'Então a primogênita disse à menor: Nosso pai é já velho, e não há varão na terra que entre a nós, segundo o costume de toda a terra;' },
      { v: 32, en: 'Come, let’s make our father drink wine, and we will lie with him, that we may preserve our father’s family line .”', pt: 'vem, demos a nosso pai vinho a beber, e deitemo-nos com ele, para que conservemos a descendência de nosso pai.' },
      { v: 33, en: 'They made their father drink wine that night: and the firstborn went in, and lay with her father. He didn’t know when she lay down, nor when she arose.', pt: 'Deram, pois, a seu pai vinho a beber naquela noite; e, entrando a primogênita, deitou-se com seu pai; e não percebeu ele quando ela se deitou, nem quando se levantou.' },
      { v: 34, en: 'It came to pass on the next day, that the firstborn said to the younger, “Behold, I lay last night with my father. Let us make him drink wine again, tonight. You go in, and lie with him, that we may preserve our father’s family line. ”', pt: 'No dia seguinte disse a primogênita à menor: Eis que eu ontem à noite me deitei com meu pai; demos-lhe vinho a beber também esta noite; e então, entrando tu, deita-te com ele, para que conservemos a descendência de nosso pai.' },
      { v: 35, en: 'They made their father drink wine that night also. The younger went and lay with him. He didn’t know when she lay down, nor when she got up.', pt: 'Tornaram, pois, a dar a seu pai vinho a beber também naquela noite; e, levantando-se a menor, deitou-se com ele; e não percebeu ele quando ela se deitou, nem quando se levantou.' },
      { v: 36, en: 'Thus both of Lot’s daughters were with child by their father.', pt: 'Assim as duas filhas de Ló conceberam de seu pai.' },
      { v: 37, en: 'The firstborn bore a son, and named him Moab. He is the father of the Moabites to this day.', pt: 'A primogênita deu a luz a um filho, e chamou-lhe Moabe; este é o pai dos moabitas de hoje.' },
      { v: 38, en: 'The younger also bore a son, and called his name Ben Ammi. He is the father of the children of Ammon to this day.', pt: 'A menor também deu à luz um filho, e chamou-lhe Ben-Ami; este é o pai dos amonitas de hoje.' },
    ],
    20: [
      { v: 1, en: 'Abraham traveled from there toward the land of the South, and lived between Kadesh and Shur. He lived as a foreigner in Gerar.', pt: 'Partiu Abraão dali para a terra do Negebe, e habitou entre Cades e Sur; e peregrinou em Gerar.' },
      { v: 2, en: 'Abraham said about Sarah his wife, “She is my sister.” Abimelech king of Gerar sent, and took Sarah.', pt: 'E havendo Abraão dito de Sara, sua mulher: É minha irmã; enviou Abimeleque, rei de Gerar, e tomou a Sara.' },
      { v: 3, en: 'But God came to Abimelech in a dream of the night, and said to him, “Behold, you are a dead man, because of the woman whom you have taken. For she is a man’s wife.”', pt: 'Deus, porém, veio a Abimeleque, em sonhos, de noite, e disse-lhe: Eis que estás para morrer por causa da mulher que tomaste; porque ela tem marido.' },
      { v: 4, en: 'Now Abimelech had not come near her. He said, “Lord, will you kill even a righteous nation?', pt: 'Ora, Abimeleque ainda não se havia chegado a ela: perguntou, pois: Senhor matarás porventura tambem uma nação justa?' },
      { v: 5, en: 'Didn’t he tell me, ‘She is my sister?’ She, even she herself, said, ‘He is my brother.’ In the integrity of my heart and the innocence of my hands I have done this.”', pt: 'Não me disse ele mesmo: É minha irmã? e ela mesma me disse: Ele é meu irmão; na sinceridade do meu coração e na inocência das minhas mãos fiz isto.' },
      { v: 6, en: 'God said to him in the dream, “Yes, I know that in the integrity of your heart you have done this, and I also withheld you from sinning against me. Therefore I didn’t allow you to touch her.', pt: 'Ao que Deus lhe respondeu em sonhos: Bem sei eu que na sinceridade do teu coração fizeste isto; e também eu te tenho impedido de pecar contra mim; por isso não te permiti tocá-la;' },
      { v: 7, en: 'Now therefore, restore the man’s wife. For he is a prophet, and he will pray for you, and you will live. If you don’t restore her, know for sure that you will die, you, and all who are yours.”', pt: 'agora, pois, restitui a mulher a seu marido, porque ele é profeta, e intercederá por ti, e viverás; se, porém, não lha restituíres, sabe que certamente morrerás, tu e tudo o que é teu.' },
      { v: 8, en: 'Abimelech rose early in the morning, and called all his servants, and told all these things in their ear. The men were very scared.', pt: 'Levantou-se Abimeleque de manhã cedo e, chamando a todos os seus servos, falou-lhes aos ouvidos todas estas palavras; e os homens temeram muito.' },
      { v: 9, en: 'Then Abimelech called Abraham, and said to him, “What have you done to us? How have I sinned against you, that you have brought on me and on my kingdom a great sin? You have done deeds to me that ought not to be done!”', pt: 'Então chamou Abimeleque a Abraão e lhe perguntou: Que é que nos fizeste? e em que pequei contra ti, para trazeres sobre mim o sobre o meu reino tamanho pecado? Tu me fizeste o que não se deve fazer.' },
      { v: 10, en: 'Abimelech said to Abraham, “What did you see, that you have done this thing?”', pt: 'Perguntou mais Abimeleque a Abraão: Com que intenção fizeste isto?' },
      { v: 11, en: 'Abraham said, “Because I thought, ‘Surely the fear of God is not in this place. They will kill me for my wife’s sake.’', pt: 'Respondeu Abraão: Porque pensei: Certamente não há temor de Deus neste lugar; matar-me-ão por causa da minha mulher.' },
      { v: 12, en: 'Besides, she is indeed my sister, the daughter of my father, but not the daughter of my mother; and she became my wife.', pt: 'Além disso ela é realmente minha irmã, filha de meu pai, ainda que não de minha mãe; e veio a ser minha mulher.' },
      { v: 13, en: 'When God caused me to wander from my father’s house, I said to her, ‘This is your kindness which you shall show to me. Everywhere that we go, say of me, “He is my brother.”’”', pt: 'Quando Deus me fez sair errante da casa de meu pai, eu lhe disse a ela: Esta é a graça que me farás: em todo lugar aonde formos, dize de mim: Ele é meu irmão.' },
      { v: 14, en: 'Abimelech took sheep and cattle, male servants and female servants, and gave them to Abraham, and restored Sarah, his wife, to him.', pt: 'Então tomou Abimeleque ovelhas e bois, e servos e servas, e os deu a Abraão; e lhe restituiu Sara, sua mulher;' },
      { v: 15, en: 'Abimelech said, “Behold, my land is before you. Dwell where it pleases you.”', pt: 'e disse-lhe Abimeleque: Eis que a minha terra está diante de ti; habita onde bem te parecer.' },
      { v: 16, en: 'To Sarah he said, “Behold, I have given your brother a thousand pieces of silver. Behold, it is for you a covering of the eyes to all that are with you. In front of all you are vindicated.”', pt: 'E a Sara disse: Eis que tenho dado a teu irmão mil moedas de prata; isso te seja por véu dos olhos a todos os que estão contigo; e perante todos estás reabilitada.' },
      { v: 17, en: 'Abraham prayed to God. God healed Abimelech, and his wife, and his female servants, and they bore children.', pt: 'Orou Abraão a Deus, e Deus sarou Abimeleque, e a sua mulher e as suas servas; de maneira que tiveram filhos;' },
      { v: 18, en: 'For Yahweh had closed up tight all the wombs of the house of Abimelech, because of Sarah, Abraham’s wife.', pt: 'porque o Senhor havia fechado totalmente todas as madres da casa de Abimeleque, por causa de Sara, mulher de Abraão.' },
    ],
    21: [
      { v: 1, en: 'Yahweh visited Sarah as he had said, and Yahweh did to Sarah as he had spoken.', pt: 'O Senhor visitou a Sara, como tinha dito, e lhe fez como havia prometido.' },
      { v: 2, en: 'Sarah conceived, and bore Abraham a son in his old age, at the set time of which God had spoken to him.', pt: 'Sara concebeu, e deu a Abraão um filho na sua velhice, ao tempo determinado, de que Deus lhe falara;' },
      { v: 3, en: 'Abraham called his son who was born to him, whom Sarah bore to him, Isaac.', pt: 'e, Abraão pôs no filho que lhe nascera, que Sara lhe dera, o nome de Isaque.' },
      { v: 4, en: 'Abraham circumcised his son, Isaac, when he was eight days old, as God had commanded him.', pt: 'E Abraão circuncidou a seu filho Isaque, quando tinha oito dias, conforme Deus lhe ordenara.' },
      { v: 5, en: 'Abraham was one hundred years old when his son, Isaac, was born to him.', pt: 'Ora, Abraão tinha cem anos, quando lhe nasceu Isaque, seu filho.' },
      { v: 6, en: 'Sarah said, “God has made me laugh. Everyone who hears will laugh with me.”', pt: 'Pelo que disse Sara: Deus preparou riso para mim; todo aquele que o ouvir, se rirá comigo.' },
      { v: 7, en: 'She said, “Who would have said to Abraham, that Sarah would nurse children? For I have borne him a son in his old age.”', pt: 'E acrescentou: Quem diria a Abraão que Sara havia de amamentar filhos? no entanto lhe dei um filho na sua velhice.' },
      { v: 8, en: 'The child grew, and was weaned. Abraham made a great feast on the day that Isaac was weaned.', pt: 'cresceu o menino, e foi desmamado; e Abraão fez um grande banquete no dia em que Isaque foi desmamado.' },
      { v: 9, en: 'Sarah saw the son of Hagar the Egyptian, whom she had borne to Abraham, mocking.', pt: 'Ora, Sara viu brincando o filho de Agar a egípcia, que esta dera à luz a Abraão.' },
      { v: 10, en: 'Therefore she said to Abraham, “Cast out this servant and her son! For the son of this servant will not be heir with my son, Isaac.”', pt: 'Pelo que disse a Abraão: Deita fora esta serva e o seu filho; porque o filho desta serva não será herdeiro com meu filho, com Isaque.' },
      { v: 11, en: 'The thing was very grievous in Abraham’s sight on account of his son.', pt: 'Pareceu isto bem duro aos olhos de Abraão, por causa de seu filho.' },
      { v: 12, en: 'God said to Abraham, “Don’t let it be grievous in your sight because of the boy, and because of your servant. In all that Sarah says to you, listen to her voice. For your offspring will be named through Isaac.', pt: 'Deus, porém, disse a Abraão: Não pareça isso duro aos teus olhos por causa do moço e por causa da tua serva; em tudo o que Sara te diz, ouve a sua voz; porque em Isaque será chamada a tua descendência.' },
      { v: 13, en: 'I will also make a nation of the son of the servant, because he is your child .”', pt: 'Mas também do filho desta serva farei uma nação, porquanto ele é da tua linhagem.' },
      { v: 14, en: 'Abraham rose up early in the morning, and took bread and a bottle of water, and gave it to Hagar, putting it on her shoulder; and gave her the child, and sent her away. She departed, and wandered in the wilderness of Beersheba.', pt: 'Então se levantou Abraão de manhã cedo e, tomando pão e um odre de àgua, os deu a Agar, pondo-os sobre o ombro dela; também lhe deu o menino e despediu-a; e ela partiu e foi andando errante pelo deserto de Beer-Seba.' },
      { v: 15, en: 'The water in the bottle was spent, and she put the child under one of the shrubs.', pt: 'E consumida a água do odre, Agar deitou o menino debaixo de um dos arbustos,' },
      { v: 16, en: 'She went and sat down opposite him, a good way off, about a bow shot away. For she said, “Don’t let me see the death of the child.” She sat over against him, and lifted up her voice, and wept.', pt: 'e foi assentar-se em frente dele, a boa distância, como a de um tiro de arco; porque dizia: Que não veja eu morrer o menino. Assim sentada em frente dele, levantou a sua voz e chorou.' },
      { v: 17, en: 'God heard the voice of the boy. The angel of God called to Hagar out of the sky, and said to her, “What ails you, Hagar? Don’t be afraid. For God has heard the voice of the boy where he is.', pt: 'Mas Deus ouviu a voz do menino; e o anjo de Deus, bradando a Agar desde o céu, disse-lhe: Que tens, Agar? não temas, porque Deus ouviu a voz do menino desde o lugar onde está.' },
      { v: 18, en: 'Get up, lift up the boy, and hold him in your hand. For I will make him a great nation.”', pt: 'Ergue-te, levanta o menino e toma-o pela mão, porque dele farei uma grande nação.' },
      { v: 19, en: 'God opened her eyes, and she saw a well of water. She went, filled the bottle with water, and gave the boy drink.', pt: 'E abriu-lhe Deus os olhos, e ela viu um poço; e foi encher de água o odre e deu de beber ao menino.' },
      { v: 20, en: 'God was with the boy, and he grew. He lived in the wilderness, and became, as he grew up, an archer.', pt: 'Deus estava com o menino, que cresceu e, morando no deserto, tornou-se flecheiro.' },
      { v: 21, en: 'He lived in the wilderness of Paran. His mother took a wife for him out of the land of Egypt.', pt: 'Ele habitou no deserto de Parã; e sua mãe tomou-lhe uma mulher da terra do Egito.' },
      { v: 22, en: 'At that time, Abimelech and Phicol the captain of his army spoke to Abraham, saying, “God is with you in all that you do.', pt: 'Naquele mesmo tempo Abimeleque, com Ficol, o chefe do seu exército, falou a Abraão, dizendo: Deus é contigo em tudo o que fazes;' },
      { v: 23, en: 'Now, therefore, swear to me here by God that you will not deal falsely with me, nor with my son, nor with my son’s son. But according to the kindness that I have done to you, you shall do to me, and to the land in which you have lived as a foreigner.”', pt: 'agora pois, jura-me aqui por Deus que não te haverás falsamente comigo, nem com meu filho, nem com o filho do meu filho; mas segundo a beneficência que te fiz, me farás a mim, e à terra onde peregrinaste.' },
      { v: 24, en: 'Abraham said, “I will swear.”', pt: 'Respondeu Abraão: Eu jurarei.' },
      { v: 25, en: 'Abraham complained to Abimelech because of a water well, which Abimelech’s servants had violently taken away.', pt: 'Abraão, porém, repreendeu a Abimeleque, por causa de um poço de água, que os servos de Abimeleque haviam tomado à força.' },
      { v: 26, en: 'Abimelech said, “I don’t know who has done this thing. You didn’t tell me, and I didn’t hear of it until today.”', pt: 'Respondeu-lhe Abimeleque: Não sei quem fez isso; nem tu mo fizeste saber, nem tampouco ouvi eu falar nisso, senão hoje.' },
      { v: 27, en: 'Abraham took sheep and cattle, and gave them to Abimelech. Those two made a covenant.', pt: 'Tomou, pois, Abraão ovelhas e bois, e os deu a Abimeleque; assim fizeram entre, si um pacto.' },
      { v: 28, en: 'Abraham set seven ewe lambs of the flock by themselves.', pt: 'Pôs Abraão, porém, à parte sete cordeiras do rebanho.' },
      { v: 29, en: 'Abimelech said to Abraham, “What do these seven ewe lambs which you have set by themselves mean?”', pt: 'E perguntou Abimeleque a Abraão: Que significam estas sete cordeiras que puseste à parte?' },
      { v: 30, en: 'He said, “You shall take these seven ewe lambs from my hand, that it may be a witness to me, that I have dug this well.”', pt: 'Respondeu Abraão: Estas sete cordeiras receberás da minha mão para que me sirvam de testemunho de que eu cavei este poço.' },
      { v: 31, en: 'Therefore he called that place Beersheba, because they both swore an oath there.', pt: 'Pelo que chamou aquele lugar Beer-Seba, porque ali os dois juraram.' },
      { v: 32, en: 'So they made a covenant at Beersheba. Abimelech rose up with Phicol, the captain of his army, and they returned into the land of the Philistines.', pt: 'Assim fizeram uma pacto em Beer-Seba. Depois se levantaram Abimeleque e Ficol, o chefe do seu exército, e tornaram para a terra dos filisteus.' },
      { v: 33, en: 'Abraham planted a tamarisk tree in Beersheba, and called there on the name of Yahweh, the Everlasting God.', pt: 'Abraão plantou uma tamargueira em Beer-Seba, e invocou ali o nome do Senhor, o Deus eterno.' },
      { v: 34, en: 'Abraham lived as a foreigner in the land of the Philistines many days.', pt: 'E peregrinou Abraão na terra dos filisteus muitos dias.' },
    ],
    22: [
      { v: 1, en: 'After these things, God tested Abraham, and said to him, “Abraham!” He said, “Here I am.”', pt: 'Sucedeu, depois destas coisas, que Deus provou a Abraão, dizendo-lhe: Abraão! E este respondeu: Eis-me aqui.' },
      { v: 2, en: 'He said, “Now take your son, your only son, whom you love, even Isaac, and go into the land of Moriah. Offer him there as a burnt offering on one of the mountains which I will tell you of.”', pt: 'Prosseguiu Deus: Toma agora teu filho; o teu único filho, Isaque, a quem amas; vai à terra de Moriá, e oferece-o ali em holocausto sobre um dos montes que te hei de mostrar.' },
      { v: 3, en: 'Abraham rose early in the morning, and saddled his donkey, and took two of his young men with him, and Isaac his son. He split the wood for the burnt offering, and rose up, and went to the place of which God had told him.', pt: 'Levantou-se, pois, Abraão de manhã cedo, albardou o seu jumento, e tomou consigo dois de seus moços e Isaque, seu filho; e, tendo cortado lenha para o holocausto, partiu para ir ao lugar que Deus lhe dissera.' },
      { v: 4, en: 'On the third day Abraham lifted up his eyes, and saw the place far off.', pt: 'Ao terceiro dia levantou Abraão os olhos, e viu o lugar de longe.' },
      { v: 5, en: 'Abraham said to his young men, “Stay here with the donkey. The boy and I will go yonder. We will worship, and come back to you.”', pt: 'E disse Abraão a seus moços: Ficai-vos aqui com o jumento, e eu e o mancebo iremos até lá; depois de adorarmos, voltaremos a vós.' },
      { v: 6, en: 'Abraham took the wood of the burnt offering and laid it on Isaac his son. He took in his hand the fire and the knife. They both went together.', pt: 'Tomou, pois, Abraão a lenha do holocausto e a pôs sobre Isaque, seu filho; tomou também na mão o fogo e o cutelo, e foram caminhando juntos.' },
      { v: 7, en: 'Isaac spoke to Abraham his father, and said, “My father?” He said, “Here I am, my son.” He said, “Here is the fire and the wood, but where is the lamb for a burnt offering?”', pt: 'Então disse Isaque a Abraão, seu pai: Meu pai! Respondeu Abraão: Eis-me aqui, meu filho! Perguntou-lhe Isaque: Eis o fogo e a lenha, mas onde está o cordeiro para o holocausto?' },
      { v: 8, en: 'Abraham said, “God will provide himself the lamb for a burnt offering, my son.” So they both went together.', pt: 'Respondeu Abraão: Deus proverá para si o cordeiro para o holocausto, meu filho. E os dois iam caminhando juntos.' },
      { v: 9, en: 'They came to the place which God had told him of. Abraham built the altar there, and laid the wood in order, bound Isaac his son, and laid him on the altar, on the wood.', pt: 'Havendo eles chegado ao lugar que Deus lhe dissera, edificou Abraão ali o altar e pôs a lenha em ordem; o amarrou, a Isaque, seu filho, e o deitou sobre o altar em cima da lenha.' },
      { v: 10, en: 'Abraham stretched out his hand, and took the knife to kill his son.', pt: 'E, estendendo a mão, pegou no cutelo para imolar a seu filho.' },
      { v: 11, en: 'Yahweh’s angel called to him out of the sky, and said, “Abraham, Abraham!” He said, “Here I am.”', pt: 'Mas o anjo do Senhor lhe bradou desde o céu, e disse: Abraão, Abraão! Ele respondeu: Eis-me aqui.' },
      { v: 12, en: 'He said, “Don’t lay your hand on the boy or do anything to him. For now I know that you fear God, since you have not withheld your son, your only son, from me.”', pt: 'Então disse o anjo: Não estendas a mão sobre o mancebo, e não lhe faças nada; porquanto agora sei que temes a Deus, visto que não me negaste teu filho, o teu único filho.' },
      { v: 13, en: 'Abraham lifted up his eyes, and looked, and saw that behind him was a ram caught in the thicket by his horns. Abraham went and took the ram, and offered him up for a burnt offering instead of his son.', pt: 'Nisso levantou Abraão os olhos e olhou, e eis atrás de si um carneiro embaraçado pelos chifres no mato; e foi Abraão, tomou o carneiro e o ofereceu em holocausto em lugar de seu filho.' },
      { v: 14, en: 'Abraham called the name of that place Yahweh Will Provide. As it is said to this day, “On Yahweh’s mountain, it will be provided.”', pt: 'Pelo que chamou Abraão àquele lugar Jeová-Jiré; donde se diz até o dia de hoje: No monte do Senhor se proverá.' },
      { v: 15, en: 'Yahweh’s angel called to Abraham a second time out of the sky,', pt: 'Então o anjo do Senhor bradou a Abraão pela segunda vez desde o céu,' },
      { v: 16, en: 'and said, “I have sworn by myself, says Yahweh, because you have done this thing, and have not withheld your son, your only son,', pt: 'e disse: Por mim mesmo jurei, diz o Senhor, porquanto fizeste isto, e não me negaste teu filho, o teu único filho,' },
      { v: 17, en: 'that I will bless you greatly, and I will multiply your offspring greatly like the stars of the heavens, and like the sand which is on the seashore. Your offspring will possess the gate of his enemies.', pt: 'que deveras te abençoarei, e grandemente multiplicarei a tua descendência, como as estrelas do céu e como a areia que está na praia do mar; e a tua descendência possuirá a porta dos seus inimigos;' },
      { v: 18, en: 'All the nations of the earth will be blessed by your offspring, because you have obeyed my voice.”', pt: 'e em tua descendência serão benditas todas as nações da terra; porquanto obedeceste à minha voz.' },
      { v: 19, en: 'So Abraham returned to his young men, and they rose up and went together to Beersheba. Abraham lived at Beersheba.', pt: 'Então voltou Abraão aos seus moços e, levantando-se, foram juntos a Beer-Seba; e Abraão habitou em Beer-Seba.' },
      { v: 20, en: 'After these things, Abraham was told, “Behold, Milcah, she also has borne children to your brother Nahor:', pt: 'Depois destas coisas anunciaram a Abraão, dizendo: Eis que também Milca tem dado à luz filhos a Naor, teu irmão:' },
      { v: 21, en: 'Uz his firstborn, Buz his brother, Kemuel the father of Aram,', pt: 'Uz o seu primogênito, e Buz seu irmão, e Quemuel, pai de Arão,' },
      { v: 22, en: 'Chesed, Hazo, Pildash, Jidlaph, and Bethuel.”', pt: 'e Quesede, Hazo, Pildas, Jidlafe e Betuel.' },
      { v: 23, en: 'Bethuel became the father of Rebekah. These eight Milcah bore to Nahor, Abraham’s brother.', pt: 'E Betuel gerou a Rebeca. Esses oito deu à luz Milca a Naor, irmão de Abraão.' },
      { v: 24, en: 'His concubine, whose name was Reumah, also bore Tebah, Gaham, Tahash, and Maacah.', pt: 'E a sua concubina, que se chamava Reumá, também deu à luz a Teba, Gaão, Taás e Maacá.' },
    ],
    23: [
      { v: 1, en: 'Sarah lived one hundred twenty-seven years. This was the length of Sarah’s life.', pt: 'Ora, os anos da vida de Sara foram cento e vinte e sete.' },
      { v: 2, en: 'Sarah died in Kiriath Arba (also called Hebron), in the land of Canaan. Abraham came to mourn for Sarah, and to weep for her.', pt: 'E morreu Sara em Quiriate-Arba, que é Hebrom, na terra de Canaã; e veio Abraão lamentá-la e chorar por ela:' },
      { v: 3, en: 'Abraham rose up from before his dead, and spoke to the children of Heth, saying,', pt: 'Depois se levantou Abraão de diante do seu morto, e falou aos filhos de Hete, dizendo:' },
      { v: 4, en: '“I am a stranger and a foreigner living with you. Give me a possession of a burying-place with you, that I may bury my dead out of my sight.”', pt: 'Estrangeiro e peregrino sou eu entre vós; dai-me o direito de um lugar de sepultura entre vós, para que eu sepulte o meu morto, removendo-o de diante da minha face.' },
      { v: 5, en: 'The children of Heth answered Abraham, saying to him,', pt: 'Responderam-lhe os filhos de Hete:' },
      { v: 6, en: '“Hear us, my lord. You are a prince of God among us. Bury your dead in the best of our tombs. None of us will withhold from you his tomb. Bury your dead.”', pt: 'Ouve-nos, senhor; príncipe de Deus és tu entre nós; enterra o teu morto na mais escolhida de nossas sepulturas; nenhum de nós te vedará a sua sepultura, para enterrares o teu morto.' },
      { v: 7, en: 'Abraham rose up, and bowed himself to the people of the land, even to the children of Heth.', pt: 'Então se levantou Abraão e, inclinando-se diante do povo da terra, diante dos filhos de Hete,' },
      { v: 8, en: 'He talked with them, saying, “If you agree that I should bury my dead out of my sight, hear me, and entreat for me to Ephron the son of Zohar,', pt: 'falou-lhes, dizendo: Se é de vossa vontade que eu sepulte o meu morto de diante de minha face, ouvi-me e intercedei por mim junto a Efrom, filho de Zoar,' },
      { v: 9, en: 'that he may give me the cave of Machpelah, which he has, which is in the end of his field. For the full price let him give it to me among you as a possession for a burial place.”', pt: 'para que ele me dê a cova de Macpela, que possui no fim do seu campo; que ma dê pelo devido preço em posse de sepulcro no meio de vós.' },
      { v: 10, en: 'Now Ephron was sitting in the middle of the children of Heth. Ephron the Hittite answered Abraham in the hearing of the children of Heth, even of all who went in at the gate of his city, saying,', pt: 'Ora, Efrom estava sentado no meio dos filhos de Hete; e respondeu Efrom, o heteu, a Abraão, aos ouvidos dos filhos de Hete, isto é, de todos os que entravam pela porta da sua cidade, dizendo:' },
      { v: 11, en: '“No, my lord, hear me. I give you the field, and I give you the cave that is in it. In the presence of the children of my people I give it to you. Bury your dead.”', pt: 'Não, meu senhor; ouve-me. O campo te dou, também te dou a cova que nele está; na presença dos filhos do meu povo ta dou; sepulta o teu morto.' },
      { v: 12, en: 'Abraham bowed himself down before the people of the land.', pt: 'Então Abraão se inclinou diante do povo da terra,' },
      { v: 13, en: 'He spoke to Ephron in the audience of the people of the land, saying, “But if you will, please hear me. I will give the price of the field. Take it from me, and I will bury my dead there.”', pt: 'e falou a Efrom, aos ouvidos do povo da terra, dizendo: Se te agrada, peço-te que me ouças. Darei o preço do campo; toma-o de mim, e sepultarei ali o meu morto.' },
      { v: 14, en: 'Ephron answered Abraham, saying to him,', pt: 'Respondeu Efrom a Abraão:' },
      { v: 15, en: '“My lord, listen to me. What is a piece of land worth four hundred shekels of silver between me and you? Therefore bury your dead.”', pt: 'Meu senhor, ouve-me. Um terreno do valor de quatrocentos siclos de prata! que é isto entre mim e ti? Sepulta, pois, o teu morto.' },
      { v: 16, en: 'Abraham listened to Ephron. Abraham weighed to Ephron the silver which he had named in the audience of the children of Heth, four hundred shekels of silver, according to the current merchants’ standard.', pt: 'E Abraão ouviu a Efrom, e pesou-lhe a prata de que este tinha falado aos ouvidos dos filhos de Hete, quatrocentos siclos de prata, moeda corrente entre os mercadores.' },
      { v: 17, en: 'So the field of Ephron, which was in Machpelah, which was before Mamre, the field, the cave which was in it, and all the trees that were in the field, that were in all of its borders, were deeded', pt: 'Assim o campo de Efrom, que estava em Macpela, em frente de Manre, o campo e a cova que nele estava, e todo o arvoredo que havia nele, por todos os seus limites ao redor, se confirmaram' },
      { v: 18, en: 'to Abraham for a possession in the presence of the children of Heth, before all who went in at the gate of his city.', pt: 'a Abraão em possessão na presença dos filhos de Hete, isto é, de todos os que entravam pela porta da sua cidade.' },
      { v: 19, en: 'After this, Abraham buried Sarah his wife in the cave of the field of Machpelah before Mamre (that is, Hebron), in the land of Canaan.', pt: 'Depois sepultou Abraão a Sara sua mulher na cova do campo de Macpela, em frente de Manre, que é Hebrom, na terra de Canaã.' },
      { v: 20, en: 'The field, and the cave that is in it, were deeded to Abraham by the children of Heth as a possession for a burial place.', pt: 'Assim o campo e a cova que nele estava foram confirmados a Abraão pelos filhos de Hete em possessão de sepultura.' },
    ],
    24: [
      { v: 1, en: 'Abraham was old, and well stricken in age. Yahweh had blessed Abraham in all things.', pt: 'Ora, Abraão era já velho e de idade avançada; e em tudo o Senhor o havia abençoado.' },
      { v: 2, en: 'Abraham said to his servant, the elder of his house, who ruled over all that he had, “Please put your hand under my thigh.', pt: 'E disse Abraão ao seu servo, o mais antigo da casa, que tinha o governo sobre tudo o que possuía: Põe a tua mão debaixo da minha coxa,' },
      { v: 3, en: 'I will make you swear by Yahweh, the God of heaven and the God of the earth, that you shall not take a wife for my son of the daughters of the Canaanites, among whom I live.', pt: 'para que eu te faça jurar pelo Senhor, Deus do céu e da terra, que não tomarás para meu filho mulher dentre as filhas dos cananeus, no meio dos quais eu habito;' },
      { v: 4, en: 'But you shall go to my country, and to my relatives, and take a wife for my son Isaac.”', pt: 'mas que irás à minha terra e à minha parentela, e dali tomarás mulher para meu filho Isaque.' },
      { v: 5, en: 'The servant said to him, “What if the woman isn’t willing to follow me to this land? Must I bring your son again to the land you came from?”', pt: 'Perguntou-lhe o servo: Se porventura a mulher não quiser seguir-me a esta terra, farei, então, tornar teu filho à terra donde saíste?' },
      { v: 6, en: 'Abraham said to him, “Beware that you don’t bring my son there again.', pt: 'Respondeu-lhe Abraão: Guarda-te de fazeres tornar para lá meu filho.' },
      { v: 7, en: 'Yahweh, the God of heaven, who took me from my father’s house, and from the land of my birth, who spoke to me, and who swore to me, saying, ‘I will give this land to your offspring. He will send his angel before you, and you shall take a wife for my son from there.', pt: 'O Senhor, Deus do céu, que me tirou da casa de meu pai e da terra da minha parentela, e que me falou, e que me jurou, dizendo: Â tua o semente darei esta terra; ele enviará o seu anjo diante de si, para que tomes de lá mulher para meu filho.' },
      { v: 8, en: 'If the woman isn’t willing to follow you, then you shall be clear from this oath to me. Only you shall not bring my son there again.”', pt: 'Se a mulher, porém, não quiser seguir-te, serás livre deste meu juramento; somente não farás meu filho tornar para lá.' },
      { v: 9, en: 'The servant put his hand under the thigh of Abraham his master, and swore to him concerning this matter.', pt: 'Então pôs o servo a sua mão debaixo da coxa de Abraão seu senhor, e jurou-lhe sobre este negócio.' },
      { v: 10, en: 'The servant took ten camels, of his master’s camels, and departed, having a variety of good things of his master’s with him. He arose, and went to Mesopotamia, to the city of Nahor.', pt: 'Tomou, pois, o servo dez dos camelos do seu senhor, porquanto todos os bens de seu senhor estavam em sua mão; e, partindo, foi para a Mesopotâmia, à cidade de Naor.' },
      { v: 11, en: 'He made the camels kneel down outside the city by the well of water at the time of evening, the time that women go out to draw water.', pt: 'Fez ajoelhar os camelos fora da cidade, junto ao poço de água, pela tarde, à hora em que as mulheres saíam a tirar água.' },
      { v: 12, en: 'He said, “Yahweh, the God of my master Abraham, please give me success today, and show kindness to my master Abraham.', pt: 'E disse: Ó Senhor, Deus de meu senhor Abraão, dá-me hoje, peço-te, bom êxito, e usa de benevolência para com o meu senhor Abraão.' },
      { v: 13, en: 'Behold, I am standing by the spring of water. The daughters of the men of the city are coming out to draw water.', pt: 'Eis que eu estou em pé junto à fonte, e as filhas dos homens desta cidade vêm saindo para tirar água;' },
      { v: 14, en: 'Let it happen, that the young lady to whom I will say, ‘Please let down your pitcher, that I may drink,’ and she will say, ‘Drink, and I will also give your camels a drink,’—let her be the one you have appointed for your servant Isaac. By this I will know that you have shown kindness to my master.”', pt: 'faze, pois, que a donzela a quem eu disser: Abaixa o teu cântaro, peço-te, para que eu beba; e ela responder: Bebe, e também darei de beber aos teus camelos; seja aquela que designaste para o teu servo Isaque. Assim conhecerei que usaste de benevolência para com o meu senhor.' },
      { v: 15, en: 'Before he had finished speaking, behold, Rebekah came out, who was born to Bethuel the son of Milcah, the wife of Nahor, Abraham’s brother, with her pitcher on her shoulder.', pt: 'Antes que ele acabasse de falar, eis que Rebeca, filha de Betuel, filho de Milca, mulher de Naor, irmão de Abraão, saía com o seu cântaro sobre o ombro.' },
      { v: 16, en: 'The young lady was very beautiful to look at, a virgin. No man had known her. She went down to the spring, filled her pitcher, and came up.', pt: 'A donzela era muito formosa à vista, virgem, a quem varão não havia conhecido; ela desceu à fonte, encheu o seu cântaro e subiu.' },
      { v: 17, en: 'The servant ran to meet her, and said, “Please give me a drink, a little water from your pitcher.”', pt: 'Então o servo correu-lhe ao encontro, e disse: Deixa-me beber, peço-te, um pouco de água do teu cântaro.' },
      { v: 18, en: 'She said, “Drink, my lord.” She hurried, and let down her pitcher on her hand, and gave him a drink.', pt: 'Respondeu ela: Bebe, meu senhor. Então com presteza abaixou o seu cântaro sobre a mão e deu-lhe de beber.' },
      { v: 19, en: 'When she had finished giving him a drink, she said, “I will also draw for your camels, until they have finished drinking.”', pt: 'E quando acabou de lhe dar de beber, disse: Tirarei também água para os teus camelos, até que acabem de beber.' },
      { v: 20, en: 'She hurried, and emptied her pitcher into the trough, and ran again to the well to draw, and drew for all his camels.', pt: 'Também com presteza despejou o seu cântaro no bebedouro e, correndo outra vez ao poço, tirou água para todos os camelos dele.' },
      { v: 21, en: 'The man looked steadfastly at her, remaining silent, to know whether Yahweh had made his journey prosperous or not.', pt: 'E o homem a contemplava atentamente, em silêncio, para saber se o Senhor havia tornado próspera a sua jornada, ou não.' },
      { v: 22, en: 'As the camels had done drinking, the man took a golden ring of half a shekel weight, and two bracelets for her hands of ten shekels weight of gold,', pt: 'Depois que os camelos acabaram de beber, tomou o homem um pendente de ouro, de meio siclo de peso, e duas pulseiras para as mãos dela, do peso de dez siclos de ouro;' },
      { v: 23, en: 'and said, “Whose daughter are you? Please tell me. Is there room in your father’s house for us to stay?”', pt: 'e perguntou: De quem és filha? dize-mo, peço-te. Há lugar em casa de teu pai para nós pousarmos?' },
      { v: 24, en: 'She said to him, “I am the daughter of Bethuel the son of Milcah, whom she bore to Nahor.”', pt: 'Ela lhe respondeu: Eu sou filha de Betuel, filho de Milca, o qual ela deu a Naor.' },
      { v: 25, en: 'She said moreover to him, “We have both straw and feed enough, and room to lodge in.”', pt: 'Disse-lhe mais: Temos palha e forragem bastante, e lugar para pousar.' },
      { v: 26, en: 'The man bowed his head, and worshiped Yahweh.', pt: 'Então inclinou-se o homem e adorou ao Senhor;' },
      { v: 27, en: 'He said, “Blessed be Yahweh, the God of my master Abraham, who has not forsaken his loving kindness and his truth toward my master. As for me, Yahweh has led me on the way to the house of my master’s relatives.”', pt: 'e disse: Bendito seja o Senhor Deus de meu senhor Abraão, que não retirou do meu senhor a sua benevolência e a sua verdade; quanto a mim, o Senhor me guiou no caminho à casa dos irmãos de meu senhor.' },
      { v: 28, en: 'The young lady ran, and told her mother’s house about these words.', pt: 'A donzela correu, e relatou estas coisas aos da casa de sua mãe.' },
      { v: 29, en: 'Rebekah had a brother, and his name was Laban. Laban ran out to the man, to the spring.', pt: 'Ora, Rebeca tinha um irmão, cujo nome era Labão, o qual saiu correndo ao encontro daquele homem até a fonte;' },
      { v: 30, en: 'When he saw the ring, and the bracelets on his sister’s hands, and when he heard the words of Rebekah his sister, saying, “This is what the man said to me,” he came to the man. Behold, he was standing by the camels at the spring.', pt: 'porquanto tinha visto o pendente, e as pulseiras sobre as mãos de sua irmã, e ouvido as palavras de sua irmã Rebeca, que dizia: Assim me falou aquele homem; e foi ter com o homem, que estava em pé junto aos camelos ao lado da fonte.' },
      { v: 31, en: 'He said, “Come in, you blessed of Yahweh. Why do you stand outside? For I have prepared the house, and room for the camels.”', pt: 'E disse: Entra, bendito do Senhor; por que estás aqui fora? pois eu já preparei a casa, e lugar para os camelos.' },
      { v: 32, en: 'The man came into the house, and he unloaded the camels. He gave straw and feed for the camels, and water to wash his feet and the feet of the men who were with him.', pt: 'Então veio o homem à casa, e desarreou os camelos; deram palha e forragem para os camelos e água para lavar os pés dele e dos homens que estavam com ele.' },
      { v: 33, en: 'Food was set before him to eat, but he said, “I will not eat until I have told my message.” He said, “Speak on.”', pt: 'Depois puseram comida diante dele. Ele, porém, disse: Não comerei, até que tenha exposto a minha incumbência. Respondeu-lhe Labão: Fala.' },
      { v: 34, en: 'He said, “I am Abraham’s servant.', pt: 'Então disse: Eu sou o servo de Abraão.' },
      { v: 35, en: 'Yahweh has blessed my master greatly. He has become great. He has given him flocks and herds, silver and gold, male servants and female servants, and camels and donkeys.', pt: 'O Senhor tem abençoado muito ao meu senhor, o qual se tem engrandecido; deu-lhe rebanhos e gado, prata e ouro, escravos e escravas, camelos e jumentos.' },
      { v: 36, en: 'Sarah, my master’s wife, bore a son to my master when she was old. He has given all that he has to him.', pt: 'E Sara, a mulher do meu senhor, mesmo depois, de velha deu um filho a meu senhor; e o pai lhe deu todos os seus bens.' },
      { v: 37, en: 'My master made me swear, saying, ‘You shall not take a wife for my son from the daughters of the Canaanites, in whose land I live,', pt: 'Ora, o meu senhor me fez jurar, dizendo: Não tomarás mulher para meu filho das filhas dos cananeus, em cuja terra habito;' },
      { v: 38, en: 'but you shall go to my father’s house, and to my relatives, and take a wife for my son.’', pt: 'irás, porém, à casa de meu pai, e à minha parentela, e tomarás mulher para meu filho.' },
      { v: 39, en: 'I asked my master, ‘What if the woman will not follow me?’', pt: 'Então respondi ao meu senhor: Porventura não me seguirá a mulher.' },
      { v: 40, en: 'He said to me, ‘Yahweh, before whom I walk, will send his angel with you, and prosper your way. You shall take a wife for my son from my relatives, and of my father’s house.', pt: 'Ao que ele me disse: O Senhor, em cuja presença tenho andado, enviará o seu anjo contigo, e prosperará o teu caminho; e da minha parentela e da casa de meu pai tomarás mulher para meu filho;' },
      { v: 41, en: 'Then will you be clear from my oath, when you come to my relatives. If they don’t give her to you, you shall be clear from my oath.’', pt: 'então serás livre do meu juramento, quando chegares à minha parentela; e se não ta derem, livre serás do meu juramento.' },
      { v: 42, en: 'I came today to the spring, and said, ‘Yahweh, the God of my master Abraham, if now you do prosper my way which I go—', pt: 'E hoje cheguei à fonte, e disse: Senhor, Deus de meu senhor Abraão, se é que agora prosperas o meu caminho, o qual venho seguindo,' },
      { v: 43, en: 'behold, I am standing by this spring of water. Let it happen, that the maiden who comes out to draw, to whom I will say, “Please give me a little water from your pitcher to drink,”', pt: 'eis que estou junto à fonte; faze, pois, que a donzela que sair para tirar água, a quem eu disser: Dá-me, peço-te, de beber um pouco de água do teu cântaro,' },
      { v: 44, en: 'and she will tell me, “Drink, and I will also draw for your camels,”—let her be the woman whom Yahweh has appointed for my master’s son.’', pt: 'e ela me responder: Bebe tu, e também tirarei água para os teus camelos; seja a mulher que o Senhor designou para o filho de meu senhor.' },
      { v: 45, en: 'Before I had finished speaking in my heart, behold, Rebekah came out with her pitcher on her shoulder. She went down to the spring, and drew. I said to her, ‘Please let me drink.’', pt: 'Ora, antes que eu acabasse de falar no meu coração, eis que Rebeca saía com o seu cântaro sobre o ombro, desceu à fonte e tirou água; e eu lhe disse: Dá-me de beber, peço-te.' },
      { v: 46, en: 'She hurried and let down her pitcher from her shoulder, and said, ‘Drink, and I will also give your camels a drink.’ So I drank, and she also gave the camels a drink.', pt: 'E ela, com presteza, abaixou o seu cântaro do ombro, e disse: Bebe, e também darei de beber aos teus camelos; assim bebi, e ela deu também de beber aos camelos.' },
      { v: 47, en: 'I asked her, and said, ‘Whose daughter are you?’ She said, ‘The daughter of Bethuel, Nahor’s son, whom Milcah bore to him.’ I put the ring on her nose, and the bracelets on her hands.', pt: 'Então lhe perguntei: De quem és filha? E ela disse: Filha de Betuel, filho de Naor, que Milca lhe deu. Então eu lhe pus o pendente no nariz e as pulseiras sobre as mãos;' },
      { v: 48, en: 'I bowed my head, and worshiped Yahweh, and blessed Yahweh, the God of my master Abraham, who had led me in the right way to take my master’s brother’s daughter for his son.', pt: 'e, inclinando-me, adorei e bendisse ao Senhor, Deus do meu senhor Abraão, que me havia conduzido pelo caminho direito para tomar para seu filho a filha do irmão do meu senhor.' },
      { v: 49, en: 'Now if you will deal kindly and truly with my master, tell me. If not, tell me, that I may turn to the right hand, or to the left.”', pt: 'Agora, pois, se vós haveis de usar de benevolência e de verdade para com o meu senhor, declarai-mo; e se não, também mo declarai, para que eu vá ou para a direita ou para a esquerda.' },
      { v: 50, en: 'Then Laban and Bethuel answered, “The thing proceeds from Yahweh. We can’t speak to you bad or good.', pt: 'Então responderam Labão e Betuel: Do Senhor procede este negócio; nós não podemos falar-te mal ou bem.' },
      { v: 51, en: 'Behold, Rebekah is before you. Take her, and go, and let her be your master’s son’s wife, as Yahweh has spoken.”', pt: 'Eis que Rebeca está diante de ti, toma-a e vai-te; seja ela a mulher do filho de teu senhor, como tem dito o Senhor.' },
      { v: 52, en: 'When Abraham’s servant heard their words, he bowed himself down to the earth to Yahweh.', pt: 'Quando o servo de Abraão ouviu as palavras deles, prostrou-se em terra diante do Senhor:' },
      { v: 53, en: 'The servant brought out jewels of silver, and jewels of gold, and clothing, and gave them to Rebekah. He also gave precious things to her brother and her mother.', pt: 'e tirou o servo jóias de prata, e jóias de ouro, e vestidos, e deu-os a Rebeca; também deu coisas preciosas a seu irmão e a sua mãe.' },
      { v: 54, en: 'They ate and drank, he and the men who were with him, and stayed all night. They rose up in the morning, and he said, “Send me away to my master.”', pt: 'Então comeram e beberam, ele e os homens que com ele estavam, e passaram a noite. Quando se levantaram de manhã, disse o servo: Deixai-me ir a meu senhor.' },
      { v: 55, en: 'Her brother and her mother said, “Let the young lady stay with us a few days, at least ten. After that she will go.”', pt: 'Disseram o irmão e a mãe da donzela: Fique ela conosco alguns dias, pelo menos dez dias; e depois irá.' },
      { v: 56, en: 'He said to them, “Don’t hinder me, since Yahweh has prospered my way. Send me away that I may go to my master.”', pt: 'Ele, porém, lhes respondeu: Não me detenhas, visto que o Senhor me tem prosperado o caminho; deixai-me partir, para que eu volte a meu senhor.' },
      { v: 57, en: 'They said, “We will call the young lady, and ask her.”', pt: 'Disseram-lhe: chamaremos a donzela, e perguntaremos a ela mesma.' },
      { v: 58, en: 'They called Rebekah, and said to her, “Will you go with this man?” She said, “I will go.”', pt: 'Chamaram, pois, a Rebeca, e lhe perguntaram: Irás tu com este homem; Respondeu ela: Irei.' },
      { v: 59, en: 'They sent away Rebekah, their sister, with her nurse, Abraham’s servant, and his men.', pt: 'Então despediram a Rebeca, sua irmã, e à sua ama e ao servo de Abraão e a seus homens;' },
      { v: 60, en: 'They blessed Rebekah, and said to her, “Our sister, may you be the mother of thousands of ten thousands, and let your offspring possess the gate of those who hate them.”', pt: 'e abençoaram a Rebeca, e disseram-lhe: Irmã nossa, sê tu a mãe de milhares de miríades, e possua a tua descendência a porta de seus aborrecedores!' },
      { v: 61, en: 'Rebekah arose with her ladies. They rode on the camels, and followed the man. The servant took Rebekah, and went his way.', pt: 'Assim Rebeca se levantou com as suas moças e, montando nos camelos, seguiram o homem; e o servo, tomando a Rebeca, partiu.' },
      { v: 62, en: 'Isaac came from the way of Beer Lahai Roi, for he lived in the land of the South.', pt: 'Ora, Isaque tinha vindo do caminho de Beer-Laai-Rói; pois habitava na terra do Negebe.' },
      { v: 63, en: 'Isaac went out to meditate in the field at the evening. He lifted up his eyes and looked. Behold, there were camels coming.', pt: 'Saíra Isaque ao campo à tarde, para meditar; e levantando os olhos, viu, e eis que vinham camelos.' },
      { v: 64, en: 'Rebekah lifted up her eyes, and when she saw Isaac, she got off the camel.', pt: 'Rebeca também levantou os olhos e, vendo a Isaque, saltou do camelo' },
      { v: 65, en: 'She said to the servant, “Who is the man who is walking in the field to meet us?” The servant said, “It is my master.” She took her veil, and covered herself.', pt: 'e perguntou ao servo: Quem é aquele homem que vem pelo campo ao nosso encontro? respondeu o servo: É meu senhor. Então ela tomou o véu e se cobriu.' },
      { v: 66, en: 'The servant told Isaac all the things that he had done.', pt: 'Depois o servo contou a Isaque tudo o que fizera.' },
      { v: 67, en: 'Isaac brought her into his mother Sarah’s tent, and took Rebekah, and she became his wife. He loved her. Isaac was comforted after his mother’s death.', pt: 'Isaque, pois, trouxe Rebeca para a tenda de Sara, sua mãe; tomou-a e ela lhe foi por mulher; e ele a amou. Assim Isaque foi consolado depois da morte de sua mãe.' },
    ],
    25: [
      { v: 1, en: 'Abraham took another wife, and her name was Keturah.', pt: 'Ora, Abraão tomou outra mulher, que se chamava Quetura.' },
      { v: 2, en: 'She bore him Zimran, Jokshan, Medan, Midian, Ishbak, and Shuah.', pt: 'Ela lhe deu à luz a Zinrã, Jocsã, Medã, Midiã, Isbaque e Suá.' },
      { v: 3, en: 'Jokshan became the father of Sheba, and Dedan. The sons of Dedan were Asshurim, Letushim, and Leummim.', pt: 'Jocsã gerou a Seba e Dedã. Os filhos de Dedã foram Assurim, Letusim e Leumim.' },
      { v: 4, en: 'The sons of Midian were: Ephah, Epher, Hanoch, Abida, and Eldaah. All these were the children of Keturah.', pt: 'Os filhos de Midiã foram Efá, Efer, Hanoque, Abidá e Eldá; todos estes foram filhos de Quetura.' },
      { v: 5, en: 'Abraham gave all that he had to Isaac,', pt: 'Abraão, porém, deu tudo quanto possuía a Isaque;' },
      { v: 6, en: 'but to the sons of Abraham’s concubines, Abraham gave gifts. He sent them away from Isaac his son, while he yet lived, eastward, to the east country.', pt: 'no entanto aos filhos das concubinas que Abraão tinha, deu ele dádivas; e, ainda em vida, os separou de seu filho Isaque, enviando-os ao Oriente, para a terra oriental.' },
      { v: 7, en: 'These are the days of the years of Abraham’s life which he lived: one hundred seventy-five years.', pt: 'Estes, pois, são os dias dos anos da vida de Abraão, que ele viveu: cento e setenta e, cinco anos.' },
      { v: 8, en: 'Abraham gave up his spirit, and died in a good old age, an old man, and full of years, and was gathered to his people.', pt: 'E Abraão expirou, morrendo em boa velhice, velho e cheio de dias; e foi congregado ao seu povo.' },
      { v: 9, en: 'Isaac and Ishmael, his sons, buried him in the cave of Machpelah, in the field of Ephron, the son of Zohar the Hittite, which is before Mamre,', pt: 'Então Isaque e Ismael, seus filhos, o sepultaram na cova de Macpela, no campo de Efrom, filho de Zoar, o heteu, que estava em frente de Manre,' },
      { v: 10, en: 'the field which Abraham purchased of the children of Heth. Abraham was buried there with Sarah, his wife.', pt: 'o campo que Abraão comprara aos filhos de Hete. Ali foi sepultado Abraão, e Sara, sua mulher.' },
      { v: 11, en: 'After the death of Abraham, God blessed Isaac, his son. Isaac lived by Beer Lahai Roi.', pt: 'Depois da morte de Abraão, Deus abençoou a Isaque, seu filho; e habitava Isaque junto a Beer-Laai-Rói.' },
      { v: 12, en: 'Now this is the history of the generations of Ishmael, Abraham’s son, whom Hagar the Egyptian, Sarah’s servant, bore to Abraham.', pt: 'Estas são as gerações de Ismael, filho de Abraão, que Agar, a egípcia, serva de Sara, lhe deu;' },
      { v: 13, en: 'These are the names of the sons of Ishmael, by their names, according to the order of their birth: the firstborn of Ishmael, Nebaioth, then Kedar, Adbeel, Mibsam,', pt: 'e estes são os nomes dos filhos de Ismael pela sua ordem, segundo as suas gerações: o primogênito de Ismael era Nebaiote, depois Quedar, Abdeel, Mibsão,' },
      { v: 14, en: 'Mishma, Dumah, Massa,', pt: 'Misma, Dumá, Massá,' },
      { v: 15, en: 'Hadad, Tema, Jetur, Naphish, and Kedemah.', pt: 'Hadade, Tema, Jetur, Nafis e Quedemá.' },
      { v: 16, en: 'These are the sons of Ishmael, and these are their names, by their villages, and by their encampments: twelve princes, according to their nations.', pt: 'Estes são os filhos de Ismael, e estes são os seus nomes pelas suas vilas e pelos seus acampamentos: doze príncipes segundo as suas tribos.' },
      { v: 17, en: 'These are the years of the life of Ishmael: one hundred thirty-seven years. He gave up his spirit and died, and was gathered to his people.', pt: 'E estes são os anos da vida de Ismael, cento e trinta e sete anos; e ele expirou e, morrendo, foi cogregado ao seu povo.' },
      { v: 18, en: 'They lived from Havilah to Shur that is before Egypt, as you go toward Assyria. He lived opposite all his relatives.', pt: 'Eles então habitaram desde Havilá até Sur, que está em frente do Egito, como quem vai em direção da Assíria; assim Ismael se estabeleceu diante da face de todos os seus irmãos.' },
      { v: 19, en: 'This is the history of the generations of Isaac, Abraham’s son. Abraham became the father of Isaac.', pt: 'E estas são as gerações de Isaque, filho de Abraão: Abraão gerou a Isaque;' },
      { v: 20, en: 'Isaac was forty years old when he took Rebekah, the daughter of Bethuel the Syrian of Paddan Aram, the sister of Laban the Syrian, to be his wife.', pt: 'e Isaque tinha quarenta anos quando tomou por mulher a Rebeca, filha de Betuel, arameu de Padã-Arã, e irmã de Labão, arameu.' },
      { v: 21, en: 'Isaac entreated Yahweh for his wife, because she was barren. Yahweh was entreated by him, and Rebekah his wife conceived.', pt: 'Ora, Isaque orou insistentemente ao Senhor por sua mulher, porquanto ela era estéril; e o Senhor ouviu as suas orações, e Rebeca, sua mulher, concebeu.' },
      { v: 22, en: 'The children struggled together within her. She said, “If it is so, why do I live?” She went to inquire of Yahweh.', pt: 'E os filhos lutavam no ventre dela; então ela disse: Por que estou eu assim? E foi consultar ao Senhor.' },
      { v: 23, en: 'Yahweh said to her, “Two nations are in your womb. Two peoples will be separated from your body. The one people will be stronger than the other people. The elder will serve the younger.”', pt: 'Respondeu-lhe o Senhor: Duas nações há no teu ventre, e dois povos se dividirão das tuas estranhas, e um povo será mais forte do que o outro povo, e o mais velho servirá ao mais moço.' },
      { v: 24, en: 'When her days to be delivered were fulfilled, behold, there were twins in her womb.', pt: 'Cumpridos que foram os dias para ela dar à luz, eis que havia gêmeos no seu ventre.' },
      { v: 25, en: 'The first came out red all over, like a hairy garment. They named him Esau.', pt: 'Saiu o primeiro, ruivo, todo ele como um vestido de pelo; e chamaram-lhe Esaú.' },
      { v: 26, en: 'After that, his brother came out, and his hand had hold on Esau’s heel. He was named Jacob. Isaac was sixty years old when she bore them.', pt: 'Depois saiu o seu irmão, agarrada sua mão ao calcanhar de Esaú; pelo que foi chamado Jacó. E Isaque tinha sessenta anos quando Rebeca os deu à luz.' },
      { v: 27, en: 'The boys grew. Esau was a skillful hunter, a man of the field. Jacob was a quiet man, living in tents.', pt: 'Cresceram os meninos; e Esaú tornou-se perito caçador, homem do campo; mas Jacó, homem sossegado, que habitava em tendas.' },
      { v: 28, en: 'Now Isaac loved Esau, because he ate his venison. Rebekah loved Jacob.', pt: 'Isaque amava a Esaú, porque comia da sua caça; mas Rebeca amava a Jacó.' },
      { v: 29, en: 'Jacob boiled stew. Esau came in from the field, and he was famished.', pt: 'Jacó havia feito um guisado, quando Esaú chegou do campo, muito cansado;' },
      { v: 30, en: 'Esau said to Jacob, “Please feed me with that same red stew, for I am famished.” Therefore his name was called Edom.', pt: 'e disse Esaú a Jacó: Deixa-me, peço-te, comer desse guisado vermelho, porque estou muito cansado. Por isso se chamou Edom.' },
      { v: 31, en: 'Jacob said, “First, sell me your birthright.”', pt: 'Respondeu Jacó: Vende-me primeiro o teu direito de primogenitura.' },
      { v: 32, en: 'Esau said, “Behold, I am about to die. What good is the birthright to me?”', pt: 'Então replicou Esaú: Eis que estou a ponto e morrer; logo, para que me servirá o direito de primogenitura?' },
      { v: 33, en: 'Jacob said, “Swear to me first.” He swore to him. He sold his birthright to Jacob.', pt: 'Ao que disse Jacó: Jura-me primeiro. Jurou-lhe, pois; e vendeu o seu direito de primogenitura a Jacó.' },
      { v: 34, en: 'Jacob gave Esau bread and stew of lentils. He ate and drank, rose up, and went his way. So Esau despised his birthright.', pt: 'Jacó deu a Esaú pão e o guisado e lentilhas; e ele comeu e bebeu; e, levantando-se, seguiu seu caminho. Assim desprezou Esaú o seu direito de primogenitura.' },
    ],
    26: [
      { v: 1, en: 'There was a famine in the land, besides the first famine that was in the days of Abraham. Isaac went to Abimelech king of the Philistines, to Gerar.', pt: 'Sobreveio à terra uma fome, além da primeira, que ocorreu nos dias de Abraão. Por isso foi Isaque a Abimeleque, rei dos filisteus, em Gerar.' },
      { v: 2, en: 'Yahweh appeared to him, and said, “Don’t go down into Egypt. Live in the land I will tell you about.', pt: 'E apareceu-lhe o Senhor e disse: Não desças ao Egito; habita na terra que eu te disser;' },
      { v: 3, en: 'Live in this land, and I will be with you, and will bless you. For I will give to you, and to your offspring, all these lands, and I will establish the oath which I swore to Abraham your father.', pt: 'peregrina nesta terra, e serei contigo e te abençoarei; porque a ti, e aos que descenderem de ti, darei todas estas terras, e confirmarei o juramento que fiz a Abraão teu pai;' },
      { v: 4, en: 'I will multiply your offspring as the stars of the sky, and will give all these lands to your offspring. In your offspring will all the nations of the earth be blessed,', pt: 'e multiplicarei a tua descendência como as estrelas do céu, e lhe darei todas estas terras; e por meio dela serão benditas todas as naçoes da terra;' },
      { v: 5, en: 'because Abraham obeyed my voice, and kept my requirements, my commandments, my statutes, and my laws.”', pt: 'porquanto Abraão obedeceu à minha voz, e guardou o meu mandado, os meus preceitos, os meus estatutos e as minhas leis.' },
      { v: 6, en: 'Isaac lived in Gerar.', pt: 'Assim habitou Isaque em Gerar.' },
      { v: 7, en: 'The men of the place asked him about his wife. He said, “She is my sister,” for he was afraid to say, “My wife”, lest, he thought, “the men of the place might kill me for Rebekah, because she is beautiful to look at.”', pt: 'Então os homens do lugar perguntaram-lhe acerca de sua mulher, e ele respondeu: É minha irmã; porque temia dizer: É minha mulher; para que porventura, dizia ele, não me matassem os homens daquele lugar por amor de Rebeca; porque era ela formosa à vista.' },
      { v: 8, en: 'When he had been there a long time, Abimelech king of the Philistines looked out at a window, and saw, and, behold, Isaac was caressing Rebekah, his wife.', pt: 'Ora, depois que ele se demorara ali muito tempo, Abimeleque, rei dos filisteus, olhou por uma janela, e viu, e eis que Isaque estava brincando com Rebeca, sua mulher.' },
      { v: 9, en: 'Abimelech called Isaac, and said, “Behold, surely she is your wife. Why did you say, ‘She is my sister?’” Isaac said to him, “Because I said, ‘Lest I die because of her.’”', pt: 'Então chamou Abimeleque a Isaque, e disse: Eis que na verdade é tua mulher; como pois disseste: E minha irmã? Respondeu-lhe Isaque: Porque eu dizia: Para que eu porventura não morra por sua causa.' },
      { v: 10, en: 'Abimelech said, “What is this you have done to us? One of the people might easily have lain with your wife, and you would have brought guilt on us!”', pt: 'Replicou Abimeleque: Que é isso que nos fizeste? Facilmente se teria deitado alguém deste povo com tua mulher, e tu terias trazido culpa sobre nós.' },
      { v: 11, en: 'Abimelech commanded all the people, saying, “He who touches this man or his wife will surely be put to death.”', pt: 'E Abimeleque ordenou a todo o povo, dizendo: Qualquer que tocar neste homem ou em sua mulher, certamente morrerá.' },
      { v: 12, en: 'Isaac sowed in that land, and reaped in the same year one hundred times what he planted. Yahweh blessed him.', pt: 'Isaque semeou naquela terra, e no mesmo ano colheu o cêntuplo; e o Senhor o abençoou.' },
      { v: 13, en: 'The man grew great, and grew more and more until he became very great.', pt: 'E engrandeceu-se o homem; e foi-se enriquecendo até que se tornou mui poderoso;' },
      { v: 14, en: 'He had possessions of flocks, possessions of herds, and a great household. The Philistines envied him.', pt: 'e tinha possessões de rebanhos e de gado, e muita gente de serviço; de modo que os filisteus o invejavam.' },
      { v: 15, en: 'Now all the wells which his father’s servants had dug in the days of Abraham his father, the Philistines had stopped, and filled with earth.', pt: 'Ora, todos os poços, que os servos de seu pai tinham cavado nos dias de seu pai Abraão, os filisteus entulharam e encheram de terra.' },
      { v: 16, en: 'Abimelech said to Isaac, “Go away from us, for you are much mightier than we.”', pt: 'E Abimeleque disse a Isaque: Aparta-te de nós; porque muito mais poderoso te tens feito do que nós.' },
      { v: 17, en: 'Isaac departed from there, encamped in the valley of Gerar, and lived there.', pt: 'Então Isaque partiu dali e, acampando no vale de Gerar, lá habitou.' },
      { v: 18, en: 'Isaac dug again the wells of water, which they had dug in the days of Abraham his father. For the Philistines had stopped them after the death of Abraham. He called their names after the names by which his father had called them.', pt: 'E Isaque tornou a cavar os poços que se haviam cavado nos dias de Abraão seu pai, pois os filisteus os haviam entulhado depois da morte de Abraão; e deu-lhes os nomes que seu pai lhes dera.' },
      { v: 19, en: 'Isaac’s servants dug in the valley, and found there a well of springing water.', pt: 'Cavaram, pois, os servos de Isaque naquele vale, e acharam ali um poço de águas vivas.' },
      { v: 20, en: 'The herdsmen of Gerar argued with Isaac’s herdsmen, saying, “The water is ours.” He called the name of the well Esek, because they contended with him.', pt: 'E os pastores de Gerar contenderam com os pastores de Isaque, dizendo: Esta água é nossa. E ele chamou ao poço Eseque, porque contenderam com ele.' },
      { v: 21, en: 'They dug another well, and they argued over that, also. He called its name Sitnah.', pt: 'Então cavaram outro poço, pelo qual também contenderam; por isso chamou-lhe Sitna.' },
      { v: 22, en: 'He left that place, and dug another well. They didn’t argue over that one. He called it Rehoboth. He said, “For now Yahweh has made room for us, and we will be fruitful in the land.”', pt: 'E partiu dali, e cavou ainda outro poço; por este não contenderam; pelo que chamou-lhe Reobote, dizendo: Pois agora o Senhor nos deu largueza, e havemos de crescer na terra.' },
      { v: 23, en: 'He went up from there to Beersheba.', pt: 'Depois subiu dali a Beer-Seba.' },
      { v: 24, en: 'Yahweh appeared to him the same night, and said, “I am the God of Abraham your father. Don’t be afraid, for I am with you, and will bless you, and multiply your offspring for my servant Abraham’s sake.”', pt: 'E apareceu-lhe o Senhor na mesma noite e disse: Eu sou o Deus de Abraão, teu pai; não temas, porque eu sou contigo, e te abençoarei e multiplicarei a tua descendência por amor do meu servo Abraão.' },
      { v: 25, en: 'He built an altar there, and called on Yahweh’s name, and pitched his tent there. There Isaac’s servants dug a well.', pt: 'Isaque, pois, edificou ali um altar e invocou o nome do Senhor; então armou ali a sua tenda, e os seus servos cavaram um poço.' },
      { v: 26, en: 'Then Abimelech went to him from Gerar, and Ahuzzath his friend, and Phicol the captain of his army.', pt: 'Então Abimeleque veio a ele de Gerar, com Aüzate, seu amigo, e Ficol, o chefe do seu exército.' },
      { v: 27, en: 'Isaac said to them, “Why have you come to me, since you hate me, and have sent me away from you?”', pt: 'E perguntou-lhes Isaque: Por que viestes ter comigo, visto que me odiais, e me repelistes de vós?' },
      { v: 28, en: 'They said, “We saw plainly that Yahweh was with you. We said, ‘Let there now be an oath between us, even between us and you, and let us make a covenant with you,', pt: 'Responderam eles: Temos visto claramente que o Senhor é contigo, pelo que dissemos: Haja agora juramento entre nós, entre nós e ti; e façamos um pacto contigo,' },
      { v: 29, en: 'that you will do us no harm, as we have not touched you, and as we have done to you nothing but good, and have sent you away in peace.’ You are now the blessed of Yahweh.”', pt: 'que não nos farás mal, assim como nós não te havemos tocado, e te fizemos somente o bem, e te deixamos ir em paz. Agora tu és o bendito do Senhor.' },
      { v: 30, en: 'He made them a feast, and they ate and drank.', pt: 'Então Isaque lhes deu um banquete, e comeram e beberam.' },
      { v: 31, en: 'They rose up some time in the morning, and swore an oath to one another. Isaac sent them away, and they departed from him in peace.', pt: 'E levantaram-se de manhã cedo e juraram de parte a parte; depois Isaque os despediu, e eles se despediram dele em paz.' },
      { v: 32, en: 'The same day, Isaac’s servants came, and told him concerning the well which they had dug, and said to him, “We have found water.”', pt: 'Nesse mesmo dia vieram os servos de Isaque e deram-lhe notícias acerca do poço que haviam cavado, dizendo-lhe: Temos achado água.' },
      { v: 33, en: 'He called it Shibah. Therefore the name of the city is Beersheba to this day.', pt: 'E ele chamou o poço Seba; por isso é o nome da cidade Beer-Seba até o dia de hoje.' },
      { v: 34, en: 'When Esau was forty years old, he took as wife Judith, the daughter of Beeri the Hittite, and Basemath, the daughter of Elon the Hittite.', pt: 'Ora, quando Esaú tinha quarenta anos, tomou por mulher a Judite, filha de Beeri, o heteu e a Basemate, filha de Elom, o heteu.' },
      { v: 35, en: 'They grieved Isaac’s and Rebekah’s spirits.', pt: 'E estas foram para Isaque e Rebeca uma amargura de espírito.' },
    ],
    27: [
      { v: 1, en: 'When Isaac was old, and his eyes were dim, so that he could not see, he called Esau his elder son, and said to him, “My son?” He said to him, “Here I am.”', pt: 'Quando Isaque já estava velho, e se lhe enfraqueciam os olhos, de maneira que não podia ver, chamou a Esaú, seu filho mais velho, e disse-lhe: Meu filho! Ele lhe respondeu: Eis-me aqui!' },
      { v: 2, en: 'He said, “See now, I am old. I don’t know the day of my death.', pt: 'Disse-lhe o pai: Eis que agora estou velho, e não sei o dia da minha morte;' },
      { v: 3, en: 'Now therefore, please take your weapons, your quiver and your bow, and go out to the field, and take me venison.', pt: 'toma, pois, as tuas armas, a tua aljava e o teu arco; e sai ao campo, e apanha para mim alguma caça;' },
      { v: 4, en: 'Make me savory food, such as I love, and bring it to me, that I may eat, and that my soul may bless you before I die.”', pt: 'e faze-me um guisado saboroso, como eu gosto, e traze-mo, para que eu coma; a fim de que a minha alma te abençoe, antes que morra.' },
      { v: 5, en: 'Rebekah heard when Isaac spoke to Esau his son. Esau went to the field to hunt for venison, and to bring it.', pt: 'Ora, Rebeca estava escutando quando Isaque falou a Esaú, seu filho. Saiu, pois, Esaú ao campo para apanhar caça e trazê-la.' },
      { v: 6, en: 'Rebekah spoke to Jacob her son, saying, “Behold, I heard your father speak to Esau your brother, saying,', pt: 'Disse então Rebeca a Jacó, seu filho: Eis que ouvi teu pai falar com Esaú, teu irmão, dizendo:' },
      { v: 7, en: '‘Bring me venison, and make me savory food, that I may eat, and bless you before Yahweh before my death.’', pt: 'Traze-me caça, e faze-me um guisado saboroso, para que eu coma, e te abençoe diante do Senhor, antes da minha morte.' },
      { v: 8, en: 'Now therefore, my son, obey my voice according to that which I command you.', pt: 'Agora, pois, filho meu, ouve a minha voz naquilo que eu te ordeno:' },
      { v: 9, en: 'Go now to the flock and get me two good young goats from there. I will make them savory food for your father, such as he loves.', pt: 'Vai ao rebanho, e traze-me de lá das cabras dois bons cabritos; e eu farei um guisado saboroso para teu pai, como ele gosta;' },
      { v: 10, en: 'You shall bring it to your father, that he may eat, so that he may bless you before his death.”', pt: 'e levá-lo-ás a teu pai, para que o coma, a fim de te abençoar antes da sua morte.' },
      { v: 11, en: 'Jacob said to Rebekah his mother, “Behold, Esau my brother is a hairy man, and I am a smooth man.', pt: 'Respondeu, porém, Jacó a Rebeca, sua mãe: Eis que Esaú, meu irmão, é peludo, e eu sou liso.' },
      { v: 12, en: 'What if my father touches me? I will seem to him as a deceiver, and I would bring a curse on myself, and not a blessing.”', pt: 'Porventura meu pai me apalpará e serei a seus olhos como enganador; assim trarei sobre mim uma maldição, e não uma bênção.' },
      { v: 13, en: 'His mother said to him, “Let your curse be on me, my son. Only obey my voice, and go get them for me.”', pt: 'Respondeu-lhe sua mãe: Meu filho, sobre mim caia essa maldição; somente obedece à minha voz, e vai trazer-mos.' },
      { v: 14, en: 'He went, and got them, and brought them to his mother. His mother made savory food, such as his father loved.', pt: 'Então ele foi, tomou-os e os trouxe a sua mãe, que fez um guisado saboroso como seu pai gostava.' },
      { v: 15, en: 'Rebekah took the good clothes of Esau, her elder son, which were with her in the house, and put them on Jacob, her younger son.', pt: 'Depois Rebeca tomou as melhores vestes de Esaú, seu filho mais velho, que tinha consigo em casa, e vestiu a Jacó, seu filho mais moço;' },
      { v: 16, en: 'She put the skins of the young goats on his hands, and on the smooth of his neck.', pt: 'com as peles dos cabritos cobriu-lhe as mãos e a lisura do pescoço;' },
      { v: 17, en: 'She gave the savory food and the bread, which she had prepared, into the hand of her son Jacob.', pt: 'e pôs o guisado saboroso e o pão que tinha preparado, na mão de Jacó, seu filho.' },
      { v: 18, en: 'He came to his father, and said, “My father?” He said, “Here I am. Who are you, my son?”', pt: 'E veio Jacó a seu pai, e chamou: Meu pai! E ele disse: Eis-me aqui; quem és tu, meu filho?' },
      { v: 19, en: 'Jacob said to his father, “I am Esau your firstborn. I have done what you asked me to do. Please arise, sit and eat of my venison, that your soul may bless me.”', pt: 'Respondeu Jacó a seu pai: Eu sou Esaú, teu primogênito; tenho feito como me disseste; levanta-te, pois, senta-te e come da minha caça, para que a tua alma me abençoe.' },
      { v: 20, en: 'Isaac said to his son, “How is it that you have found it so quickly, my son?” He said, “Because Yahweh your God gave me success.”', pt: 'Perguntou Isaque a seu filho: Como é que tão depressa a achaste, filho meu? Respondeu ele: Porque o Senhor, teu Deus, a mandou ao meu encontro.' },
      { v: 21, en: 'Isaac said to Jacob, “Please come near, that I may feel you, my son, whether you are really my son Esau or not.”', pt: 'Então disse Isaque a Jacó: Chega-te, pois, para que eu te apalpe e veja se és meu filho Esaú mesmo, ou não.' },
      { v: 22, en: 'Jacob went near to Isaac his father. He felt him, and said, “The voice is Jacob’s voice, but the hands are the hands of Esau.”', pt: 'chegou-se Jacó a Isaque, seu pai, que o apalpou, e disse: A voz é a voz de Jacó, porém as mãos são as mãos de Esaú.' },
      { v: 23, en: 'He didn’t recognize him, because his hands were hairy, like his brother, Esau’s hands. So he blessed him.', pt: 'E não o reconheceu, porquanto as suas mãos estavam peludas, como as de Esaú seu irmão; e abençoou-o.' },
      { v: 24, en: 'He said, “Are you really my son Esau?” He said, “I am.”', pt: 'No entanto perguntou: Tu és mesmo meu filho Esaú? E ele declarou: Eu o sou.' },
      { v: 25, en: 'He said, “Bring it near to me, and I will eat of my son’s venison, that my soul may bless you.” He brought it near to him, and he ate. He brought him wine, and he drank.', pt: 'Disse-lhe então seu pai: Traze-mo, e comerei da caça de meu filho, para que a minha alma te abençoe: E Jacó lho trouxe, e ele comeu; trouxe-lhe também vinho, e ele bebeu.' },
      { v: 26, en: 'His father Isaac said to him, “Come near now, and kiss me, my son.”', pt: 'Disse-lhe mais Isaque, seu pai: Aproxima-te agora, e beija-me, meu filho.' },
      { v: 27, en: 'He came near, and kissed him. He smelled the smell of his clothing, and blessed him, and said, “Behold, the smell of my son is as the smell of a field which Yahweh has blessed.', pt: 'E ele se aproximou e o beijou; e seu pai, sentindo-lhe o cheiro das vestes o abençoou, e disse: Eis que o cheiro de meu filho é como o cheiro de um campo que o Senhor abençoou.' },
      { v: 28, en: 'God give you of the dew of the sky, of the fatness of the earth, and plenty of grain and new wine.', pt: 'Que Deus te dê do orvalho do céu, e dos lugares férteis da terra, e abundância de trigo e de mosto;' },
      { v: 29, en: 'Let peoples serve you, and nations bow down to you. Be lord over your brothers. Let your mother’s sons bow down to you. Cursed be everyone who curses you. Blessed be everyone who blesses you.”', pt: 'sirvam-te povos, e nações se encurvem a ti; sê senhor de teus irmãos, e os filhos da tua mãe se encurvem a ti; sejam malditos os que te amaldiçoarem, e benditos sejam os que te abençoarem.' },
      { v: 30, en: 'As soon as Isaac had finished blessing Jacob, and Jacob had just gone out from the presence of Isaac his father, Esau his brother came in from his hunting.', pt: 'Tão logo Isaque acabara de abençoar a Jacó, e este saíra da presença de seu pai, chegou da caça Esaú, seu irmão;' },
      { v: 31, en: 'He also made savory food, and brought it to his father. He said to his father, “Let my father arise, and eat of his son’s venison, that your soul may bless me.”', pt: 'e fez também ele um guisado saboroso e, trazendo-o a seu pai, disse-lhe: Levantate, meu pai, e come da caça de teu filho, para que a tua alma me abençoe.' },
      { v: 32, en: 'Isaac his father said to him, “Who are you?” He said, “I am your son, your firstborn, Esau.”', pt: 'Perguntou-lhe Isaque, seu pai: Quem és tu? Respondeu ele: Eu sou teu filho, o teu primogênito, Esaú.' },
      { v: 33, en: 'Isaac trembled violently, and said, “Who, then, is he who has taken venison, and brought it me, and I have eaten of all before you came, and have blessed him? Yes, he will be blessed.”', pt: 'Então estremeceu Isaque de um estremecimento muito grande e disse: Quem, pois, é aquele que apanhou caça e ma trouxe? Eu comi de tudo, antes que tu viesses, e abençoei-o, e ele será bendito.' },
      { v: 34, en: 'When Esau heard the words of his father, he cried with an exceeding great and bitter cry, and said to his father, “Bless me, even me also, my father.”', pt: 'Esaú, ao ouvir as palavras de seu pai, bradou com grande e mui amargo brado, e disse a seu pai: Abençoa-me também a mim, meu pai!' },
      { v: 35, en: 'He said, “Your brother came with deceit, and has taken away your blessing.”', pt: 'Respondeu Isaque: Veio teu irmão e com sutileza tomou a tua bênção.' },
      { v: 36, en: 'He said, “Isn’t he rightly named Jacob? For he has supplanted me these two times. He took away my birthright. See, now he has taken away my blessing.” He said, “Haven’t you reserved a blessing for me?”', pt: 'Disse Esaú: Não se chama ele com razão Jacó, visto que já por duas vezes me enganou? tirou-me o direito de primogenitura, e eis que agora me tirou a bênção. E perguntou: Não reservaste uma bênção para mim?' },
      { v: 37, en: 'Isaac answered Esau, “Behold, I have made him your lord, and all his brothers I have given to him for servants. I have sustained him with grain and new wine. What then will I do for you, my son?”', pt: 'Respondeu Isaque a Esaú: Eis que o tenho posto por senhor sobre ti, e todos os seus irmãos lhe tenho dado por servos; e de trigo e de mosto o tenho fortalecido. Que, pois, poderei eu fazer por ti, meu filho?' },
      { v: 38, en: 'Esau said to his father, “Have you but one blessing, my father? Bless me, even me also, my father.” Esau lifted up his voice, and wept.', pt: 'Disse Esaú a seu pai: Porventura tens uma única bênção, meu pai? Abençoa-me também a mim, meu pai. E levantou Esaú a voz, e chorou.' },
      { v: 39, en: 'Isaac his father answered him, “Behold, of the fatness of the earth will be your dwelling, and of the dew of the sky from above.', pt: 'Respondeu-lhe Isaque, seu pai: Longe dos lugares férteis da terra será a tua habitação, longe do orvalho do alto céu;' },
      { v: 40, en: 'By your sword will you live, and you will serve your brother. It will happen, when you will break loose, that you shall shake his yoke from off your neck.”', pt: 'pela tua espada viverás, e a teu irmão, serviras; mas quando te tornares impaciente, então sacudirás o seu jugo do teu pescoço.' },
      { v: 41, en: 'Esau hated Jacob because of the blessing with which his father blessed him. Esau said in his heart, “The days of mourning for my father are at hand. Then I will kill my brother Jacob.”', pt: 'Esaú, pois, odiava a Jacó por causa da bênção com que seu pai o tinha abençoado, e disse consigo: Vêm chegando os dias de luto por meu pai; então hei de matar Jacó, meu irmão.' },
      { v: 42, en: 'The words of Esau, her elder son, were told to Rebekah. She sent and called Jacob, her younger son, and said to him, “Behold, your brother Esau comforts himself about you by planning to kill you.', pt: 'Ora, foram denunciadas a Rebeca estas palavras de Esaú, seu filho mais velho; pelo que ela mandou chamar Jacó, seu filho mais moço, e lhe disse: Eis que Esaú teu irmão se consola a teu respeito, propondo matar-te.' },
      { v: 43, en: 'Now therefore, my son, obey my voice. Arise, flee to Laban, my brother, in Haran.', pt: 'Agora, pois, meu filho, ouve a minha voz; levanta-te, refugia-te na casa de Labão, meu irmão, em Harã,' },
      { v: 44, en: 'Stay with him a few days, until your brother’s fury turns away;', pt: 'e demora-te com ele alguns dias, até que passe o furor de teu irmão;' },
      { v: 45, en: 'until your brother’s anger turn away from you, and he forgets what you have done to him. Then I will send, and get you from there. Why should I be bereaved of you both in one day?”', pt: 'até que se desvie de ti a ira de teu irmão, e ele se esqueça do que lhe fizeste; então mandarei trazer-te de lá; por que seria eu desfilhada de vós ambos num só dia?' },
      { v: 46, en: 'Rebekah said to Isaac, “I am weary of my life because of the daughters of Heth. If Jacob takes a wife of the daughters of Heth, such as these, of the daughters of the land, what good will my life do me?”', pt: 'E disse Rebeca a Isaque: Enfadada estou da minha vida, por causa das filhas de Hete; se Jacó tomar mulher dentre as filhas de Hete, tais como estas, dentre as filhas desta terra, para que viverei?' },
    ],
    28: [
      { v: 1, en: 'Isaac called Jacob, blessed him, and commanded him, “You shall not take a wife of the daughters of Canaan.', pt: 'Isaque, pois, chamou Jacó, e o abençoou, e ordenou-lhe, dizendo: Não tomes mulher dentre as filhas de Canaã.' },
      { v: 2, en: 'Arise, go to Paddan Aram, to the house of Bethuel your mother’s father. Take a wife from there from the daughters of Laban, your mother’s brother.', pt: 'Levanta-te, vai a Padã-Arã, à casa de Betuel, pai de tua mãe, e toma de lá uma mulher dentre as filhas de Labão, irmão de tua mãe.' },
      { v: 3, en: 'May God Almighty bless you, and make you fruitful, and multiply you, that you may be a company of peoples,', pt: 'Deus Todo-Poderoso te abençoe, te faça frutificar e te multiplique, para que venhas a ser uma multidão de povos; seu' },
      { v: 4, en: 'and give you the blessing of Abraham, to you, and to your offspring with you, that you may inherit the land where you travel, which God gave to Abraham.”', pt: 'e te dê a bênção de Abraão, a ti e à tua descendência contigo, para que herdes a terra de tuas peregrinaçoes, que Deus deu a Abraão.' },
      { v: 5, en: 'Isaac sent Jacob away. He went to Paddan Aram to Laban, son of Bethuel the Syrian, Rebekah’s brother, Jacob’s and Esau’s mother.', pt: 'Assim despediu Isaque a Jacó, o qual foi a Padã-Arã, a Labão, filho de Betuel, arameu, irmão de Rebeca, mãe de Jacó e de Esaú.' },
      { v: 6, en: 'Now Esau saw that Isaac had blessed Jacob and sent him away to Paddan Aram, to take him a wife from there, and that as he blessed him he gave him a command, saying, “You shall not take a wife of the daughters of Canaan,”', pt: 'Ora, viu Esaú que Isaque abençoara a Jacó, e o enviara a Padã-Arã, para tomar de lá mulher para si, e que, abençoando-o, lhe ordenara, dizendo: Não tomes mulher dentre as filhas de Canaã,' },
      { v: 7, en: 'and that Jacob obeyed his father and his mother, and was gone to Paddan Aram.', pt: 'e que Jacó, obedecendo a seu pai e a sua mãe, fora a Padã- Arã;' },
      { v: 8, en: 'Esau saw that the daughters of Canaan didn’t please Isaac, his father.', pt: 'vendo também Esaú que as filhas de Canaã eram más aos olhos de Isaque seu pai,' },
      { v: 9, en: 'Esau went to Ishmael, and took, besides the wives that he had, Mahalath the daughter of Ishmael, Abraham’s son, the sister of Nebaioth, to be his wife.', pt: 'foi-se Esaú a Ismael e, além das mulheres que já tinha, tomou por mulher a Maalate, filha de Ismael, filho de Abraão, irmã de Nebaiote.' },
      { v: 10, en: 'Jacob went out from Beersheba, and went toward Haran.', pt: 'Partiu, pois, Jacó de Beer-Seba e se foi em direção a Harã;' },
      { v: 11, en: 'He came to a certain place, and stayed there all night, because the sun had set. He took one of the stones of the place, and put it under his head, and lay down in that place to sleep.', pt: 'e chegou a um lugar onde passou a noite, porque o sol já se havia posto; e, tomando uma das pedras do lugar e pondo-a debaixo da cabeça, deitou-se ali para dormir.' },
      { v: 12, en: 'He dreamed. Behold, a stairway set upon the earth, and its top reached to heaven. Behold, the angels of God ascending and descending on it.', pt: 'Então sonhou: estava posta sobre a terra uma escada, cujo topo chegava ao céu; e eis que os anjos de Deus subiam e desciam por ela;' },
      { v: 13, en: 'Behold, Yahweh stood above it, and said, “I am Yahweh, the God of Abraham your father, and the God of Isaac. The land whereon you lie, to you will I give it, and to your offspring .', pt: 'por cima dela estava o Senhor, que disse: Eu sou o Senhor, o Deus de Abraão teu pai, e o Deus de Isaque; esta terra em que estás deitado, eu a darei a ti e à tua descendência;' },
      { v: 14, en: 'Your offspring will be as the dust of the earth, and you will spread abroad to the west, and to the east, and to the north, and to the south. In you and in your offspring will all the families of the earth be blessed.', pt: 'e a tua descendência será como o pó da terra; dilatar-te-ás para o ocidente, para o oriente, para o norte e para o sul; por meio de ti e da tua descendência serão benditas todas as famílias da terra.' },
      { v: 15, en: 'Behold, I am with you, and will keep you, wherever you go, and will bring you again into this land. For I will not leave you, until I have done that which I have spoken of to you.”', pt: 'Eis que estou contigo, e te guardarei por onde quer que fores, e te farei tornar a esta terra; pois não te deixarei até que haja cumprido aquilo de que te tenho falado.' },
      { v: 16, en: 'Jacob awakened out of his sleep, and he said, “Surely Yahweh is in this place, and I didn’t know it.”', pt: 'Ao acordar Jacó do seu sono, disse: Realmente o Senhor está neste lugar; e eu não o sabia.' },
      { v: 17, en: 'He was afraid, and said, “How dreadful is this place! This is none other than God’s house, and this is the gate of heaven.”', pt: 'E temeu, e disse: Quão terrível é este lugar! Este não é outro lugar senão a casa de Deus; e esta é a porta dos céus.' },
      { v: 18, en: 'Jacob rose up early in the morning, and took the stone that he had put under his head, and set it up for a pillar, and poured oil on its top.', pt: 'Jacó levantou-se de manhã cedo, tomou a pedra que pusera debaixo da cabeça, e a pôs como coluna; e derramou-lhe azeite em cima.' },
      { v: 19, en: 'He called the name of that place Bethel, but the name of the city was Luz at the first.', pt: 'E chamou aquele lugar Betel; porém o nome da cidade antes era Luz.' },
      { v: 20, en: 'Jacob vowed a vow, saying, “If God will be with me, and will keep me in this way that I go, and will give me bread to eat, and clothing to put on,', pt: 'Fez também Jacó um voto, dizendo: Se Deus for comigo e me guardar neste caminho que vou seguindo, e me der pão para comer e vestes para vestir,' },
      { v: 21, en: 'so that I come again to my father’s house in peace, and Yahweh will be my God,', pt: 'de modo que eu volte em paz à casa de meu pai, e se o Senhor for o meu Deus,' },
      { v: 22, en: 'then this stone, which I have set up for a pillar, will be God’s house. Of all that you will give me I will surely give a tenth to you.”', pt: 'então esta pedra que tenho posto como coluna será casa de Deus; e de tudo quanto me deres, certamente te darei o dízimo.' },
    ],
    29: [
      { v: 1, en: 'Then Jacob went on his journey, and came to the land of the children of the east.', pt: 'Então pôs-se Jacó a caminho e chegou à terra dos filhos do Oriente.' },
      { v: 2, en: 'He looked, and behold, a well in the field, and, behold, three flocks of sheep lying there by it. For out of that well they watered the flocks. The stone on the well’s mouth was large.', pt: 'E olhando, viu ali um poço no campo, e três rebanhos de ovelhas deitadas junto dele; pois desse poço se dava de beber aos rebanhos; e havia uma grande pedra sobre a boca do poço.' },
      { v: 3, en: 'There all the flocks were gathered. They rolled the stone from the well’s mouth, and watered the sheep, and put the stone again on the well’s mouth in its place.', pt: 'Ajuntavam-se ali todos os rebanhos; os pastores removiam a pedra da boca do poço, davam de beber às ovelhas e tornavam a pôr a pedra no seu lugar sobre a boca do poço.' },
      { v: 4, en: 'Jacob said to them, “My relatives, where are you from?” They said, “We are from Haran.”', pt: 'Perguntou-lhes Jacó: Meus irmãos, donde sois? Responderam eles: Somos de Harã.' },
      { v: 5, en: 'He said to them, “Do you know Laban, the son of Nahor?” They said, “We know him.”', pt: 'Perguntou-lhes mais: Conheceis a Labão, filho de Naor; Responderam: Conhecemos.' },
      { v: 6, en: 'He said to them, “Is it well with him?” They said, “It is well. See, Rachel, his daughter, is coming with the sheep.”', pt: 'Perguntou-lhes ainda: vai ele bem? Responderam: Vai bem; e eis ali Raquel, sua filha, que vem chegando com as ovelhas.' },
      { v: 7, en: 'He said, “Behold, it is still the middle of the day, not time to gather the livestock together. Water the sheep, and go and feed them.”', pt: 'Disse ele: Eis que ainda vai alto o dia; não é hora de se ajuntar o gado; dai de beber às ovelhas, e ide apascentá-las.' },
      { v: 8, en: 'They said, “We can’t, until all the flocks are gathered together, and they roll the stone from the well’s mouth. Then we water the sheep.”', pt: 'Responderam: Não podemos, até que todos os rebanhos se ajuntem, e seja removida a pedra da boca do poço; assim é que damos de beber às ovelhas.' },
      { v: 9, en: 'While he was yet speaking with them, Rachel came with her father’s sheep, for she kept them.', pt: 'Enquanto Jacó ainda lhes falava, chegou Raquel com as ovelhas de seu pai; porquanto era ela quem as apascentava.' },
      { v: 10, en: 'When Jacob saw Rachel the daughter of Laban, his mother’s brother, and the sheep of Laban, his mother’s brother, Jacob went near, and rolled the stone from the well’s mouth, and watered the flock of Laban his mother’s brother.', pt: 'Quando Jacó viu a Raquel, filha de Labão, irmão de sua mãe, e as ovelhas de Labão, irmão de sua mãe, chegou-se, revolveu a pedra da boca do poço e deu de beber às ovelhas de Labão, irmão de sua mãe.' },
      { v: 11, en: 'Jacob kissed Rachel, and lifted up his voice, and wept.', pt: 'Então Jacó beijou a Raquel e, levantando a voz, chorou.' },
      { v: 12, en: 'Jacob told Rachel that he was her father’s brother, and that he was Rebekah’s son. She ran and told her father.', pt: 'E Jacó anunciou a Raquel que ele era irmão de seu pai, e que era filho de Rebeca. Raquel, pois foi correndo para anunciá-lo a, seu pai.' },
      { v: 13, en: 'When Laban heard the news of Jacob, his sister’s son, he ran to meet Jacob, and embraced him, and kissed him, and brought him to his house. Jacob told Laban all these things.', pt: 'Quando Labão ouviu essas novas de Jacó, filho de sua irmã, correu-lhe ao encontro, abraçou-o, beijou-o e o levou à sua casa. E Jacó relatou a Labão todas essas, coisas.' },
      { v: 14, en: 'Laban said to him, “Surely you are my bone and my flesh.” He stayed with him for a month.', pt: 'Disse-lhe Labão: Verdadeiramente tu és meu osso e minha carne. E Jacó ficou com ele um mês inteiro.' },
      { v: 15, en: 'Laban said to Jacob, “Because you are my brother, should you therefore serve me for nothing? Tell me, what will your wages be?”', pt: 'Depois perguntou Labão a Jacó: Por seres meu irmão hás de servir-me de graça? Declara-me, qual será o teu salário?' },
      { v: 16, en: 'Laban had two daughters. The name of the elder was Leah, and the name of the younger was Rachel.', pt: 'Ora, Labão tinha duas filhas; o nome da mais velha era Léia, e o da mais moça Raquel.' },
      { v: 17, en: 'Leah’s eyes were weak, but Rachel was beautiful in form and attractive.', pt: 'Léia tinha os olhos enfermos, enquanto que Raquel era formosa de porte e de semblante.' },
      { v: 18, en: 'Jacob loved Rachel. He said, “I will serve you seven years for Rachel, your younger daughter.”', pt: 'Jacó, porquanto amava a Raquel, disse: Sete anos te servirei para ter a Raquel, tua filha mais moça.' },
      { v: 19, en: 'Laban said, “It is better that I give her to you, than that I should give her to another man. Stay with me.”', pt: 'Respondeu Labão: Melhor é que eu a dê a ti do que a outro; fica comigo.' },
      { v: 20, en: 'Jacob served seven years for Rachel. They seemed to him but a few days, for the love he had for her.', pt: 'Assim serviu Jacó sete anos por causa de Raquel; e estes lhe pareciam como poucos dias, pelo muito que a amava.' },
      { v: 21, en: 'Jacob said to Laban, “Give me my wife, for my days are fulfilled, that I may go in to her.”', pt: 'Então Jacó disse a Labão: Dá-me minha mulher, porque o tempo já está cumprido; para que eu a tome por mulher.' },
      { v: 22, en: 'Laban gathered together all the men of the place, and made a feast.', pt: 'Reuniu, pois, Labão todos os homens do lugar, e fez um banquete.' },
      { v: 23, en: 'In the evening, he took Leah his daughter, and brought her to him. He went in to her.', pt: 'Â tarde tomou a Léia, sua filha e a trouxe a Jacó, que esteve com ela.' },
      { v: 24, en: 'Laban gave Zilpah his servant to his daughter Leah for a servant.', pt: 'E Labão deu sua serva Zilpa por serva a Léia, sua filha.' },
      { v: 25, en: 'In the morning, behold, it was Leah! He said to Laban, “What is this you have done to me? Didn’t I serve with you for Rachel? Why then have you deceived me?”', pt: 'Quando amanheceu, eis que era Léia; pelo que perguntou Jacó a Labão: Que é isto que me fizeste? Porventura não te servi em troca de Raquel? Por que, então, me enganaste?' },
      { v: 26, en: 'Laban said, “It is not done so in our place, to give the younger before the firstborn.', pt: 'Respondeu Labão: Não se faz assim em nossa terra; não se dá a menor antes da primogênita.' },
      { v: 27, en: 'Fulfill the week of this one, and we will give you the other also for the service which you will serve with me yet seven other years.”', pt: 'Cumpre a semana desta; então te daremos também a outra, pelo trabalho de outros sete anos que ainda me servirás.' },
      { v: 28, en: 'Jacob did so, and fulfilled her week. He gave him Rachel his daughter as wife.', pt: 'Assim fez Jacó, e cumpriu a semana de Léia; depois Labão lhe deu por mulher sua filha Raquel.' },
      { v: 29, en: 'Laban gave to Rachel his daughter Bilhah, his servant, to be her servant.', pt: 'E Labão deu sua serva Bila por serva a Raquel, sua filha.' },
      { v: 30, en: 'He went in also to Rachel, and he loved also Rachel more than Leah, and served with him yet seven other years.', pt: 'Então Jacó esteve também com Raquel; e amou a Raquel muito mais do que a Léia; e serviu com Labão ainda outros sete anos.' },
      { v: 31, en: 'Yahweh saw that Leah was hated, and he opened her womb, but Rachel was barren.', pt: 'Viu, pois, o Senhor que Léia era desprezada e tornou-lhe fecunda a madre; Raquel, porém, era estéril.' },
      { v: 32, en: 'Leah conceived, and bore a son, and she named him Reuben. For she said, “Because Yahweh has looked at my affliction; for now my husband will love me.”', pt: 'E Léia concebeu e deu à luz um filho, a quem chamou Rúben; pois disse: Porque o Senhor atendeu à minha aflição; agora me amará meu marido.' },
      { v: 33, en: 'She conceived again, and bore a son, and said, “Because Yahweh has heard that I am hated, he has therefore given me this son also.” She named him Simeon.', pt: 'Concebeu outra vez, e deu à luz um filho; e disse: Porquanto o Senhor ouviu que eu era desprezada, deu-me também este. E lhe chamou Simeão.' },
      { v: 34, en: 'She conceived again, and bore a son. Said, “Now this time will my husband be joined to me, because I have borne him three sons.” Therefore his name was called Levi.', pt: 'Concebeu ainda outra vez e deu à luz um filho e disse: Agora esta vez se unirá meu marido a mim, porque três filhos lhe tenho dado. Portanto lhe chamou Levi.' },
      { v: 35, en: 'She conceived again, and bore a son. She said, “This time will I praise Yahweh.” Therefore she named him Judah. Then she stopped bearing.', pt: 'De novo concebeu e deu à luz um filho; e disse: Esta vez louvarei ao Senhor. Por isso lhe chamou Judá. E cessou de ter filhos.' },
    ],
    30: [
      { v: 1, en: 'When Rachel saw that she bore Jacob no children, Rachel envied her sister. She said to Jacob, “Give me children, or else I will die.”', pt: 'Vendo Raquel que não dava filhos a Jacó, teve inveja de sua irmã, e disse a Jacó: Dá-me filhos, senão eu morro.' },
      { v: 2, en: 'Jacob’s anger burned against Rachel, and he said, “Am I in God’s place, who has withheld from you the fruit of the womb?”', pt: 'Então se acendeu a ira de Jacó contra Raquel; e disse: Porventura estou eu no lugar de Deus que te impediu o fruto do ventre?' },
      { v: 3, en: 'She said, “Behold, my maid Bilhah. Go in to her, that she may bear on my knees, and I also may obtain children by her.”', pt: 'Respondeu ela: Eis aqui minha serva Bila; recebe-a por mulher, para que ela dê à luz sobre os meus joelhos, e eu deste modo tenha filhos por ela.' },
      { v: 4, en: 'She gave him Bilhah her servant as wife, and Jacob went in to her.', pt: 'Assim lhe deu a Bila, sua serva, por mulher; e Jacó a conheceu.' },
      { v: 5, en: 'Bilhah conceived, and bore Jacob a son.', pt: 'Bila concebeu e deu à luz um filho a Jacó.' },
      { v: 6, en: 'Rachel said, “God has judged me, and has also heard my voice, and has given me a son.” Therefore called she his name Dan.', pt: 'Então disse Raquel: Julgou-me Deus; ouviu a minha voz e me deu um filho; pelo que lhe chamou Dã.' },
      { v: 7, en: 'Bilhah, Rachel’s servant, conceived again, and bore Jacob a second son.', pt: 'E Bila, serva de Raquel, concebeu outra vez e deu à luz um segundo filho a Jacó.' },
      { v: 8, en: 'Rachel said, “I have wrestled with my sister with mighty wrestlings, and have prevailed.” She named him Naphtali.', pt: 'Então disse Raquel: Com grandes lutas tenho lutado com minha irmã, e tenho vencido; e chamou-lhe Naftali.' },
      { v: 9, en: 'When Leah saw that she had finished bearing, she took Zilpah, her servant, and gave her to Jacob as a wife.', pt: 'Também Léia, vendo que cessara de ter filhos, tomou a Zilpa, sua serva, e a deu a Jacó por mulher.' },
      { v: 10, en: 'Zilpah, Leah’s servant, bore Jacob a son.', pt: 'E Zilpa, serva de Léia, deu à luz um filho a Jacó.' },
      { v: 11, en: 'Leah said, “How fortunate!” She named him Gad.', pt: 'Então disse Léia: Afortunada! e chamou-lhe Gade.' },
      { v: 12, en: 'Zilpah, Leah’s servant, bore Jacob a second son.', pt: 'Depois Zilpa, serva de Léia, deu à luz um segundo filho a Jacó.' },
      { v: 13, en: 'Leah said, “Happy am I, for the daughters will call me happy.” She named him Asher.', pt: 'Então disse Léia: Feliz sou eu! porque as filhas me chamarão feliz; e chamou-lhe Aser.' },
      { v: 14, en: 'Reuben went in the days of wheat harvest, and found mandrakes in the field, and brought them to his mother, Leah. Then Rachel said to Leah, “Please give me some of your son’s mandrakes.”', pt: 'Ora, saiu Rúben nos dias da ceifa do trigo e achou mandrágoras no campo, e as trouxe a Léia, sua mãe. Então disse Raquel a Léia: Dá-me, peço, das mandrágoras de teu filho.' },
      { v: 15, en: 'She said to her, “Is it a small matter that you have taken away my husband? Would you take away my son’s mandrakes, also?” Rachel said, “Therefore he will lie with you tonight for your son’s mandrakes.”', pt: 'Ao que lhe respondeu Léia: É já pouco que me hajas tirado meu marido? queres tirar também as mandrágoras de meu filho? Prosseguiu Raquel: Por isso ele se deitará contigo esta noite pelas mandrágoras de teu filho.' },
      { v: 16, en: 'Jacob came from the field in the evening, and Leah went out to meet him, and said, “You must come in to me; for I have surely hired you with my son’s mandrakes.” He lay with her that night.', pt: 'Quando, pois, Jacó veio à tarde do campo, saiu-lhe Léia ao encontro e disse: Hás de estar comigo, porque certamente te aluguei pelas mandrágoras de meu filho. E com ela deitou-se Jacó aquela noite.' },
      { v: 17, en: 'God listened to Leah, and she conceived, and bore Jacob a fifth son.', pt: 'E ouviu Deus a Léia, e ela concebeu e deu a Jacó um quinto filho.' },
      { v: 18, en: 'Leah said, “God has given me my hire, because I gave my servant to my husband.” She named him Issachar.', pt: 'Então disse Léia: Deus me tem dado o meu galardão, porquanto dei minha serva a meu marido. E chamou ao filho Issacar.' },
      { v: 19, en: 'Leah conceived again, and bore a sixth son to Jacob.', pt: 'Concebendo Léia outra vez, deu a Jacó um sexto filho;' },
      { v: 20, en: 'Leah said, “God has endowed me with a good dowry. Now my husband will live with me, because I have borne him six sons.” She named him Zebulun.', pt: 'e disse: Deus me deu um excelente dote; agora morará comigo meu marido, porque lhe tenho dado seis filhos. E chamou-lhe Zebulom.' },
      { v: 21, en: 'Afterwards, she bore a daughter, and named her Dinah.', pt: 'Depois. disto deu à luz uma filha, e chamou-lhe Diná.' },
      { v: 22, en: 'God remembered Rachel, and God listened to her, and opened her womb.', pt: 'Também lembrou-se Deus de Raquel, ouviu-a e a tornou fecunda.' },
      { v: 23, en: 'She conceived, bore a son, and said, “God has taken away my reproach.”', pt: 'De modo que ela concebeu e deu à luz um filho, e disse: Tirou-me Deus o opróbrio.' },
      { v: 24, en: 'She named him Joseph, saying, “May Yahweh add another son to me.”', pt: 'E chamou-lhe José, dizendo: Acrescente-me o Senhor ainda outro filho.' },
      { v: 25, en: 'When Rachel had borne Joseph, Jacob said to Laban, “Send me away, that I may go to my own place, and to my country.', pt: 'Depois que Raquel deu à luz a José, disse Jacó a Labão: Despede-me a fim de que eu vá para meu lugar e para minha terra.' },
      { v: 26, en: 'Give me my wives and my children for whom I have served you, and let me go; for you know my service with which I have served you.”', pt: 'Dá-me as minhas mulheres, e os meus filhos, pelas quais te tenho servido, e deixame ir; pois tu sabes o serviço que te prestei.' },
      { v: 27, en: 'Laban said to him, “If now I have found favor in your eyes, stay here, for I have divined that Yahweh has blessed me for your sake.”', pt: 'Labão lhe respondeu: Se tenho achado graça aos teus olhos, fica comigo; pois tenho percebido que o Senhor me abençoou por amor de ti.' },
      { v: 28, en: 'He said, “Appoint me your wages, and I will give it.”', pt: 'E disse mais: Determina-me o teu salário, que to darei.' },
      { v: 29, en: 'He said to him, “You know how I have served you, and how your livestock have fared with me.', pt: 'Ao que lhe respondeu Jacó: Tu sabes como te hei servido, e como tem passado o teu gado comigo.' },
      { v: 30, en: 'For it was little which you had before I came, and it has increased to a multitude. Yahweh has blessed you wherever I turned. Now when will I provide for my own house also?”', pt: 'Porque o pouco que tinhas antes da minha vinda tem se multiplicado abundantemente; e o Senhor te tem abençoado por onde quer que eu fui. Agora, pois, quando hei de trabalhar também por minha casa?' },
      { v: 31, en: 'He said, “What shall I give you?” Jacob said, “You shall not give me anything. If you will do this thing for me, I will again feed your flock and keep it.', pt: 'Insistiu Labão: Que te darei? Então respondeu Jacó: Não me darás nada; tornarei a apascentar e a guardar o teu rebanho se me fizeres isto:' },
      { v: 32, en: 'I will pass through all your flock today, removing from there every speckled and spotted one, and every black one among the sheep, and the spotted and speckled among the goats. This will be my hire.', pt: 'Passarei hoje por todo o teu rebanho, separando dele todos os salpicados e malhados, e todos os escuros entre as ovelhas, e os malhados e salpicados entre as cabras; e isto será o meu salário.' },
      { v: 33, en: 'So my righteousness will answer for me hereafter, when you come concerning my hire that is before you. Every one that is not speckled and spotted among the goats, and black among the sheep, that might be with me, will be considered stolen.”', pt: 'De modo que responderá por mim a minha justiça no dia de amanhã, quando vieres ver o meu salário assim exposto diante de ti: tudo o que não for salpicado e malhado entre as cabras e escuro entre as ovelhas, esse, se for achado comigo, será tido por furtado.' },
      { v: 34, en: 'Laban said, “Behold, let it be according to your word.”', pt: 'Concordou Labão, dizendo: Seja conforme a tua palavra.' },
      { v: 35, en: 'That day, he removed the male goats that were streaked and spotted, and all the female goats that were speckled and spotted, every one that had white in it, and all the black ones among the sheep, and gave them into the hand of his sons.', pt: 'E separou naquele mesmo dia os bodes listrados e malhados e todas as cabras salpicadas e malhadas, tudo em que havia algum branco, e todos os escuros entre os cordeiros e os deu nas mãos de seus filhos;' },
      { v: 36, en: 'He set three days’ journey between himself and Jacob, and Jacob fed the rest of Laban’s flocks.', pt: 'e pôs três dias de caminho entre si e Jacó; e Jacó apascentava o restante dos rebanhos de Labão.' },
      { v: 37, en: 'Jacob took to himself rods of fresh poplar, almond, plane tree, peeled white streaks in them, and made the white appear which was in the rods.', pt: 'Então tomou Jacó varas verdes de estoraque, de amendoeira e de plátano e, descascando nelas riscas brancas, descobriu o branco que nelas havia;' },
      { v: 38, en: 'He set the rods which he had peeled opposite the flocks in the gutters in the watering-troughs where the flocks came to drink. They conceived when they came to drink.', pt: 'e as varas que descascara pôs em frente dos rebanhos, nos cochos, isto é, nos bebedouros, onde os rebanhos bebiam; e conceberam quando vinham beber.' },
      { v: 39, en: 'The flocks conceived before the rods, and the flocks produced streaked, speckled, and spotted.', pt: 'Os rebanhos concebiam diante das varas, e as ovelhas davam crias listradas, salpicadas e malhadas.' },
      { v: 40, en: 'Jacob separated the lambs, and set the faces of the flocks toward the streaked and all the black in the flock of Laban: and he put his own droves apart, and didn’t put them into Laban’s flock.', pt: 'Então separou Jacó os cordeiros, e fez os rebanhos olhar para os listrados e para todos os escuros no rebanho de Labão; e pôs seu rebanho à parte, e não pôs com o rebanho de Labão.' },
      { v: 41, en: 'Whenever the stronger of the flock conceived, Jacob laid the rods in front of the eyes of the flock in the gutters, that they might conceive among the rods;', pt: 'e todas as vezes que concebiam as ovelhas fortes, punha Jacó as varas nos bebedouros, diante dos olhos do rebanho, para que concebessem diante das varas;' },
      { v: 42, en: 'but when the flock were feeble, he didn’t put them in. So the feebler were Laban’s, and the stronger Jacob’s.', pt: 'mas quando era fraco o rebanho, ele não as punha. Assim as fracas eram de Labão, e as fortes de Jacó.' },
      { v: 43, en: 'The man increased exceedingly, and had large flocks, female servants and male servants, and camels and donkeys.', pt: 'E o homem se enriqueceu sobremaneira, e teve grandes rebanhos, servas e servos, camelos e jumentos.' },
    ],
    31: [
      { v: 1, en: 'He heard the words of Laban’s sons, saying, “Jacob has taken away all that was our father’s. He has obtained all this wealth from that which was our father’s.”', pt: 'Jacó, entretanto, ouviu as palavras dos filhos de Labão, que diziam: Jacó tem levado tudo o que era de nosso pai, e do que era de nosso pai adquiriu ele todas estas, riquezas.' },
      { v: 2, en: 'Jacob saw the expression on Laban’s face, and, behold, it was not toward him as before.', pt: 'Viu também Jacó o rosto de Labão, e eis que não era para com ele como dantes.' },
      { v: 3, en: 'Yahweh said to Jacob, “Return to the land of your fathers, and to your relatives, and I will be with you.”', pt: 'Disse o Senhor, então, a Jacó: Volta para a terra de teus pais e para a tua parentela; e eu serei contigo.' },
      { v: 4, en: 'Jacob sent and called Rachel and Leah to the field to his flock,', pt: 'Pelo que Jacó mandou chamar a Raquel e a Léia ao campo, onde estava o seu rebanho,' },
      { v: 5, en: 'and said to them, “I see the expression on your father’s face, that it is not toward me as before; but the God of my father has been with me.', pt: 'e lhes disse: vejo que o rosto de vosso pai para comigo não é como anteriormente; porém o Deus de meu pai tem estado comigo.' },
      { v: 6, en: 'You know that I have served your father with all of my strength.', pt: 'Ora, vós mesmas sabeis que com todas as minhas forças tenho servido a vosso pai.' },
      { v: 7, en: 'Your father has deceived me, and changed my wages ten times, but God didn’t allow him to hurt me.', pt: 'Mas vosso pai me tem enganado, e dez vezes mudou o meu salário; Deus, porém, não lhe permitiu que me fizesse mal.' },
      { v: 8, en: 'If he said this, ‘The speckled will be your wages,’ then all the flock bore speckled. If he said this, ‘The streaked will be your wages,’ then all the flock bore streaked.', pt: 'Quando ele dizia assim: Os salpicados serão o teu salário; então todo o rebanho dava salpicados. E quando ele dizia assim: Os listrados serão o teu salário, então todo o rebanho dava listrados.' },
      { v: 9, en: 'Thus God has taken away your father’s livestock, and given them to me.', pt: 'De modo que Deus tem tirado o gado de vosso pai, e mo tem dado a mim.' },
      { v: 10, en: 'During mating season, I lifted up my eyes, and saw in a dream, and behold, the male goats which leaped on the flock were streaked, speckled, and grizzled.', pt: 'Pois sucedeu que, ao tempo em que o rebanho concebia, levantei os olhos e num sonho vi que os bodes que cobriam o rebanho eram listrados, salpicados e malhados.' },
      { v: 11, en: 'The angel of God said to me in the dream, ‘Jacob,’ and I said, ‘Here I am.’', pt: 'Disse-me o anjo de Deus no sonho: Jacó! Eu respondi: Eis-me aqui.' },
      { v: 12, en: 'He said, ‘Now lift up your eyes, and behold, all the male goats which leap on the flock are streaked, speckled, and grizzled, for I have seen all that Laban does to you.', pt: 'Prosseguiu o anjo: Levanta os teus olhos e vê que todos os bodes que cobrem o rebanho são listrados, salpicados e malhados; porque tenho visto tudo o que Labão te vem fazendo.' },
      { v: 13, en: 'I am the God of Bethel, where you anointed a pillar, where you vowed a vow to me. Now arise, get out from this land, and return to the land of your birth.’”', pt: 'Eu sou o Deus de Betel, onde ungiste uma coluna, onde me fizeste um voto; levanta-te, pois, sai-te desta terra e volta para a terra da tua parentela.' },
      { v: 14, en: 'Rachel and Leah answered him, “Is there yet any portion or inheritance for us in our father’s house?', pt: 'Então lhe responderam Raquel e Léia: Temos nós ainda parte ou herança na casa de nosso pai?' },
      { v: 15, en: 'Aren’t we considered as foreigners by him? For he has sold us, and has also used up our money.', pt: 'Não somos tidas por ele como estrangeiras? pois nos vendeu, e consumiu todo o nosso preço.' },
      { v: 16, en: 'For all the riches which God has taken away from our father, that is ours and our children’s. Now then, whatever God has said to you, do.”', pt: 'Toda a riqueza que Deus tirou de nosso pai é nossa e de nossos filhos; portanto, faze tudo o que Deus te mandou.' },
      { v: 17, en: 'Then Jacob rose up, and set his sons and his wives on the camels,', pt: 'Levantou-se, pois, Jacó e fez montar seus filhos e suas mulheres sobre os camelos;' },
      { v: 18, en: 'and he took away all his livestock, and all his possessions which he had gathered, including the livestock which he had gained in Paddan Aram, to go to Isaac his father, to the land of Canaan.', pt: 'e levou todo o seu gado, e toda a sua fazenda, que havia adquirido, o gado que possuía, que havia adquirido em Padã-Arã, a fim de ir ter com Isaque, seu pai, à terra de Canaã.' },
      { v: 19, en: 'Now Laban had gone to shear his sheep: and Rachel stole the teraphim that were her father’s.', pt: 'Ora, tendo Labão ido tosquiar as suas ovelhas, Raquel furtou os ídolos que pertenciam a seu pai.' },
      { v: 20, en: 'Jacob deceived Laban the Syrian, in that he didn’t tell him that he was running away.', pt: 'Jacó iludiu a Labão, o arameu, não lhe fazendo saber que fugia;' },
      { v: 21, en: 'So he fled with all that he had. He rose up, passed over the River, and set his face toward the mountain of Gilead.', pt: 'e fugiu com tudo o que era seu; e, levantando-se, passou o Rio, e foi em direção à montanha de Gileade.' },
      { v: 22, en: 'Laban was told on the third day that Jacob had fled.', pt: 'Ao terceiro dia foi Labão avisado de que Jacó havia fugido.' },
      { v: 23, en: 'He took his relatives with him, and pursued him seven days’ journey. He overtook him in the mountain of Gilead.', pt: 'Então, tomando consigo seus irmãos, seguiu atrás de Jacó jornada de sete dias; e alcançou-o na montanha de Gileade.' },
      { v: 24, en: 'God came to Laban, the Syrian, in a dream of the night, and said to him, “Be careful that you don’t speak to Jacob either good or bad.”', pt: 'Mas Deus apareceu de noite em sonho a Labão, o arameu, e disse-lhe: Guardate, que não fales a Jacó nem bem nem mal.' },
      { v: 25, en: 'Laban caught up with Jacob. Now Jacob had pitched his tent in the mountain, and Laban with his relatives encamped in the mountain of Gilead.', pt: 'Alcançou, pois, Labão a Jacó. Ora, Jacó tinha armado a sua tenda na montanha; armou também Labão com os seus irmãos a sua tenda na montanha de Gileade.' },
      { v: 26, en: 'Laban said to Jacob, “What have you done, that you have deceived me, and carried away my daughters like captives of the sword?', pt: 'Então disse Labão a Jacó: Que fizeste, que me iludiste e levaste minhas filhas como cativas da espada?' },
      { v: 27, en: 'Why did you flee secretly, and deceive me, and didn’t tell me, that I might have sent you away with mirth and with songs, with tambourine and with harp;', pt: 'Por que fuizeste ocultamente, e me iludiste e não mo fizeste saber, para que eu te enviasse com alegria e com cânticos, ao som de tambores e de harpas;' },
      { v: 28, en: 'and didn’t allow me to kiss my sons and my daughters? Now have you done foolishly.', pt: 'Por que não me permitiste beijar meus filhos e minhas filhas? Ora, assim procedeste nesciamente.' },
      { v: 29, en: 'It is in the power of my hand to hurt you, but the God of your father spoke to me last night, saying, ‘Be careful that you don’t speak to Jacob either good or bad.’', pt: 'Está no poder da minha mão fazer-vos o mal, mas o Deus de vosso pai falou-me ontem à noite, dizendo: Guarda-te, que não fales a Jacó nem bem nem mal.' },
      { v: 30, en: 'Now, you want to be gone, because you greatly longed for your father’s house, but why have you stolen my gods?”', pt: 'Mas ainda que quiseste ir embora, porquanto tinhas saudades da casa de teu pai, por que furtaste os meus deuses?' },
      { v: 31, en: 'Jacob answered Laban, “Because I was afraid, for I said, ‘Lest you should take your daughters from me by force.’', pt: 'Respondeu-lhe Jacó: Porque tive medo; pois dizia comigo que tu me arrebatarias as tuas filhas.' },
      { v: 32, en: 'Anyone you find your gods with shall not live. Before our relatives, discern what is yours with me, and take it.” For Jacob didn’t know that Rachel had stolen them.', pt: 'Com quem achares os teus deuses, porém, esse não viverá; diante de nossos irmãos descobre o que é teu do que está comigo, e leva-o contigo. Pois Jacó não sabia que Raquel os tinha furtado.' },
      { v: 33, en: 'Laban went into Jacob’s tent, into Leah’s tent, and into the tent of the two female servants; but he didn’t find them. He went out of Leah’s tent, and entered into Rachel’s tent.', pt: 'Entrou, pois, Labão na tenda de Jacó, na tenda de Léia e na tenda das duas servas, e não os achou; e, saindo da tenda de Léia, entrou na tenda de Raquel.' },
      { v: 34, en: 'Now Rachel had taken the teraphim, put them in the camel’s saddle, and sat on them. Laban felt around all the tent, but didn’t find them.', pt: 'Ora, Raquel havia tomado os ídolos e os havia metido na albarda do camelo, e se assentara em cima deles. Labão apalpou toda a tenda, mas não os achou.' },
      { v: 35, en: 'She said to her father, “Don’t let my lord be angry that I can’t rise up before you; for I’m having my period.” He searched, but didn’t find the teraphim.', pt: 'E ela disse a seu pai: Não se acenda a ira nos olhos de meu senhor, por eu não me poder levantar na tua presença, pois estou com o incômodo das mulheres. Assim ele procurou, mas não achou os ídolos.' },
      { v: 36, en: 'Jacob was angry, and argued with Laban. Jacob answered Laban, “What is my trespass? What is my sin, that you have hotly pursued me?', pt: 'Então irou-se Jacó e contendeu com Labão, dizendo: Qual é a minha transgressão? qual é o meu pecado, que tão furiosamente me tens perseguido?' },
      { v: 37, en: 'Now that you have felt around in all my stuff, what have you found of all your household stuff? Set it here before my relatives and your relatives, that they may judge between us two.', pt: 'Depois de teres apalpado todos os meus móveis, que achaste de todos os móveis da tua casar. Põe-no aqui diante de meus irmãos e de teus irmãos, para que eles julguem entre nós ambos.' },
      { v: 38, en: '“These twenty years I have been with you. Your ewes and your female goats have not cast their young, and I haven’t eaten the rams of your flocks.', pt: 'Estes vinte anos estive eu contigo; as tuas ovelhas e as tuas cabras nunca abortaram, e não comi os carneiros do teu rebanho.' },
      { v: 39, en: 'That which was torn of animals, I didn’t bring to you. I bore its loss. Of my hand you required it, whether stolen by day or stolen by night.', pt: 'Não te trouxe eu o despedaçado; eu sofri o dano; da minha mão requerias tanto o furtado de dia como o furtado de noite.' },
      { v: 40, en: 'This was my situation: in the day the drought consumed me, and the frost by night; and my sleep fled from my eyes.', pt: 'Assim andava eu; de dia me consumia o calor, e de noite a geada; e o sono me fugia dos olhos.' },
      { v: 41, en: 'These twenty years I have been in your house. I served you fourteen years for your two daughters, and six years for your flock, and you have changed my wages ten times.', pt: 'Estive vinte anos em tua casa; catorze anos te servi por tuas duas filhas, e seis anos por teu rebanho; dez vezes mudaste o meu salário.' },
      { v: 42, en: 'Unless the God of my father, the God of Abraham, and the fear of Isaac, had been with me, surely now you would have sent me away empty. God has seen my affliction and the labor of my hands, and rebuked you last night.”', pt: 'Se o Deus de meu pai, o Deus de Abraão e o Temor de Isaque não fora por mim, certamente hoje me mandarias embora vazio. Mas Deus tem visto a minha aflição e o trabalho das minhas mãos, e repreendeu-te ontem à noite.' },
      { v: 43, en: 'Laban answered Jacob, “The daughters are my daughters, the children are my children, the flocks are my flocks, and all that you see is mine: and what can I do today to these my daughters, or to their children whom they have borne?', pt: 'Respondeu-lhe Labão: Estas filhas são minhas filhas, e estes filhos são meus filhos, e este rebanho é meu rebanho, e tudo o que vês é meu; e que farei hoje a estas minhas filhas, ou aos filhos que elas tiveram?' },
      { v: 44, en: 'Now come, let us make a covenant, you and I; and let it be for a witness between me and you.”', pt: 'Agora pois vem, e façamos um pacto, eu e tu; e sirva ele de testemunha entre mim e ti.' },
      { v: 45, en: 'Jacob took a stone, and set it up for a pillar.', pt: 'Então tomou Jacó uma pedra, e a erigiu como coluna.' },
      { v: 46, en: 'Jacob said to his relatives, “Gather stones.” They took stones, and made a heap. They ate there by the heap.', pt: 'E disse a seus irmãos: Ajuntai pedras. Tomaram, pois, pedras e fizeram um montão, e ali junto ao montão comeram.' },
      { v: 47, en: 'Laban called it Jegar Sahadutha, but Jacob called it Galeed.', pt: 'Labão lhe chamou Jegar-Saaduta, e Jacó chamou-lhe Galeede.' },
      { v: 48, en: 'Laban said, “This heap is witness between me and you today.” Therefore it was named Galeed', pt: 'Disse, pois, Labão: Este montão é hoje testemunha entre mim e ti. Por isso foi chamado Galeede;' },
      { v: 49, en: 'and Mizpah, for he said, “Yahweh watch between me and you, when we are absent one from another.', pt: 'e também Mizpá, porquanto disse: Vigie o Senhor entre mim e ti, quando estivermos apartados um do outro.' },
      { v: 50, en: 'If you afflict my daughters, or if you take wives besides my daughters, no man is with us; behold, God is witness between me and you.”', pt: 'Se afligires as minhas filhas, e se tomares outras mulheres além das minhas filhas, embora ninguém esteja conosco, lembra-te de que Deus é testemunha entre mim e ti.' },
      { v: 51, en: 'Laban said to Jacob, “See this heap, and see the pillar, which I have set between me and you.', pt: 'Disse ainda Labão a Jacó: Eis aqui este montão, e eis aqui a coluna que levantei entre mim e ti.' },
      { v: 52, en: 'May this heap be a witness, and the pillar be a witness, that I will not pass over this heap to you, and that you will not pass over this heap and this pillar to me, for harm.', pt: 'Seja este montão testemunha, e seja esta coluna testemunha de que, para mal, nem passarei eu deste montão a ti, nem passarás tu deste montão e desta coluna a mim.' },
      { v: 53, en: 'The God of Abraham, and the God of Nahor, the God of their father, judge between us.” Then Jacob swore by the fear of his father, Isaac.', pt: 'O Deus de Abraão e o Deus de Naor, o Deus do pai deles, julgue entre nós. E jurou Jacó pelo Temor de seu pai Isaque.' },
      { v: 54, en: 'Jacob offered a sacrifice in the mountain, and called his relatives to eat bread. They ate bread, and stayed all night in the mountain.', pt: 'Então Jacó ofereceu um sacrifício na montanha, e convidou seus irmãos para comerem pão; e, tendo comido, passaram a noite na montanha.' },
      { v: 55, en: 'Early in the morning, Laban rose up, and kissed his sons and his daughters, and blessed them. Laban departed and returned to his place.', pt: 'Levantou-se Labão de manhã cedo, beijou seus filhos e suas filhas e os abençoou; e, partindo, voltou para o seu lugar.' },
    ],
    32: [
      { v: 1, en: 'Jacob went on his way, and the angels of God met him.', pt: 'Jacó também seguiu o seu caminho; e encontraram-no os anjos de Deus.' },
      { v: 2, en: 'When he saw them, Jacob said, “This is God’s army.” He called the name of that place Mahanaim.', pt: 'Quando Jacó os viu, disse: Este é o exército de Deus. E chamou àquele lugar Maanaim.' },
      { v: 3, en: 'Jacob sent messengers in front of him to Esau, his brother, to the land of Seir, the field of Edom.', pt: 'Então enviou Jacó mensageiros diante de si a Esaú, seu irmão, à terra de Seir, o território de Edom,' },
      { v: 4, en: 'He commanded them, saying, “This is what you shall tell my lord, Esau: ‘This is what your servant, Jacob, says. I have lived as a foreigner with Laban, and stayed until now.', pt: 'tendo-lhes ordenado: Deste modo falareis a meu senhor Esaú: Assim diz Jacó, teu servo: Como peregrino morei com Labão, e com ele fiquei até agora;' },
      { v: 5, en: 'I have cattle, donkeys, flocks, male servants, and female servants. I have sent to tell my lord, that I may find favor in your sight.’”', pt: 'e tenho bois e jumentos, rebanhos, servos e servas; e mando comunicar isso a meu senhor, para achar graça aos teus olhos.' },
      { v: 6, en: 'The messengers returned to Jacob, saying, “We came to your brother Esau. Not only that, but he comes to meet you, and four hundred men with him.”', pt: 'Depois os mensageiros voltaram a Jacó, dizendo: Fomos ter com teu irmão Esaú; e, em verdade, vem ele para encontrar-te, e quatrocentos homens com ele.' },
      { v: 7, en: 'Then Jacob was greatly afraid and was distressed. He divided the people who were with him, and the flocks, and the herds, and the camels, into two companies;', pt: 'Jacó teve muito medo e ficou aflito; dividiu em dois bandos o povo que estava com ele, bem como os rebanhos, os bois e os camelos;' },
      { v: 8, en: 'and he said, “If Esau comes to the one company, and strikes it, then the company which is left will escape.”', pt: 'pois dizia: Se Esaú vier a um bando e o ferir, o outro bando escapará.' },
      { v: 9, en: 'Jacob said, “God of my father Abraham, and God of my father Isaac, Yahweh, who said to me, ‘Return to your country, and to your relatives, and I will do you good,’', pt: 'Disse mais Jacó: o Deus de meu pai Abraão, Deus de meu pai Isaque, ó Senhor, que me disseste: Volta para a tua terra, e para a tua parentela, e eu te farei bem!' },
      { v: 10, en: 'I am not worthy of the least of all the loving kindnesses, and of all the truth, which you have shown to your servant; for with just my staff I crossed over this Jordan; and now I have become two companies.', pt: 'Não sou digno da menor de todas as tuas beneficências e de toda a fidelidade que tens usado para com teu servo; porque com o meu cajado passei este Jordão, e agora volto em dois bandos.' },
      { v: 11, en: 'Please deliver me from the hand of my brother, from the hand of Esau: for I fear him, lest he come and strike me, and the mothers with the children.', pt: 'Livra-me, peço-te, da mão de meu irmão, da mão de Esaú, porque eu o temo; acaso não venha ele matar-me, e a mãe com os filhos.' },
      { v: 12, en: 'You said, ‘I will surely do you good, and make your offspring as the sand of the sea, which can’t be counted because there are so many.’”', pt: 'Pois tu mesmo disseste: Certamente te farei bem, e farei a tua descendência como a areia do mar, que pela multidão não se pode contar.' },
      { v: 13, en: 'He stayed there that night, and took from that which he had with him, a present for Esau, his brother:', pt: 'Passou ali aquela noite; e do que tinha tomou um presente para seu irmão Esaú:' },
      { v: 14, en: 'two hundred female goats and twenty male goats, two hundred ewes and twenty rams,', pt: 'duzentas cabras e vinte bodes, duzentas ovelhas e vinte carneiros,' },
      { v: 15, en: 'thirty milk camels and their colts, forty cows, ten bulls, twenty female donkeys and ten foals.', pt: 'trinta camelas de leite com suas crias, quarenta vacas e dez touros, vinte jumentas e dez jumentinhos.' },
      { v: 16, en: 'He delivered them into the hands of his servants, every herd by itself, and said to his servants, “Pass over before me, and put a space between herd and herd.”', pt: 'Então os entregou nas mãos dos seus servos, cada manada em separado; e disse a seus servos: Passai adiante de mim e ponde espaço entre manada e manada.' },
      { v: 17, en: 'He commanded the foremost, saying, “When Esau, my brother, meets you, and asks you, saying, ‘Whose are you? Where are you going? Whose are these before you?’', pt: 'E ordenou ao primeiro, dizendo: Quando Esaú, meu irmão, te encontrar e te perguntar: De quem és, e para onde vais, e de quem são estes diante de ti?' },
      { v: 18, en: 'Then you shall say, ‘They are your servant, Jacob’s. It is a present sent to my lord, Esau. Behold, he also is behind us.’”', pt: 'Então responderás: São de teu servo Jacó, presente que envia a meu senhor, a Esaú, e eis que ele vem também atrás dé nos.' },
      { v: 19, en: 'He commanded also the second, and the third, and all that followed the herds, saying, “This is how you shall speak to Esau, when you find him.', pt: 'Ordenou igualmente ao segundo, e ao terceiro, e a todos os que vinham atrás das manadas, dizendo: Desta maneira falareis a Esaú quando o achardes.' },
      { v: 20, en: 'You shall say, ‘Not only that, but behold, your servant, Jacob, is behind us.’” For, he said, “I will appease him with the present that goes before me, and afterward I will see his face. Perhaps he will accept me.”', pt: 'E direis também: Eis que o teu servo Jacó vem atrás de nós. Porque dizia: Aplacá-lo-ei com o presente, que vai adiante de mim, e depois verei a sua face; porventura ele me aceitará.' },
      { v: 21, en: 'So the present passed over before him, and he himself stayed that night in the camp.', pt: 'Foi, pois, o presente adiante dele; ele, porém, passou aquela noite no arraial.' },
      { v: 22, en: 'He rose up that night, and took his two wives, and his two servants, and his eleven sons, and crossed over the ford of the Jabbok.', pt: 'Naquela mesma noite levantou-se e, tomando suas duas mulheres, suas duas servas e seus onze filhos, passou o vau de Jaboque.' },
      { v: 23, en: 'He took them, and sent them over the stream, and sent over that which he had.', pt: 'Tomou-os, e fê-los passar o ribeiro, e fez passar tudo o que tinha.' },
      { v: 24, en: 'Jacob was left alone, and wrestled with a man there until the breaking of the day.', pt: 'Jacó, porém, ficou só; e lutava com ele um homem até o romper do dia.' },
      { v: 25, en: 'When he saw that he didn’t prevail against him, he touched the hollow of his thigh, and the hollow of Jacob’s thigh was strained, as he wrestled.', pt: 'Quando este viu que não prevalecia contra ele, tocou-lhe a juntura da coxa, e se deslocou a juntura da coxa de Jacó, enquanto lutava com ele.' },
      { v: 26, en: 'The man said, “Let me go, for the day breaks.” Jacob said, “I won’t let you go, unless you bless me.”', pt: 'Disse o homem: Deixa-me ir, porque já vem rompendo o dia. Jacó, porém, respondeu: Não te deixarei ir, se me não abençoares.' },
      { v: 27, en: 'He said to him, “What is your name?” He said, “Jacob”.', pt: 'Perguntou-lhe, pois: Qual é o teu nome? E ele respondeu: Jacó.' },
      { v: 28, en: 'He said, “Your name will no longer be called Jacob, but Israel; for you have fought with God and with men, and have prevailed.”', pt: 'Então disse: Não te chamarás mais Jacó, mas Israel; porque tens lutado com Deus e com os homens e tens prevalecido.' },
      { v: 29, en: 'Jacob asked him, “Please tell me your name.” He said, “Why is it that you ask what my name is?” He blessed him there.', pt: 'Perguntou-lhe Jacó: Dize-me, peço-te, o teu nome. Respondeu o homem: Por que perguntas pelo meu nome? E ali o abençoou.' },
      { v: 30, en: 'Jacob called the name of the place Peniel : for, he said, “I have seen God face to face, and my life is preserved.”', pt: 'Pelo que Jacó chamou ao lugar Peniel, dizendo: Porque tenho visto Deus face a face, e a minha vida foi preservada.' },
      { v: 31, en: 'The sun rose on him as he passed over Peniel, and he limped because of his thigh.', pt: 'E nascia o sol, quando ele passou de Peniel; e coxeava de uma perna.' },
      { v: 32, en: 'Therefore the children of Israel don’t eat the sinew of the hip, which is on the hollow of the thigh, to this day, because he touched the hollow of Jacob’s thigh in the sinew of the hip.', pt: 'Por isso os filhos de Israel não comem até o dia de hoje o nervo do quadril, que está sobre a juntura da coxa, porquanto o homem tocou a juntura da coxa de Jacó no nervo do quadril.' },
    ],
    33: [
      { v: 1, en: 'Jacob lifted up his eyes, and looked, and, behold, Esau was coming, and with him four hundred men. He divided the children between Leah, Rachel, and the two servants.', pt: 'Levantou Jacó os olhos, e olhou, e eis que vinha Esaú, e quatrocentos homens com ele. Então repartiu os filhos entre Léia, e Raquel, e as duas servas.' },
      { v: 2, en: 'He put the servants and their children in front, Leah and her children after, and Rachel and Joseph at the rear.', pt: 'Pôs as servas e seus filhos na frente, Léia e seus filhos atrás destes, e Raquel e José por últimos.' },
      { v: 3, en: 'He himself passed over in front of them, and bowed himself to the ground seven times, until he came near to his brother.', pt: 'Mas ele mesmo passou adiante deles, e inclinou-se em terra sete vezes, até chegar perto de seu irmão.' },
      { v: 4, en: 'Esau ran to meet him, embraced him, fell on his neck, kissed him, and they wept.', pt: 'Então Esaú correu-lhe ao encontro, abraçou-o, lançou-se-lhe ao pescoço, e o beijou; e eles choraram.' },
      { v: 5, en: 'He lifted up his eyes, and saw the women and the children; and said, “Who are these with you?” He said, “The children whom God has graciously given your servant.”', pt: 'E levantando Esaú os olhos, viu as mulheres e os meninos, e perguntou: Quem são estes contigo? Respondeu-lhe Jacó: Os filhos que Deus bondosamente tem dado a teu servo.' },
      { v: 6, en: 'Then the servants came near with their children, and they bowed themselves.', pt: 'Então chegaram-se as servas, elas e seus filhos, e inclinaram-se.' },
      { v: 7, en: 'Leah also and her children came near, and bowed themselves. After them, Joseph came near with Rachel, and they bowed themselves.', pt: 'Chegaram-se também Léia e seus filhos, e inclinaram-se; depois chegaram-se José e Raquel e se inclinaram.' },
      { v: 8, en: 'Esau said, “What do you mean by all this company which I met?” Jacob said, “To find favor in the sight of my lord.”', pt: 'Perguntou Esaú: Que queres dizer com todo este bando que tenho encontrado? Respondeu Jacó: Para achar graça aos olhos de meu senhor.' },
      { v: 9, en: 'Esau said, “I have enough, my brother; let that which you have be yours.”', pt: 'Mas Esaú disse: Tenho bastante, meu irmão; seja teu o que tens.' },
      { v: 10, en: 'Jacob said, “Please, no, if I have now found favor in your sight, then receive my present at my hand, because I have seen your face, as one sees the face of God, and you were pleased with me.', pt: 'Replicou-lhe Jacó: Não, mas se agora tenho achado graça aos teus olhos, aceita o presente da minha mão; porquanto tenho visto o teu rosto, como se tivesse visto o rosto de Deus, e tu te agradaste de mim.' },
      { v: 11, en: 'Please take the gift that I brought to you, because God has dealt graciously with me, and because I have enough.” He urged him, and he took it.', pt: 'Aceita, peço-te, o meu presente, que eu te trouxe; porque Deus tem sido bondoso para comigo, e porque tenho de tudo. E insistiu com ele, e ele o aceitou.' },
      { v: 12, en: 'Esau said, “Let us take our journey, and let us go, and I will go before you.”', pt: 'Então Esaú disse: Ponhamo-nos a caminho e vamos; eu irei adiante de ti.' },
      { v: 13, en: 'Jacob said to him, “My lord knows that the children are tender, and that the flocks and herds with me have their young, and if they overdrive them one day, all the flocks will die.', pt: 'Respondeu-lhe Jacó: Meu senhor sabe que estes filhos são tenros, e que tenho comigo ovelhas e vacas de leite; se forem obrigadas a caminhar demais por um só dia, todo o rebanho morrerá.' },
      { v: 14, en: 'Please let my lord pass over before his servant, and I will lead on gently, according to the pace of the livestock that are before me and according to the pace of the children, until I come to my lord to Seir.”', pt: 'Passe o meu senhor adiante de seu servo; e eu seguirei, conduzindo-os calmamente, conforme o passo do gado que está diante de mim, e conforme o passo dos meninos, até que chegue a meu senhor em Seir.' },
      { v: 15, en: 'Esau said, “Let me now leave with you some of the folk who are with me.” He said, “Why? Let me find favor in the sight of my lord.”', pt: 'Ao que disse Esaú: Permite ao menos que eu deixe contigo alguns da minha gente. Replicou Jacó: Para que? Basta que eu ache graça aos olhos de meu senhor.' },
      { v: 16, en: 'So Esau returned that day on his way to Seir.', pt: 'Assim tornou Esaú aquele dia pelo seu caminho em direção a Seir.' },
      { v: 17, en: 'Jacob traveled to Succoth, built himself a house, and made shelters for his livestock. Therefore the name of the place is called Succoth.', pt: 'Jacó, porém, partiu para Sucote, e edificou para si uma casa, e fez barracas para o seu gado; por isso o lugar se chama Sucote.' },
      { v: 18, en: 'Jacob came in peace to the city of Shechem, which is in the land of Canaan, when he came from Paddan Aram; and encamped before the city.', pt: 'Depois chegou Jacó em paz à cidade de Siquém, que está na terra de Canaã, quando veio de Padã-Arã; e armou a sua tenda diante da cidade.' },
      { v: 19, en: 'He bought the parcel of ground where he had spread his tent, at the hand of the children of Hamor, Shechem’s father, for one hundred pieces of money.', pt: 'E comprou a parte do campo, em que estendera a sua tenda, dos filhos de Hamor, pai de Siquém, por cem peças de dinheiro.' },
      { v: 20, en: 'He erected an altar there, and called it El Elohe Israel.', pt: 'Então levantou ali um altar, e chamou-lhe o El-Eloé-Israel.' },
    ],
    34: [
      { v: 1, en: 'Dinah, the daughter of Leah, whom she bore to Jacob, went out to see the daughters of the land.', pt: 'Diná, filha de Léia, que esta tivera de Jacó, saiu para ver as filhas da terra.' },
      { v: 2, en: 'Shechem the son of Hamor the Hivite, the prince of the land, saw her. He took her, lay with her, and humbled her.', pt: 'Viu-a Siquém, filho de Hamor o heveu, príncipe da terra; e, tomando-a, deitou-se com ela e humilhou-a.' },
      { v: 3, en: 'His soul joined to Dinah, the daughter of Jacob, and he loved the young lady, and spoke kindly to the young lady.', pt: 'Assim se apegou a sua alma a Diná, filha de Jacó, e, amando a donzela, falou-lhe afetuosamente.' },
      { v: 4, en: 'Shechem spoke to his father, Hamor, saying, “Get me this young lady as a wife.”', pt: 'Então disse Siquém a Hamor seu pai: Consegue-me esta donzela por mulher.' },
      { v: 5, en: 'Now Jacob heard that he had defiled Dinah, his daughter; and his sons were with his livestock in the field. Jacob held his peace until they came.', pt: 'Ora, Jacó ouviu que Siquém havia contaminado a Diná sua filha. Entretanto, estando seus filhos no campo com o gado, calou-se Jacó até que viessem.' },
      { v: 6, en: 'Hamor the father of Shechem went out to Jacob to talk with him.', pt: 'Hamor, pai de Siquém, saiu a fim de falar com Jacó.' },
      { v: 7, en: 'The sons of Jacob came in from the field when they heard it. The men were grieved, and they were very angry, because he had done folly in Israel in lying with Jacob’s daughter; a thing ought not to be done.', pt: 'Os filhos de Jacó, pois, vieram do campo logo que souberam do caso; e entristeceram-se e iraram-se muito, porque Siquém havia cometido uma insensatez em Israel, deitando-se com a filha de Jacó, coisa que não se devia fazer.' },
      { v: 8, en: 'Hamor talked with them, saying, “The soul of my son, Shechem, longs for your daughter. Please give her to him as a wife.', pt: 'Então falou Hamor com eles, dizendo: A alma de meu filho Siquém afeiçoou-se fortemente a vossa filha; dai-lha, peço-vos, por mulher.' },
      { v: 9, en: 'Make marriages with us. Give your daughters to us, and take our daughters for yourselves.', pt: 'Também aparentai-vos conosco; dai-nos as vossas filhas e recebei as nossas.' },
      { v: 10, en: 'You shall dwell with us, and the land will be before you. Live and trade in it, and get possessions in it.”', pt: 'Assim habitareis conosco; a terra estará diante de vós; habitai e negociai nela, e nela adquiri propriedades.' },
      { v: 11, en: 'Shechem said to her father and to her brothers, “Let me find favor in your eyes, and whatever you will tell me I will give.', pt: 'Depois disse Siquém ao pai e aos irmãos dela: Ache eu graça aos vossos olhos, e darei o que me disserdes;' },
      { v: 12, en: 'Ask me a great amount for a dowry, and I will give whatever you ask of me, but give me the young lady as a wife.”', pt: 'exigi de mim o que quiserdes em dote e presentes, e darei o que me pedirdes; somente dai-me a donzela por mulher.' },
      { v: 13, en: 'The sons of Jacob answered Shechem and Hamor his father with deceit, and spoke, because he had defiled Dinah their sister,', pt: 'Então os filhos de Jacó, respondendo, falaram enganosamente a Siquém e a Hamor, seu pai, porque Siquém havia contaminado a Diná, sua irmã,' },
      { v: 14, en: 'and said to them, “We can’t do this thing, to give our sister to one who is uncircumcised; for that is a reproach to us.', pt: 'e lhes disseram: Não podemos fazer p isto, dar a nossa irmã a um homem incircunciso; porque isso seria uma vergonha para nós.' },
      { v: 15, en: 'Only on this condition will we consent to you. If you will be as we are, that every male of you be circumcised;', pt: 'Sob esta única condição consentiremos; se vos tornardes como nós, circuncidando-se todo varão entre vós;' },
      { v: 16, en: 'then will we give our daughters to you, and we will take your daughters to us, and we will dwell with you, and we will become one people.', pt: 'então vos daremos nossas filhas a vós, e receberemos vossas filhas para nós; assim habitaremos convosco e nos tornaremos um só povo.' },
      { v: 17, en: 'But if you will not listen to us, to be circumcised, then we will take our sister, and we will be gone.”', pt: 'Mas se não nos ouvirdes, e não vos circuncidardes, levaremos nossa filha e nos iremos embora.' },
      { v: 18, en: 'Their words pleased Hamor and Shechem, Hamor’s son.', pt: 'E suas palavras agradaram a Hamor e a Siquém, seu filho.' },
      { v: 19, en: 'The young man didn’t wait to do this thing, because he had delight in Jacob’s daughter, and he was honored above all the house of his father.', pt: 'Não tardou, pois, o mancebo em fazer isso, porque se agradava da filha de Jacó. Era ele o mais honrado de toda a casa de seu pai.' },
      { v: 20, en: 'Hamor and Shechem, his son, came to the gate of their city, and talked with the men of their city, saying,', pt: 'Vieram, pois, Hamor e Siquém, seu filho, à porta da sua cidade, e falaram aos homens da cidade, dizendo:' },
      { v: 21, en: '“These men are peaceful with us. Therefore let them live in the land and trade in it. For behold, the land is large enough for them. Let us take their daughters to us for wives, and let us give them our daughters.', pt: 'Estes homens são pacíficos para conosco; portanto habitem na terra e negociem nela, pois é bastante espaçosa para eles. Recebamos por mulheres as suas filhas, e lhes demos as nossas.' },
      { v: 22, en: 'Only on this condition will the men consent to us to live with us, to become one people, if every male among us is circumcised, as they are circumcised.', pt: 'Mas sob uma única condição é que consentirão aqueles homens em habitar conosco para nos tornarmos um só povo: se todo varão entre nós se circuncidar, como eles são circuncidados.' },
      { v: 23, en: 'Won’t their livestock and their possessions and all their animals be ours? Only let us give our consent to them, and they will dwell with us.”', pt: 'O seu gado, as suas aquisições, e todos os seus animais, não serão nossos? consintamos somente com eles, e habitarão conosco.' },
      { v: 24, en: 'All who went out of the gate of his city listened to Hamor, and to Shechem his son; and every male was circumcised, all who went out of the gate of his city.', pt: 'E deram ouvidos a Hamor e a Siquém, seu filho, todos os que saíam da porta da cidade; e foi circuncidado todo varão, todos os que saíam pela porta da sua cidade.' },
      { v: 25, en: 'On the third day, when they were sore, two of Jacob’s sons, Simeon and Levi, Dinah’s brothers, each took his sword, came upon the unsuspecting city, and killed all the males.', pt: 'Ao terceiro dia, quando os homens estavam doridos, dois filhos de Jacó, Simeão e Levi, irmãos de Diná, tomaram cada um a sua espada, entraram na cidade com toda a segurança e mataram todo varão.' },
      { v: 26, en: 'They killed Hamor and Shechem, his son, with the edge of the sword, and took Dinah out of Shechem’s house, and went away.', pt: 'Mataram também ao fio da espada a Hamor e a Siquém, seu filho; e, tirando Diná da casa de Siquém, saíram.' },
      { v: 27, en: 'Jacob’s sons came on the dead, and plundered the city, because they had defiled their sister.', pt: 'Vieram os filhos de Jacó aos mortos e saquearam a cidade; porquanto haviam contaminado a sua irmã.' },
      { v: 28, en: 'They took their flocks, their herds, their donkeys, that which was in the city, that which was in the field,', pt: 'Tomaram-lhes os rebanhos, os bois, os jumentos, e o que havia tanto na cidade como no campo;' },
      { v: 29, en: 'and all their wealth. They took captive all their little ones and their wives, and took as plunder everything that was in the house.', pt: 'e todos os seus bens, e todos os seus pequeninos, e as suas mulheres, levaram por presa; e despojando as casas, levaram tudo o que havia nelas.' },
      { v: 30, en: 'Jacob said to Simeon and Levi, “You have troubled me, to make me odious to the inhabitants of the land, among the Canaanites and the Perizzites. I am few in number. They will gather themselves together against me and strike me, and I will be destroyed, I and my house.”', pt: 'Então disse Jacó a Simeão e a Levi: Tendes-me perturbado, fazendo-me odioso aos habitantes da terra, aos cananeus e perizeus. Tendo eu pouca gente, eles se ajuntarão e me ferirão; e serei destruído, eu com minha casa.' },
      { v: 31, en: 'They said, “Should he deal with our sister as with a prostitute?”', pt: 'Ao que responderam: Devia ele tratar a nossa irmã como a uma prostituta?' },
    ],
    35: [
      { v: 1, en: 'God said to Jacob, “Arise, go up to Bethel, and live there. Make there an altar to God, who appeared to you when you fled from the face of Esau your brother.”', pt: 'Depois disse Deus a Jacó: Levanta-te, sobe a Betel e habita ali; e faze ali um altar ao Deus que te apareceu quando fugias da face de Esaú, teu irmão.' },
      { v: 2, en: 'Then Jacob said to his household, and to all who were with him, “Put away the foreign gods that are among you, purify yourselves, change your garments.', pt: 'Então disse Jacó à sua família, e a todos os que com ele estavam: Lançai fora os deuses estranhos que há no meio de vós, e purificai-vos e mudai as vossas vestes.' },
      { v: 3, en: 'Let us arise, and go up to Bethel. I will make there an altar to God, who answered me in the day of my distress, and was with me on the way which I went.”', pt: 'Levantemo-nos, e subamos a Betel; ali farei um altar ao Deus que me respondeu no dia da minha angústia, e que foi comigo no caminho por onde andei.' },
      { v: 4, en: 'They gave to Jacob all the foreign gods which were in their hands, and the rings which were in their ears; and Jacob hid them under the oak which was by Shechem.', pt: 'Entregaram, pois, a Jacó todos os deuses estranhos, que tinham nas mãos, e as arrecadas que pendiam das suas orelhas; e Jacó os escondeu debaixo do carvalho que está junto a Siquém.' },
      { v: 5, en: 'They traveled, and a terror of God was on the cities that were around them, and they didn’t pursue the sons of Jacob.', pt: 'Então partiram; e o terror de Deus sobreveio às cidades que lhes estavam ao redor, de modo que não perseguiram os filhos de Jacó.' },
      { v: 6, en: 'So Jacob came to Luz (that is, Bethel), which is in the land of Canaan, he and all the people who were with him.', pt: 'Assim chegou Jacó à Luz, que está na terra de Canaã (esta é Betel), ele e todo o povo que estava com ele.' },
      { v: 7, en: 'He built an altar there, and called the place El Beth El; because there God was revealed to him, when he fled from the face of his brother.', pt: 'Edificou ali um altar, e chamou ao lugar El-Betel; porque ali Deus se lhe tinha manifestado quando fugia da face de seu irmão.' },
      { v: 8, en: 'Deborah, Rebekah’s nurse, died, and she was buried below Bethel under the oak; and its name was called Allon Bacuth.', pt: 'Morreu Débora, a ama de Rebeca, e foi sepultada ao pé de Betel, debaixo do carvalho, ao qual se chamou Alom-Bacute.' },
      { v: 9, en: 'God appeared to Jacob again, when he came from Paddan Aram, and blessed him.', pt: 'Apareceu Deus outra vez a Jacó, quando ele voltou de Padã-Arã, e o abençoou.' },
      { v: 10, en: 'God said to him, “Your name is Jacob. Your name shall not be Jacob any more, but your name will be Israel.” He named him Israel.', pt: 'E disse-lhe Deus: O teu nome é Jacó; não te chamarás mais Jacó, mas Israel será o teu nome. Chamou-lhe Israel.' },
      { v: 11, en: 'God said to him, “I am God Almighty. Be fruitful and multiply. A nation and a company of nations will be from you, and kings will come out of your body.', pt: 'Disse-lhe mais: Eu sou Deus Todo-Poderoso; frutifica e multiplica-te; uma nação, sim, uma multidão de nações sairá de ti, e reis procederão dos teus lombos;' },
      { v: 12, en: 'The land which I gave to Abraham and Isaac, I will give it to you, and to your offspring after you will I give the land.”', pt: 'a terra que dei a Abraão e a Isaque, a ti a darei; também à tua descendência depois de ti a darei.' },
      { v: 13, en: 'God went up from him in the place where he spoke with him.', pt: 'E Deus subiu dele, do lugar onde lhe falara.' },
      { v: 14, en: 'Jacob set up a pillar in the place where he spoke with him, a pillar of stone. He poured out a drink offering on it, and poured oil on it.', pt: 'Então Jacó erigiu uma coluna no lugar onde Deus lhe falara, uma coluna de pedra; e sobre ela derramou uma libação e deitou-lhe também azeite;' },
      { v: 15, en: 'Jacob called the name of the place where God spoke with him “Bethel”.', pt: 'e Jacó chamou Betel ao lugar onde Deus lhe falara.' },
      { v: 16, en: 'They traveled from Bethel. There was still some distance to come to Ephrath, and Rachel travailed. She had hard labor.', pt: 'Depois partiram de Betel; e, faltando ainda um trecho pequeno para chegar a Efrata, Raquel começou a sentir dores de parto, e custou-lhe o dar à luz.' },
      { v: 17, en: 'When she was in hard labor, the midwife said to her, “Don’t be afraid, for now you will have another son.”', pt: 'Quando ela estava nas dores do parto, disse-lhe a parteira: Não temas, pois ainda terás este filho.' },
      { v: 18, en: 'As her soul was departing (for she died), she named him Benoni, but his father named him Benjamin.', pt: 'Então Raquel, ao sair-lhe a alma (porque morreu), chamou ao filho Benôni; mas seu pai chamou-lhe Benjamim.' },
      { v: 19, en: 'Rachel died, and was buried on the way to Ephrath (also called Bethlehem).', pt: 'Assim morreu Raquel, e foi sepultada no caminho de Efrata (esta é Bete-Leém).' },
      { v: 20, en: 'Jacob set up a pillar on her grave. The same is the Pillar of Rachel’s grave to this day.', pt: 'E Jacó erigiu uma coluna sobre a sua sepultura; esta é a coluna da sepultura de Raquel até o dia de hoje.' },
      { v: 21, en: 'Israel traveled, and spread his tent beyond the tower of Eder.', pt: 'Então partiu Israel, e armou a sua tenda além de Migdal-Eder.' },
      { v: 22, en: 'While Israel lived in that land, Reuben went and lay with Bilhah, his father’s concubine, and Israel heard of it. Now the sons of Jacob were twelve.', pt: 'Quando Israel habitava naquela terra, foi Rúben e deitou-se com Bila, concubina de seu pai; e Israel o soube. Eram doze os filhos de Jacó:' },
      { v: 23, en: 'The sons of Leah: Reuben (Jacob’s firstborn), Simeon, Levi, Judah, Issachar, and Zebulun.', pt: 'Os filhos de Léia: Rúben o primogênito de Jacó, depois Simeão, Levi, Judá, Issacar e Zebulom;' },
      { v: 24, en: 'The sons of Rachel: Joseph and Benjamin.', pt: 'os filhos de Raquel: José e Benjamim;' },
      { v: 25, en: 'The sons of Bilhah (Rachel’s servant): Dan and Naphtali.', pt: 'os filhos de Bila, serva de Raquel: Dã e Naftali;' },
      { v: 26, en: 'The sons of Zilpah (Leah’s servant): Gad and Asher. These are the sons of Jacob, who were born to him in Paddan Aram.', pt: 'os filhos de Zilpa, serva de Léia: Gade e Aser. Estes são os filhos de Jacó, que lhe nasceram em Padã-Arã.' },
      { v: 27, en: 'Jacob came to Isaac his father, to Mamre, to Kiriath Arba (which is Hebron), where Abraham and Isaac lived as foreigners.', pt: 'Jacó veio a seu pai Isaque, a Manre, a Quiriate-Arba (esta é Hebrom), onde peregrinaram Abraão e Isaque.' },
      { v: 28, en: 'The days of Isaac were one hundred eighty years.', pt: 'Foram os dias de Isaque cento e oitenta anos;' },
      { v: 29, en: 'Isaac gave up the spirit, and died, and was gathered to his people, old and full of days. Esau and Jacob, his sons, buried him.', pt: 'e, exalando o espírito, morreu e foi congregado ao seu povo, velho e cheio de dias; e Esaú e Jacó, seus filhos, o sepultaram.' },
    ],
    36: [
      { v: 1, en: 'Now this is the history of the generations of Esau (that is, Edom).', pt: 'Estas são as gerações de Esaú (este é Edom):' },
      { v: 2, en: 'Esau took his wives from the daughters of Canaan: Adah the daughter of Elon, the Hittite; and Oholibamah the daughter of Anah, the daughter of Zibeon, the Hivite;', pt: 'Esaú tomou dentre as filhas de Canaã suas mulheres: Ada, filha de Elom o heteu, e Aolíbama, filha de Ana, filha de Zibeão o heveu,' },
      { v: 3, en: 'and Basemath, Ishmael’s daughter, sister of Nebaioth.', pt: 'e Basemate, filha de Ismael, irmã de Nebaiote.' },
      { v: 4, en: 'Adah bore to Esau Eliphaz. Basemath bore Reuel.', pt: 'Ada teve de Esaú a Elifaz, e Basemate teve a Reuel; e Aolíbama teve a Jeús, Jalão e Corá; estes são os filhos de Esaú, que lhe nasceram na terra de Canaã.' },
      { v: 5, en: 'Oholibamah bore Jeush, Jalam, and Korah. These are the sons of Esau, who were born to him in the land of Canaan.', pt: 'Depois Esaú tomou suas mulheres, seus filhos, suas filhas e todas as almas de sua casa, seu gado, todos os seus animais e todos os seus bens, que havia adquirido na terra de Canaã, e foi-se para outra terra, apartando-se de seu irmão Jacó.' },
      { v: 6, en: 'Esau took his wives, his sons, his daughters, and all the members of his household, with his livestock, all his animals, and all his possessions, which he had gathered in the land of Canaan, and went into a land away from his brother Jacob.', pt: 'Porque os seus bens eram abundantes demais para habitarem juntos; e a terra de suas peregrinações não os podia sustentar por causa do seu gado.' },
      { v: 7, en: 'For their substance was too great for them to dwell together, and the land of their travels couldn’t bear them because of their livestock.', pt: 'Portanto Esaú habitou no monte de Seir; Esaú é Edom.' },
      { v: 8, en: 'Esau lived in the hill country of Seir. Esau is Edom.', pt: 'Estas, pois, são as gerações de Esaú, pai dos edomeus, no monte de Seir:' },
      { v: 9, en: 'This is the history of the generations of Esau the father of the Edomites in the hill country of Seir:', pt: 'Estes são os nomes dos filhos de Esaú: Elifaz, filho de Ada, mulher de Esaú; Reuel, filho de Basemate, mulher de Esaú.' },
      { v: 10, en: 'these are the names of Esau’s sons: Eliphaz, the son of Adah, the wife of Esau; and Reuel, the son of Basemath, the wife of Esau.', pt: 'E os filhos de Elifaz foram: Temã, Omar, Zefô, Gatã e Quenaz.' },
      { v: 11, en: 'The sons of Eliphaz were Teman, Omar, Zepho, and Gatam, and Kenaz.', pt: 'Timna era concubina de Elifaz, filho de Esaú, e teve de Elifaz a Amaleque. São esses os filhos de Ada, mulher de Esaú.' },
      { v: 12, en: 'Timna was concubine to Eliphaz, Esau’s son; and she bore to Eliphaz Amalek. These are the sons of Adah, Esau’s wife.', pt: 'Foram estes os filhos de Reuel: Naate e Zerá, Sama e Mizá. Foram esses os filhos de Basemate, mulher de Esaú.' },
      { v: 13, en: 'These are the sons of Reuel: Nahath, Zerah, Shammah, and Mizzah. These were the sons of Basemath, Esau’s wife.', pt: 'Estes foram os filhos de Aolíbama, filha de Ana, filha de Zibeão, mulher de Esaú: ela teve de Esaú Jeús, Jalão e Corá.' },
      { v: 14, en: 'These were the sons of Oholibamah, the daughter of Anah, the daughter of Zibeon, Esau’s wife: she bore to Esau Jeush, Jalam, and Korah.', pt: 'São estes os chefes dos filhos de Esaú: dos filhos de Elifaz, o primogênito de Esaú, os chefes Temã, Omar, Zefô, Quenaz,' },
      { v: 15, en: 'These are the chiefs of the sons of Esau: the sons of Eliphaz the firstborn of Esau: chief Teman, chief Omar, chief Zepho, chief Kenaz,', pt: 'Corá, Gatã e Amaleque. São esses os chefes que nasceram a Elifaz na terra de Edom; esses são os filhos de Ada.' },
      { v: 16, en: 'chief Korah, chief Gatam, chief Amalek: these are the chiefs who came of Eliphaz in the land of Edom; these are the sons of Adah.', pt: 'Estes são os filhos de Reuel, filho de Esaú: os chefes Naate, Zerá, Sama e Mizá; esses são os chefes que nasceram a Reuel na terra de Edom; esses são os filhos de Basemate, mulher de Esaú.' },
      { v: 17, en: 'These are the sons of Reuel, Esau’s son: chief Nahath, chief Zerah, chief Shammah, chief Mizzah: these are the chiefs who came of Reuel in the land of Edom; these are the sons of Basemath, Esau’s wife.', pt: 'Estes são os filhos de Aolíbama, mulher de Esaú: os chefes Jeús, Jalão e Corá; esses são os chefes que nasceram a líbama, filha de Ana, mulher de Esaú.' },
      { v: 18, en: 'These are the sons of Oholibamah, Esau’s wife: chief Jeush, chief Jalam, chief Korah: these are the chiefs who came of Oholibamah the daughter of Anah, Esau’s wife.', pt: 'Esses são os filhos de Esaú, e esses seus príncipes: ele é Edom.' },
      { v: 19, en: 'These are the sons of Esau (that is, Edom), and these are their chiefs.', pt: 'São estes os filhos de Seir, o horeu, moradores da terra: Lotã, Sobal, Zibeão, Anás,' },
      { v: 20, en: 'These are the sons of Seir the Horite, the inhabitants of the land: Lotan, Shobal, Zibeon, Anah,', pt: 'Disom, Eser e Disã; esses são os chefes dos horeus, filhos de Seir, na terra de Edom.' },
      { v: 21, en: 'Dishon, Ezer, and Dishan. These are the chiefs who came of the Horites, the children of Seir in the land of Edom.', pt: 'Os filhos de Lotã foram: Hori e Hemã; e a irmã de Lotã era Timna.' },
      { v: 22, en: 'The children of Lotan were Hori and Heman. Lotan’s sister was Timna.', pt: 'Estes são os filhos de Sobal: Alvã, Manaate, Ebal, Sefô e Onão.' },
      { v: 23, en: 'These are the children of Shobal: Alvan, Manahath, Ebal, Shepho, and Onam.', pt: 'Estes são os filhos de Zibeão: Aías e Anás; este é o Anás que achou as fontes termais no deserto, quando apascentava os jumentos de Zibeão, seu pai.' },
      { v: 24, en: 'These are the children of Zibeon: Aiah and Anah. This is Anah who found the hot springs in the wilderness, as he fed the donkeys of Zibeon his father.', pt: 'São estes os filhos de Ana: Disom e Aolíbama, filha de Ana.' },
      { v: 25, en: 'These are the children of Anah: Dishon and Oholibamah, the daughter of Anah.', pt: 'São estes os filhos de Disom: Hendã, Esbã, Itrã e Querã.' },
      { v: 26, en: 'These are the children of Dishon: Hemdan, Eshban, Ithran, and Cheran.', pt: 'Estes são os filhos de Eser: Bilã, Zaavã e Acã.' },
      { v: 27, en: 'These are the children of Ezer: Bilhan, Zaavan, and Akan.', pt: 'Estes são os filhos de Disã: Uz e Arã.' },
      { v: 28, en: 'These are the children of Dishan: Uz and Aran.', pt: 'Estes são os chefes dos horeus: Lotã, Sobal, Zibeão, Anás,' },
      { v: 29, en: 'These are the chiefs who came of the Horites: chief Lotan, chief Shobal, chief Zibeon, chief Anah,', pt: 'Disom, Eser e Disã; esses são os chefes dos horeus que governaram na terra de Seir.' },
      { v: 30, en: 'chief Dishon, chief Ezer, and chief Dishan: these are the chiefs who came of the Horites, according to their chiefs in the land of Seir.', pt: 'São estes os reis que reinaram na terra de Edom, antes que reinasse rei algum sobre os filhos de Israel.' },
      { v: 31, en: 'These are the kings who reigned in the land of Edom, before any king reigned over the children of Israel.', pt: 'Reinou, pois, em Edom Belá, filho de Beor; e o nome da sua cidade era Dinabá.' },
      { v: 32, en: 'Bela, the son of Beor, reigned in Edom. The name of his city was Dinhabah.', pt: 'Morreu Belá; e Jobabe, filho de Zerá de Bozra, reinou em seu lugar.' },
      { v: 33, en: 'Bela died, and Jobab, the son of Zerah of Bozrah, reigned in his place.', pt: 'Morreu Jobabe; e Husão, da terra dos temanitas, reinou em seu lugar.' },
      { v: 34, en: 'Jobab died, and Husham of the land of the Temanites reigned in his place.', pt: 'Morreu Husão; e em seu lugar reinou Hadade, filho de Bedade, que feriu a Midiã no campo de Moabe; e o nome da sua cidade era Avite.' },
      { v: 35, en: 'Husham died, and Hadad, the son of Bedad, who struck Midian in the field of Moab, reigned in his place. The name of his city was Avith.', pt: 'Morreu Hadade; e Sâmela de Masreca reinou em seu lugar.' },
      { v: 36, en: 'Hadad died, and Samlah of Masrekah reigned in his place.', pt: 'Morreu Sâmela; e Saul de Reobote junto ao rio reinou em seu lugar.' },
      { v: 37, en: 'Samlah died, and Shaul of Rehoboth by the river, reigned in his place.', pt: 'Morreu Saul; e Baal-Hanã, filho de Acbor, reinou em seu lugar.' },
      { v: 38, en: 'Shaul died, and Baal Hanan, the son of Achbor reigned in his place.', pt: 'Morreu Baal-Hanã, filho de Acbor; e Hadar reinou em seu lugar; e o nome da sua cidade era Paú; e o nome de sua mulher era Meetabel, filha de Matrede, filha de Me-Zaabe.' },
      { v: 39, en: 'Baal Hanan the son of Achbor died, and Hadar reigned in his place. The name of his city was Pau. His wife’s name was Mehetabel, the daughter of Matred, the daughter of Mezahab.', pt: 'Estes são os nomes dos chefes dos filhos de Esaú, segundo as suas famílias, segundo os seus lugares, pelos seus nomes: os chefes Timna, Alva, Jetete,' },
      { v: 40, en: 'These are the names of the chiefs who came from Esau, according to their families, after their places, and by their names: chief Timna, chief Alvah, chief Jetheth,', pt: 'Aolíbama, Elá, Pinom,' },
      { v: 41, en: 'chief Oholibamah, chief Elah, chief Pinon,', pt: 'Quenaz, Temã, Mibzar,' },
      { v: 42, en: 'chief Kenaz, chief Teman, chief Mibzar,', pt: 'Magdiel e Irão; esses são os chefes de Edom, segundo as suas habitações, na terra ,da sua possessão. Este é Esaú, pai dos edomeus.' },
      { v: 43, en: 'chief Magdiel, and chief Iram. These are the chiefs of Edom, according to their habitations in the land of their possession. This is Esau, the father of the Edomites.', pt: 'chief Magdiel, and chief Iram. These are the chiefs of Edom, according to their habitations in the land of their possession. This is Esau, the father of the Edomites.' },
    ],
    37: [
      { v: 1, en: 'Jacob lived in the land of his father’s travels, in the land of Canaan.', pt: 'Jacó habitava na terra das peregrinações de seu pai, na terra de Canaã.' },
      { v: 2, en: 'This is the history of the generations of Jacob. Joseph, being seventeen years old, was feeding the flock with his brothers. He was a boy with the sons of Bilhah and Zilpah, his father’s wives. Joseph brought an evil report of them to their father.', pt: 'Estas são as gerações de Jacó. José, aos dezessete anos de idade, estava com seus irmãos apascentando os rebanhos; sendo ainda jovem, andava com os filhos de Bila, e com os filhos de Zilpa, mulheres de seu pai; e José trazia a seu pai más notícias a respeito deles.' },
      { v: 3, en: 'Now Israel loved Joseph more than all his children, because he was the son of his old age, and he made him a coat of many colors.', pt: 'Israel amava mais a José do que a todos os seus filhos, porque era filho da sua velhice; e fez-lhe uma túnica de várias cores.' },
      { v: 4, en: 'His brothers saw that their father loved him more than all his brothers, and they hated him, and couldn’t speak peaceably to him.', pt: 'Vendo, pois, seus irmãos que seu pai o amava mais do que a todos eles, odiavam-no, e não lhe podiam falar pacificamente.' },
      { v: 5, en: 'Joseph dreamed a dream, and he told it to his brothers, and they hated him all the more.', pt: 'José teve um sonho, que contou a seus irmãos; por isso o odiaram ainda mais.' },
      { v: 6, en: 'He said to them, “Please hear this dream which I have dreamed:', pt: 'Pois ele lhes disse: Ouvi, peço-vos, este sonho que tive:' },
      { v: 7, en: 'for behold, we were binding sheaves in the field, and behold, my sheaf arose and also stood upright; and behold, your sheaves came around, and bowed down to my sheaf.”', pt: 'Estávamos nós atando molhos no campo, e eis que o meu molho, levantando-se, ficou em pé; e os vossos molhos o rodeavam, e se inclinavam ao meu molho.' },
      { v: 8, en: 'His brothers said to him, “Will you indeed reign over us? Or will you indeed have dominion over us?” They hated him all the more for his dreams and for his words.', pt: 'Responderam-lhe seus irmãos: Tu pois, deveras reinarás sobre nós? Tu deveras terás domínio sobre nós? Por isso ainda mais o odiavam por causa dos seus sonhos e das suas palavras.' },
      { v: 9, en: 'He dreamed yet another dream, and told it to his brothers, and said, “Behold, I have dreamed yet another dream: and behold, the sun and the moon and eleven stars bowed down to me.”', pt: 'Teve José outro sonho, e o contou a seus irmãos, dizendo: Tive ainda outro sonho; e eis que o sol, e a lua, e onze estrelas se inclinavam perante mim.' },
      { v: 10, en: 'He told it to his father and to his brothers. His father rebuked him, and said to him, “What is this dream that you have dreamed? Will I and your mother and your brothers indeed come to bow ourselves down to you to the earth?”', pt: 'Quando o contou a seu pai e a seus irmãos, repreendeu-o seu pai, e disse-lhe: Que sonho é esse que tiveste? Porventura viremos, eu e tua mãe, e teus irmãos, a inclinar-nos com o rosto em terra diante de ti?' },
      { v: 11, en: 'His brothers envied him, but his father kept this saying in mind.', pt: 'Seus irmãos, pois, o invejavam; mas seu pai guardava o caso no seu coração.' },
      { v: 12, en: 'His brothers went to feed their father’s flock in Shechem.', pt: 'Ora, foram seus irmãos apascentar o rebanho de seu pai, em Siquém.' },
      { v: 13, en: 'Israel said to Joseph, “Aren’t your brothers feeding the flock in Shechem? Come, and I will send you to them.” He said to him, “Here I am.”', pt: 'Disse, pois, Israel a José: Não apascentam teus irmãos o rebanho em Siquém? Vem, e enviar-te-ei a eles. Respondeu-lhe José: Eis-me aqui.' },
      { v: 14, en: 'He said to him, “Go now, see whether it is well with your brothers, and well with the flock; and bring me word again.” So he sent him out of the valley of Hebron, and he came to Shechem.', pt: 'Disse-lhe Israel: Vai, vê se vão bem teus irmãos, e o rebanho; e traze-me resposta. Assim o enviou do vale de Hebrom; e José foi a Siquém.' },
      { v: 15, en: 'A certain man found him, and behold, he was wandering in the field. The man asked him, “What are you looking for?”', pt: 'E um homem encontrou a José, que andava errante pelo campo, e perguntou-lhe: Que procuras?' },
      { v: 16, en: 'He said, “I am looking for my brothers. Tell me, please, where they are feeding the flock.”', pt: 'Respondeu ele: Estou procurando meus irmãos; dize-me, peço-te, onde apascentam eles o rebanho.' },
      { v: 17, en: 'The man said, “They have left here, for I heard them say, ‘Let us go to Dothan.’” Joseph went after his brothers, and found them in Dothan.', pt: 'Disse o homem: Foram-se daqui; pois ouvi-lhes dizer: Vamos a Dotã. José, pois, seguiu seus irmãos, e os achou em Dotã.' },
      { v: 18, en: 'They saw him afar off, and before he came near to them, they conspired against him to kill him.', pt: 'Eles o viram de longe e, antes que chegasse aonde estavam, conspiraram contra ele, para o matarem,' },
      { v: 19, en: 'They said to one another, “Behold, this dreamer comes.', pt: 'dizendo uns aos outros: Eis que lá vem o sonhador!' },
      { v: 20, en: 'Come now therefore, and let’s kill him, and cast him into one of the pits, and we will say, ‘An evil animal has devoured him.’ We will see what will become of his dreams.”', pt: 'Vinde pois agora, fmatemo-lo e lancemo-lo numa das covas; e diremos: uma besta-fera o devorou. Veremos, então, o que será dos seus sonhos.' },
      { v: 21, en: 'Reuben heard it, and delivered him out of their hand, and said, “Let’s not take his life.”', pt: 'Mas Rúben, ouvindo isso, livrou-o das mãos deles, dizendo: Não lhe tiremos a vida.' },
      { v: 22, en: 'Reuben said to them, “Shed no blood. Throw him into this pit that is in the wilderness, but lay no hand on him”—that he might deliver him out of their hand, to restore him to his father.', pt: 'Também lhes disse Rúben: Não derrameis sangue; lançai-o nesta cova, que está no deserto, e não lanceis mão nele. Disse isto para livrá-lo das mãos deles, a fim de restituí-lo a seu pai.' },
      { v: 23, en: 'When Joseph came to his brothers, they stripped Joseph of his coat, the coat of many colors that was on him;', pt: 'Logo que José chegou a seus irmãos, estes o despiram da sua túnica, a túnica de várias cores, que ele trazia;' },
      { v: 24, en: 'and they took him, and threw him into the pit. The pit was empty. There was no water in it.', pt: 'e tomando-o, lançaram-no na cova; mas a cova estava vazia, não havia água nela.' },
      { v: 25, en: 'They sat down to eat bread, and they lifted up their eyes and looked, and saw a caravan of Ishmaelites was coming from Gilead, with their camels bearing spices and balm and myrrh, going to carry it down to Egypt.', pt: 'Depois sentaram-se para comer; e, levantando os olhos, viram uma caravana de ismaelitas que vinha de Gileade; nos seus camelos traziam tragacanto, bálsamo e mirra, que iam levar ao Egito.' },
      { v: 26, en: 'Judah said to his brothers, “What profit is it if we kill our brother and conceal his blood?', pt: 'Disse Judá a seus irmãos: De que nos aproveita matar nosso irmão e encobrir o seu sangue?' },
      { v: 27, en: 'Come, and let’s sell him to the Ishmaelites, and not let our hand be on him; for he is our brother, our flesh.” His brothers listened to him.', pt: 'Vinde, vendamo-lo a esses ismaelitas, e não seja nossa mão sobre ele; porque é nosso irmao, nossa carne. E escutaram-no seus irmãos.' },
      { v: 28, en: 'Midianites who were merchants passed by, and they drew and lifted up Joseph out of the pit, and sold Joseph to the Ishmaelites for twenty pieces of silver. They brought Joseph into Egypt.', pt: 'Ao passarem os negociantes midianitas, tiraram José, alçando-o da cova, e venderam-no por vinte siclos de prata aos ismaelitas, os quais o levaram para o Egito.' },
      { v: 29, en: 'Reuben returned to the pit; and saw that Joseph wasn’t in the pit; and he tore his clothes.', pt: 'Ora, Rúben voltou à cova, e eis que José não estava na cova; pelo que rasgou as suas vestes' },
      { v: 30, en: 'He returned to his brothers, and said, “The child is no more; and I, where will I go?”', pt: 'e, tornando a seus irmãos, disse: O menino não aparece; e eu, aonde irei?' },
      { v: 31, en: 'They took Joseph’s coat, and killed a male goat, and dipped the coat in the blood.', pt: 'Tomaram, então, a túnica de José, mataram um cabrito, e tingiram a túnica no sangue.' },
      { v: 32, en: 'They took the coat of many colors, and they brought it to their father, and said, “We have found this. Examine it, now, whether it is your son’s coat or not.”', pt: 'Enviaram a túnica de várias cores, mandando levá-la a seu pai e dizer-lhe: Achamos esta túnica; vê se é a túnica de teu filho, ou não.' },
      { v: 33, en: 'He recognized it, and said, “It is my son’s coat. An evil animal has devoured him. Joseph is without doubt torn in pieces.”', pt: 'Ele a reconheceu e exclamou: A túnica de meu filho! uma besta-fera o devorou; certamente José foi despedaçado.' },
      { v: 34, en: 'Jacob tore his clothes, and put sackcloth on his waist, and mourned for his son many days.', pt: 'Então Jacó rasgou as suas vestes, e pôs saco sobre os seus lombos e lamentou seu filho por muitos dias.' },
      { v: 35, en: 'All his sons and all his daughters rose up to comfort him, but he refused to be comforted. He said, “For I will go down to Sheol to my son mourning.” His father wept for him.', pt: 'E levantaram-se todos os seus filhos e todas as suas filhas, para o consolarem; ele, porém, recusou ser consolado, e disse: Na verdade, com choro hei de descer para meu filho até o Seol. Assim o chorou seu pai.' },
      { v: 36, en: 'The Midianites sold him into Egypt to Potiphar, an officer of Pharaoh’s, the captain of the guard.', pt: 'Os midianitas venderam José no Egito a Potifar, oficial de Faraó, capitão da guarda.' },
    ],
    38: [
      { v: 1, en: 'At that time, Judah went down from his brothers, and visited a certain Adullamite, whose name was Hirah.', pt: 'Nesse tempo Judá desceu de entre seus irmãos e entrou na casa dum adulamita, que se chamava Hira,' },
      { v: 2, en: 'Judah saw there a certain Canaanite man named Shua’s daughter. He took her, and went in to her.', pt: 'e viu Judá ali a filha de um cananeu, que se chamava Suá; tomou-a por mulher, e esteve com ela.' },
      { v: 3, en: 'She conceived, and bore a son; and he named him Er.', pt: 'Ela concebeu e teve um filho, e o pai chamou-lhe Er.' },
      { v: 4, en: 'She conceived again, and bore a son; and she named him Onan.', pt: 'Tornou ela a conceber e teve um filho, a quem ela chamou Onã.' },
      { v: 5, en: 'She yet again bore a son, and named him Shelah: and he was at Chezib, when she bore him.', pt: 'Teve ainda mais um filho, e chamou-lhe Selá. Estava Judá em Quezibe, quando ela o teve.' },
      { v: 6, en: 'Judah took a wife for Er, his firstborn, and her name was Tamar.', pt: 'Depois Judá tomou para Er, o seu primogênito, uma mulher, por nome Tamar.' },
      { v: 7, en: 'Er, Judah’s firstborn, was wicked in Yahweh’s sight. Yahweh killed him.', pt: 'Ora, Er, o primogênito de Judá, era mau aos olhos do Senhor, pelo que o Senhor o matou.' },
      { v: 8, en: 'Judah said to Onan, “Go in to your brother’s wife, and perform the duty of a husband’s brother to her, and raise up offspring for your brother.”', pt: 'Então disse Judá a Onã: Toma a mulher de teu irmão, e cumprindo-lhe o dever de cunhado, suscita descendência a teu irmão.' },
      { v: 9, en: 'Onan knew that the offspring wouldn’t be his; and when he went in to his brother’s wife, he spilled it on the ground, lest he should give offspring to his brother.', pt: 'Onã, porém, sabia que tal descendência não havia de ser para ele; de modo que, toda vez que se unia à mulher de seu irmão, derramava o sêmen no chão para não dar descendência a seu irmão.' },
      { v: 10, en: 'The thing which he did was evil in Yahweh’s sight, and he killed him also.', pt: 'E o que ele fazia era mau aos olhos do Senhor, pelo que o matou também a ele.' },
      { v: 11, en: 'Then Judah said to Tamar, his daughter-in-law, “Remain a widow in your father’s house, until Shelah, my son, is grown up”; for he said, “Lest he also die, like his brothers.” Tamar went and lived in her father’s house.', pt: 'Então disse Judá a Tamar sua nora: Conserva-te viúva em casa de teu pai, até que Selá, meu filho, venha a ser homem; porquanto disse ele: Para que porventura não morra também este, como seus irmãos. Assim se foi Tamar e morou em casa de seu pai.' },
      { v: 12, en: 'After many days, Shua’s daughter, the wife of Judah, died. Judah was comforted, and went up to his sheep shearers to Timnah, he and his friend Hirah, the Adullamite.', pt: 'Com o correr do tempo, morreu a filha de Suá, mulher de Judá. Depois de consolado, Judá subiu a Timnate para ir ter com os tosquiadores das suas ovelhas, ele e Hira seu amigo, o adulamita.' },
      { v: 13, en: 'Tamar was told, “Behold, your father-in-law is going up to Timnah to shear his sheep.”', pt: 'E deram aviso a Tamar, dizendo: Eis que o teu sogro sobe a Timnate para tosquiar as suas ovelhas.' },
      { v: 14, en: 'She took off her the garments of her widowhood, and covered herself with her veil, and wrapped herself, and sat in the gate of Enaim, which is by the way to Timnah; for she saw that Shelah was grown up, and she wasn’t given to him as a wife.', pt: 'Então ela se despiu dos vestidos da sua viuvez e se cobriu com o véu, e assim envolvida, assentou-se à porta de Enaim que está no caminho de Timnate; porque via que Selá já era homem, e ela lhe não fora dada por mulher.' },
      { v: 15, en: 'When Judah saw her, he thought that she was a prostitute, for she had covered her face.', pt: 'Ao vê-la, Judá julgou que era uma prostituta, porque ela havia coberto o rosto.' },
      { v: 16, en: 'He turned to her by the way, and said, “Please come, let me come in to you,” for he didn’t know that she was his daughter-in-law. She said, “What will you give me, that you may come in to me?”', pt: 'E dirigiu-se para ela no caminho, e disse: Vem, deixa-me estar contigo; porquanto não sabia que era sua nora. Perguntou-lhe ela: Que me darás, para estares comigo?' },
      { v: 17, en: 'He said, “I will send you a young goat from the flock.” She said, “Will you give me a pledge, until you send it?”', pt: 'Respondeu ele: Eu te enviarei um cabrito do rebanho. Perguntou ela ainda: Dar-me-ás um penhor até que o envies?' },
      { v: 18, en: 'He said, “What pledge will I give you?” She said, “Your signet and your cord, and your staff that is in your hand.” He gave them to her, and came in to her, and she conceived by him.', pt: 'Então ele respondeu: Que penhor é o que te darei? Disse ela: O teu selo com a corda, e o cajado que está em tua mão. Ele, pois, lhos deu, e esteve com ela, e ela concebeu dele.' },
      { v: 19, en: 'She arose, and went away, and put off her veil from her, and put on the garments of her widowhood.', pt: 'E ela se levantou e se foi; tirou de si o véu e vestiu os vestidos da sua viuvez.' },
      { v: 20, en: 'Judah sent the young goat by the hand of his friend, the Adullamite, to receive the pledge from the woman’s hand, but he didn’t find her.', pt: 'Depois Judá enviou o cabrito por mão do seu amigo o adulamita, para receber o penhor da mão da mulher; porém ele não a encontrou.' },
      { v: 21, en: 'Then he asked the men of her place, saying, “Where is the prostitute, that was at Enaim by the road?” They said, “There has been no prostitute here.”', pt: 'Pelo que perguntou aos homens daquele lugar: Onde está a prostituta que estava em Enaim junto ao caminho? E disseram: Aqui não esteve prostituta alguma.' },
      { v: 22, en: 'He returned to Judah, and said, “I haven’t found her; and also the men of the place said, ‘There has been no prostitute here.’”', pt: 'Voltou, pois, a Judá e disse: Não a achei; e também os homens daquele lugar disseram: Aqui não esteve prostituta alguma.' },
      { v: 23, en: 'Judah said, “Let her keep it, lest we be shamed. Behold, I sent this young goat, and you haven’t found her.”', pt: 'Então disse Judá: Deixa-a ficar com o penhor, para que não caiamos em desprezo; eis que enviei este cabrito, mas tu não a achaste.' },
      { v: 24, en: 'About three months later, Judah was told, “Tamar, your daughter-in-law, has played the prostitute. Moreover, behold, she is with child by prostitution.” Judah said, “Bring her out, and let her be burned.”', pt: 'Passados quase três meses, disseram a Judá: Tamar, tua nora, se prostituiu e eis que está grávida da sua prostituição. Então disse Judá: Tirai-a para fora, e seja ela queimada.' },
      { v: 25, en: 'When she was brought out, she sent to her father-in-law, saying, “By the man, whose these are, I am with child.” She also said, “Please discern whose are these—the signet, and the cords, and the staff.”', pt: 'Quando ela estava sendo tirada para fora, mandou dizer a seu sogro: Do homem a quem pertencem estas coisas eu concebi. Disse mais: Reconhece, peço-te, de quem são estes, o selo com o cordão, e o cajado.' },
      { v: 26, en: 'Judah acknowledged them, and said, “She is more righteous than I, because I didn’t give her to Shelah, my son.” He knew her again no more.', pt: 'Reconheceu-os, pois, Judá, e disse: Ela é mais justa do que eu, porquanto não a dei a meu filho Selá. E nunca mais a conheceu.' },
      { v: 27, en: 'In the time of her travail, behold, twins were in her womb.', pt: 'Sucedeu que, ao tempo de ela dar à luz, havia gêmeos em seu ventre;' },
      { v: 28, en: 'When she travailed, one put out a hand, and the midwife took and tied a scarlet thread on his hand, saying, “This came out first.”', pt: 'e dando ela à luz, um pôs fora a mão, e a parteira tomou um fio encarnado e o atou em sua mão, dizendo: Este saiu primeiro.' },
      { v: 29, en: 'As he drew back his hand, behold, his brother came out, and she said, “Why have you made a breach for yourself?” Therefore his name was called Perez.', pt: 'Mas recolheu ele a mão, e eis que seu irmão saiu; pelo que ela disse: Como tens tu rompido! Portanto foi chamado Pérez.' },
      { v: 30, en: 'Afterward his brother came out, that had the scarlet thread on his hand, and his name was called Zerah.', pt: 'Depois saiu o seu irmão, em cuja mão estava o fio encamado; e foi chamado Zerá.' },
    ],
    39: [
      { v: 1, en: 'Joseph was brought down to Egypt. Potiphar, an officer of Pharaoh’s, the captain of the guard, an Egyptian, bought him from the hand of the Ishmaelites that had brought him down there.', pt: 'José foi levado ao Egito; e Potifar, oficial de Faraó, capitão da guarda, egípcio, comprou-o da mão dos ismaelitas que o haviam levado para lá.' },
      { v: 2, en: 'Yahweh was with Joseph, and he was a prosperous man. He was in the house of his master the Egyptian.', pt: 'Mas o Senhor era com José, e ele tornou-se próspero; e estava na casa do seu senhor, o egípcio.' },
      { v: 3, en: 'His master saw that Yahweh was with him, and that Yahweh made all that he did prosper in his hand.', pt: 'E viu o seu senhor que Deus era com ele, e que fazia prosperar em sua mão tudo quanto ele empreendia.' },
      { v: 4, en: 'Joseph found favor in his sight. He ministered to him, and he made him overseer over his house, and all that he had he put into his hand.', pt: 'Assim José achou graça aos olhos dele, e o servia; de modo que o fez mordomo da sua casa, e entregou na sua mão tudo o que tinha.' },
      { v: 5, en: 'From the time that he made him overseer in his house, and over all that he had, Yahweh blessed the Egyptian’s house for Joseph’s sake. Yahweh’s blessing was on all that he had, in the house and in the field.', pt: 'Desde que o pôs como mordomo sobre a sua casa e sobre todos os seus bens, o Senhor abençoou a casa do egípcio por amor de José; e a bênção do Senhor estava sobre tudo o que tinha, tanto na casa como no campo.' },
      { v: 6, en: 'He left all that he had in Joseph’s hand. He didn’t concern himself with anything, except for the food which he ate. Joseph was well-built and handsome.', pt: 'Potifar deixou tudo na mão de José, de maneira que nada sabia do que estava com ele, a não ser do pão que comia. Ora, José era formoso de porte e de semblante.' },
      { v: 7, en: 'After these things, his master’s wife set her eyes on Joseph; and she said, “Lie with me.”', pt: 'E aconteceu depois destas coisas que a mulher do seu senhor pôs os olhos em José, e lhe disse: Deita-te comigo.' },
      { v: 8, en: 'But he refused, and said to his master’s wife, “Behold, my master doesn’t know what is with me in the house, and he has put all that he has into my hand.', pt: 'Mas ele recusou, e disse à mulher do seu senhor: Eis que o meu senhor não sabe o que está comigo na sua casa, e entregou em minha mão tudo o que tem;' },
      { v: 9, en: 'No one is greater in this house than I am, and he has not kept back anything from me but you, because you are his wife. How then can I do this great wickedness, and sin against God?”', pt: 'ele não é maior do que eu nesta casa; e nenhuma coisa me vedou, senão a ti, porquanto és sua mulher. Como, pois, posso eu cometer este grande mal, e pecar contra Deus?' },
      { v: 10, en: 'As she spoke to Joseph day by day, he didn’t listen to her, to lie by her, or to be with her.', pt: 'Entretanto, ela instava com José dia após dia; ele, porém, não lhe dava ouvidos, para se deitar com ela, ou estar com ela.' },
      { v: 11, en: 'About this time, he went into the house to do his work, and there were none of the men of the house inside.', pt: 'Mas sucedeu, certo dia, que entrou na casa para fazer o seu serviço; e nenhum dos homens da casa estava lá dentro.' },
      { v: 12, en: 'She caught him by his garment, saying, “Lie with me!” He left his garment in her hand, and ran outside.', pt: 'Então ela, pegando-o pela capa, lhe disse: Deita-te comigo! Mas ele, deixando a capa na mão dela, fugiu, escapando para fora.' },
      { v: 13, en: 'When she saw that he had left his garment in her hand, and had run outside,', pt: 'Quando ela viu que ele deixara a capa na mão dela e fugira para fora,' },
      { v: 14, en: 'she called to the men of her house, and spoke to them, saying, “Behold, he has brought a Hebrew in to us to mock us. He came in to me to lie with me, and I cried with a loud voice.', pt: 'chamou pelos homens de sua casa, e disse-lhes: Vede! meu marido trouxe-nos um hebreu para nos insultar; veio a mim para se deitar comigo, e eu gritei em alta voz;' },
      { v: 15, en: 'When he heard that I lifted up my voice and cried, he left his garment by me, and ran outside.”', pt: 'e ouvigiu-se para ela no caminho, e disse: Vem, deixa-me deixou, aqui a sua capa e fugiu, escapando para fora.' },
      { v: 16, en: 'She laid up his garment by her, until his master came home.', pt: 'Ela guardou a capa consigo, até que o senhor dele voltou a casa.' },
      { v: 17, en: 'She spoke to him according to these words, saying, “The Hebrew servant, whom you have brought to us, came in to me to mock me,', pt: 'Então falou-lhe conforme as mesmas palavras, dizendo: O servo hebreu, que nos trouxeste, veio a mim para me insultar;' },
      { v: 18, en: 'and as I lifted up my voice and cried, he left his garment by me, and ran outside.”', pt: 'mas, levantando eu a voz e gritando, ele deixou comigo a capa e fugiu para fora.' },
      { v: 19, en: 'When his master heard the words of his wife, which she spoke to him, saying, “This is what your servant did to me,” his wrath was kindled.', pt: 'Tendo o seu senhor ouvido as palavras de sua mulher, que lhe falava, dizendo: Desta maneira me fez teu servo, a sua ira se acendeu.' },
      { v: 20, en: 'Joseph’s master took him, and put him into the prison, the place where the king’s prisoners were bound, and he was there in custody.', pt: 'Então o senhor de José o tomou, e o lançou no cárcere, no lugar em que os presos do rei estavam encarcerados; e ele ficou ali no cárcere.' },
      { v: 21, en: 'But Yahweh was with Joseph, and showed kindness to him, and gave him favor in the sight of the keeper of the prison.', pt: 'O Senhor, porém, era com José, estendendo sobre ele a sua benignidade e dando-lhe graça aos olhos do carcereiro,' },
      { v: 22, en: 'The keeper of the prison committed to Joseph’s hand all the prisoners who were in the prison. Whatever they did there, he was responsible for it.', pt: 'o qual entregou na mão de José todos os presos que estavam no cárcere; e era José quem ordenava tudo o que se fazia ali.' },
      { v: 23, en: 'The keeper of the prison didn’t look after anything that was under his hand, because Yahweh was with him; and that which he did, Yahweh made it prosper.', pt: 'E o carcereiro não tinha cuidado de coisa alguma que estava na mão de José, porquanto o Senhor era com ele, fazendo prosperar tudo quanto ele empreendia.' },
    ],
    40: [
      { v: 1, en: 'After these things, the butler of the king of Egypt and his baker offended their lord, the king of Egypt.', pt: 'Depois destas coisas o copeiro do rei do Egito e o seu padeiro ofenderam o seu senhor, o rei do Egito.' },
      { v: 2, en: 'Pharaoh was angry with his two officers, the chief cup bearer and the chief baker.', pt: 'Pelo que se indignou Faraó contra os seus dois oficiais, contra o copeiro-mor e contra o padeiro-mor;' },
      { v: 3, en: 'He put them in custody in the house of the captain of the guard, into the prison, the place where Joseph was bound.', pt: 'e mandou detê-los na casa do capitão da guarda, no cárcere onde José estava preso;' },
      { v: 4, en: 'The captain of the guard assigned them to Joseph, and he took care of them. They stayed in prison many days.', pt: 'e o capitão da guarda pô-los a cargo de José, que os servia. Assim estiveram por algum tempo em detenção.' },
      { v: 5, en: 'They both dreamed a dream, each man his dream, in one night, each man according to the interpretation of his dream, the cup bearer and the baker of the king of Egypt, who were bound in the prison.', pt: 'Ora, tiveram ambos um sonho, cada um seu sonho na mesma noite, cada um conforme a interpretação do seu sonho, o copeiro e o padeiro do rei do Egito, que se achavam presos no cárcere:' },
      { v: 6, en: 'Joseph came in to them in the morning, and saw them, and saw that they were sad.', pt: 'Quando José veio a eles pela manhã, viu que estavam perturbados:' },
      { v: 7, en: 'He asked Pharaoh’s officers who were with him in custody in his master’s house, saying, “Why do you look so sad today?”', pt: 'Perguntou, pois, a esses oficiais de Faraó, que com ele estavam no cárcere da casa de seu senhor, dizendo: Por que estão os vossos semblantes tão tristes hoje?' },
      { v: 8, en: 'They said to him, “We have dreamed a dream, and there is no one who can interpret it.” Joseph said to them, “Don’t interpretations belong to God? Please tell it to me.”', pt: 'Responderam-lhe: Tivemos um sonho e ninguém há que o interprete. Pelo que lhes disse José: Porventura não pertencem a Deus as interpretações? Contai-mo, peço-vos.' },
      { v: 9, en: 'The chief cup bearer told his dream to Joseph, and said to him, “In my dream, behold, a vine was in front of me,', pt: 'Então contou o copeiro-mor o seu sonho a José, dizendo-lhe: Eis que em meu sonho havia uma vide diante de mim,' },
      { v: 10, en: 'and in the vine were three branches. It was as though it budded, it blossomed, and its clusters produced ripe grapes.', pt: 'e na vide três sarmentos; e, tendo a vide brotado, saíam as suas flores, e os seus cachos produziam uvas maduras.' },
      { v: 11, en: 'Pharaoh’s cup was in my hand; and I took the grapes, and pressed them into Pharaoh’s cup, and I gave the cup into Pharaoh’s hand.”', pt: 'O copo de Faraó estava na minha mão; e, tomando as uvas, eu as espremia no copo de Faraó e entregava o copo na mão de Faraó.' },
      { v: 12, en: 'Joseph said to him, “This is its interpretation: the three branches are three days.', pt: 'Então disse-lhe José: Esta é a sua interpretação: Os três sarmentos são três dias;' },
      { v: 13, en: 'Within three more days, Pharaoh will lift up your head, and restore you to your office. You will give Pharaoh’s cup into his hand, the way you did when you were his cup bearer.', pt: 'dentro de três dias Faraó levantará a tua cabeça, e te restaurará ao teu cargo; e darás o copo de Faraó na sua mão, conforme o costume antigo, quando eras seu copeiro.' },
      { v: 14, en: 'But remember me when it will be well with you, and please show kindness to me, and make mention of me to Pharaoh, and bring me out of this house.', pt: 'Mas lembra-te de mim, quando te for bem; usa, peço-te, de compaixão para comigo e faze menção de mim a Faraó e tira-me desta casa;' },
      { v: 15, en: 'For indeed, I was stolen away out of the land of the Hebrews, and here also I have done nothing that they should put me into the dungeon.”', pt: 'porque, na verdade, fui roubado da terra dos hebreus; e aqui também nada tenho feito para que me pusessem na masmorra.' },
      { v: 16, en: 'When the chief baker saw that the interpretation was good, he said to Joseph, “I also was in my dream, and behold, three baskets of white bread were on my head.', pt: 'Quando o padeiro-mor viu que a interpretação era boa, disse a José: Eu também sonhei, e eis que três cestos de pão branco estavam sobre a minha cabeça.' },
      { v: 17, en: 'In the uppermost basket there were all kinds of baked food for Pharaoh, and the birds ate them out of the basket on my head.”', pt: 'E no cesto mais alto havia para Faraó manjares de todas as qualidades que fazem os padeiros; e as aves os comiam do cesto que estava sobre a minha cabeça.' },
      { v: 18, en: 'Joseph answered, “This is its interpretation. The three baskets are three days.', pt: 'Então respondeu José: Esta é a interpretação do sonho: Os três cestos são três dias;' },
      { v: 19, en: 'Within three more days, Pharaoh will lift up your head from off you, and will hang you on a tree; and the birds will eat your flesh from off you.”', pt: 'dentro de três dias tirará Faraó a tua cabeça, e te pendurará num madeiro, e as aves comerão a tua carne de sobre ti.' },
      { v: 20, en: 'On the third day, which was Pharaoh’s birthday, he made a feast for all his servants, and he lifted up the head of the chief cup bearer and the head of the chief baker among his servants.', pt: 'E aconteceu ao terceiro dia, o dia natalício de Faraó, que este deu um banquete a todos os seus servos; e levantou a cabeça do copeiro-mor, e a cabeça do padeiro-mor no meio dos seus servos;' },
      { v: 21, en: 'He restored the chief cup bearer to his position again, and he gave the cup into Pharaoh’s hand;', pt: 'e restaurou o copeiro-mor ao seu cargo de copeiro, e este deu o copo na mão de Faraó;' },
      { v: 22, en: 'but he hanged the chief baker, as Joseph had interpreted to them.', pt: 'mas ao padeiro-mor enforcou, como José lhes havia interpretado.' },
      { v: 23, en: 'Yet the chief cup bearer didn’t remember Joseph, but forgot him.', pt: 'O copeiro-mor, porém, não se lembrou de José, antes se esqueceu dele.' },
    ],
    41: [
      { v: 1, en: 'At the end of two full years, Pharaoh dreamed: and behold, he stood by the river.', pt: 'Passados dois anos inteiros, Faraó sonhou que estava em pé junto ao rio Nilo;' },
      { v: 2, en: 'Behold, there came up out of the river seven cattle, sleek and fat, and they fed in the marsh grass.', pt: 'e eis que subiam do rio sete vacas, formosas à vista e gordas de carne, e pastavam no carriçal.' },
      { v: 3, en: 'Behold, seven other cattle came up after them out of the river, ugly and thin, and stood by the other cattle on the brink of the river.', pt: 'Após elas subiam do rio outras sete vacas, feias à vista e magras de carne; e paravam junto às outras vacas à beira do Nilo.' },
      { v: 4, en: 'The ugly and thin cattle ate up the seven sleek and fat cattle. So Pharaoh awoke.', pt: 'E as vacas feias à vista e magras de carne devoravam as sete formosas à vista e gordas. Então Faraó acordou.' },
      { v: 5, en: 'He slept and dreamed a second time: and behold, seven heads of grain came up on one stalk, healthy and good.', pt: 'Depois dormiu e tornou a sonhar; e eis que brotavam dum mesmo pé sete espigas cheias e boas.' },
      { v: 6, en: 'Behold, seven heads of grain, thin and blasted with the east wind, sprung up after them.', pt: 'Após elas brotavam sete espigas miúdas e queimadas do vento oriental;' },
      { v: 7, en: 'The thin heads of grain swallowed up the seven healthy and full ears. Pharaoh awoke, and behold, it was a dream.', pt: 'e as espigas miúdas devoravam as sete espigas grandes e cheias. Então Faraó acordou, e eis que era um sonho.' },
      { v: 8, en: 'In the morning, his spirit was troubled, and he sent and called for all of Egypt’s magicians and wise men. Pharaoh told them his dreams, but there was no one who could interpret them to Pharaoh.', pt: 'Pela manhã o seu espírito estava perturbado; pelo que mandou chamar todos os adivinhadores do Egito, e todos os seus sábios; e Faraó contou-lhes os seus sonhos, mas não havia quem lhos interpretasse.' },
      { v: 9, en: 'Then the chief cup bearer spoke to Pharaoh, saying, “I remember my faults today.', pt: 'Então falou o copeiro-mor a Faraó, dizendo: Dos meus pecados me lembro hoje:' },
      { v: 10, en: 'Pharaoh was angry with his servants, and put me in custody in the house of the captain of the guard, with the chief baker.', pt: 'Estando faraó mui indignado contra os seus servos, e pondo-me sob prisão na casa do captão da guarda, a mim e ao padeiro-mor.' },
      { v: 11, en: 'We dreamed a dream in one night, he and I. We dreamed each man according to the interpretation of his dream.', pt: 'Então sonhamos um sonho na mesma noite, eu e ele, cada um conforme a interpretação do seu sonho sonhamos.' },
      { v: 12, en: 'There was with us there a young man, a Hebrew, servant to the captain of the guard, and we told him, and he interpreted to us our dreams. To each man according to his dream he interpreted.', pt: 'Ora, estava ali conosco um mancebo hbreu, servo do capitão da guarda, ao qual contamos os nossos sonhos, e ele no-los interpretou, a cada um conforme o seu sonho.' },
      { v: 13, en: 'As he interpreted to us, so it was. He restored me to my office, and he hanged him.”', pt: 'E como ele nos interpretou, assim mesmo foi feito: a mim me fez tornar ao meu estado, e a ele fez enforcar.' },
      { v: 14, en: 'Then Pharaoh sent and called Joseph, and they brought him hastily out of the dungeon. He shaved himself, changed his clothing, and came in to Pharaoh.', pt: 'Então enviou Faraó, e chamou a José, e o fizeram sair logo da cova; e barbeou-se e mudou os seus vestidos, e veio a Faraó.' },
      { v: 15, en: 'Pharaoh said to Joseph, “I have dreamed a dream, and there is no one who can interpret it. I have heard it said of you, that when you hear a dream you can interpret it.”', pt: 'E Faraó disse a José: Eu sonhei um sonho, e ninguém há que o interprete; mas de ri ouvi dizer que quando ouves um sonho o interpretas.' },
      { v: 16, en: 'Joseph answered Pharaoh, saying, “It isn’t in me. God will give Pharaoh an answer of peace.”', pt: 'E respondeu José a Faraó, dizendo: Isso não está em mim; Deus dará resposta de paz a Faraó.' },
      { v: 17, en: 'Pharaoh spoke to Joseph, “In my dream, behold, I stood on the brink of the river:', pt: 'Então disse Faraó a José: Eis que em meu sonho estava em pé na praia do rio,' },
      { v: 18, en: 'and behold, there came up out of the river seven cattle, fat and sleek. They fed in the marsh grass,', pt: 'E eis que subiam do rio sete vacas gordas de carne e formosas à vista, e pastavam no prado.' },
      { v: 19, en: 'and behold, seven other cattle came up after them, poor and very ugly and thin, such as I never saw in all the land of Egypt for ugliness.', pt: 'E eis que outras sete vacas subiam após estas, muito feias à vista, e magras de carne; não tenho visto outras taus, quanto à fealdade, em toda a terra do Egito' },
      { v: 20, en: 'The thin and ugly cattle ate up the first seven fat cattle,', pt: 'E as vacas magras e feias comiam as primeiras sete vacas gordas;' },
      { v: 21, en: 'and when they had eaten them up, it couldn’t be known that they had eaten them, but they were still ugly, as at the beginning. So I awoke.', pt: 'E entravam em suas entranhas, mas não se conhecia que houvessem entrado em suas entranhas; porque o seu parecer era feio como no principio. Então acordei.' },
      { v: 22, en: 'I saw in my dream, and behold, seven heads of grain came up on one stalk, full and good:', pt: 'Depois vi em meu sonho, e eis que dum mesmo pé subiam sete espigas cheias e boas;' },
      { v: 23, en: 'and behold, seven heads of grain, withered, thin, and blasted with the east wind, sprung up after them.', pt: 'E eis que sete espigas secas, miúdas e queimadas do vento oriental brotavam após elas.' },
      { v: 24, en: 'The thin heads of grain swallowed up the seven good heads of grain. I told it to the magicians, but there was no one who could explain it to me.”', pt: 'E as sete espigas miudas devoravam as sete espigas boas. E eu disse-o aos magos, mas ninguém houve que mo interpretasse.' },
      { v: 25, en: 'Joseph said to Pharaoh, “The dream of Pharaoh is one. What God is about to do he has declared to Pharaoh.', pt: 'Então disse José a Faraó: O sonho de Faraó é um só; o que Deus há de fazer, notificou-o a Faraó.' },
      { v: 26, en: 'The seven good cattle are seven years; and the seven good heads of grain are seven years. The dream is one.', pt: 'As sete vacas formosas são sete anos; as sete espigas formosas também são sete anos; o sonho é um só.' },
      { v: 27, en: 'The seven thin and ugly cattle that came up after them are seven years, and also the seven empty heads of grain blasted with the east wind; they will be seven years of famine.', pt: 'E as sete vacas magras e feias à vista, que subiam depois delas, são sete anos, como as sete espigas miúdas e queimadas do vento oriental; serão sete anos de fome.' },
      { v: 28, en: 'That is the thing which I spoke to Pharaoh. What God is about to do he has shown to Pharaoh.', pt: 'Esta é a palavra que tenho dito a Faraó; o que Deus há de fazer, mostrou-o a Faraó.' },
      { v: 29, en: 'Behold, there come seven years of great plenty throughout all the land of Egypt.', pt: 'E eis que vêm sete anos, e haverá grande fartura em toda a terra do Egito' },
      { v: 30, en: 'There will arise after them seven years of famine, and all the plenty will be forgotten in the land of Egypt. The famine will consume the land,', pt: 'E depois deles levantar-se-ão sete anos de fome, e toda aquela fartura será esquecida na terra do Egito, e a fome consumirá a terra:' },
      { v: 31, en: 'and the plenty will not be known in the land by reason of that famine which follows; for it will be very grievous.', pt: 'e não será conhecida a abundância na terra, por causa daquela fome que seguirá; porquanto será gravíssima.' },
      { v: 32, en: 'The dream was doubled to Pharaoh, because the thing is established by God, and God will shortly bring it to pass.', pt: 'Ora, se o sonho foi duplicado a Faraó, é porque esta coisa é determinada por Deus, e ele brevemente a fará.' },
      { v: 33, en: '“Now therefore let Pharaoh look for a discreet and wise man, and set him over the land of Egypt.', pt: 'Portanto, proveja-se agora Faraó de um homem entendido e sábio, e o ponha sobre a terra do Egito.' },
      { v: 34, en: 'Let Pharaoh do this, and let him appoint overseers over the land, and take up the fifth part of the land of Egypt’s produce in the seven plenteous years.', pt: 'Faça isto Faraó: nomeie administradores sobre a terra, que tomem a quinta parte dos produtos da terra do Egito nos sete anos de fartura;' },
      { v: 35, en: 'Let them gather all the food of these good years that come, and lay up grain under the hand of Pharaoh for food in the cities, and let them keep it.', pt: 'e ajuntem eles todo o mantimento destes bons anos que vêm, e amontoem trigo debaixo da mão de Faraó, para mantimento nas cidades e o guardem;' },
      { v: 36, en: 'The food will be for a store to the land against the seven years of famine, which will be in the land of Egypt; that the land not perish through the famine.”', pt: 'assim será o mantimento para provimento da terra, para os sete anos de fome, que haverá na terra do Egito; para que a terra não pereça de fome.' },
      { v: 37, en: 'The thing was good in the eyes of Pharaoh, and in the eyes of all his servants.', pt: 'Esse parecer foi bom aos olhos de Faraó, e aos olhos de todos os seus servos.' },
      { v: 38, en: 'Pharaoh said to his servants, “Can we find such a one as this, a man in whom is the Spirit of God?”', pt: 'Perguntou, pois, Faraó a seus servos: Poderíamos achar um homem como este, em quem haja o espírito de Deus?' },
      { v: 39, en: 'Pharaoh said to Joseph, “Because God has shown you all of this, there is no one so discreet and wise as you.', pt: 'Depois disse Faraó a José: Porquanto Deus te fez saber tudo isto, ninguém há tão entendido e sábio como tu.' },
      { v: 40, en: 'You shall be over my house, and according to your word will all my people be ruled. Only in the throne I will be greater than you.”', pt: 'Tu estarás sobre a minha casa, e por tua voz se governará todo o meu povo; somente no trono eu serei maior que tu.' },
      { v: 41, en: 'Pharaoh said to Joseph, “Behold, I have set you over all the land of Egypt.”', pt: 'Disse mais Faraó a José: Vê, eu te hei posto sobre toda a terra do Egito.' },
      { v: 42, en: 'Pharaoh took off his signet ring from his hand, and put it on Joseph’s hand, and arrayed him in robes of fine linen, and put a gold chain about his neck,', pt: 'E Faraó tirou da mão o seu anel-sinete e pô-lo na mão de José, vestiu-o de traje de linho fino, e lhe pôs ao pescoço um colar de ouro.' },
      { v: 43, en: 'and he made him to ride in the second chariot which he had. They cried before him, “Bow the knee!” He set him over all the land of Egypt.', pt: 'Ademais, fê-lo subir ao seu segundo carro, e clamavam diante dele: Ajoelhai-vos. Assim Faraó o constituiu sobre toda a terra do Egito.' },
      { v: 44, en: 'Pharaoh said to Joseph, “I am Pharaoh, and without you shall no man lift up his hand or his foot in all the land of Egypt.”', pt: 'Ainda disse Faraó a José: Eu sou Faraó; sem ti, pois, ninguém levantará a mão ou o pé em toda a terra do Egito.' },
      { v: 45, en: 'Pharaoh called Joseph’s name Zaphenath-Paneah; and he gave him Asenath, the daughter of Potiphera priest of On as a wife. Joseph went out over the land of Egypt.', pt: 'Faraó chamou a José Zafnate-Paneã, e deu-lhe por mulher Asenate, filha de Potífera, sacerdote de Om. Depois saiu José por toda a terra do Egito.' },
      { v: 46, en: 'Joseph was thirty years old when he stood before Pharaoh king of Egypt. Joseph went out from the presence of Pharaoh, and went throughout all the land of Egypt.', pt: 'Ora, José era da idade de trinta anos, quando se apresentou a Faraó, rei do Egito. E saiu José da presença de Faraó e passou por toda a terra do Egito.' },
      { v: 47, en: 'In the seven plenteous years the earth produced abundantly.', pt: 'Durante os sete anos de fartura a terra produziu a mancheias;' },
      { v: 48, en: 'He gathered up all the food of the seven years which were in the land of Egypt, and laid up the food in the cities: the food of the field, which was around every city, he laid up in the same.', pt: 'e José ajuntou todo o mantimento dos sete anos, que houve na terra do Egito, e o guardou nas cidades; o mantimento do campo que estava ao redor de cada cidade, guardou-o dentro da mesma.' },
      { v: 49, en: 'Joseph laid up grain as the sand of the sea, very much, until he stopped counting, for it was without number.', pt: 'Assim José ajuntou muitíssimo trigo, como a areia do mar, até que cessou de contar; porque não se podia mais contá-lo.' },
      { v: 50, en: 'To Joseph were born two sons before the year of famine came, whom Asenath, the daughter of Potiphera priest of On, bore to him.', pt: 'Antes que viesse o ano da fome, nasceram a José dois filhos, que lhe deu Asenate, filha de Potífera, sacerdote de Om.' },
      { v: 51, en: 'Joseph called the name of the firstborn Manasseh, “For”, he said, “God has made me forget all my toil, and all my father’s house.”', pt: 'E chamou José ao primogênito Manassés; porque disse: Deus me fez esquecer de todo o meu trabalho, e de toda a casa de meu pai.' },
      { v: 52, en: 'The name of the second, he called Ephraim : “For God has made me fruitful in the land of my affliction.”', pt: 'Ao segundo chamou Efraim; porque disse: Deus me fez crescer na terra da minha aflição.' },
      { v: 53, en: 'The seven years of plenty, that were in the land of Egypt, came to an end.', pt: 'Acabaram-se, então, os sete anos de fartura que houve na terra do Egito;' },
      { v: 54, en: 'The seven years of famine began to come, just as Joseph had said. There was famine in all lands, but in all the land of Egypt there was bread.', pt: 'e começaram a vir os sete anos de fome, como José tinha dito; e havia fome em todas as terras; porém, em toda a terra do Egito havia pão.' },
      { v: 55, en: 'When all the land of Egypt was famished, the people cried to Pharaoh for bread, and Pharaoh said to all the Egyptians, “Go to Joseph. What he says to you, do.”', pt: 'Depois toda a terra do Egito teve fome, e o povo clamou a Faraó por pão; e Faraó disse a todos os egípcios: Ide a José; o que ele vos disser, fazei.' },
      { v: 56, en: 'The famine was over all the surface of the earth. Joseph opened all the store houses, and sold to the Egyptians. The famine was severe in the land of Egypt.', pt: 'De modo que, havendo fome sobre toda a terra, abriu José todos os depósitos, e vendia aos egípcios; porque a fome prevaleceu na terra do Egito.' },
      { v: 57, en: 'All countries came into Egypt, to Joseph, to buy grain, because the famine was severe in all the earth.', pt: 'Também de todas as terras vinham ao Egito, para comprarem de José; porquanto a fome prevaleceu em todas as terras.' },
    ],
    42: [
      { v: 1, en: 'Now Jacob saw that there was grain in Egypt, and Jacob said to his sons, “Why do you look at one another?”', pt: 'Ora, Jacó soube que havia trigo no Egito, e disse a seus filhos: Por que estais olhando uns para os outros?' },
      { v: 2, en: 'He said, “Behold, I have heard that there is grain in Egypt. Go down there, and buy for us from there, so that we may live, and not die.”', pt: 'Disse mais: Tenho ouvido que há trigo no Egito; descei até lá, e de lá comprai-o para nós, a fim de que vivamos e não morramos.' },
      { v: 3, en: 'Joseph’s ten brothers went down to buy grain from Egypt.', pt: 'Então desceram os dez irmãos de José, para comprarem trigo no Egito.' },
      { v: 4, en: 'But Jacob didn’t send Benjamin, Joseph’s brother, with his brothers; for he said, “Lest perhaps harm happen to him.”', pt: 'Mas a Benjamim, irmão de José, não enviou Jacó com os seus irmãos, pois disse: Para que, porventura, não lhe suceda algum desastre.' },
      { v: 5, en: 'The sons of Israel came to buy among those who came, for the famine was in the land of Canaan.', pt: 'Assim entre os que iam lá, foram os filhos de Israel para comprar, porque havia fome na terra de Canaã.' },
      { v: 6, en: 'Joseph was the governor over the land. It was he who sold to all the people of the land. Joseph’s brothers came, and bowed themselves down to him with their faces to the earth.', pt: 'José era o governador da terra; era ele quem vendia a todo o povo da terra; e vindo os irmãos de José, prostraram-se diante dele com o rosto em terra.' },
      { v: 7, en: 'Joseph saw his brothers, and he recognized them, but acted like a stranger to them, and spoke roughly with them. He said to them, “Where did you come from?” They said, “From the land of Canaan to buy food.”', pt: 'José, vendo seus irmãos, reconheceu-os; mas portou-se como estranho para com eles, falou-lhes asperamente e perguntou-lhes: Donde vindes? Responderam eles: Da terra de Canaã, para comprarmos mantimento.' },
      { v: 8, en: 'Joseph recognized his brothers, but they didn’t recognize him.', pt: 'José, pois, reconheceu seus irmãos, mas eles não o reconheceram.' },
      { v: 9, en: 'Joseph remembered the dreams which he dreamed about them, and said to them, “You are spies! You have come to see the nakedness of the land.”', pt: 'Lembrou-se então José dos sonhos que tivera a respeito deles, e disse-lhes: Vós sois espias, e viestes para ver a nudez da terra.' },
      { v: 10, en: 'They said to him, “No, my lord, but your servants have come to buy food.', pt: 'Responderam-lhe eles: Não, senhor meu; mas teus servos vieram comprar mantimento.' },
      { v: 11, en: 'We are all one man’s sons; we are honest men. Your servants are not spies.”', pt: 'Nós somos todos filhos de um mesmo homem; somos homens de retidão; os teus servos não são espias.' },
      { v: 12, en: 'He said to them, “No, but you have come to see the nakedness of the land!”', pt: 'Replicou-lhes: Não; antes viestes para ver a nudez da terra.' },
      { v: 13, en: 'They said, “We, your servants, are twelve brothers, the sons of one man in the land of Canaan; and behold, the youngest is today with our father, and one is no more.”', pt: 'Mas eles disseram: Nós, teus servos, somos doze irmãos, filhos de um homem da terra de Canaã; o mais novo está hoje com nosso pai, e outro já não existe.' },
      { v: 14, en: 'Joseph said to them, “It is like I told you, saying, ‘You are spies!’', pt: 'Respondeu-lhe José: É assim como vos disse; sois espias.' },
      { v: 15, en: 'By this you shall be tested. By the life of Pharaoh, you shall not go out from here, unless your youngest brother comes here.', pt: 'Nisto sereis provados: Pela vida de Faraó, não saireis daqui, a menos que venha para cá vosso irmão mais novo.' },
      { v: 16, en: 'Send one of you, and let him get your brother, and you shall be bound, that your words may be tested, whether there is truth in you, or else by the life of Pharaoh surely you are spies.”', pt: 'Enviai um dentre vós, que traga vosso irmão, mas vós ficareis presos, a fim de serem provadas as vossas palavras, se há verdade convosco; e se não, pela vida de Faraó, vós sois espias.' },
      { v: 17, en: 'He put them all together into custody for three days.', pt: 'E meteu-os juntos na prisão por três dias.' },
      { v: 18, en: 'Joseph said to them the third day, “Do this, and live, for I fear God.', pt: 'Ao terceiro dia disse-lhes José: Fazei isso, e vivereis; porque eu temo a Deus.' },
      { v: 19, en: 'If you are honest men, then let one of your brothers be bound in your prison; but you go, carry grain for the famine of your houses.', pt: 'Se sois homens de retidão, que fique um dos irmãos preso na casa da vossa prisão; mas ide vós, levai trigo para a fome de vossas casas,' },
      { v: 20, en: 'Bring your youngest brother to me; so will your words be verified, and you won’t die.” They did so.', pt: 'e trazei-me o vosso irmão mais novo; assim serão verificadas vossas palavras, e não morrereis. E eles assim fizeram.' },
      { v: 21, en: 'They said to one another, “We are certainly guilty concerning our brother, in that we saw the distress of his soul, when he begged us, and we wouldn’t listen. Therefore this distress has come upon us.”', pt: 'Então disseram uns aos outros: Nós, na verdade, somos culpados no tocante a nosso irmão, porquanto vimos a angústia da sua alma, quando nos rogava, e não o quisemos atender; é por isso que vem sobre nós esta angústia.' },
      { v: 22, en: 'Reuben answered them, saying, “Didn’t I tell you, saying, ‘Don’t sin against the child,’ and you wouldn’t listen? Therefore also, behold, his blood is required.”', pt: 'Respondeu-lhes Rúben: Não vos dizia eu: Não pequeis contra o menino; Mas não quisestes ouvir; por isso agora é requerido de nós o seu sangue.' },
      { v: 23, en: 'They didn’t know that Joseph understood them; for there was an interpreter between them.', pt: 'E eles não sabiam que José os entendia, porque havia intérprete entre eles.' },
      { v: 24, en: 'He turned himself away from them, and wept. Then he returned to them, and spoke to them, and took Simeon from among them, and bound him before their eyes.', pt: 'Nisto José se retirou deles e chorou. Depois tornou a eles, falou-lhes, e tomou a Simeão dentre eles, e o amarrou perante os seus olhos.' },
      { v: 25, en: 'Then Joseph gave a command to fill their bags with grain, and to restore each man’s money into his sack, and to give them food for the way. So it was done to them.', pt: 'Então ordenou José que lhes enchessem de trigo os sacos, que lhes restituíssem o dinheiro a cada um no seu saco, e lhes dessem provisões para o caminho. E assim lhes foi feito.' },
      { v: 26, en: 'They loaded their donkeys with their grain, and departed from there.', pt: 'Eles, pois, carregaram o trigo sobre os seus jumentos, e partiram dali.' },
      { v: 27, en: 'As one of them opened his sack to give his donkey food in the lodging place, he saw his money. Behold, it was in the mouth of his sack.', pt: 'Quando um deles abriu o saco, para dar forragem ao seu jumento na estalagem, viu o seu dinheiro, pois estava na boca do saco.' },
      { v: 28, en: 'He said to his brothers, “My money is restored! Behold, it is in my sack!” Their hearts failed them, and they turned trembling to one another, saying, “What is this that God has done to us?”', pt: 'E disse a seus irmãos: Meu dinheiro foi-me devolvido; ei-lo aqui no saco. Então lhes desfaleceu o coração e, tremendo, viravam-se uns para os outros, dizendo: Que é isto que Deus nos tem feito?' },
      { v: 29, en: 'They came to Jacob their father, to the land of Canaan, and told him all that had happened to them, saying,', pt: 'Depois vieram para Jacó, seu pai, na terra de Canaã, e contaram-lhe tudo o que lhes acontecera, dizendo:' },
      { v: 30, en: '“The man, the lord of the land, spoke roughly with us, and took us for spies of the country.', pt: 'O homem, o senhor da terra, falou-nos asperamente, e tratou-nos como espias da terra;' },
      { v: 31, en: 'We said to him, ‘We are honest men. We are no spies.', pt: 'mas dissemos-lhe: Somos homens de retidão; não somos espias;' },
      { v: 32, en: 'We are twelve brothers, sons of our father; one is no more, and the youngest is today with our father in the land of Canaan.’', pt: 'somos doze irmãos, filhos de nosso pai; um já não existe e o mais novo está hoje com nosso pai na terra de Canaã.' },
      { v: 33, en: 'The man, the lord of the land, said to us, ‘By this I will know that you are honest men: leave one of your brothers with me, and take grain for the famine of your houses, and go your way.', pt: 'Respondeu-nos o homem, o senhor da terra: Nisto conhecerei que vós sois homens de retidão: Deixai comigo um de vossos irmãos, levai trigo para a fome de vossas casas, e parti,' },
      { v: 34, en: 'Bring your youngest brother to me. Then I will know that you are not spies, but that you are honest men. So I will deliver your brother to you, and you shall trade in the land.’”', pt: 'e trazei-me vosso irmão mais novo; assim saberei que não sois espias, mas homens de retidão; então vos entregarei o vosso irmão e negociareis na terra.' },
      { v: 35, en: 'As they emptied their sacks, behold, each man’s bundle of money was in his sack. When they and their father saw their bundles of money, they were afraid.', pt: 'E aconteceu que, despejando eles os sacos, eis que o pacote de dinheiro de cada um estava no seu saco; quando eles e seu pai viram os seus pacotes de dinheiro, tiveram medo.' },
      { v: 36, en: 'Jacob, their father, said to them, “You have bereaved me of my children! Joseph is no more, Simeon is no more, and you want to take Benjamin away. All these things are against me.”', pt: 'Então Jacó, seu pai, disse-lhes: Tendes-me desfilhado; José já não existe, e não existe Simeão, e haveis de levar Benjamim! Todas estas coisas vieram sobre mim.' },
      { v: 37, en: 'Reuben spoke to his father, saying, “Kill my two sons, if I don’t bring him to you. Entrust him to my care, and I will bring him to you again.”', pt: 'Mas Rúben falou a seu pai, dizendo: Mata os meus dois filhos, se eu to não tornar a trazer; entrega-o em minha mão, e to tornarei a trazer.' },
      { v: 38, en: 'He said, “My son shall not go down with you; for his brother is dead, and he only is left. If harm happens to him along the way in which you go, then you will bring down my gray hairs with sorrow to Sheol.”', pt: 'Ele porém disse: Não descerá meu filho convosco; porquanto o seu irmão é morto, e só ele ficou. Se lhe suceder algum desastre pelo caminho em que fordes, fareis descer minhas cãs com tristeza ao Seol.' },
    ],
    43: [
      { v: 1, en: 'The famine was severe in the land.', pt: 'Ora, a fome era gravíssima na terra.' },
      { v: 2, en: 'When they had eaten up the grain which they had brought out of Egypt, their father said to them, “Go again, buy us a little more food.”', pt: 'Tendo eles acabado de comer o mantimento que trouxeram do Egito, disse-lhes seu pai: voltai, comprai-nos um pouco de alimento.' },
      { v: 3, en: 'Judah spoke to him, saying, “The man solemnly warned us, saying, ‘You shall not see my face, unless your brother is with you.’', pt: 'Mas respondeu-lhe Judá: Expressamente nos advertiu o homem, dizendo: Não vereis a minha face, se vosso irmão não estiver convosco.' },
      { v: 4, en: 'If you’ll send our brother with us, we’ll go down and buy you food,', pt: 'Se queres enviar conosco o nosso irmão, desceremos e te compraremos alimento; mas se não queres enviá-lo, não desceremos, porquanto o homem nos disse: Não vereis a minha face, se vosso irmão não estiver convosco.' },
      { v: 5, en: 'but if you’ll not send him, we’ll not go down, for the man said to us, ‘You shall not see my face, unless your brother is with you.’”', pt: 'Perguntou Israel: Por que me fizeste este mal, fazendo saber ao homem que tínheis ainda outro irmão?' },
      { v: 6, en: 'Israel said, “Why did you treat me so badly, telling the man that you had another brother?”', pt: 'Responderam eles: O homem perguntou particularmente por nós, e pela nossa parentela, dizendo: vive ainda vosso pai? tendes mais um irmão? e respondemos-lhe segundo o teor destas palavras. Podíamos acaso saber que ele diria: Trazei vosso irmão?' },
      { v: 7, en: 'They said, “The man asked directly concerning ourselves, and concerning our relatives, saying, ‘Is your father still alive? Have you another brother?’ We just answered his questions. Is there any way we could know that he would say, ‘Bring your brother down?’”', pt: 'Então disse Judá a Israel, seu pai: Envia o mancebo comigo, e levantar-nos-emos e iremos, para que vivamos e não morramos, nem nós, nem tu, nem nossos filhinhos.' },
      { v: 8, en: 'Judah said to Israel, his father, “Send the boy with me, and we’ll get up and go, so that we may live, and not die, both we, and you, and also our little ones.', pt: 'Eu serei fiador por ele; da minha mão o requererás. Se eu to não trouxer, e o não puser diante de ti, serei réu de crime para contigo para sempre.' },
      { v: 9, en: 'I’ll be collateral for him. From my hand will you require him. If I don’t bring him to you, and set him before you, then let me bear the blame forever,', pt: 'E se não nos tivéssemos demorado, certamente já segunda vez estaríamos de volta.' },
      { v: 10, en: 'for if we hadn’t delayed, surely we would have returned a second time by now.”', pt: 'Então disse-lhes Israel seu pai: Se é sim, fazei isto: tomai os melhores produtos da terra nas vossas vasilhas, e levai ao homem um presente: um pouco de bálsamo e um pouco de mel, tragacanto e mirra, nozes de fístico e amêndoas;' },
      { v: 11, en: 'Their father, Israel, said to them, “If it must be so, then do this. Take from the choice fruits of the land in your bags, and carry down a present for the man, a little balm, a little honey, spices and myrrh, nuts, and almonds;', pt: 'levai em vossas mãos dinheiro em dobro; e o dinheiro que foi devolvido na boca dos vossos sacos, tornai a levá-lo em vossas mãos; bem pode ser que fosse engano.' },
      { v: 12, en: 'and take double money in your hand, and take back the money that was returned in the mouth of your sacks. Perhaps it was an oversight.', pt: 'Levai também vosso irmão; levantai-vos e voltai ao homem;' },
      { v: 13, en: 'Take your brother also, get up, and return to the man.', pt: 'e Deus Todo-Poderoso vos dê misericórdia diante do homem, para que ele deixe vir convosco vosso outro irmão, e Benjamim; e eu, se for desfilhado, desfilhado ficarei.' },
      { v: 14, en: 'May God Almighty give you mercy before the man, that he may release to you your other brother and Benjamin. If I am bereaved of my children, I am bereaved.”', pt: 'Tomaram, pois, os homens aquele presente, e dinheiro em dobro nas mãos, e a Benjamim; e, levantando-se desceram ao Egito e apresentaram-se diante de José.' },
      { v: 15, en: 'The men took that present, and they took double money in their hand, and Benjamin; and got up, went down to Egypt, and stood before Joseph.', pt: 'Quando José viu Benjamim com eles, disse ao despenseiro de sua casa: Leva os homens à casa, mata reses, e apronta tudo; pois eles comerão comigo ao meio-dia.' },
      { v: 16, en: 'When Joseph saw Benjamin with them, he said to the steward of his house, “Bring the men into the house, and butcher an animal, and prepare; for the men will dine with me at noon.”', pt: 'E o homem fez como José ordenara, e levou-os à casa de José.' },
      { v: 17, en: 'The man did as Joseph commanded, and the man brought the men to Joseph’s house.', pt: 'Então os homens tiveram medo, por terem sido levados à casa de José; e diziam: por causa do dinheiro que da outra vez foi devolvido nos nossos sacos que somos trazidos aqui, para nos criminar e cair sobre nós, para que nos tome por servos, tanto a nós como a nossos jumentos.' },
      { v: 18, en: 'The men were afraid, because they were brought to Joseph’s house; and they said, “Because of the money that was returned in our sacks the first time, we’re brought in; that he may seek occasion against us, attack us, and seize us as slaves, along with our donkeys.”', pt: 'Por isso eles se chegaram ao despenseiro da casa de José, e falaram com ele à porta da casa,' },
      { v: 19, en: 'They came near to the steward of Joseph’s house, and they spoke to him at the door of the house,', pt: 'e disseram: Ai! senhor meu, na verdade descemos dantes a comprar mantimento;' },
      { v: 20, en: 'and said, “Oh, my lord, we indeed came down the first time to buy food.', pt: 'e quando chegamos à estalagem, abrimos os nossos sacos, e eis que o dinheiro de cada um estava na boca do seu saco, nosso dinheiro por seu peso; e tornamos a trazê-lo em nossas mãos;' },
      { v: 21, en: 'When we came to the lodging place, we opened our sacks, and behold, each man’s money was in the mouth of his sack, our money in full weight. We have brought it back in our hand.', pt: 'também trouxemos outro dinheiro em nossas mãos, para comprar mantimento; não sabemos quem tenha posto o dinheiro em nossos sacos.' },
      { v: 22, en: 'We have brought down other money in our hand to buy food. We don’t know who put our money in our sacks.”', pt: 'Respondeu ele: Paz seja convosco, não temais; o vosso Deus, e o Deus de vosso pai, deu-vos um tesouro nos vossos sacos; o vosso dinheiro chegou-me às mãos. E trouxe-lhes fora Simeão.' },
      { v: 23, en: 'He said, “Peace be to you. Don’t be afraid. Your God, and the God of your father, has given you treasure in your sacks. I received your money.” He brought Simeon out to them.', pt: 'Depois levou os homens à casa de José, e deu-lhes ãgua, e eles lavaram os pés; também deu forragem aos seus jumentos.' },
      { v: 24, en: 'The man brought the men into Joseph’s house, and gave them water, and they washed their feet. He gave their donkeys fodder.', pt: 'Então eles prepararam o presente para quando José viesse ao meio-dia; porque tinham ouvido que ali haviam de comer.' },
      { v: 25, en: 'They prepared the present for Joseph’s coming at noon, for they heard that they should eat bread there.', pt: 'Quando José chegou em casa, trouxeram-lhe ali o presente que guardavam junto de si; e inclinaram-se a ele até a terra.' },
      { v: 26, en: 'When Joseph came home, they brought him the present which was in their hand into the house, and bowed themselves down to the earth before him.', pt: 'Então ele lhes perguntou como estavam; e prosseguiu: vosso pai, o ancião de quem falastes, está bem? ainda vive?' },
      { v: 27, en: 'He asked them of their welfare, and said, “Is your father well, the old man of whom you spoke? Is he yet alive?”', pt: 'Responderam eles: O teu servo, nosso pai, estã bem; ele ainda vive. E abaixaram a cabeça, e inclinaram-se.' },
      { v: 28, en: 'They said, “Your servant, our father, is well. He is still alive.” They bowed down humbly.', pt: 'Levantando os olhos, José viu a Benjamim, seu irmão, filho de sua mãe, e perguntou: É este o vosso irmão mais novo de quem me falastes? E disse: Deus seja benévolo para contigo, meu filho.' },
      { v: 29, en: 'He lifted up his eyes, and saw Benjamin, his brother, his mother’s son, and said, “Is this your youngest brother, of whom you spoke to me?” He said, “God be gracious to you, my son.”', pt: 'E José apressou-se, porque se lhe comoveram as entranhas por causa de seu irmão, e procurou onde chorar; e, entrando na sua câmara, chorou ali.' },
      { v: 30, en: 'Joseph hurried, for his heart yearned over his brother; and he sought a place to weep. He entered into his room, and wept there.', pt: 'Depois lavou o rosto, e saiu; e se conteve e disse: Servi a comida.' },
      { v: 31, en: 'He washed his face, and came out. He controlled himself, and said, “Serve the meal.”', pt: 'Serviram-lhe, pois, a ele à parte, e a eles também à parte, e à parte aos egípcios que comiam com ele; porque os egípcios não podiam comer com os hebreus, porquanto é isso abominação aos egípcios.' },
      { v: 32, en: 'They served him by himself, and them by themselves, and the Egyptians, that ate with him, by themselves, because the Egyptians don’t eat bread with the Hebrews, for that is an abomination to the Egyptians.', pt: 'Sentaram-se diante dele, o primogênito segundo a sua primogenitura, e o menor segundo a sua menoridade; do que os homens se maravilhavam entre si.' },
      { v: 33, en: 'They sat before him, the firstborn according to his birthright, and the youngest according to his youth, and the men marveled one with another.', pt: 'Então ele lhes apresentou as porções que estavam diante dele; mas a porção de Benjamim era cinco vezes maior do que a de qualquer deles. E eles beberam, e se regalaram com ele.' },
      { v: 34, en: 'He sent portions to them from before him, but Benjamin’s portion was five times as much as any of theirs. They drank, and were merry with him.', pt: 'He sent portions to them from before him, but Benjamin’s portion was five times as much as any of theirs. They drank, and were merry with him.' },
    ],
    44: [
      { v: 1, en: 'He commanded the steward of his house, saying, “Fill the men’s sacks with food, as much as they can carry, and put each man’s money in his sack’s mouth.', pt: 'Depois José deu ordem ao despenseiro de sua casa, dizendo: Enche de mantimento os sacos dos homens, quanto puderem levar, e põe o dinheiro de cada um na boca do seu saco.' },
      { v: 2, en: 'Put my cup, the silver cup, in the sack’s mouth of the youngest, with his grain money.” He did according to the word that Joseph had spoken.', pt: 'E a minha taça de prata porãs na boca do saco do mais novo, com o dinheiro do seu trigo. Assim fez ele conforme a palavra que José havia dito.' },
      { v: 3, en: 'As soon as the morning was light, the men were sent away, they and their donkeys.', pt: 'Logo que veio a luz da manhã, foram despedidos os homens, eles com os seus jumentos.' },
      { v: 4, en: 'When they had gone out of the city, and were not yet far off, Joseph said to his steward, “Up, follow after the men. When you overtake them, ask them, ‘Why have you rewarded evil for good?', pt: 'Havendo eles saído da cidade, mas não se tendo distanciado muito, disse José ao seu despenseiro: Levanta-te e segue os homens; e, alcançando-os, dize-lhes: Por que tornastes o mal pelo bem?' },
      { v: 5, en: 'Isn’t this that from which my lord drinks, and by which he indeed divines? You have done evil in so doing.’”', pt: 'Não é esta a taça por que bebe meu senhor, e de que se serve para adivinhar? Fizestes mal no que fizestes.' },
      { v: 6, en: 'He overtook them, and he spoke these words to them.', pt: 'Então ele, tendo-os alcançado, lhes falou essas mesmas palavras.' },
      { v: 7, en: 'They said to him, “Why does my lord speak such words as these? Far be it from your servants that they should do such a thing!', pt: 'Responderam-lhe eles: Por que falo meu senhor tais palavras? Longe estejam teus servos de fazerem semelhante coisa.' },
      { v: 8, en: 'Behold, the money, which we found in our sacks’ mouths, we brought again to you out of the land of Canaan. How then should we steal silver or gold out of your lord’s house?', pt: 'Eis que o dinheiro, que achamos nas bocas dos nossos sacos, to tornamos a trazer desde a terra de Canaã; como, pois, furtaríamos da casa do teu senhor prata ou ouro?' },
      { v: 9, en: 'With whomever of your servants it is found, let him die, and we also will be my lord’s slaves.”', pt: 'Aquele dos teus servos com quem a taça for encontrada, morra; e ainda nós seremos escravos do meu senhor.' },
      { v: 10, en: 'He said, “Now also let it be according to your words: he with whom it is found will be my slave; and you will be blameless.”', pt: 'Ao que disse ele: Seja conforme as vossas palavras; aquele com quem a taça for encontrada será meu escravo; mas vós sereis inocentes.' },
      { v: 11, en: 'Then they hurried, and each man took his sack down to the ground, and each man opened his sack.', pt: 'Então eles se apressaram cada um a pôr em terra o seu saco, e cada um a abri-lo.' },
      { v: 12, en: 'He searched, beginning with the oldest, and ending at the youngest. The cup was found in Benjamin’s sack.', pt: 'E o despenseiro buscou, começando pelo maior, e acabando pelo mais novo; e achou-se a taça no saco de Benjamim.' },
      { v: 13, en: 'Then they tore their clothes, and each man loaded his donkey, and returned to the city.', pt: 'Então rasgaram os seus vestidos e, tendo cada um carregado o seu jumento, voltaram à cidade.' },
      { v: 14, en: 'Judah and his brothers came to Joseph’s house, and he was still there. They fell on the ground before him.', pt: 'E veio Judá com seus irmãos à casa de José, pois ele ainda estava ali; e prostraram-se em terra diante dele.' },
      { v: 15, en: 'Joseph said to them, “What deed is this that you have done? Don’t you know that such a man as I can indeed divine?”', pt: 'Logo lhes perguntou José: Que ação é esta que praticastes? não sabeis vós que um homem como eu pode, muito bem, adivinhar?' },
      { v: 16, en: 'Judah said, “What will we tell my lord? What will we speak? Or how will we clear ourselves? God has found out the iniquity of your servants. Behold, we are my lord’s slaves, both we, and he also in whose hand the cup is found.”', pt: 'Respondeu Judá: Que diremos a meu senhor? que falaremos? e como nos justificaremos? Descobriu Deus a iniqüidade de teus servos; eis que somos escravos de meu senhor, tanto nós como aquele em cuja mão foi achada a taça.' },
      { v: 17, en: 'He said, “Far be it from me that I should do so. The man in whose hand the cup is found, he will be my slave; but as for you, go up in peace to your father.”', pt: 'Disse José: Longe esteja eu de fazer isto; o homem em cuja mão a taça foi achada, aquele será meu servo; porém, quanto a vós, subi em paz para vosso pai.' },
      { v: 18, en: 'Then Judah came near to him, and said, “Oh, my lord, please let your servant speak a word in my lord’s ears, and don’t let your anger burn against your servant; for you are even as Pharaoh.', pt: 'Então Judà se chegou a ele, e disse: Ai! senhor meu, deixa, peço-te, o teu servo dizer uma palavra aos ouvidos de meu senhor; e não se acenda a tua ira contra o teu servo; porque tu és como Faraó.' },
      { v: 19, en: 'My lord asked his servants, saying, ‘Have you a father, or a brother?’', pt: 'Meu senhor perguntou a seus servos, dizendo: Tendes vós pai, ou irmão?' },
      { v: 20, en: 'We said to my lord, ‘We have a father, an old man, and a child of his old age, a little one; and his brother is dead, and he alone is left of his mother; and his father loves him.’', pt: 'E respondemos a meu senhor: Temos pai, já velho, e há um filho da sua velhice, um menino pequeno; o irmão deste é morto, e ele ficou o único de sua mãe; e seu pai o ama.' },
      { v: 21, en: 'You said to your servants, ‘Bring him down to me, that I may set my eyes on him.’', pt: 'Então tu disseste a teus servos: Trazei-mo, para que eu ponha os olhos sobre ele.' },
      { v: 22, en: 'We said to my lord, ‘The boy can’t leave his father: for if he should leave his father, his father would die.’', pt: 'E quando respondemos a meu senhor: O menino não pode deixar o seu pai; pois se ele deixasse o seu pai, este morreria;' },
      { v: 23, en: 'You said to your servants, ‘Unless your youngest brother comes down with you, you will see my face no more.’', pt: 'replicaste a teus servos: A menos que desça convosco vosso irmão mais novo, nunca mais vereis a minha face.' },
      { v: 24, en: 'When we came up to your servant my father, we told him the words of my lord.', pt: 'Então subimos a teu servo, meu pai, e lhe contamos as palavras de meu senhor.' },
      { v: 25, en: 'Our father said, ‘Go again and buy us a little food.’', pt: 'Depois disse nosso pai: Tornai, comprai-nos um pouco de mantimento;' },
      { v: 26, en: 'We said, ‘We can’t go down. If our youngest brother is with us, then we will go down: for we may not see the man’s face, unless our youngest brother is with us.’', pt: 'e lhe respondemos: Não podemos descer; mas, se nosso irmão menor for conosco, desceremos; pois não podemos ver a face do homem, se nosso irmão menor não estiver conosco.' },
      { v: 27, en: 'Your servant, my father, said to us, ‘You know that my wife bore me two sons:', pt: 'Então nos disse teu servo, meu pai: Vós sabeis que minha mulher me deu dois filhos;' },
      { v: 28, en: 'and the one went out from me, and I said, “Surely he is torn in pieces”; and I haven’t seen him since.', pt: 'um saiu de minha casa e eu disse: certamente foi despedaçado, e não o tenho visto mais;' },
      { v: 29, en: 'If you take this one also from me, and harm happens to him, you will bring down my gray hairs with sorrow to Sheol.’', pt: 'se também me tirardes a este, e lhe acontecer algum desastre, fareis descer as minhas cãs com tristeza ao Seol.' },
      { v: 30, en: 'Now therefore when I come to your servant my father, and the boy is not with us; since his life is bound up in the boy’s life;', pt: 'Agora, pois, se eu for ter com o teu servo, meu pai, e o menino não estiver conosco, como a sua alma está ligada com a alma dele,' },
      { v: 31, en: 'it will happen, when he sees that the boy is no more, that he will die. Your servants will bring down the gray hairs of your servant, our father, with sorrow to Sheol.', pt: 'acontecerá que, vendo ele que o menino ali não está, morrerá; e teus servos farão descer as cãs de teu servo, nosso pai com tristeza ao Seol.' },
      { v: 32, en: 'For your servant became collateral for the boy to my father, saying, ‘If I don’t bring him to you, then I will bear the blame to my father forever.’', pt: 'Porque teu servo se deu como fiador pelo menino para com meu pai, dizendo: Se eu to não trouxer de volta, serei culpado, para com meu pai para sempre.' },
      { v: 33, en: 'Now therefore, please let your servant stay instead of the boy, my lord’s slave; and let the boy go up with his brothers.', pt: 'Agora, pois, fique teu servo em lugar do menino como escravo de meu senhor, e que suba o menino com seus irmãos.' },
      { v: 34, en: 'For how will I go up to my father, if the boy isn’t with me?—lest I see the evil that will come on my father.”', pt: 'Porque, como subirei eu a meu pai, se o menino não for comigo? para que não veja eu o mal que sobrevirá a meu pai.' },
    ],
    45: [
      { v: 1, en: 'Then Joseph couldn’t control himself before all those who stood before him, and he cried, “Cause everyone to go out from me!” No one else stood with him, while Joseph made himself known to his brothers.', pt: 'Então José não se podia conter diante de todos os que estavam com ele; e clamou: Fazei a todos sair da minha presença; e ninguém ficou com ele, quando se deu a conhecer a seus irmãos.' },
      { v: 2, en: 'He wept aloud. The Egyptians heard, and the house of Pharaoh heard.', pt: 'E levantou a voz em choro, de maneira que os egípcios o ouviram, bem como a casa de Faraó.' },
      { v: 3, en: 'Joseph said to his brothers, “I am Joseph! Does my father still live?” His brothers couldn’t answer him; for they were terrified at his presence.', pt: 'Disse, então, José a seus irmãos: Eu sou José; vive ainda meu pai? E seus irmãos não lhe puderam responder, pois estavam pasmados diante dele.' },
      { v: 4, en: 'Joseph said to his brothers, “Come near to me, please.” They came near. “He said, I am Joseph, your brother, whom you sold into Egypt.', pt: 'José disse mais a seus irmãos: Chegai-vos a mim, peço-vos. E eles se chegaram. Então ele prosseguiu: Eu sou José, vosso irmão, a quem vendestes para o Egito.' },
      { v: 5, en: 'Now don’t be grieved, nor angry with yourselves, that you sold me here, for God sent me before you to preserve life.', pt: 'Agora, pois, não vos entristeçais, nem vos aborreçais por me haverdes vendido para cá; porque para preservar vida é que Deus me enviou adiante de vós.' },
      { v: 6, en: 'For these two years the famine has been in the land, and there are yet five years, in which there will be no plowing and no harvest.', pt: 'Porque já houve dois anos de fome na terra, e ainda restam cinco anos em que não haverá lavoura nem sega.' },
      { v: 7, en: 'God sent me before you to preserve for you a remnant in the earth, and to save you alive by a great deliverance.', pt: 'Deus enviou-me adiante de vós, para conservar-vos descendência na terra, e para guardar-vos em vida por um grande livramento.' },
      { v: 8, en: 'So now it wasn’t you who sent me here, but God, and he has made me a father to Pharaoh, lord of all his house, and ruler over all the land of Egypt.', pt: 'Assim não fostes vós que me enviastes para cá, senão Deus, que me tem posto por pai de Faraó, e por senhor de toda a sua casa, e como governador sobre toda a terra do Egito.' },
      { v: 9, en: 'Hurry, and go up to my father, and tell him, ‘This is what your son Joseph says, “God has made me lord of all Egypt. Come down to me. Don’t wait.', pt: 'Apressai-vos, subi a meu pai, e dizei-lhe: Assim disse teu filho José: Deus me tem posto por senhor de toda a terra do Egito; desce a mim, e não te demores;' },
      { v: 10, en: 'You shall dwell in the land of Goshen, and you will be near to me, you, your children, your children’s children, your flocks, your herds, and all that you have.', pt: 'habitarás na terra de Gósem e estarás perto de mim, tu e os teus filhos e os filhos de teus filhos, e os teus rebanhos, o teu gado e tudo quanto tens;' },
      { v: 11, en: 'There I will nourish you; for there are yet five years of famine; lest you come to poverty, you, and your household, and all that you have.”’', pt: 'ali te sustentarei, porque ainda haverá cinco anos de fome, para que não sejas reduzido à pobreza, tu e tua casa, e tudo o que tens.' },
      { v: 12, en: 'Behold, your eyes see, and the eyes of my brother Benjamin, that it is my mouth that speaks to you.', pt: 'Eis que os vossos olhos, e os de meu irmão Benjamim, vêem que é minha boca que vos fala.' },
      { v: 13, en: 'You shall tell my father of all my glory in Egypt, and of all that you have seen. You shall hurry and bring my father down here.”', pt: 'Fareis, pois, saber a meu pai toda a minha glória no Egito; e tudo o que tendes visto; e apressar-vos-eis a fazer descer meu pai para cá.' },
      { v: 14, en: 'He fell on his brother Benjamin’s neck, and wept, and Benjamin wept on his neck.', pt: 'Então se lançou ao pescoço de Benjamim seu irmão, e chorou; e Benjamim chorou também ao pescoço dele.' },
      { v: 15, en: 'He kissed all his brothers, and wept on them. After that his brothers talked with him.', pt: 'E José beijou a todos os seus irmãos, chorando sobre eles; depois seus irmãos falaram com ele.' },
      { v: 16, en: 'The report of it was heard in Pharaoh’s house, saying, “Joseph’s brothers have come.” It pleased Pharaoh well, and his servants.', pt: 'Esta nova se fez ouvir na casa de Faraó: São vindos os irmãos de José; o que agradou a Faraó e a seus servos.' },
      { v: 17, en: 'Pharaoh said to Joseph, “Tell your brothers, ‘Do this. Load your animals, and go, travel to the land of Canaan.', pt: 'Ordenou Faraó a José: Dize a teus irmãos: Fazei isto: carregai os vossos animais e parti, tornai à terra de Canaã;' },
      { v: 18, en: 'Take your father and your households, and come to me, and I will give you the good of the land of Egypt, and you will eat the fat of the land.’', pt: 'tomai o vosso pai e as vossas familias e vinde a mim; e eu vos darei o melhor da terra do Egito, e comereis da fartura da terra.' },
      { v: 19, en: 'Now you are commanded: do this. Take wagons out of the land of Egypt for your little ones, and for your wives, and bring your father, and come.', pt: 'A ti, pois, é ordenado dizer-lhes: Fazei isto: levai vós da terra do Egito carros para vossos meninos e para vossas mulheres; trazei vosso pai, e vinde.' },
      { v: 20, en: 'Also, don’t concern yourselves about your belongings, for the good of all the land of Egypt is yours.”', pt: 'E não vos pese coisa alguma das vossas alfaias; porque o melhor de toda a terra do Egito será vosso.' },
      { v: 21, en: 'The sons of Israel did so. Joseph gave them wagons, according to the commandment of Pharaoh, and gave them provision for the way.', pt: 'Assim fizeram os filhos de Israel. José lhes deu carros, conforme o mandado de Faraó, e deu-lhes também provisão para o caminho.' },
      { v: 22, en: 'He gave each one of them changes of clothing, but to Benjamin he gave three hundred pieces of silver and five changes of clothing.', pt: 'A todos eles deu, a cada um, mudas de roupa; mas a Benjamim deu trezentas peças de prata, e cinco mudas de roupa.' },
      { v: 23, en: 'He sent the following to his father: ten donkeys loaded with the good things of Egypt, and ten female donkeys loaded with grain and bread and provision for his father by the way.', pt: 'E a seu pai enviou o seguinte: dez jumentos carregados do melhor do Egito, e dez jumentas carregadas de trigo, pão e provisão para seu pai, para o caminho.' },
      { v: 24, en: 'So he sent his brothers away, and they departed. He said to them, “See that you don’t quarrel on the way.”', pt: 'Assim despediu seus irmãos e, ao partirem eles, disse-lhes: Não contendais pelo caminho.' },
      { v: 25, en: 'They went up out of Egypt, and came into the land of Canaan, to Jacob their father.', pt: 'Então subiram do Egito, vieram à terra de Canaã, a Jacó seu pai,' },
      { v: 26, en: 'They told him, saying, “Joseph is still alive, and he is ruler over all the land of Egypt.” His heart fainted, for he didn’t believe them.', pt: 'e lhe anunciaram, dizendo: José ainda vive, e é governador de toda a terra do Egito. E o seu coração desmaiou, porque não os acreditava.' },
      { v: 27, en: 'They told him all the words of Joseph, which he had said to them. When he saw the wagons which Joseph had sent to carry him, the spirit of Jacob, their father, revived.', pt: 'Quando, porém, eles lhe contaram todas as palavras que José lhes falara, e vendo Jacó, seu pai, os carros que José enviara para levá-lo, reanimou-se-lhe o espírito;' },
      { v: 28, en: 'Israel said, “It is enough. Joseph my son is still alive. I will go and see him before I die.”', pt: 'e disse Israel: Basta; ainda vive meu filho José; eu irei e o verei antes que morra.' },
    ],
    46: [
      { v: 1, en: 'Israel traveled with all that he had, and came to Beersheba, and offered sacrifices to the God of his father, Isaac.', pt: 'Partiu, pois, Israel com tudo quanto tinha e veio a Beer-Seba, onde ofereceu sacrifícios ao Deus de seu pai Isaque.' },
      { v: 2, en: 'God spoke to Israel in the visions of the night, and said, “Jacob, Jacob!” He said, “Here I am.”', pt: 'Falou Deus a Israel em visões de noite, e disse: Jacó, Jacó! Respondeu Jacó: Eis-me aqui.' },
      { v: 3, en: 'He said, “I am God, the God of your father. Don’t be afraid to go down into Egypt, for there I will make of you a great nation.', pt: 'E Deus disse: Eu sou Deus, o Deus de teu pai; não temas descer para o Egito; porque eu te farei ali uma grande nação.' },
      { v: 4, en: 'I will go down with you into Egypt. I will also surely bring you up again. Joseph will close your eyes.”', pt: 'Eu descerei contigo para o Egito, e certamente te farei tornar a subir; e José porá a sua mão sobre os teus olhos.' },
      { v: 5, en: 'Jacob rose up from Beersheba, and the sons of Israel carried Jacob, their father, their little ones, and their wives, in the wagons which Pharaoh had sent to carry him.', pt: 'Então Jacó se levantou de Beer-Seba; e os filhos de Israel levaram seu pai Jacó, e seus meninos, e as suas mulheres, nos carros que Faraó enviara para o levar.' },
      { v: 6, en: 'They took their livestock, and their goods, which they had gotten in the land of Canaan, and came into Egypt—Jacob, and all his offspring with him,', pt: 'Também tomaram o seu gado e os seus bens que tinham adquirido na terra de Canaã, e vieram para o Egito, Jacó e toda a sua descendência com ele.' },
      { v: 7, en: 'his sons, and his sons’ sons with him, his daughters, and his sons’ daughters, and he brought all his offspring with him into Egypt.', pt: 'Os seus filhos e os filhos de seus filhos com ele, as suas filhas e as filhas de seus filhos, e toda a sua descendência, levou-os consigo para o Egito.' },
      { v: 8, en: 'These are the names of the children of Israel, who came into Egypt, Jacob and his sons: Reuben, Jacob’s firstborn.', pt: 'São estes os nomes dos filhos de Israel, que vieram para o Egito, Jacó e seus filhos: Rúben, o primogênito de Jacó.' },
      { v: 9, en: 'The sons of Reuben: Hanoch, Pallu, Hezron, and Carmi.', pt: 'E os filhos de Rúben: Hanoque, Palu, Hezrom e Carmi.' },
      { v: 10, en: 'The sons of Simeon: Jemuel, Jamin, Ohad, Jachin, Zohar, and Shaul the son of a Canaanite woman.', pt: 'E os filhos de Simeão: Jemuel, Jamim, Oade, Jaquim, Zoar, e Saul, filho de uma mulher cananéia.' },
      { v: 11, en: 'The sons of Levi: Gershon, Kohath, and Merari.', pt: 'E os filhos de Levi: Gérsom, Coate e Merári.' },
      { v: 12, en: 'The sons of Judah: Er, Onan, Shelah, Perez, and Zerah; but Er and Onan died in the land of Canaan. The sons of Perez were Hezron and Hamul.', pt: 'E os filhos de Judá: Er, Onã, Selá, Pérez e Zerá. Er e Onã, porém, morreram na terra de Canaã. E os filhos de Pérez foram Hezrom e Hamul,' },
      { v: 13, en: 'The sons of Issachar: Tola, Puvah, Iob, and Shimron.', pt: 'E os filhos de Issacar: Tola, Puva, Iobe e Sinrom.' },
      { v: 14, en: 'The sons of Zebulun: Sered, Elon, and Jahleel.', pt: 'E os filhos de Zebulom: Serede, Elom e Jaleel.' },
      { v: 15, en: 'These are the sons of Leah, whom she bore to Jacob in Paddan Aram, with his daughter Dinah. All the souls of his sons and his daughters were thirty-three.', pt: 'Estes são os filhos de Léia, que ela deu a Jacó em Padã-Arã, além de Diná, sua filha; todas as almas de seus filhos e de suas filhas eram trinta e três.' },
      { v: 16, en: 'The sons of Gad: Ziphion, Haggi, Shuni, Ezbon, Eri, Arodi, and Areli.', pt: 'E os filhos de Gade: Zifiom, Hagui, Suni, Ezbom, Eri, Arodi e Areli.' },
      { v: 17, en: 'The sons of Asher: Imnah, Ishvah, Ishvi, Beriah, and Serah their sister. The sons of Beriah: Heber and Malchiel.', pt: 'E os filhos de Aser: Imná, Isvá, Isvi e Beria, e Sera, a irmã deles; e os filhos de Beria: Heber e Malquiel.' },
      { v: 18, en: 'These are the sons of Zilpah, whom Laban gave to Leah, his daughter, and these she bore to Jacob, even sixteen souls.', pt: 'Estes são os filhos de Zilpa, a qual Labão deu à sua filha Léia; e estes ela deu a Jacó, ao todo dezesseis almas.' },
      { v: 19, en: 'The sons of Rachel, Jacob’s wife: Joseph and Benjamin.', pt: 'Os filhos de Raquel, mulher de Jacó: José e Benjamim.' },
      { v: 20, en: 'To Joseph in the land of Egypt were born Manasseh and Ephraim, whom Asenath, the daughter of Potiphera, priest of On, bore to him.', pt: 'E nasceram a José na terra do Egito Manassés e Efraim, que lhe deu Asenate, filha de Potífera, sacerdote de Om.' },
      { v: 21, en: 'The sons of Benjamin: Bela, Becher, Ashbel, Gera, Naaman, Ehi, Rosh, Muppim, Huppim, and Ard.', pt: 'E os filhos de Benjamim: Belá, Bequer, Asbel, Gêra, Naamã, Eí, Ros, Mupim, Hupim e Arde.' },
      { v: 22, en: 'These are the sons of Rachel, who were born to Jacob: all the souls were fourteen.', pt: 'Estes são os filhos de Raquel, que nasceram a Jacó, ao todo catorze almas.' },
      { v: 23, en: 'The son of Dan: Hushim.', pt: 'E os filhos de Dã: Husim.' },
      { v: 24, en: 'The sons of Naphtali: Jahzeel, Guni, Jezer, and Shillem.', pt: 'E os filhos de Naftali: Jazeel, Guni, Jezer e Silém.' },
      { v: 25, en: 'These are the sons of Bilhah, whom Laban gave to Rachel, his daughter, and these she bore to Jacob: all the souls were seven.', pt: 'Estes são os filhos de Bila, a qual Labão deu à sua filha Raquel; e estes deu ela a Jacó, ao todo sete almas.' },
      { v: 26, en: 'All the souls who came with Jacob into Egypt, who were his direct offspring, besides Jacob’s sons’ wives, all the souls were sixty-six.', pt: 'Todas as almas que vieram com Jacó para o Egito e que saíram da sua coxa, fora as mulheres dos filhos de Jacó, eram todas sessenta e seis almas;' },
      { v: 27, en: 'The sons of Joseph, who were born to him in Egypt, were two souls. All the souls of the house of Jacob, who came into Egypt, were seventy.', pt: 'e os filhos de José, que lhe nasceram no Egito, eram duas almas. Todas as almas da casa de Jacó, que vieram para o Egito eram setenta.' },
      { v: 28, en: 'He sent Judah before him to Joseph, to show the way before him to Goshen, and they came into the land of Goshen.', pt: 'Ora, Jacó enviou Judá adiante de si a José, para o encaminhar a Gósen; e chegaram à terra de Gósen.' },
      { v: 29, en: 'Joseph prepared his chariot, and went up to meet Israel, his father, in Goshen. He presented himself to him, and fell on his neck, and wept on his neck a good while.', pt: 'Então José aprontou o seu carro, e subiu ao encontro de Israel, seu pai, a Gósen; e tendo-se-lhe apresentado, lançou-se ao seu pescoço, e chorou sobre o seu pescoço longo tempo.' },
      { v: 30, en: 'Israel said to Joseph, “Now let me die, since I have seen your face, that you are still alive.”', pt: 'E Israel disse a José: Morra eu agora, já que tenho visto o teu rosto, pois que ainda vives.' },
      { v: 31, en: 'Joseph said to his brothers, and to his father’s house, “I will go up, and speak with Pharaoh, and will tell him, ‘My brothers, and my father’s house, who were in the land of Canaan, have come to me.', pt: 'Depois disse José a seus irmãos, e à casa de seu pai: Eu subirei e informarei a Faraó, e lhe direi: Meus irmãos e a casa de meu pai, que estavam na terra de Canaã, vieram para mim.' },
      { v: 32, en: 'These men are shepherds, for they have been keepers of livestock, and they have brought their flocks, and their herds, and all that they have.’', pt: 'Os homens são pastores, que se ocupam em apascentar gado; e trouxeram os seus rebanhos, o seu gado e tudo o que têm.' },
      { v: 33, en: 'It will happen, when Pharaoh summons you, and will say, ‘What is your occupation?’', pt: 'Quando, pois, Faraó vos chamar e vos perguntar: Que ocupação é a vossa?' },
      { v: 34, en: 'that you shall say, ‘Your servants have been keepers of livestock from our youth even until now, both we, and our fathers:’ that you may dwell in the land of Goshen; for every shepherd is an abomination to the Egyptians.”', pt: 'respondereis: Nós, teus servos, temos sido pastores de gado desde a nossa mocidade até agora, tanto nós como nossos pais. Isso direis para que habiteis na terra de Gósen; porque todo pastor de ovelhas é abominação para os egípcios.' },
    ],
    47: [
      { v: 1, en: 'Then Joseph went in and told Pharaoh, and said, “My father and my brothers, with their flocks, their herds, and all that they own, have come out of the land of Canaan; and behold, they are in the land of Goshen.”', pt: 'Então veio José, e informou a Faraó, dizendo: Meu pai e meus irmãos, com seus rebanhos e seu gado, e tudo o que têm, chegaram da terra de Canaã e estão na terra de Gósen.' },
      { v: 2, en: 'From among his brothers he took five men, and presented them to Pharaoh.', pt: 'E tomou dentre seus irmãos cinco homens e os apresentou a Faraó.' },
      { v: 3, en: 'Pharaoh said to his brothers, “What is your occupation?” They said to Pharaoh, “Your servants are shepherds, both we, and our fathers.”', pt: 'Então perguntou Faraó a esses irmãos de José: Que ocupação é a vossa; Responderam-lhe: Nós, teus servos, somos pastores de ovelhas, tanto nós como nossos pais.' },
      { v: 4, en: 'They said to Pharaoh, “We have come to live as foreigners in the land, for there is no pasture for your servants’ flocks. For the famine is severe in the land of Canaan. Now therefore, please let your servants dwell in the land of Goshen.”', pt: 'Disseram mais a Faraó: Viemos para peregrinar nesta terra; porque não há pasto para os rebanhos de teus servos, porquanto a fome é grave na terra de Canaã; agora, pois, rogamos-te permitas que teus servos habitem na terra de Gósen.' },
      { v: 5, en: 'Pharaoh spoke to Joseph, saying, “Your father and your brothers have come to you.', pt: 'Então falou Faraó a José, dizendo: Teu pai e teus irmãos vieram a ti;' },
      { v: 6, en: 'The land of Egypt is before you. Make your father and your brothers dwell in the best of the land. Let them dwell in the land of Goshen. If you know any able men among them, then put them in charge of my livestock.”', pt: 'a terra do Egito está diante de ti; no melhor da terra faze habitar teu pai e teus irmãos; habitem na terra de Gósen. E se sabes que entre eles hà homens capazes, põe-nos sobre os pastores do meu gado.' },
      { v: 7, en: 'Joseph brought in Jacob, his father, and set him before Pharaoh, and Jacob blessed Pharaoh.', pt: 'Também José introduziu a Jacó, seu pai, e o apresentou a Faraó; e Jacó abençoou a Faraó.' },
      { v: 8, en: 'Pharaoh said to Jacob, “How many are the days of the years of your life?”', pt: 'Então perguntou Faraó a Jacó: Quantos são os dias dos anos da tua vida?' },
      { v: 9, en: 'Jacob said to Pharaoh, “The days of the years of my pilgrimage are one hundred thirty years. Few and evil have been the days of the years of my life, and they have not attained to the days of the years of the life of my fathers in the days of their pilgrimage.”', pt: 'Respondeu-lhe Jacó: Os dias dos anos das minhas peregrinações são cento e trinta anos; poucos e maus têm sido os dias dos anos da minha vida, e não chegaram aos dias dos anos da vida de meus pais nos dias das suas peregrinações.' },
      { v: 10, en: 'Jacob blessed Pharaoh, and went out from the presence of Pharaoh.', pt: 'E Jacó abençoou a Faraó, e saiu da sua presença.' },
      { v: 11, en: 'Joseph placed his father and his brothers, and gave them a possession in the land of Egypt, in the best of the land, in the land of Rameses, as Pharaoh had commanded.', pt: 'José, pois, estabeleceu a seu pai e seus irmãos, dando-lhes possessão na terra do Egito, no melhor da terra, na terra de Ramessés, como Faraó ordenara.' },
      { v: 12, en: 'Joseph nourished his father, his brothers, and all of his father’s household, with bread, according to their families.', pt: 'E José sustentou de pão seu pai, seus irmãos e toda a casa de seu pai, segundo o número de seus filhos.' },
      { v: 13, en: 'There was no bread in all the land; for the famine was very severe, so that the land of Egypt and the land of Canaan fainted by reason of the famine.', pt: 'Ora, não havia pão em toda a terra, porque a fome era mui grave; de modo que a terra do Egito e a terra de Canaã desfaleciam por causa da fome.' },
      { v: 14, en: 'Joseph gathered up all the money that was found in the land of Egypt, and in the land of Canaan, for the grain which they bought: and Joseph brought the money into Pharaoh’s house.', pt: 'Então José recolheu todo o dinheiro que se achou na terra do Egito, e na terra de Canaã, pelo trigo que compravam; e José trouxe o dinheiro à casa de Faraó.' },
      { v: 15, en: 'When the money was all spent in the land of Egypt, and in the land of Canaan, all the Egyptians came to Joseph, and said, “Give us bread, for why should we die in your presence? For our money fails.”', pt: 'Quando se acabou o dinheiro na terra do Egito, e na terra de Canaã, vieram todos os egípcios a José, dizendo: Dà-nos pão; por que morreremos na tua presença? porquanto o dinheiro nos falta.' },
      { v: 16, en: 'Joseph said, “Give me your livestock; and I will give you food for your livestock, if your money is gone.”', pt: 'Respondeu José: Trazei o vosso gado, e vo-lo darei por vosso gado, se falta o dinheiro.' },
      { v: 17, en: 'They brought their livestock to Joseph, and Joseph gave them bread in exchange for the horses, and for the flocks, and for the herds, and for the donkeys: and he fed them with bread in exchange for all their livestock for that year.', pt: 'Então trouxeram o seu gado a José; e José deu-lhes pão em troca dos cavalos, e das ovelhas, e dos bois, e dos jumentos; e os sustentou de pão aquele ano em troca de todo o seu gado.' },
      { v: 18, en: 'When that year was ended, they came to him the second year, and said to him, “We will not hide from my lord how our money is all spent, and the herds of livestock are my lord’s. There is nothing left in the sight of my lord, but our bodies, and our lands.', pt: 'Findo aquele ano, vieram a José no ano seguinte e disseram-lhe: Não ocultaremos ao meu senhor que o nosso dinheiro está todo gasto; as manadas de gado jà pertencem a meu senhor; e nada resta diante de meu senhor, senão o nosso corpo e a nossa terra;' },
      { v: 19, en: 'Why should we die before your eyes, both we and our land? Buy us and our land for bread, and we and our land will be servants to Pharaoh. Give us seed, that we may live, and not die, and that the land won’t be desolate.”', pt: 'por que morreremos diante dos teus olhos, tanto nós como a nossa terra? Compra-nos a nós e a nossa terra em troca de pão, e nós e a nossa terra seremos servos de Faraó; dá-nos também semente, para que vivamos e não morramos, e para que a terra não fique desolada.' },
      { v: 20, en: 'So Joseph bought all the land of Egypt for Pharaoh, for every man of the Egyptians sold his field, because the famine was severe on them, and the land became Pharaoh’s.', pt: 'Assim José comprou toda a terra do Egito para Faraó; porque os egípcios venderam cada um o seu campo, porquanto a fome lhes era grave em extremo; e a terra ficou sendo de Faraó.' },
      { v: 21, en: 'As for the people, he moved them to the cities from one end of the border of Egypt even to the other end of it.', pt: 'Quanto ao povo, José fê-lo passar às cidades, desde uma até a outra extremidade dos confins do Egito.' },
      { v: 22, en: 'Only he didn’t buy the land of the priests, for the priests had a portion from Pharaoh, and ate their portion which Pharaoh gave them. That is why they didn’t sell their land.', pt: 'Somente a terra dos sacerdotes não a comprou, porquanto os sacerdotes tinham rações de Faraó, e eles comiam as suas rações que Faraó lhes havia dado; por isso não venderam a sua terra.' },
      { v: 23, en: 'Then Joseph said to the people, “Behold, I have bought you and your land today for Pharaoh. Behold, here is seed for you, and you shall sow the land.', pt: 'Então disse José ao povo: Hoje vos tenho comprado a vós e a vossa terra para Faraó; eis aí tendes semente para vós, para que semeeis a terra.' },
      { v: 24, en: 'It will happen at the harvests, that you shall give a fifth to Pharaoh, and four parts will be your own, for seed of the field, for your food, for them of your households, and for food for your little ones.”', pt: 'Há de ser, porém, que no tempo as colheitas dareis a quinta parte a Faraó, e quatro partes serão vossas, para semente do campo, e para o vosso mantimento e dos que estão nas vossas casas, e para o mantimento de vossos filhinho.' },
      { v: 25, en: 'They said, “You have saved our lives! Let us find favor in the sight of my lord, and we will be Pharaoh’s servants.”', pt: 'Responderam eles: Tu nos tens conservado a vida! achemos graça aos olhos de meu senhor, e seremos servos de Faraó.' },
      { v: 26, en: 'Joseph made it a statute concerning the land of Egypt to this day, that Pharaoh should have the fifth. Only the land of the priests alone didn’t become Pharaoh’s.', pt: 'José, pois, estabeleceu isto por estatuto quanto ao solo do Egito, até o dia de hoje, que a Faraó coubesse o quinto a produção; somente a terra dos sacerdotes não ficou sendo de Faraó.' },
      { v: 27, en: 'Israel lived in the land of Egypt, in the land of Goshen; and they got themselves possessions therein, and were fruitful, and multiplied exceedingly.', pt: 'Assim habitou Israel na terra do Egito, na terra de Gósen; e nela adquiriram propriedades, e frutificaram e multiplicaram-se muito.' },
      { v: 28, en: 'Jacob lived in the land of Egypt seventeen years. So the days of Jacob, the years of his life, were one hundred forty-seven years.', pt: 'E Jacó viveu na terra do Egito dezessete anos; de modo que os dias de Jacó, os anos da sua vida, foram cento e quarenta e sete anos.' },
      { v: 29, en: 'The time came near that Israel must die, and he called his son Joseph, and said to him, “If now I have found favor in your sight, please put your hand under my thigh, and deal kindly and truly with me. Please don’t bury me in Egypt,', pt: 'Quando se aproximava o tempo da morte de Israel, chamou ele a José, seu filho, e disse-lhe: Se tenho achado graça aos teus olhos, põe a mão debaixo da minha coxa, e usa para comigo de benevolência e de verdade: rogo-te que não me enterres no Egito;' },
      { v: 30, en: 'but when I sleep with my fathers, you shall carry me out of Egypt, and bury me in their burying place.” He said, “I will do as you have said.”', pt: 'mas quando eu dormir com os meus pais, levar-me-ás do Egito e enterrar-me-ás junto à sepultura deles. Respondeu José: Farei conforme a tua palavra.' },
      { v: 31, en: 'He said, “Swear to me,” and he swore to him. Israel bowed himself on the bed’s head.', pt: 'E Jacó disse: Jura-me; e ele lhe jurou. Então Israel inclinou-se sobre a cabeceira da cama.' },
    ],
    48: [
      { v: 1, en: 'After these things, someone said to Joseph, “Behold, your father is sick.” He took with him his two sons, Manasseh and Ephraim.', pt: 'Depois destas coisas disseram a José: Eis que teu pai está enfermo. Então José tomou consigo os seus dois filhos, Manassés e Efraim.' },
      { v: 2, en: 'Someone told Jacob, and said, “Behold, your son Joseph comes to you,” and Israel strengthened himself, and sat on the bed.', pt: 'Disse alguém a Jacó: Eis que José, teu olho, vem ter contigo. E esforçando-se Israel, sentou-se sobre a cama.' },
      { v: 3, en: 'Jacob said to Joseph, “God Almighty appeared to me at Luz in the land of Canaan, and blessed me,', pt: 'E disse Jacó a José: O Deus Todo-Poderoso me apareceu em Luz, na terra de Canaã, e me abençoou,' },
      { v: 4, en: 'and said to me, ‘Behold, I will make you fruitful, and multiply you, and I will make of you a company of peoples, and will give this land to your offspring after you for an everlasting possession.’', pt: 'e me disse: Eis que te farei frutificar e te multiplicarei; tornar-te-ei uma multidão de povos e darei esta terra à tua descendência depois de ti, em possessão perpétua.' },
      { v: 5, en: 'Now your two sons, who were born to you in the land of Egypt before I came to you into Egypt, are mine; Ephraim and Manasseh, even as Reuben and Simeon, will be mine.', pt: 'Agora, pois, os teus dois filhos, que nasceram na terra do Egito antes que eu viesse a ti no Egito, são meus: Efraim e Manassés serão meus, como Rúben e Simeão;' },
      { v: 6, en: 'Your issue, whom you become the father of after them, will be yours. They will be called after the name of their brothers in their inheritance.', pt: 'mas a prole que tiveres depois deles será tua; segundo o nome de seus irmãos serão eles chamados na sua herança.' },
      { v: 7, en: 'As for me, when I came from Paddan, Rachel died by me in the land of Canaan on the way, when there was still some distance to come to Ephrath, and I buried her there on the way to Ephrath (also called Bethlehem).”', pt: 'Quando eu vinha de Padã, morreu-me Raquel no caminho, na terra de Canaã, quando ainda faltava alguma distância para chegar a Efrata; sepultei-a ali no caminho que vai dar a Efrata, isto é, Belém.' },
      { v: 8, en: 'Israel saw Joseph’s sons, and said, “Who are these?”', pt: 'Quando Israel viu os filhos de José, perguntou: Quem são estes?' },
      { v: 9, en: 'Joseph said to his father, “They are my sons, whom God has given me here.” He said, “Please bring them to me, and I will bless them.”', pt: 'Respondeu José a seu pai: Eles são meus filhos, que Deus me tem dado aqui. Continuou Israel: Traze-mos aqui, e eu os abençoarei.' },
      { v: 10, en: 'Now the eyes of Israel were dim for age, so that he couldn’t see. He brought them near to him; and he kissed them, and embraced them.', pt: 'Os olhos de Israel, porém, se tinham escurecido por causa da velhice, de modo que não podia ver. José, pois, fê-los chegar a ele; e ele os beijou e os abraçou.' },
      { v: 11, en: 'Israel said to Joseph, “I didn’t think I would see your face, and behold, God has let me see your offspring also.”', pt: 'E Israel disse a José: Eu não cuidara ver o teu rosto; e eis que Deus me fez ver também a tua descendência.' },
      { v: 12, en: 'Joseph brought them out from between his knees, and he bowed himself with his face to the earth.', pt: 'Então José os tirou dos joelhos de seu pai; e inclinou-se à terra diante da sua face.' },
      { v: 13, en: 'Joseph took them both, Ephraim in his right hand toward Israel’s left hand, and Manasseh in his left hand toward Israel’s right hand, and brought them near to him.', pt: 'E José tomou os dois, a Efraim com a sua mão direita, à esquerda de Israel, e a Manassés com a sua mão esquerda, à direita de Israel, e assim os fez chegar a ele.' },
      { v: 14, en: 'Israel stretched out his right hand, and laid it on Ephraim’s head, who was the younger, and his left hand on Manasseh’s head, guiding his hands knowingly, for Manasseh was the firstborn.', pt: 'Mas Israel, estendendo a mão direita, colocou-a sobre a cabeça de Efraim, que era o menor, e a esquerda sobre a cabeça de Manassés, dirigindo as mãos assim propositadamente, sendo embora este o primogênito.' },
      { v: 15, en: 'He blessed Joseph, and said, “The God before whom my fathers Abraham and Isaac walked, the God who has fed me all my life long to this day,', pt: 'E abençoou a José, dizendo: O Deus em cuja presença andaram os meus pais Abraão e Isaque, o Deus que tem sido o meu pastor durante toda a minha vida até este dia,' },
      { v: 16, en: 'the angel who has redeemed me from all evil, bless the lads, and let my name be named on them, and the name of my fathers Abraham and Isaac. Let them grow into a multitude upon the earth.”', pt: 'o anjo que me tem livrado de todo o mal, abençoe estes mancebos, e seja chamado neles o meu nome, e o nome de meus pois Abraão e Isaque; e multipliquem-se abundantemente no meio da terra.' },
      { v: 17, en: 'When Joseph saw that his father laid his right hand on the head of Ephraim, it displeased him. He held up his father’s hand, to remove it from Ephraim’s head to Manasseh’s head.', pt: 'Vendo José que seu pai colocava a mão direita sobre a cabeça de Efraim, foi-lhe isso desagradável; levantou, pois, a mão de seu pai, para a transpor da cabeça de Efraim para a cabeça de Manassés.' },
      { v: 18, en: 'Joseph said to his father, “Not so, my father; for this is the firstborn; put your right hand on his head.”', pt: 'E José disse a seu pai: Nãa assim, meu pai, porque este é o primogênito; põe a mão direita sobre a sua cabeça.' },
      { v: 19, en: 'His father refused, and said, “I know, my son, I know. He also will become a people, and he also will be great. However, his younger brother will be greater than he, and his offspring will become a multitude of nations.”', pt: 'Mas seu pai, recusando, disse: Eu o sei, meu filho, eu o sei; ele também se tornará um povo, ele também será grande; contudo o seu irmão menor será maior do que ele, e a sua descendência se tornará uma multidão de nações.' },
      { v: 20, en: 'He blessed them that day, saying, “In you will Israel bless, saying, ‘God make you as Ephraim and as Manasseh’” He set Ephraim before Manasseh.', pt: 'Assim os abençoou naquele dia, dizendo: Por ti Israel abençoará e dirá: Deus te faça como Efraim e como Manassés. E pôs a Efraim diante de Manassés.' },
      { v: 21, en: 'Israel said to Joseph, “Behold, I am dying, but God will be with you, and bring you again to the land of your fathers.', pt: 'Depois disse Israel a José: Eis que eu morro; mas Deus será convosco, e vos fará tornar para a terra de vossos pais.' },
      { v: 22, en: 'Moreover I have given to you one portion above your brothers, which I took out of the hand of the Amorite with my sword and with my bow.”', pt: 'E eu te dou um pedaço de terra a mais do que a teus irmãos, o qual tomei com a minha espada e com o meu arco da mão dos amorreus.' },
    ],
    49: [
      { v: 1, en: 'Jacob called to his sons, and said: “Gather yourselves together, that I may tell you that which will happen to you in the days to come.', pt: 'Depois chamou Jacó a seus filhos, e disse: Ajuntai-vos para que eu vos anuncie o que vos há de acontecer nos dias vindouros.' },
      { v: 2, en: 'Assemble yourselves, and hear, you sons of Jacob. Listen to Israel, your father.', pt: 'Ajuntai-vos, e ouvi, filhos de Jacó; ouvi a Israel vosso pai:' },
      { v: 3, en: '“Reuben, you are my firstborn, my might, and the beginning of my strength; excelling in dignity, and excelling in power.', pt: 'Rúben, tu és meu primogênito, minha força e as primícias do meu vigor, preeminente em dignidade e preeminente em poder.' },
      { v: 4, en: 'Boiling over like water, you shall not excel; because you went up to your father’s bed, then defiled it. He went up to my couch.', pt: 'Descomedido como a àgua, não reterás a preeminência; porquanto subiste ao leito de teu pai; então o contaminaste. Sim, ele subiu à minha cama.' },
      { v: 5, en: '“Simeon and Levi are brothers. Their swords are weapons of violence.', pt: 'Simeão e Levi são irmãos; as suas espadas são instrumentos de violência.' },
      { v: 6, en: 'My soul, don’t come into their council. My glory, don’t be united to their assembly; for in their anger they killed men. In their self-will they hamstrung cattle.', pt: 'No seu concílio não entres, ó minha alma! com a sua assembléia não te ajuntes, ó minha glória! porque no seu furor mataram homens, e na sua teima jarretaram bois.' },
      { v: 7, en: 'Cursed be their anger, for it was fierce; and their wrath, for it was cruel. I will divide them in Jacob, and scatter them in Israel.', pt: 'Maldito o seu furor, porque era forte! maldita a sua ira, porque era cruel! Dividi-los-ei em Jacó, e os espalharei em Israel.' },
      { v: 8, en: '“Judah, your brothers will praise you. Your hand will be on the neck of your enemies. Your father’s sons will bow down before you.', pt: 'Judá, a ti te louvarão teus irmãos; a tua mão será sobre o pescoço de teus inimigos: diante de ti se prostrarão os filhos de teu pai.' },
      { v: 9, en: 'Judah is a lion’s cub. From the prey, my son, you have gone up. He stooped down, he crouched as a lion, as a lioness. Who will rouse him up?', pt: 'Judá é um leãozinho. Subiste da presa, meu filho. Ele se encurva e se deita como um leão, e como uma leoa; quem o despertará?' },
      { v: 10, en: 'The scepter will not depart from Judah, nor the ruler’s staff from between his feet, until he comes to whom it belongs. To him will the obedience of the peoples be.', pt: 'O cetro não se arredará de Judà, nem o bastão de autoridade dentre seus pés, até que venha aquele a quem pertence; e a ele obedecerão os povos.' },
      { v: 11, en: 'Binding his foal to the vine, his donkey’s colt to the choice vine; he has washed his garments in wine, his robes in the blood of grapes.', pt: 'Atando ele o seu jumentinho à vide, e o filho da sua jumenta à videira seleta, lava as suas roupas em vinho e a sua vestidura em sangue de uvas.' },
      { v: 12, en: 'His eyes will be red with wine, his teeth white with milk.', pt: 'Os olhos serão escurecidos pelo vinho, e os dentes brancos de leite.' },
      { v: 13, en: '“Zebulun will dwell at the haven of the sea. He will be for a haven of ships. His border will be on Sidon.', pt: 'Zebulom habitarà no litoral; será ele ancoradouro de navios; e o seu termo estender-se-á até Sidom.' },
      { v: 14, en: '“Issachar is a strong donkey, lying down between the saddlebags.', pt: 'Issacar é jumento forte, deitado entre dois fardos.' },
      { v: 15, en: 'He saw a resting place, that it was good, the land, that it was pleasant. He bows his shoulder to the burden, and becomes a servant doing forced labor.', pt: 'Viu ele que o descanso era bom, e que a terra era agradável. Sujeitou os seus ombros à carga e entregou-se ao serviço forçado de um escravo.' },
      { v: 16, en: '“Dan will judge his people, as one of the tribes of Israel.', pt: 'Dã julgará o seu povo, como uma das tribos de Israel.' },
      { v: 17, en: 'Dan will be a serpent on the trail, an adder in the path, That bites the horse’s heels, so that his rider falls backward.', pt: 'Dã será serpente junto ao caminho, uma víbora junto à vereda, que morde os calcanhares do cavalo, de modo que caia o seu cavaleiro para trás.' },
      { v: 18, en: 'I have waited for your salvation, Yahweh.', pt: 'A tua salvação tenho esperado, ó Senhor!' },
      { v: 19, en: '“A troop will press on Gad, but he will press on their heel.', pt: 'Quanto a Gade, guerrilheiros o acometerão; mas ele, por sua vez, os acometerá.' },
      { v: 20, en: '“Asher’s food will be rich. He will produce royal dainties.', pt: 'De Aser, o seu pão será gordo; ele produzirá delícias reais.' },
      { v: 21, en: '“Naphtali is a doe set free, who bears beautiful fawns.', pt: 'Naftali é uma gazela solta; ele profere palavras formosas.' },
      { v: 22, en: '“Joseph is a fruitful vine, a fruitful vine by a spring. His branches run over the wall.', pt: 'José é um ramo frutífero, ramo frutífero junto a uma fonte; seus raminhos se estendem sobre o muro.' },
      { v: 23, en: 'The archers have severely grieved him, shot at him, and persecuted him:', pt: 'Os flecheiros lhe deram amargura, e o flecharam e perseguiram,' },
      { v: 24, en: 'But his bow remained strong. The arms of his hands were made strong, by the hands of the Mighty One of Jacob, (from there is the shepherd, the stone of Israel),', pt: 'mas o seu arco permaneceu firme, e os seus braços foram fortalecidos pelas mãos do Poderoso de Jacó, o Pastor, o Rochedo de Israel,' },
      { v: 25, en: 'even by the God of your father, who will help you; by the Almighty, who will bless you, with blessings of heaven above, blessings of the deep that lies below, blessings of the breasts, and of the womb.', pt: 'pelo Deus de teu pai, o qual te ajudará, e pelo Todo-Poderoso, o qual te abençoara, com bênçãos dos céus em cima, com bênçãos do abismo que jaz embaixo, com bênçãos dos seios e da madre.' },
      { v: 26, en: 'The blessings of your father have prevailed above the blessings of your ancestors, above the boundaries of the ancient hills. They will be on the head of Joseph, on the crown of the head of him who is separated from his brothers.', pt: 'As bênçãos de teu pai excedem as bênçãos dos montes eternos, as coisas desejadas dos eternos outeiros; sejam elas sobre a cabeça de José, e sobre o alto da cabeça daquele que foi separado de seus irmãos.' },
      { v: 27, en: '“Benjamin is a ravenous wolf. In the morning he will devour the prey. At evening he will divide the plunder.”', pt: 'Benjamim é lobo que despedaça; pela manhã devorará a presa, e à tarde repartirã o despojo.' },
      { v: 28, en: 'All these are the twelve tribes of Israel, and this is what their father spoke to them and blessed them. He blessed everyone according to his blessing.', pt: 'Todas estas são as doze tribos de Israel: e isto é o que lhes falou seu pai quando os abençoou; a cada um deles abençoou segundo a sua bênção.' },
      { v: 29, en: 'He instructed them, and said to them, “I am to be gathered to my people. Bury me with my fathers in the cave that is in the field of Ephron the Hittite,', pt: 'Depois lhes deu ordem, dizendo-lhes: Eu estou para ser congregado ao meu povo; sepultai-me com meus pais, na cova que está no campo de Efrom, o heteu,' },
      { v: 30, en: 'in the cave that is in the field of Machpelah, which is before Mamre, in the land of Canaan, which Abraham bought with the field from Ephron the Hittite as a burial place.', pt: 'na cova que está no campo de Macpela, que está em frente de Manre, na terra de Canaã, cova esta que Abraão comprou de Efrom, o heteu, juntamente com o respectivo campo, como propriedade de sepultura.' },
      { v: 31, en: 'There they buried Abraham and Sarah, his wife. There they buried Isaac and Rebekah, his wife, and there I buried Leah:', pt: 'Ali sepultaram a Abraão e a Sara, sua mulher; ali sepultaram a Isaque e a Rebeca, sua mulher; e ali eu sepultei a Léia.' },
      { v: 32, en: 'the field and the cave that is therein, which was purchased from the children of Heth.”', pt: 'O campo e a cova que está nele foram comprados aos filhos de Hete.' },
      { v: 33, en: 'When Jacob finished charging his sons, he gathered up his feet into the bed, and yielded up the spirit, and was gathered to his people.', pt: 'Acabando Jacó de dar estas instruçães a seus filhos, encolheu os seus pés na cama, expirou e foi congregado ao seu povo.' },
    ],
    50: [
      { v: 1, en: 'Joseph fell on his father’s face, wept on him, and kissed him.', pt: 'Então José se lançou sobre o rosto de seu pai, chorou sobre ele e o beijou.' },
      { v: 2, en: 'Joseph commanded his servants, the physicians, to embalm his father; and the physicians embalmed Israel.', pt: 'E José ordenou a seus servos, os médicos, que embalsamassem a seu pai; e os médicos embalsamaram a Israel.' },
      { v: 3, en: 'Forty days were fulfilled for him, for that is how many the days it takes to embalm. The Egyptians wept for him for seventy days.', pt: 'Cumpriram-se-lhe quarenta dias, porque assim se cumprem os dias de embalsamação; e os egípcios o choraram setenta dias.' },
      { v: 4, en: 'When the days of weeping for him were past, Joseph spoke to the house of Pharaoh, saying, “If now I have found favor in your eyes, please speak in the ears of Pharaoh, saying,', pt: 'Passados, pois, os dias de seu choro, disse José à casa de Faraó: Se agora tenho achado graça aos vossos olhos, rogo-vos que faleis aos ouvidos de Faraó, dizendo:' },
      { v: 5, en: '‘My father made me swear, saying, “Behold, I am dying. Bury me in my grave which I have dug for myself in the land of Canaan.” Now therefore, please let me go up and bury my father, and I will come again.’”', pt: 'Meu pai me fez jurar, dizendo: Eis que eu morro; em meu sepulcro, que cavei para mim na terra de Canaã, ali me sepultarás. Agora, pois, deixa-me subir, peço-te, e sepultar meu pai; então voltarei.' },
      { v: 6, en: 'Pharaoh said, “Go up, and bury your father, just like he made you swear.”', pt: 'Respondeu Faraó: Sobe, e sepulta teu pai, como ele te fez jurar.' },
      { v: 7, en: 'Joseph went up to bury his father; and with him went up all the servants of Pharaoh, the elders of his house, all the elders of the land of Egypt,', pt: 'Subiu, pois, José para sepultar a seu pai; e com ele subiram todos os servos de Faraó, os anciãos da sua casa, e todos os anciãos da terra do Egito,' },
      { v: 8, en: 'All the house of Joseph, his brothers, and his father’s house. Only their little ones, their flocks, and their herds, they left in the land of Goshen.', pt: 'como também toda a casa de José, e seus irmãos, e a casa de seu pai; somente deixaram na terra de Gósen os seus pequeninos, os seus rebanhos e o seu gado.' },
      { v: 9, en: 'There went up with him both chariots and horsemen. It was a very great company.', pt: 'E subiram com ele tanto carros como gente a cavalo; de modo que o concurso foi mui grande.' },
      { v: 10, en: 'They came to the threshing floor of Atad, which is beyond the Jordan, and there they lamented with a very great and severe lamentation. He mourned for his father seven days.', pt: 'Chegando eles à eira de Atade, que está além do Jordão, fizeram ali um grande e forte pranto; assim fez José por seu pai um grande pranto por sete dias.' },
      { v: 11, en: 'When the inhabitants of the land, the Canaanites, saw the mourning in the floor of Atad, they said, “This is a grievous mourning by the Egyptians.” Therefore its name was called Abel Mizraim, which is beyond the Jordan.', pt: 'Os moradores da terra, os cananeus, vendo o pranto na eira de Atade, disseram: Grande pranto é este dos egípcios; pelo que o lugar foi chamado Abel-Mizraim, o qual está além do Jordão.' },
      { v: 12, en: 'His sons did to him just as he commanded them,', pt: 'Assim os filhos de Jacó lhe fizeram como ele lhes ordenara;' },
      { v: 13, en: 'for his sons carried him into the land of Canaan, and buried him in the cave of the field of Machpelah, which Abraham bought with the field, as a possession for a burial site, from Ephron the Hittite, near Mamre.', pt: 'pois o levaram para a terra de Canaã, e o sepultaram na cova do campo de Macpela, que Abraão tinha comprado com o campo, como propriedade de sepultura, a Efrom, o heteu, em frente de Manre.' },
      { v: 14, en: 'Joseph returned into Egypt—he, and his brothers, and all that went up with him to bury his father, after he had buried his father.', pt: 'Depois de haver sepultado seu pai, José voltou para o Egito, ele, seus irmãos, e todos os que com ele haviam subido para sepultar seu pai.' },
      { v: 15, en: 'When Joseph’s brothers saw that their father was dead, they said, “It may be that Joseph will hate us, and will fully pay us back for all the evil which we did to him.”', pt: 'Vendo os irmãos de José que seu pai estava morto, disseram: Porventura José nos odiará e nos retribuirá todo o mal que lhe fizemos.' },
      { v: 16, en: 'They sent a message to Joseph, saying, “Your father commanded before he died, saying,', pt: 'Então mandaram dizer a José: Teu pai, antes da sua morte, nos ordenou:' },
      { v: 17, en: '‘You shall tell Joseph, “Now please forgive the disobedience of your brothers, and their sin, because they did evil to you.”’ Now, please forgive the disobedience of the servants of the God of your father.” Joseph wept when they spoke to him.', pt: 'Assim direis a José: Perdoa a transgressão de teus irmãos, e o seu pecado, porque te fizeram mal. Agora, pois, rogamos-te que perdoes a transgressão dos servos do Deus de teu pai. E José chorou quando eles lhe falavam.' },
      { v: 18, en: 'His brothers also went and fell down before his face; and they said, “Behold, we are your servants.”', pt: 'Depois vieram também seus irmãos, prostraram-se diante dele e disseram: Eis que nós somos teus servos.' },
      { v: 19, en: 'Joseph said to them, “Don’t be afraid, for am I in the place of God?', pt: 'Respondeu-lhes José: Não temais; acaso estou eu em lugar de Deus?' },
      { v: 20, en: 'As for you, you meant evil against me, but God meant it for good, to bring to pass, as it is today, to save many people alive.', pt: 'Vós, na verdade, intentastes o mal contra mim; Deus, porém, o intentou para o bem, para fazer o que se vê neste dia, isto é, conservar muita gente com vida.' },
      { v: 21, en: 'Now therefore don’t be afraid. I will nourish you and your little ones.” He comforted them, and spoke kindly to them.', pt: 'Agora, pois, não temais; eu vos sustentarei, a vós e a vossos filhinhos. Assim ele os consolou, e lhes falou ao coração.' },
      { v: 22, en: 'Joseph lived in Egypt, he, and his father’s house. Joseph lived one hundred ten years.', pt: 'José, pois, habitou no Egito, ele e a casa de seu pai; e viveu cento e dez anos.' },
      { v: 23, en: 'Joseph saw Ephraim’s children to the third generation. The children also of Machir, the son of Manasseh, were born on Joseph’s knees.', pt: 'E viu José os filhos de Efraim, da terceira geração; também os filhos de Maquir, filho de Manassés, nasceram sobre os joelhos de José.' },
      { v: 24, en: 'Joseph said to his brothers, “I am dying, but God will surely visit you, and bring you up out of this land to the land which he swore to Abraham, to Isaac, and to Jacob.”', pt: 'Depois disse José a seus irmãos: Eu morro; mas Deus certamente vos visitará, e vos fará subir desta terra para a terra que jurou a Abraão, a Isaque e a Jacó.' },
      { v: 25, en: 'Joseph took an oath from the children of Israel, saying, “God will surely visit you, and you shall carry up my bones from here.”', pt: 'E José fez jurar os filhos de Israel, dizendo: Certamente Deus vos visitará, e fareis transportar daqui os meus ossos.' },
      { v: 26, en: 'So Joseph died, being one hundred ten years old, and they embalmed him, and he was put in a coffin in Egypt.', pt: 'Assim morreu José, tendo cento e dez anos de idade; e o embalsamaram e o puseram num caixão no Egito.' },
    ],
  },
};

export default book;
